window.DHP={"translators":{"muller":{"name":"F. Max Müller","year":1881,"n":423,"src":"Project Gutenberg (public domain)"},"wagiswara":{"name":"Wagiswara & Saunders","year":1912,"n":420,"src":"Project Gutenberg (public domain)"},"kaviratna":{"name":"Harischandra Kaviratna","year":1980,"n":423,"src":"Theosophical Univ. Press"},"buddharakkhita":{"name":"Acharya Buddharakkhita","year":1985,"n":423,"src":"Access to Insight"},"thanissaro":{"name":"Thanissaro Bhikkhu","year":1997,"n":423,"src":"Access to Insight"},"suddhaso":{"name":"Bhikkhu Suddhāso","year":2016,"n":423,"src":"SuttaCentral"},"sujato":{"name":"Bhikkhu Sujato","year":2021,"n":423,"src":"SuttaCentral"}},"order":["muller","wagiswara","kaviratna","buddharakkhita","thanissaro","suddhaso","sujato"],"vaggas":[{"n":1,"pali":"Yamakavagga","en":"Pairs","from":1,"to":20},{"n":2,"pali":"Appamādavagga","en":"Diligence","from":21,"to":32},{"n":3,"pali":"Cittavagga","en":"The Mind","from":33,"to":43},{"n":4,"pali":"Pupphavagga","en":"Flowers","from":44,"to":59},{"n":5,"pali":"Bālavagga","en":"The Fool","from":60,"to":75},{"n":6,"pali":"Paṇḍitavagga","en":"The Astute","from":76,"to":89},{"n":7,"pali":"Arahantavagga","en":"The Perfected Ones","from":90,"to":99},{"n":8,"pali":"Sahassavagga","en":"The Thousands","from":100,"to":115},{"n":9,"pali":"Pāpavagga","en":"Wickedness","from":116,"to":128},{"n":10,"pali":"Daṇḍavagga","en":"The Rod","from":129,"to":145},{"n":11,"pali":"Jarāvagga","en":"Old Age","from":146,"to":156},{"n":12,"pali":"Attavagga","en":"The Self","from":157,"to":166},{"n":13,"pali":"Lokavagga","en":"The World","from":167,"to":178},{"n":14,"pali":"Buddhavagga","en":"The Buddhas","from":179,"to":196},{"n":15,"pali":"Sukhavagga","en":"Happiness","from":197,"to":208},{"n":16,"pali":"Piyavagga","en":"The Beloved","from":209,"to":220},{"n":17,"pali":"Kodhavagga","en":"Anger","from":221,"to":234},{"n":18,"pali":"Malavagga","en":"Stains","from":235,"to":255},{"n":19,"pali":"Dhammaṭṭhavagga","en":"The Just","from":256,"to":272},{"n":20,"pali":"Maggavagga","en":"The Path","from":273,"to":289},{"n":21,"pali":"Pakiṇṇakavagga","en":"Miscellaneous","from":290,"to":305},{"n":22,"pali":"Nirayavagga","en":"Hell","from":306,"to":319},{"n":23,"pali":"Nāgavagga","en":"Elephants","from":320,"to":333},{"n":24,"pali":"Taṇhāvagga","en":"Craving","from":334,"to":359},{"n":25,"pali":"Bhikkhuvagga","en":"Mendicants","from":360,"to":382},{"n":26,"pali":"Brāhmaṇavagga","en":"Brahmins","from":383,"to":423}],"verses":[{"n":1,"vg":1,"pali":"Manopubbaṅgamā dhammā,\nmanoseṭṭhā manomayā;\nManasā ce paduṭṭhena,\nbhāsati vā karoti vā;\nTato naṁ dukkhamanveti,\ncakkaṁva vahato padaṁ.","v":[{"k":"muller","t":"All that we are is the result of what we have thought: it is founded on our thoughts, it is made up of our thoughts. If a man speaks or acts with an evil thought, pain follows him, as the wheel follows the foot of the ox that draws the carriage."},{"k":"wagiswara","t":"All states arising have mind for their causing,\nMind for their master, of mind are the offspring.\nHe who with foul mind speaks or does action--\nHim pain pursues as the wheel dogs the ox-hoof."},{"k":"kaviratna","t":"All the phenomena of existence have mind as their precursor, mind as their supreme leader, and of mind are they made. If with an impure mind one speaks or acts, suffering follows him in the same way as the wheel follows the foot of the drawer (of the chariot)."},{"k":"buddharakkhita","t":"Mind precedes all mental states. Mind is their chief; they are all mind-wrought. If with an impure mind a person speaks or acts suffering follows him like the wheel that follows the foot of the ox."},{"k":"thanissaro","t":"Phenomena are preceded by the heart,\nruled by the heart,\nmade of the heart.\nIf you speak or act\nwith a corrupted heart,\nthen suffering follows you —\nas the wheel of the cart,\nthe track of the ox\nthat pulls it."},{"k":"suddhaso","t":"All things are preceded by the mind,\nsurpassed by the mind, created by the mind.\nIf one speaks or acts\nwith a corrupted mind,\nThen suffering follows,\nAs a track follows a wheel."},{"k":"sujato","t":"Intention shapes experiences;\nintention is first, they're made by intention.\nIf with corrupt intent\nyou speak or act,\nsuffering follows you,\nlike a wheel, the ox's foot."}]},{"n":2,"vg":1,"pali":"Manopubbaṅgamā dhammā,\nmanoseṭṭhā manomayā;\nManasā ce pasannena,\nbhāsati vā karoti vā;\nTato naṁ sukhamanveti,\nchāyāva anapāyinī.","v":[{"k":"muller","t":"All that we are is the result of what we have thought: it is founded on our thoughts, it is made up of our thoughts. If a man speaks or acts with a pure thought, happiness follows him, like a shadow that never leaves him."},{"k":"wagiswara","t":"All states arising have mind for their causing,\nMind for their master, of mind are the offspring.\nHe who with pure mind speaks or does action--\nHim bliss pursues, to him clings like his shadow."},{"k":"kaviratna","t":"All the phenomena of existence have mind as their precursor, mind as their supreme leader, and of mind are they made. If with a pure mind one speaks or acts, happiness follows him like his shadow that never leaves him."},{"k":"buddharakkhita","t":"Mind precedes all mental states. Mind is their chief; they are all mind-wrought. If with a pure mind a person speaks or acts happiness follows him like his never-departing shadow."},{"k":"thanissaro","t":"Phenomena are preceded by the heart,\nruled by the heart,\nmade of the heart.\nIf you speak or act\nwith a calm, bright heart,\nthen happiness follows you,\nlike a shadow\nthat never leaves."},{"k":"suddhaso","t":"All things are preceded by the mind,\nsurpassed by the mind, created by the mind.\nIf one speaks or acts\nwith a pure mind,\nThen happiness follows,\nAs a shadow that never leaves."},{"k":"sujato","t":"Intention shapes experiences;\nintention is first, they're made by intention.\nIf with pure intent\nyou speak or act,\nhappiness follows you\nlike a shadow that never leaves."}]},{"n":3,"vg":1,"pali":"Akkocchi maṁ avadhi maṁ,\najini maṁ ahāsi me;\nYe ca taṁ upanayhanti,\nveraṁ tesaṁ na sammati.","v":[{"k":"muller","t":"\"He abused me, he beat me, he defeated me, he robbed me,\"--in those who harbour such thoughts hatred will never cease."},{"k":"wagiswara","t":"\"This man abused me: he beat me and conquered,\nConquered and plundered.\" Cherishing in such thoughts,\nNever appeased is the hatred of such men."},{"k":"kaviratna","t":"The hatred of those who harbor such ill feelings as, \"He reviled me, assaulted me, vanquished me and robbed me,\" is never appeased."},{"k":"buddharakkhita","t":"\"He abused me, he struck me, he overpowered me, he robbed me.\" Those who harbor such thoughts do not still their hatred."},{"k":"thanissaro","t":"'He insulted me,\nhit me,\nbeat me,\nrobbed me'\n— for those who brood on this,\nhostility isn't stilled."},{"k":"suddhaso","t":"\"They abused me, they hurt me,\nthey defeated me, they robbed me!\"\nFor those who hold on to this\nhostility is never replaced by peace."},{"k":"sujato","t":"\"They abused me, they hit me!\nThey beat me, they robbed me!\"\nFor those who bear such a grudge,\nhatred is never laid to rest."}]},{"n":4,"vg":1,"pali":"Akkocchi maṁ avadhi maṁ,\najini maṁ ahāsi me;\nYe ca taṁ nupanayhanti,\nveraṁ tesūpasammati.","v":[{"k":"muller","t":"\"He abused me, he beat me, he defeated me, he robbed me,\"--in those who do not harbour such thoughts hatred will cease."},{"k":"wagiswara","t":"\"This man abused me, he beat me and conquered,\nConquered and plundered.\" Not having such thoughts,\nQuickly appeased is the hatred of such men."},{"k":"kaviratna","t":"The hatred of those who do not harbor such ill feelings as, \"He reviled me, assaulted me, vanquished me and robbed me,\" is easily pacified."},{"k":"buddharakkhita","t":"\"He abused me, he struck me, he overpowered me, he robbed me.\" Those who do not harbor such thoughts still their hatred."},{"k":"thanissaro","t":"'He insulted me,\nhit me,\nbeat me,\nrobbed me' —\nfor those who don't brood on this,\nhostility is stilled."},{"k":"suddhaso","t":"\"They abused me, they hurt me,\nthey defeated me, they robbed me!\"\nFor those who do not hold on to this\nhostility is replaced by peace."},{"k":"sujato","t":"\"They abused me, they hit me!\nThey beat me, they robbed me!\"\nFor those who bear no such grudge,\nhatred is laid to rest."}]},{"n":5,"vg":1,"pali":"Na hi verena verāni,\nsammantīdha kudācanaṁ;\nAverena ca sammanti,\nesa dhammo sanantano.","v":[{"k":"muller","t":"For hatred does not cease by hatred at any time: hatred ceases by love, this is an old rule."},{"k":"wagiswara","t":"Never by hatred is hatred appeaséd\nNay! but by kindness; that's the old-time Norm."},{"k":"kaviratna","t":"Through hatred, hatreds are never appeased; through non-hatred are hatreds always appeased — and this is a law eternal."},{"k":"buddharakkhita","t":"Hatred is never appeased by hatred in this world. By non-hatred alone is hatred appeased. This is a law eternal."},{"k":"thanissaro","t":"Hostilities aren't stilled\nthrough hostility,\nregardless.\nHostilities are stilled\nthrough non-hostility:\nthis, an unending truth."},{"k":"suddhaso","t":"Hostility is never pacified\nby means of hostility.\nOnly by means of non-hostility is it pacified.\nThis is an eternal truth."},{"k":"sujato","t":"For never is hatred\nlaid to rest by hate,\nit's laid to rest by love:\nthis is an ancient teaching."}]},{"n":6,"vg":1,"pali":"Pare ca na vijānanti,\nmayamettha yamāmase;\nYe ca tattha vijānanti,\ntato sammanti medhagā.","v":[{"k":"muller","t":"The world does not know that we must all come to an end here;--but those who know it, their quarrels cease at once."},{"k":"wagiswara","t":"Others don't grasp this--\"We men are mortals\".\nMen who can grasp this soon end their quarrels."},{"k":"kaviratna","t":"Most people never realize that all of us here shall one day perish. But those who do realize that truth settle their quarrels peacefully."},{"k":"buddharakkhita","t":"There are those who do not realize that one day we all must die. But those who do realize this settle their quarrels."},{"k":"thanissaro","t":"Unlike those who don't realize\nthat we're here on the verge\nof perishing,\nthose who do:\ntheir quarrels are stilled."},{"k":"suddhaso","t":"Others do not know\nthat we must be restrained.\nThe wise ones who know this\nattain peace."},{"k":"sujato","t":"When others do not understand,\nlet us, who do understand this,\nrestrain ourselves in this regard;\nfor that is how conflicts are laid to rest."}]},{"n":7,"vg":1,"pali":"Subhānupassiṁ viharantaṁ,\nindriyesu asaṁvutaṁ;\nBhojanamhi cāmattaññuṁ,\nkusītaṁ hīnavīriyaṁ;\nTaṁ ve pasahati māro,\nvāto rukkhaṁva dubbalaṁ.","v":[{"k":"muller","t":"He who lives looking for pleasures only, his senses uncontrolled, immoderate in his food, idle, and weak, Mara (the tempter) will certainly overthrow him, as the wind throws down a weak tree."},{"k":"wagiswara","t":"Looking for fair sights, unchecked in his senses,\nIn food uncontrolled, slack, inert, without vigour,\nDeath overwhelms him, as winds uproot weak trees."},{"k":"kaviratna","t":"The pleasure-seeker who finds delight in physical objects, whose senses are unsubdued, who is immoderate in eating, indolent and listless, him Mara (the Evil One) prevails against, as does the monsoon wind against a weak-rooted tree."},{"k":"buddharakkhita","t":"Just as a storm throws down a weak tree, so does Mara overpower the man who lives for the pursuit of pleasures, who is uncontrolled in his senses, immoderate in eating, indolent, and dissipated. [1]"},{"k":"thanissaro","t":"One who stays focused on the beautiful,\nis unrestrained with the senses,\nknowing no moderation in food,\napathetic, unenergetic:\nMara overcomes him\nas the wind, a weak tree."},{"k":"suddhaso","t":"If one focuses on beauty,\nlacks sense-restraint,\ndoes not know the right amount when eating,\nis lazy, and lacks energy,\nMāra subdues such a person\njust as the wind subdues a weak tree."},{"k":"sujato","t":"Those who contemplate the beautiful,\ntheir faculties unrestrained,\nimmoderate in eating,\nlazy, lacking energy:\nMāra strikes them down\nlike the wind, a feeble tree."}]},{"n":8,"vg":1,"pali":"Asubhānupassiṁ viharantaṁ,\nIndriyesu susaṁvutaṁ;\nBhojanamhi ca mattaññuṁ,\nSaddhaṁ āraddhavīriyaṁ;\nTaṁ ve nappasahati māro,\nVāto selaṁva pabbataṁ.","v":[{"k":"muller","t":"He who lives without looking for pleasures, his senses well controlled, moderate in his food, faithful and strong, him Mara will certainly not overthrow, any more than the wind throws down a rocky mountain."},{"k":"wagiswara","t":"He who lives sense-restrained, heedless of fair sights,\nWho in food keeps the mean, is trusty and sturdy,\nDeath cannot shake him: winds cannot move mountains."},{"k":"kaviratna","t":"He who perceives no pleasure in physical objects, who has perfect control of his senses, is moderate in eating, who is unflinching in faith, energetic, him Mara does not prevail against any more than does the wind against a rocky mountain."},{"k":"buddharakkhita","t":"Just as a storm cannot prevail against a rocky mountain, so Mara can never overpower the man who lives meditating on the impurities, who is controlled in his senses, moderate in eating, and filled with faith and earnest effort. [2]"},{"k":"thanissaro","t":"One who stays focused on the foul,\nis restrained with regard to the senses,\nknowing moderation in food,\nfull of conviction & energy:\nMara does not overcome him\nas the wind, a mountain of rock."},{"k":"suddhaso","t":"If one does not focus on beauty,\nhas good sense-restraint,\nknows the right amount when eating,\nhas faith, and has persistent energy,\nMāra does not subdue such a person\njust as the wind does not subdue a stone mountain."},{"k":"sujato","t":"Those who contemplate the ugly,\ntheir faculties well-restrained,\neating in moderation,\nfaithful and energetic:\nMāra cannot strike them down,\nlike the wind, a rocky mountain."}]},{"n":9,"vg":1,"pali":"Anikkasāvo kāsāvaṁ,\nyo vatthaṁ paridahissati;\nApeto damasaccena,\nna so kāsāvamarahati.","v":[{"k":"muller","t":"He who wishes to put on the yellow dress without having cleansed himself from sin, who disregards temperance and truth, is unworthy of the yellow dress."},{"k":"wagiswara","t":"Without doffing his faults who would don the monk's yellow,\nVoid of truth and of training, deserves not the monk's robe.\nIf he doff all his faults and be versed in the virtues,\nIn the training and truth firm, he merits the monk's robe."},{"k":"kaviratna","t":"He who dons the yellow robe without even cleansing himself of sensuality, who is devoid of self-restraint and truthfulness, is indeed not fit for the yellow robe."},{"k":"buddharakkhita","t":"Whoever being depraved, devoid of self-control and truthfulness, should don the monk's yellow robe, he surely is not worthy of the robe."},{"k":"thanissaro","t":"He who, depraved,\ndevoid\nof truthfulness\n& self-control,\nputs on the ochre robe,\ndoesn't deserve the ochre robe."},{"k":"suddhaso","t":"An impure person\nwho dons a monastic robe\nwithout true self-control\nis not worthy of the monastic robe."},{"k":"sujato","t":"One who, not free of stains themselves,\nwould wear the robe stained in ocher,\nbereft of self-control and of truth:\nthey are not worthy of the ocher robe."}]},{"n":10,"vg":1,"pali":"Yo ca vantakasāvassa,\nsīlesu susamāhito;\nUpeto damasaccena,\nsa ve kāsāvamarahati.","v":[{"k":"muller","t":"But he who has cleansed himself from sin, is well grounded in all virtues, and regards also temperance and truth, he is indeed worthy of the yellow dress."},{"k":"wagiswara","t":"Without doffing his faults who would don the monk's yellow,\nVoid of truth and of training, deserves not the monk's robe.\nIf he doff all his faults and be versed in the virtues,\nIn the training and truth firm, he merits the monk's robe."},{"k":"kaviratna","t":"He who is purged of all sensuality, firmly established in moral virtues, possessed of self-restraint and truthfulness, is indeed fit for the yellow robe."},{"k":"buddharakkhita","t":"But whoever is purged of depravity, well-established in virtues and filled with self-control and truthfulness, he indeed is worthy of the yellow robe."},{"k":"thanissaro","t":"But he who is free\nof depravity\nendowed\nwith truthfulness\n& self-control,\nwell-established\nin the precepts,\ntruly deserves the ochre robe."},{"k":"suddhaso","t":"One who has expelled all impurity,\nis focused on moral conduct,\nand is committed to true self-control\nis worthy of the monastic robe."},{"k":"sujato","t":"One who's purged all their stains,\nsteady in ethics,\npossessed of self-control and of truth,\nthey are truly worthy of the ocher robe."}]},{"n":11,"vg":1,"pali":"Asāre sāramatino,\nsāre cāsāradassino;\nTe sāraṁ nādhigacchanti,\nmicchāsaṅkappagocarā.","v":[{"k":"muller","t":"They who imagine truth in untruth, and see untruth in truth, never arrive at truth, but follow vain desires."},{"k":"wagiswara","t":"In the false seeing truth, and in truth seeing falsehood,\nMen touch not the truth, but are fed on illusion.\nBut in truth seeing truth and falsehood in falsehood,\nMen touch the truth ever, feeding on right thoughts."},{"k":"kaviratna","t":"Those who take the non-real for the real and the real for the non-real and thus fall victims to erroneous notions, never reach the essence of reality."},{"k":"buddharakkhita","t":"Those who mistake the unessential to be essential and the essential to be unessential, dwelling in wrong thoughts, never arrive at the essential."},{"k":"thanissaro","t":"Those who regard\nnon-essence as essence\nand see essence as non-,\ndon't get to the essence,\nranging about in wrong resolves."},{"k":"suddhaso","t":"One who thinks the non-essential is essential\nand who sees the essential as non-essential\ndoes not arrive at the essence;\ntheir conduct is based on incorrect attitudes."},{"k":"sujato","t":"Thinking the inessential is essential,\nseeing the essential as inessential;\nthey don't realize the essential,\nfor wrong thoughts are their habitat."}]},{"n":12,"vg":1,"pali":"Sārañca sārato ñatvā,\nasārañca asārato;\nTe sāraṁ adhigacchanti,\nsammāsaṅkappagocarā.","v":[{"k":"muller","t":"They who know truth in truth, and untruth in untruth, arrive at truth, and follow true desires."},{"k":"wagiswara","t":"In the false seeing truth, and in truth seeing falsehood,\nMen touch not the truth, but are fed on illusion.\nBut in truth seeing truth and falsehood in falsehood,\nMen touch the truth ever, feeding on right thoughts."},{"k":"kaviratna","t":"Having realized the essential as the essential and the nonessential as the nonessential, they by thus following correct thinking attain the essential."},{"k":"buddharakkhita","t":"Those who know the essential to be essential and the unessential to be unessential, dwelling in right thoughts, do arrive at the essential."},{"k":"thanissaro","t":"But those who know\nessence as essence,\nand non-essence as non-,\nget to the essence,\nranging about in right resolves."},{"k":"suddhaso","t":"One who knows the essential as essential\nand the non-essential as non-essential\narrives at the essence;\ntheir conduct is based on correct attitudes."},{"k":"sujato","t":"Having known the essential as essential,\nand the inessential as inessential;\nthey realize the essential,\nfor right thoughts are their habitat."}]},{"n":13,"vg":1,"pali":"Yathā agāraṁ ducchannaṁ,\nvuṭṭhī samativijjhati;\nEvaṁ abhāvitaṁ cittaṁ,\nrāgo samativijjhati.","v":[{"k":"muller","t":"As rain breaks through an ill-thatched house, passion will break through an unreflecting mind."},{"k":"wagiswara","t":"As the rain through the roof of a house that is ill-thatched,\nLust leaks through the mind not composed by the training:\nAs rain never leaks through the roof that is well-thatched,\nSo through the mind well-trained lust leaketh never."},{"k":"kaviratna","t":"As the monsoon rain pierces through the roof of an ill-thatched house, so lust enters the undisciplined mind."},{"k":"buddharakkhita","t":"Just as rain breaks through an ill-thatched house, so passion penetrates an undeveloped mind."},{"k":"thanissaro","t":"As rain seeps into\nan ill-thatched hut,\nso passion,\nthe undeveloped mind."},{"k":"suddhaso","t":"Just as rain penetrates\na poorly sealed house,\nin the same way, passion penetrates\nan undeveloped mind."},{"k":"sujato","t":"Just as rain seeps into\na poorly roofed house,\nlust seeps into\nan undeveloped mind."}]},{"n":14,"vg":1,"pali":"Yathā agāraṁ suchannaṁ,\nvuṭṭhī na samativijjhati;\nEvaṁ subhāvitaṁ cittaṁ,\nrāgo na samativijjhati.","v":[{"k":"muller","t":"As rain does not break through a well-thatched house, passion will not break through a well-reflecting mind."},{"k":"wagiswara","t":"As the rain through the roof of a house that is ill-thatched,\nLust leaks through the mind not composed by the training:\nAs rain never leaks through the roof that is well-thatched,\nSo through the mind well-trained lust leaketh never."},{"k":"kaviratna","t":"As the monsoon rain does not enter a well-thatched house, so lust does not enter a well-disciplined mind."},{"k":"buddharakkhita","t":"Just as rain does not break through a well-thatched house, so passion never penetrates a well-developed mind."},{"k":"thanissaro","t":"As rain doesn't seep into\na well-thatched hut,\nso passion does not,\nthe well-developed mind."},{"k":"suddhaso","t":"Just as rain does not penetrate\na well-sealed house,\nin the same way, passion does not penetrate\na well-developed mind."},{"k":"sujato","t":"Just as rain doesn't seep into\na well roofed house,\nlust doesn't seep into\na well developed mind."}]},{"n":15,"vg":1,"pali":"Idha socati pecca socati,\nPāpakārī ubhayattha socati;\nSo socati so vihaññati,\nDisvā kammakiliṭṭhamattano.","v":[{"k":"muller","t":"The evil-doer mourns in this world, and he mourns in the next; he mourns in both. He mourns and suffers when he sees the evil of his own work."},{"k":"wagiswara","t":"Here he grieves and grieves hereafter: doubly grieves the evil-doer,\nGrieves and suffers anguish when he sees the foulness of his deeds."},{"k":"kaviratna","t":"The sinner laments here, laments hereafter, and he laments in both worlds. Having seen himself sullied by his sinful deeds, the evildoer grieves and is afflicted."},{"k":"buddharakkhita","t":"The evil-doer grieves here and hereafter; he grieves in both the worlds. He laments and is afflicted, recollecting his own impure deeds."},{"k":"thanissaro","t":"Here he grieves\nhe grieves hereafter.\nIn both worlds\nthe wrong-doer grieves.\nHe grieves, he's afflicted,\nseeing the corruption\nof his deeds."},{"k":"suddhaso","t":"One sorrows here, one sorrows afterwards,\nan evildoer sorrows both times.\nOne sorrows and agonizes\nafter seeing one's own defiled actions."},{"k":"sujato","t":"Here they grieve, hereafter they grieve,\nan evildoer grieves in both places.\nThey grieve and fret,\nseeing their own corrupt deeds."}]},{"n":16,"vg":1,"pali":"Idha modati pecca modati,\nKatapuñño ubhayattha modati;\nSo modati so pamodati,\nDisvā kammavisuddhimattano.","v":[{"k":"muller","t":"The virtuous man delights in this world, and he delights in the next; he delights in both. He delights and rejoices, when he sees the purity of his own work."},{"k":"wagiswara","t":"Happy here, he's happy after: doing good he's doubly glad:\nGlad, exceeding happy, when he sees the pureness of his deeds."},{"k":"kaviratna","t":"The doer of wholesome deeds rejoices here and rejoices hereafter; thus he rejoices in both places. Having beheld his pure deeds he rejoices exceedingly."},{"k":"buddharakkhita","t":"The doer of good rejoices here and hereafter; he rejoices in both the worlds. He rejoices and exults, recollecting his own pure deeds."},{"k":"thanissaro","t":"Here he rejoices\nhe rejoices hereafter.\nIn both worlds\nthe merit-maker rejoices.\nHe rejoices, is jubilant,\nseeing the purity\nof his deeds."},{"k":"suddhaso","t":"One rejoices here, one rejoices afterwards,\none who has made merit rejoices both times.\nOne rejoices and exults\nafter seeing one's own pure actions."},{"k":"sujato","t":"Here they rejoice, hereafter they rejoice,\none who does good rejoices in both places.\nThey rejoice and celebrate,\nseeing their own pure deeds."}]},{"n":17,"vg":1,"pali":"Idha tappati pecca tappati,\nPāpakārī ubhayattha tappati;\n\"Pāpaṁ me katan\"ti tappati,\nBhiyyo tappati duggatiṁ gato.","v":[{"k":"muller","t":"The evil-doer suffers in this world, and he suffers in the next; he suffers in both. He suffers when he thinks of the evil he has done; he suffers more when going on the evil path."},{"k":"wagiswara","t":"Here he suffers, suffers after: doubly suffer evil-doers:\nThoughts of ill-deeds torture, much more torture when they enter hell."},{"k":"kaviratna","t":"He repents here, repents hereafter, the evildoer repents in both worlds. \"Evil has been committed by me,\" thinking thus he repents. Having taken the path of evil he repents even more."},{"k":"buddharakkhita","t":"The evil-doer suffers here and hereafter; he suffers in both the worlds. The thought, \"Evil have I done,\" torments him, and he suffers even more when gone to realms of woe."},{"k":"thanissaro","t":"Here he's tormented\nhe's tormented hereafter.\nIn both worlds\nthe wrong-doer's tormented.\nHe's tormented at the thought,\n'I've done wrong.'\nHaving gone to a bad destination,\nhe's tormented\nall the more."},{"k":"suddhaso","t":"Tormented here, tormented afterwards,\nan evildoer is tormented both times.\nOne is tormented by the thought \"I have done evil,\"\nAnd one is tormented even more when one has arrived at a bad destiny."},{"k":"sujato","t":"Here they're tormented,\nhereafter they're tormented,\nan evildoer is tormented in both places.\nThey're tormented\nthinking of bad things they've done;\nwhen gone to a bad place,\nthey're tormented all the more."}]},{"n":18,"vg":1,"pali":"Idha nandati pecca nandati,\nKatapuñño ubhayattha nandati;\n\"Puññaṁ me katan\"ti nandati,\nBhiyyo nandati suggatiṁ gato.","v":[{"k":"muller","t":"The virtuous man is happy in this world, and he is happy in the next; he is happy in both. He is happy when he thinks of the good he has done; he is still more happy when going on the good path."},{"k":"wagiswara","t":"He rejoices here and after: doing good he's doubly glad:\nThoughts of good deeds comfort, much more comfort when they enter heaven."},{"k":"kaviratna","t":"He rejoices here, he rejoices hereafter, the doer of wholesome deeds rejoices in both worlds. \"Good has been committed by me,\" thinking thus he rejoices. Having taken the celestial path, he rejoices exceedingly."},{"k":"buddharakkhita","t":"The doer of good delights here and hereafter; he delights in both the worlds. The thought, \"Good have I done,\" delights him, and he delights even more when gone to realms of bliss."},{"k":"thanissaro","t":"Here he delights\nhe delights hereafter.\nIn both worlds\nthe merit-maker delights.\nHe delights at the thought,\n'I've made merit.'\nHaving gone to a good destination,\nhe delights\nall the more."},{"k":"suddhaso","t":"One delights here, one delights afterwards,\none who has made merit delights both times.\nOne is delighted by the thought \"I have made merit,\"\nAnd one delights even more when one has arrived at a good destiny."},{"k":"sujato","t":"Here they delight, hereafter they delight,\none who does good delights in both places.\nThey delight thinking of good things they've done;\nwhen gone to a good place, they delight all the more."}]},{"n":19,"vg":1,"pali":"Bahumpi ce saṁhita bhāsamāno,\nNa takkaro hoti naro pamatto;\nGopova gāvo gaṇayaṁ paresaṁ,\nNa bhāgavā sāmaññassa hoti.","v":[{"k":"muller","t":"The thoughtless man, even if he can recite a large portion (of the law), but is not a doer of it, has no share in the priesthood, but is like a cowherd counting the cows of others."},{"k":"wagiswara","t":"Though reciting many verses, if they do not what they preach,\nSluggards, counting others' cattle, cannot share the Brotherhood."},{"k":"kaviratna","t":"A heedless man, though he utters much of the Canon, but does not act accordingly, is like unto a cowherd who counts the cattle of others. He is, verily, not a sharer of the fruit of the monastic life."},{"k":"buddharakkhita","t":"Much though he recites the sacred texts, but acts not accordingly, that heedless man is like a cowherd who only counts the cows of others — he does not partake of the blessings of the holy life."},{"k":"thanissaro","t":"If he recites many teachings, but\n— heedless man —\ndoesn't do what they say,\nlike a cowherd counting the cattle of\nothers,\nhe has no share in the contemplative life."},{"k":"suddhaso","t":"A negligent person who says much that is beneficial\nbut does not act accordingly\nis like a cowherd who counts other people's cows,\nand is not part of the contemplative life."},{"k":"sujato","t":"Much though they may recite scripture,\nif a negligent person does not apply them,\nthen, like a cowherd who counts the cattle of others,\nthey miss out on the blessings of the ascetic life."}]},{"n":20,"vg":1,"pali":"Appampi ce saṁhita bhāsamāno,\nDhammassa hoti anudhammacārī;\nRāgañca dosañca pahāya mohaṁ,\nSammappajāno suvimuttacitto;\nAnupādiyāno idha vā huraṁ vā,\nSa bhāgavā sāmaññassa hoti.\nYamakavaggo paṭhamo.","v":[{"k":"muller","t":"The follower of the law, even if he can recite only a small portion (of the law), but, having forsaken passion and hatred and foolishness, possesses true knowledge and serenity of mind, he, caring for nothing in this world or that to come, has indeed a share in the priesthood."},{"k":"wagiswara","t":"Practising the Norm he preaches, though he utter verses few,\nQuit of anger, lust and folly, truly wise, with thoughts set free,\nCaring nought for this or that world, he hath part in brotherhood.\n^$/"},{"k":"kaviratna","t":"A man, though he recites only a little of the Canon, but acts according to the precepts of the Sacred Law, who, having got rid of lust, hatred and delusion, has firmly established himself in liberated thought, and clinging to no worldly possessions here or hereafter — such a one becomes indeed a sharer of the true fruit of the monastic life."},{"k":"buddharakkhita","t":"Little though he recites the sacred texts, but puts the Teaching into practice, forsaking lust, hatred, and delusion, with true wisdom and emancipated mind, clinging to nothing of this or any other world — he indeed partakes of the blessings of a holy life."},{"k":"thanissaro","t":"If he recites next to nothing\nbut follows the Dhamma\nin line with the Dhamma;\nabandoning passion,\naversion, delusion;\nalert,\nhis mind well-released,\nnot clinging\neither here or hereafter:\nhe has his share in the contemplative life."},{"k":"suddhaso","t":"Even if they say little that is beneficial,\none who lives according to the Dhamma,\nhaving abandoned passion, hatred, and delusion,\nwith accurate understanding and a well-liberated mind,\nnot grasping either here or beyond,\nis part of the contemplative life."},{"k":"sujato","t":"Little though they may recite scripture,\nif they live in line with the teaching,\nhaving given up greed, hate, and delusion,\nwith deep understanding and heart well freed,\nnot grasping to this life or the next,\nthey share in the blessings of the ascetic life."}]},{"n":21,"vg":2,"pali":"Appamādo amatapadaṁ,\npamādo maccuno padaṁ;\nAppamattā na mīyanti,\nye pamattā yathā matā.","v":[{"k":"muller","t":"Earnestness is the path of immortality (Nirvana), thoughtlessness the path of death. Those who are in earnest do not die, those who are thoughtless are as if dead already."},{"k":"wagiswara","t":"Heedfulness leads to the Deathless; heedlessness leads unto Death!\nHeedful men live on for ever; they who heed not are as dead."},{"k":"kaviratna","t":"Vigilance is the path to immortality; non-vigilance is the path to death; the vigilant do not die; the non-vigilant, though alive, are like unto the dead."},{"k":"buddharakkhita","t":"Heedfulness is the path to the Deathless. Heedlessness is the path to death. The heedful die not. The heedless are as if dead already. [3]"},{"k":"thanissaro","t":"Heedfulness: the path to the Deathless.\nHeedlessness: the path to death.\nThe heedful do not die.\nThe heedless are as if\nalready dead."},{"k":"suddhaso","t":"Non-negligence is the path of the Deathless,\nnegligence is the path of death.\nThose who are not negligent never die,\nthose who are negligent are like the dead."},{"k":"sujato","t":"Heedfulness is the state free of death;\nheedlessness is the state of death.\nThe heedful do not die,\nwhile the heedless are like the dead."}]},{"n":22,"vg":2,"pali":"Evaṁ visesato ñatvā,\nappamādamhi paṇḍitā;\nAppamāde pamodanti,\nariyānaṁ gocare ratā.","v":[{"k":"muller","t":"Those who are advanced in earnestness, having understood this clearly, delight in earnestness, and rejoice in the knowledge of the Ariyas (the elect)."},{"k":"wagiswara","t":"Knowing this full surely, wise men take delight in heedfulness;\nHeedfully they range with joy the pastures of the Worthy Ones."},{"k":"kaviratna","t":"Knowing this outstanding feature of vigilance, the wise delight in vigilance, rejoicing in the ways of the Noble Ones (ariya)."},{"k":"buddharakkhita","t":"Clearly understanding this excellence of heedfulness, the wise exult therein and enjoy the resort of the Noble Ones. [4]"},{"k":"thanissaro","t":"Knowing this as a true distinction,\nthose wise in heedfulness\nrejoice in heedfulness,\nenjoying the range of the noble ones."},{"k":"suddhaso","t":"This is what the wise distinctly know\nabout non-negligence.\nThey rejoice in non-negligence,\nenjoying the territory of the noble ones."},{"k":"sujato","t":"Understanding this distinction\nwhen it comes to heedfulness,\nthe astute rejoice in heedfulness,\nhappy in the noble ones' domain."}]},{"n":23,"vg":2,"pali":"Te jhāyino sātatikā,\nniccaṁ daḷhaparakkamā;\nPhusanti dhīrā nibbānaṁ,\nyogakkhemaṁ anuttaraṁ.","v":[{"k":"muller","t":"These wise people, meditative, steady, always possessed of strong powers, attain to Nirvana, the highest happiness."},{"k":"wagiswara","t":"Meditative, persevering, ever with strong might endowed,\nWise men reach the Blissful Haven, reach Security Supreme."},{"k":"kaviratna","t":"Those wise ones, contemplative, ever-striving sages of great prowess, realize nirvana, the incomparable bliss of yoga (union)."},{"k":"buddharakkhita","t":"The wise ones, ever meditative and steadfastly persevering, alone experience Nibbana, the incomparable freedom from bondage."},{"k":"thanissaro","t":"The enlightened, constantly\nabsorbed in jhana,\npersevering,\nfirm in their effort:\nthey touch Unbinding,\nthe unexcelled rest\nfrom the yoke."},{"k":"suddhaso","t":"Those who meditate continuously,\nwho always persevere,\nSteadfast, they touch Nibbāna—\nthe unsurpassable safety."},{"k":"sujato","t":"They who regularly meditate,\nalways staunchly vigorous;\nthe attentive realize extinguishment,\nthe supreme sanctuary from the yoke."}]},{"n":24,"vg":2,"pali":"Uṭṭhānavato satīmato,\nSucikammassa nisammakārino;\nSaññatassa dhammajīvino,\nAppamattassa yasobhivaḍḍhati.","v":[{"k":"muller","t":"If an earnest person has roused himself, if he is not forgetful, if his deeds are pure, if he acts with consideration, if he restrains himself, and lives according to law,--then his glory will increase."},{"k":"wagiswara","t":"Heedful men's good name increaseth, if they strive with mind subdued\nPure in deed, with thoughts well-guarded, well-controlled of lawful lives."},{"k":"kaviratna","t":"Greatly increasing is the glory of him who exerts himself, is thoughtful, pure in character, analytical, self-restrained, vigilant, and lives according to Dhamma (the Law)."},{"k":"buddharakkhita","t":"Ever grows the glory of him who is energetic, mindful and pure in conduct, discerning and self-controlled, righteous and heedful."},{"k":"thanissaro","t":"Those with initiative,\nmindful,\nclean in action,\nacting with due consideration,\nheedful, restrained,\nliving the Dhamma:\ntheir glory\ngrows."},{"k":"suddhaso","t":"Glory increases for those who are proactive and mindful,\nwith pure and careful conduct,\nself-restrained, living the Dhamma,\nand not negligent."},{"k":"sujato","t":"For the hard-working and mindful,\npure of deed and attentive,\nrestrained, living righteously, and diligent,\ntheir reputation only grows."}]},{"n":25,"vg":2,"pali":"Uṭṭhānenappamādena,\nsaṁyamena damena ca;\nDīpaṁ kayirātha medhāvī,\nyaṁ ogho nābhikīrati.","v":[{"k":"muller","t":"By rousing himself, by earnestness, by restraint and control, the wise man may make for himself an island which no flood can overwhelm."},{"k":"wagiswara","t":"Let the wise man, striving, heedful, well-controlled and temperate,\nMake himself an island which the flood shall never sweep away."},{"k":"kaviratna","t":"Through diligence, vigilance, self-restraint and subjugation of the senses, the wise aspirant makes an island for himself that no flood could engulf."},{"k":"buddharakkhita","t":"By effort and heedfulness, discipline and self-mastery, let the wise one make for himself an island which no flood can overwhelm."},{"k":"thanissaro","t":"Through initiative, heedfulness,\nrestraint, & self-control,\nthe wise would make\nan island\nno flood\ncan submerge."},{"k":"suddhaso","t":"By being proactive and not negligent,\nself-restrained and self-controlled,\na wise person makes an island\nwhich no flood can submerge."},{"k":"sujato","t":"By hard work and diligence,\nby restraint and by self-control,\na smart person would build an island\nthat the floods cannot overflow."}]},{"n":26,"vg":2,"pali":"Pamādamanuyuñjanti,\nbālā dummedhino janā;\nAppamādañca medhāvī,\ndhanaṁ seṭṭhaṁva rakkhati.","v":[{"k":"muller","t":"Fools follow after vanity, men of evil wisdom. The wise man keeps earnestness as his best jewel."},{"k":"wagiswara","t":"Heedlessness the foolish follow, men of small intelligence;\nAs the best of treasures wise men guard the prize of Heedfulness."},{"k":"kaviratna","t":"Thoughtless men of great ignorance sink into negligence. But the wise man guards vigilance as his supreme treasure."},{"k":"buddharakkhita","t":"The foolish and ignorant indulge in heedlessness, but the wise one keeps his heedfulness as his best treasure."},{"k":"thanissaro","t":"They're addicted to heedlessness\n— dullards, fools —\nwhile one who is wise\ncherishes heedfulness\nas his highest wealth."},{"k":"suddhaso","t":"Fools and idiots commit\nto negligence,\nwhereas a wise person protects non-negligence\nas the greatest wealth."},{"k":"sujato","t":"Fools and simpletons\ndevote themselves to negligence.\nBut the wise protect diligence\nas their best treasure."}]},{"n":27,"vg":2,"pali":"Mā pamādamanuyuñjetha,\nmā kāmaratisanthavaṁ;\nAppamatto hi jhāyanto,\npappoti vipulaṁ sukhaṁ.","v":[{"k":"muller","t":"Follow not after vanity, nor after the enjoyment of love and lust! He who is earnest and meditative, obtains ample joy."},{"k":"wagiswara","t":"Cleave not thou to Heedlessness, cleave not thou to Passion's snares;\nStrenuous and meditative, wisdom winneth widespread bliss."},{"k":"kaviratna","t":"Betake yourselves not unto negligence; do not indulge in sensuous pleasures. For the vigilant and thoughtful aspirant acquires an amplitude of bliss."},{"k":"buddharakkhita","t":"Do not give way to heedlessness. Do not indulge in sensual pleasures. Only the heedful and meditative attain great happiness."},{"k":"thanissaro","t":"Don't give way to heedlessness\nor to intimacy\nwith sensual delight —\nfor a heedful person,\nabsorbed in jhana,\nattains an abundance of ease."},{"k":"suddhaso","t":"Do not commit to negligence\nor to involvement in sensuality;\nfor one who meditates without negligence\nattains abundant bliss."},{"k":"sujato","t":"Don't devote yourself to negligence,\nor delight in erotic intimacy.\nFor if you're diligent and meditate,\nyou'll attain abundant happiness."}]},{"n":28,"vg":2,"pali":"Pamādaṁ appamādena,\nyadā nudati paṇḍito;\nPaññāpāsādamāruyha,\nasoko sokiniṁ pajaṁ;\nPabbataṭṭhova bhūmaṭṭhe,\ndhīro bāle avekkhati.","v":[{"k":"muller","t":"When the learned man drives away vanity by earnestness, he, the wise, climbing the terraced heights of wisdom, looks down upon the fools, serene he looks upon the toiling crowd, as one that stands on a mountain looks down upon them that stand upon the plain."},{"k":"wagiswara","t":"Lo! the sage that drives away the cloud of sloth by Heedfulness,\nClimbing up the heights of wisdom, sorrowless looks down upon\nAll the miserable beings, as a hillman on the plains."},{"k":"kaviratna","t":"When the wise man casts off laxity through vigilance, he is like unto a man who, having ascended the high tower of wisdom, looks upon the sorrowing people with an afflicted heart. He beholds suffering ignorant men as a mountaineer beholds people in a valley."},{"k":"buddharakkhita","t":"Just as one upon the summit of a mountain beholds the groundlings, even so when the wise man casts away heedlessness by heedfulness and ascends the high tower of wisdom, this sorrowless sage beholds the sorrowing and foolish multitude."},{"k":"thanissaro","t":"When the wise person drives out\nheedlessness\nwith heedfulness,\nhaving climbed the high tower\nof discernment,\nsorrow-free,\nhe observes the sorrowing crowd —\nas the enlightened man,\nhaving scaled\na summit,\nthe fools on the ground below."},{"k":"suddhaso","t":"When a wise person dispels negligence\nby practicing non-negligence,\nthen having ascended in the palace of wisdom,\nsorrowless, they look at this sorrowful generation,\nas a wise person on a mountain\nlooks down at the fools on the ground."},{"k":"sujato","t":"When the astute dispel negligence\nby means of diligence,\nascending the palace of wisdom,\nsorrowless, they behold this generation of sorrow,\nas an attentive one on a mountain top\nbeholds the fools below."}]},{"n":29,"vg":2,"pali":"Appamatto pamattesu,\nsuttesu bahujāgaro;\nAbalassaṁva sīghasso,\nhitvā yāti sumedhaso.","v":[{"k":"muller","t":"Earnest among the thoughtless, awake among the sleepers, the wise man advances like a racer, leaving behind the hack."},{"k":"wagiswara","t":"Strenuous amid the heedless, 'mid the sleepers wide awake,\nAs a racer beats the weak jade, so the wise outstrips the fools."},{"k":"kaviratna","t":"Vigilant among the heedless, wakeful among the sleeping ones, the wise man forges ahead, as a swift steed outstrips a horse of lesser strength."},{"k":"buddharakkhita","t":"Heedful among the heedless, wide-awake among the sleepy, the wise man advances like a swift horse leaving behind a weak jade."},{"k":"thanissaro","t":"Heedful among the heedless,\nwakeful among those asleep,\njust as a fast horse advances,\nleaving the weak behind:\nso the wise."},{"k":"suddhaso","t":"Not negligent amidst the negligent,\nwide awake amidst the sleeping—\nlike a swift horse leaving behind a feeble one,\nthe wise leave them behind and move on."},{"k":"sujato","t":"Heedful among the heedless,\nwide awake while others sleep—\na true sage leaves them behind,\nlike a swift horse passing a feeble."}]},{"n":30,"vg":2,"pali":"Appamādena maghavā,\ndevānaṁ seṭṭhataṁ gato;\nAppamādaṁ pasaṁsanti,\npamādo garahito sadā.","v":[{"k":"muller","t":"By earnestness did Maghavan (Indra) rise to the lordship of the gods. People praise earnestness; thoughtlessness is always blamed."},{"k":"wagiswara","t":"Maghavā by Heedfulness attained the kingship of the gods;\nHeedfulness is praised for ever; Heedlessness is ever blamed."},{"k":"kaviratna","t":"Through vigilance, did Maghavan (Indra) attain to the sovereignty of the gods. Vigilance is ever praised and negligence is ever loathed by the sages."},{"k":"buddharakkhita","t":"By Heedfulness did Indra become the overlord of the gods. Heedfulness is ever praised, and heedlessness ever despised. [5]"},{"k":"thanissaro","t":"Through heedfulness, Indra won\nto lordship over the gods.\nHeedfulness is praised,\nheedlessness censured —\nalways."},{"k":"suddhaso","t":"By means of non-negligence\nMaghavā became the best of the angels;\nthey praise non-negligence,\nwhereas negligence is always criticized."},{"k":"sujato","t":"Maghavā became chief of the gods\nby means of diligence.\nPeople praise diligence,\nwhile negligence is always deplored."}]},{"n":31,"vg":2,"pali":"Appamādarato bhikkhu,\npamāde bhayadassi vā;\nSaṁyojanaṁ aṇuṁ thūlaṁ,\nḍahaṁ aggīva gacchati.","v":[{"k":"muller","t":"A Bhikshu (mendicant) who delights in earnestness, who looks with fear on thoughtlessness, moves about like fire, burning all his fetters, small or large."},{"k":"wagiswara","t":"Monks whom Heedfulness delighteth, seeing fear in Heedlessness,\nAs the fire blazeth onwards, burn their fetters great and small."},{"k":"kaviratna","t":"The bhikkhu (monk) who delights in vigilance, who regards negligence with abhorrence, advances, consuming all subtle and gross fetters, like the fire."},{"k":"buddharakkhita","t":"The monk who delights in heedfulness and looks with fear at heedlessness advances like fire, burning all fetters, small and large."},{"k":"thanissaro","t":"The monk delighting in heedfulness,\nseeing danger in heedlessness,\nadvances like a fire,\nburning fetters\ngreat & small."},{"k":"suddhaso","t":"A monk who approves of non-negligence\nand sees the danger in negligence\nproceeds like a fire—\nburning up fetters, small and large."},{"k":"sujato","t":"A mendicant who loves diligence,\nseeing fear in negligence—\nadvances like fire,\nburning up fetters big and small."}]},{"n":32,"vg":2,"pali":"Appamādarato bhikkhu,\npamāde bhayadassi vā;\nAbhabbo parihānāya,\nnibbānasseva santike.\nAppamādavaggo dutiyo.","v":[{"k":"muller","t":"A Bhikshu (mendicant) who delights in reflection, who looks with fear on thoughtlessness, cannot fall away (from his perfect state)--he is close upon Nirvana."},{"k":"wagiswara","t":"Monks whom Heedfulness delighteth, seeing fear in Heedlessness,\nCannot fall into destruction; they are near Nibbāna's shore."},{"k":"kaviratna","t":"The bhikkhu who delights in vigilance, who looks upon negligence with abhorrence, is not liable to fall back, because he is indeed close to nirvana."},{"k":"buddharakkhita","t":"The monk who delights in heedfulness and looks with fear at heedlessness will not fall. He is close to Nibbana."},{"k":"thanissaro","t":"The monk delighting in heedfulness,\nseeing danger in heedlessness\n— incapable of falling back —\nstands right on the verge\nof Unbinding."},{"k":"suddhaso","t":"A monk who approves of non-negligence\nand sees the danger in negligence\ncannot decline\nand is close to Nibbāna."},{"k":"sujato","t":"A mendicant who loves diligence,\nseeing fear in negligence—\nsuch a one can't decline,\nand has drawn near to extinguishment."}]},{"n":33,"vg":3,"pali":"Phandanaṁ capalaṁ cittaṁ,\ndūrakkhaṁ dunnivārayaṁ;\nUjuṁ karoti medhāvī,\nusukārova tejanaṁ.","v":[{"k":"muller","t":"As a fletcher makes straight his arrow, a wise man makes straight his trembling and unsteady thought, which is difficult to guard, difficult to hold back."},{"k":"wagiswara","t":"The fugitive, flickering mind,\nHard to guard and hard to bind,\nThe wise men train as they choose,\nAs a fletcher fashions a shaft to his use."},{"k":"kaviratna","t":"The discerning man straightens his mind, which is fickle and unsteady, difficult to guard and restrain, as the skilled fletcher straightens the shaft (of the arrow)."},{"k":"buddharakkhita","t":"Just as a fletcher straightens an arrow shaft, even so the discerning man straightens his mind — so fickle and unsteady, so difficult to guard."},{"k":"thanissaro","t":"Quivering, wavering,\nhard to guard,\nto hold in check:\nthe mind.\nThe sage makes it straight —\nlike a fletcher,\nthe shaft of an arrow."},{"k":"suddhaso","t":"Unstable and unsteady is the mind,\ndifficult to protect and restrain.\nThe wise straighten it,\nlike a fletcher straightens an arrow."},{"k":"sujato","t":"The mind quivers and shakes,\nhard to guard, hard to curb.\nThe discerning straighten it out,\nlike a fletcher straightens an arrow."}]},{"n":34,"vg":3,"pali":"Vārijova thale khitto,\nokamokataubbhato;\nPariphandatidaṁ cittaṁ,\nmāradheyyaṁ pahātave.","v":[{"k":"muller","t":"As a fish taken from his watery home and thrown on dry ground, our thought trembles all over in order to escape the dominion of Mara (the tempter)."},{"k":"wagiswara","t":"Like a fish flung out on the bank;\nDrawn from its watery home in a tank,\nFlutters this fugitive mind\nTo leave the realm of Māra behind."},{"k":"kaviratna","t":"As the fish, taken out of its watery home and thrown on land, thrashes around, so does the mind tremble, while freeing itself from the dominion of Mara (the Evil One)."},{"k":"buddharakkhita","t":"As a fish when pulled out of water and cast on land throbs and quivers, even so is this mind agitated. Hence should one abandon the realm of Mara."},{"k":"thanissaro","t":"Like a fish\npulled from its home in the water\n& thrown on land:\nthis mind flips & flaps about\nto escape Mara's sway."},{"k":"suddhaso","t":"Like a fish pulled from its home\nand thrown on dry land,\nthe mind thrashes about,\nstruggling to escape the realm of Māra."},{"k":"sujato","t":"Like a fish pulled from the sea\nand cast upon the shore,\nthis mind flounders about,\ntrying to throw off Māra's dominion."}]},{"n":35,"vg":3,"pali":"Dunniggahassa lahuno,\nyatthakāmanipātino;\nCittassa damatho sādhu,\ncittaṁ dantaṁ sukhāvahaṁ.","v":[{"k":"muller","t":"It is good to tame the mind, which is difficult to hold in and flighty, rushing wherever it listeth; a tamed mind brings happiness."},{"k":"wagiswara","t":"Impalpable, hard to seize,\nEagerly rushing wherever it please,\nGood is the taming of mind;\nA mind well-tamed is a treasure to find."},{"k":"kaviratna","t":"The mind is unstable and flighty. It wanders wherever it desires. Therefore it is good to control the mind. A disciplined mind brings happiness."},{"k":"buddharakkhita","t":"Wonderful, indeed, it is to subdue the mind, so difficult to subdue, ever swift, and seizing whatever it desires. A tamed mind brings happiness."},{"k":"thanissaro","t":"Hard to hold down,\nnimble,\nalighting wherever it likes:\nthe mind.\nIts taming is good.\nThe mind well-tamed\nbrings ease."},{"k":"suddhaso","t":"The mind is fast-moving and hard to subdue,\nlanding wherever it wishes;\nit is good to train it—\na trained mind brings happiness."},{"k":"sujato","t":"Hard to hold back, flighty,\nalighting where it will;\nit's good to tame the mind;\na tamed mind leads to bliss."}]},{"n":36,"vg":3,"pali":"Sududdasaṁ sunipuṇaṁ,\nyatthakāmanipātinaṁ;\nCittaṁ rakkhetha medhāvī,\ncittaṁ guttaṁ sukhāvahaṁ.","v":[{"k":"muller","t":"Let the wise man guard his thoughts, for they are difficult to perceive, very artful, and they rush wherever they list: thoughts well guarded bring happiness."},{"k":"wagiswara","t":"Invisible, subtle indeed,\nEagerly rushing its passions to feed,\nLet the wise man guard this mind;\nA guarded mind is a treasure to find."},{"k":"kaviratna","t":"The mind is incomprehensible and exceedingly subtle. It wanders wherever it desires. Therefore, let the wise aspirant watch over the mind. A well-guarded mind brings happiness."},{"k":"buddharakkhita","t":"Let the discerning man guard the mind, so difficult to detect and extremely subtle, seizing whatever it desires. A guarded mind brings happiness."},{"k":"thanissaro","t":"So hard to see,\nso very, very subtle,\nalighting wherever it likes:\nthe mind.\nThe wise should guard it.\nThe mind protected\nbrings ease."},{"k":"suddhaso","t":"The mind is very subtle and hard to see,\nlanding wherever it wishes;\nthe wise protect it—\na guarded mind brings happiness."},{"k":"sujato","t":"So hard to see, so subtle,\nalighting where it will;\nthe discerning protect the mind,\na guarded mind leads to bliss."}]},{"n":37,"vg":3,"pali":"Dūraṅgamaṁ ekacaraṁ,\nasarīraṁ guhāsayaṁ;\nYe cittaṁ saṁyamissanti,\nmokkhanti mārabandhanā.","v":[{"k":"muller","t":"Those who bridle their mind which travels far, moves about alone, is without a body, and hides in the chamber (of the heart), will be free from the bonds of Mara (the tempter)."},{"k":"wagiswara","t":"Wandering, dwelling apart,\nBodiless there in the cave of the heart,\nThey who subdue this mind\nLeave all the fetters of Māra behind."},{"k":"kaviratna","t":"Those who control the mind which wanders afar, solitary, incorporeal, and which resides in the inner cavern (of the heart), will liberate themselves from the shackles of Mara."},{"k":"buddharakkhita","t":"Dwelling in the cave (of the heart), the mind, without form, wanders far and alone. Those who subdue this mind are liberated from the bonds of Mara."},{"k":"thanissaro","t":"Wandering far,\ngoing alone,\nbodiless,\nlying in a cave:\nthe mind.\nThose who restrain it:\nfrom Mara's bonds\nthey'll be freed."},{"k":"suddhaso","t":"The mind travels far, wanders alone,\nincorporeal, self-sheltered;\nthose who restrain it\nbecome free from the bonds of Māra."},{"k":"sujato","t":"The mind travels far, wandering alone;\nincorporeal, it lies hidden in the heart.\nThose who will restrain the mind\nare freed from Māra's bonds."}]},{"n":38,"vg":3,"pali":"Anavaṭṭhitacittassa,\nsaddhammaṁ avijānato;\nPariplavapasādassa,\npaññā na paripūrati.","v":[{"k":"muller","t":"If a man's thoughts are unsteady, if he does not know the true law, if his peace of mind is troubled, his knowledge will never be perfect."},{"k":"wagiswara","t":"If he know not the Doctrine Pure,\nIf he waver in faith and be not sure,\nIf his mind be not strong-willed,\nThe cup of his wisdom is never fulfilled."},{"k":"kaviratna","t":"He whose mind is not steady, who is ignorant of the true Dhamma, whose tranquillity is ruffled, the wisdom of such a man does not come to fullness."},{"k":"buddharakkhita","t":"Wisdom never becomes perfect in one whose mind is not steadfast, who knows not the Good Teaching and whose faith wavers."},{"k":"thanissaro","t":"For a person of unsteady mind,\nnot knowing true Dhamma,\nserenity\nset adrift:\ndiscernment doesn't grow full."},{"k":"suddhaso","t":"For one whose mind is unsettled,\nwho does not understand the true Dhamma,\nand whose clarity is disturbed,\nwisdom does not become complete."},{"k":"sujato","t":"Those of unsteady mind,\nwho don't understand the true teaching,\nand whose confidence wavers,\ndo not perfect their wisdom."}]},{"n":39,"vg":3,"pali":"Anavassutacittassa,\nananvāhatacetaso;\nPuññapāpapahīnassa,\nnatthi jāgarato bhayaṁ.","v":[{"k":"muller","t":"If a man's thoughts are not dissipated, if his mind is not perplexed, if he has ceased to think of good or evil, then there is no fear for him while he is watchful."},{"k":"wagiswara","t":"If his mind be free from desire,\nIf his thought be free from anger's fire,\nIf evil and good he forsake,\nThere is no fear in the man that's awake."},{"k":"kaviratna","t":"Fear has he none, whose mind is not defiled by passion, whose heart is devoid of hatred, who has surpassed (the dichotomy of) good and evil and who is vigilant."},{"k":"buddharakkhita","t":"There is no fear for an awakened one, whose mind is not sodden (by lust) nor afflicted (by hate), and who has gone beyond both merit and demerit. [6]"},{"k":"thanissaro","t":"For a person of unsoddened mind,\nunassaulted\nawareness,\nabandoning merit & evil,\nwakeful,\nthere is no danger\nno fear."},{"k":"suddhaso","t":"One whose mind is free from influences,\nwhose mind is unafflicted,\nwho has abandoned both merit and evil, and is alert\nhas no fear."},{"k":"sujato","t":"One whose mind is not festering,\nwhose heart is undamaged,\nwho's given up right and wrong,\nalert, has nothing to fear."}]},{"n":40,"vg":3,"pali":"Kumbhūpamaṁ kāyamimaṁ viditvā,\nNagarūpamaṁ cittamidaṁ ṭhapetvā;\nYodhetha māraṁ paññāvudhena,\nJitañca rakkhe anivesano siyā.","v":[{"k":"muller","t":"Knowing that this body is (fragile) like a jar, and making this thought firm like a fortress, one should attack Mara (the tempter) with the weapon of knowledge, one should watch him when conquered, and should never rest."},{"k":"wagiswara","t":"\"Body's a vessel of clay;\nMind must be made like a fort,\" if he say,\nLet him give battle to Mara, arrayed\nIn the weapons of wisdom, unafraid\nLet him conquer and guard him and passionless stay."},{"k":"kaviratna","t":"Knowing the corporeal body to be fragile, as an earthen jar, and fortifying the mind like a citadel, let the wise man fight Mara with the sword of wisdom. He should now protect what he has won, without attachment."},{"k":"buddharakkhita","t":"Realizing that this body is as fragile as a clay pot, and fortifying this mind like a well-fortified city, fight out Mara with the sword of wisdom. Then, guarding the conquest, remain unattached."},{"k":"thanissaro","t":"Knowing this body\nis like a clay jar,\nsecuring this mind\nlike a fort,\nattack Mara\nwith the spear of discernment,\nthen guard what's won\nwithout settling there,\nwithout laying claim."},{"k":"suddhaso","t":"Having understood that this body is like a clay pot,\nhaving fortified the mind like a city,\ncombat Māra using wisdom as one's weapon,\nand protect the victory—you can be free of any abode."},{"k":"sujato","t":"Knowing this body breaks like a pot,\nand fortifying the mind like a citadel,\nattack Māra with the sword of wisdom,\nguard your conquest, and never settle."}]},{"n":41,"vg":3,"pali":"Aciraṁ vatayaṁ kāyo,\npathaviṁ adhisessati;\nChuddho apetaviññāṇo,\nniratthaṁva kaliṅgaraṁ.","v":[{"k":"muller","t":"Before long, alas! this body will lie on the earth, despised, without understanding, like a useless log."},{"k":"wagiswara","t":"Soon, ah! soon on the earth\nWill this body lie, a thing of no worth,\nNeglected, void of the six\nWorkings of sense, a mere bundle of sticks."},{"k":"kaviratna","t":"Alas! ere long, this corporeal body will lie flat upon the earth, unheeded, devoid of consciousness, like a useless log of wood."},{"k":"buddharakkhita","t":"Ere long, alas! this body will lie upon the earth, unheeded and lifeless, like a useless log."},{"k":"thanissaro","t":"All too soon, this body\nwill lie on the ground\ncast off,\nbereft of consciousness,\nlike a useless scrap\nof wood."},{"k":"suddhaso","t":"Before long, this body\nwill lie on the ground\ndiscarded and devoid of consciousness\nlike a useless log."},{"k":"sujato","t":"All too soon this body\nwill lie upon the earth,\nbereft of consciousness,\ntossed aside like a worthless log."}]},{"n":42,"vg":3,"pali":"Diso disaṁ yaṁ taṁ kayirā,\nverī vā pana verinaṁ;\nMicchāpaṇihitaṁ cittaṁ,\npāpiyo naṁ tato kare.","v":[{"k":"muller","t":"Whatever a hater may do to a hater, or an enemy to an enemy, a wrongly-directed mind will do us greater mischief."},{"k":"wagiswara","t":"Whatever the ill that a foe\nDoth a foe, whatever the grudge he may owe.\nGreater by far will he find\nThe ill that is done by an ill-trained mind."},{"k":"kaviratna","t":"An ill-directed mind does greater harm to the self than a hater does to another hater or an enemy to another enemy."},{"k":"buddharakkhita","t":"Whatever harm an enemy may do to an enemy, or a hater to a hater, an ill-directed mind inflicts on oneself a greater harm."},{"k":"thanissaro","t":"Whatever an enemy might do\nto an enemy,\nor a foe to a foe,\nthe ill-directed mind\ncan do to you\neven worse."},{"k":"suddhaso","t":"Compared to what might be done by an enemy to an enemy\nor one hostile person to another,\na wrongly directed mind\ncan cause even more harm than that."},{"k":"sujato","t":"A wrongly directed mind\nwould do you more harm\nthan a hater to the hated,\nor an enemy to their foe."}]},{"n":43,"vg":3,"pali":"Na taṁ mātā pitā kayirā,\naññe vāpi ca ñātakā;\nSammāpaṇihitaṁ cittaṁ,\nseyyaso naṁ tato kare.\nCittavaggo tatiyo.","v":[{"k":"muller","t":"Not a mother, not a father will do so much, nor any other relative; a well-directed mind will do us greater service."},{"k":"wagiswara","t":"Nay, not a father or mother\nCould do so much; not a kinsman or other;\nGreater by far will he find\nThe good that is done by a well-trained mind."},{"k":"kaviratna","t":"Neither father nor mother, nor any other kindred, can confer greater benefit than does the well-directed mind."},{"k":"buddharakkhita","t":"Neither mother, father, nor any other relative can do one greater good than one's own well-directed mind."},{"k":"thanissaro","t":"Whatever a mother, father\nor other kinsman\nmight do for you,\nthe well-directed mind\ncan do for you\neven better."},{"k":"suddhaso","t":"Compared to what might be done by a mother or a father\nor any other relative,\na rightly directed mind\ncan bring even more benefit than that."},{"k":"sujato","t":"A rightly directed mind\nwould do you more good\nthan your mother or father\nor any other relative."}]},{"n":44,"vg":4,"pali":"Ko imaṁ pathaviṁ vicessati,\nYamalokañca imaṁ sadevakaṁ;\nKo dhammapadaṁ sudesitaṁ,\nKusalo pupphamiva pacessati.","v":[{"k":"muller","t":"Who shall overcome this earth, and the world of Yama (the lord of the departed), and the world of the gods? Who shall find out the plainly shown path of virtue, as a clever man finds out the (right) flower?"},{"k":"wagiswara","t":"Who shall discern this earth aright\nAnd the Realm of Death and the World of Light?\nWho shall choose out the Way\nOf righteousness well displayed,\nAs a skilled hand chooseth a flower gay?"},{"k":"kaviratna","t":"Who shall gain victory over this earth together with the domain of Yama (ruler of the Underworld) with its gods? Who shall find the well-proclaimed Dhammapada (path of truth), even as the expert gardener selects the choicest flower?"},{"k":"buddharakkhita","t":"Who shall overcome this earth, this realm of Yama and this sphere of men and gods? Who shall bring to perfection the well-taught path of wisdom as an expert garland-maker would his floral design?"},{"k":"thanissaro","t":"Who will penetrate this earth\n& this realm of death\nwith all its gods?\nWho will ferret out\nthe well-taught Dhamma-saying,\nas the skillful flower-arranger\nthe flower?"},{"k":"suddhaso","t":"Who will investigate this earth,\nthis world of death and angels?\nWho will collect the well-taught verses of truth,\nas a skilled florist collects flowers?"},{"k":"sujato","t":"Who bestirs this earth,\nand the Yama realm with its gods?\nWho sets out the well-taught word of truth,\nas an expert a flower?"}]},{"n":45,"vg":4,"pali":"Sekho pathaviṁ vicessati,\nYamalokañca imaṁ sadevakaṁ;\nSekho dhammapadaṁ sudesitaṁ,\nKusalo pupphamiva pacessati.","v":[{"k":"muller","t":"The disciple will overcome the earth, and the world of Yama, and the world of the gods. The disciple will find out the plainly shown path of virtue, as a clever man finds out the (right) flower."},{"k":"wagiswara","t":"The disciple discerneth this earth aright\nAnd the Realm of Death and the World of Light;\nThe disciple chooseth the Way\nOf Righteousness well displayed,\nAs a skilled hand chooseth a flower gay."},{"k":"kaviratna","t":"The disciple will gain victory over the earth and the realm of Yama together with its gods. The true disciple will indeed find the well-proclaimed Dhammapada, even as the expert gardener selects the choicest flower."},{"k":"buddharakkhita","t":"A striver-on-the path shall overcome this earth, this realm of Yama and this sphere of men and gods. The striver-on-the-path shall bring to perfection the well-taught path of wisdom, as an expert garland-maker would his floral design. [7]"},{"k":"thanissaro","t":"The learner-on-the-path\nwill penetrate this earth\n& this realm of death\nwith all its gods.\nThe learner-on-the-path\nwill ferret out\nthe well-taught Dhamma-saying,\nas the skillful flower-arranger\nthe flower."},{"k":"suddhaso","t":"A trainee will investigate this earth,\nthis world of death and angels.\nA trainee will collect the well-taught verses of truth,\nas a skilled florist collects flowers."},{"k":"sujato","t":"A trainee bestirs this earth,\nand the Yama realm with its gods.\nA trainee sets out the well-taught word of truth,\nas an expert a flower."}]},{"n":46,"vg":4,"pali":"Pheṇūpamaṁ kāyamimaṁ viditvā,\nMarīcidhammaṁ abhisambudhāno;\nChetvāna mārassa papupphakāni,\nAdassanaṁ maccurājassa gacche.","v":[{"k":"muller","t":"He who knows that this body is like froth, and has learnt that it is as unsubstantial as a mirage, will break the flower-pointed arrow of Mara, and never see the king of death."},{"k":"wagiswara","t":"Seeing this body as like unto foam,\nIllusive, by insight of wisdom alone,\nScattering Death's flower-tipp'd shafts,\nHe shall pass to a realm where Death is unknown."},{"k":"kaviratna","t":"Recognizing this corporeal body to be evanescent as foam, comprehending this worldly nature as a mirage, and having broken the flower-arrows of Cupid (Mara), the true aspirant will go beyond the realm of the Evil One."},{"k":"buddharakkhita","t":"Realizing that this body is like froth, penetrating its mirage-like nature, and plucking out Mara's flower-tipped arrows of sensuality, go beyond sight of the King of Death!"},{"k":"thanissaro","t":"Knowing this body\nis like foam,\nrealizing its nature\n— a mirage —\ncutting out\nthe blossoms of Mara,\nyou go where the King of Death\ncan't see."},{"k":"suddhaso","t":"Having understood that this body is like foam,\none who is aware that it is like a mirage,\nhaving cut Māra's flower strands,\ngoes where the Lord of Death does not see."},{"k":"sujato","t":"Knowing this body's like foam,\nrealizing it's all just a mirage,\nand cutting off Māra's blossoming,\nvanish from the King of Death."}]},{"n":47,"vg":4,"pali":"Pupphāni heva pacinantaṁ,\nbyāsattamanasaṁ naraṁ;\nSuttaṁ gāmaṁ mahoghova,\nmaccu ādāya gacchati.","v":[{"k":"muller","t":"Death carries off a man who is gathering flowers and whose mind is distracted, as a flood carries off a sleeping village."},{"k":"wagiswara","t":"Culling life's blossoms here and there,\nWith his mind entangled by pleasures' delay,\nDeath comes and carries him off,\nAs a flood sweeps a slumbering village away."},{"k":"kaviratna","t":"The hedonist who seeks only the blossoms of sensual delights, who indulges only in such pleasures, him the Evil One carries off, as a flood carries off the inhabitants of a sleeping village."},{"k":"buddharakkhita","t":"As a mighty flood sweeps away the sleeping village, so death carries away the person of distracted mind who only plucks the flowers (of pleasure)."},{"k":"thanissaro","t":"The man immersed in\ngathering blossoms,\nhis heart distracted:\ndeath sweeps him away —\nas a great flood,\na village asleep."},{"k":"suddhaso","t":"As if they were collecting flowers,\na person collects mental attachments;\nlike a sleeping village taken away by a great flood,\nthey are taken away by death."},{"k":"sujato","t":"As a mighty flood sweeps off a sleeping village,\ndeath steals away a man\neven as he gathers flowers,\nhis mind caught up in them."}]},{"n":48,"vg":4,"pali":"Pupphāni heva pacinantaṁ,\nbyāsattamanasaṁ naraṁ;\nAtittaññeva kāmesu,\nantako kurute vasaṁ.","v":[{"k":"muller","t":"Death subdues a man who is gathering flowers, and whose mind is distracted, before he is satiated in his pleasures."},{"k":"wagiswara","t":"Culling life's blossoms here and there,\nWith his mind entangled by pleasures' delay,\nInsatiate in desire,\nDeath makes him his bondsman and takes him away."},{"k":"kaviratna","t":"The hedonist who seeks only the blossoms of sensual delights, whose mind is agitated, him the Evil One (Mara) brings under his sway even before his carnal desires are satiated."},{"k":"buddharakkhita","t":"The Destroyer brings under his sway the person of distracted mind who, insatiate in sense desires, only plucks the flowers (of pleasure)."},{"k":"thanissaro","t":"The man immersed in\ngathering blossoms,\nhis heart distracted,\ninsatiable in sensual pleasures:\nthe End-Maker holds him\nunder his sway."},{"k":"suddhaso","t":"As if they were collecting flowers,\na person collects mental attachments;\nnever sated when it comes to sensuality,\nthey are dominated by the Ender."},{"k":"sujato","t":"The terminator gains control of the man\nwho has not had his fill of pleasures,\neven as he gathers flowers,\nhis mind caught up in them."}]},{"n":49,"vg":4,"pali":"Yathāpi bhamaro pupphaṁ,\nvaṇṇagandhamaheṭhayaṁ;\nPaleti rasamādāya,\nevaṁ gāme munī care.","v":[{"k":"muller","t":"As the bee collects nectar and departs without injuring the flower, or its colour or scent, so let a sage dwell in his village."},{"k":"wagiswara","t":"As a bee on the wing flits from flower to flower,\nNot harming the scent or the blossom's hue,\nAnd is gone taking only the taste,\nLet the sage his way through the village pursue."},{"k":"kaviratna","t":"As the bee takes away the nectar, and departs from the flower without harming its color or fragrance, so let a sage move about in the village."},{"k":"buddharakkhita","t":"As a bee gathers honey from the flower without injuring its color or fragrance, even so the sage goes on his alms-round in the village. [8]"},{"k":"thanissaro","t":"As a bee — without harming\nthe blossom,\nits color,\nits fragrance —\ntakes its nectar & flies away:\nso should the sage\ngo through a village."},{"k":"suddhaso","t":"Just as a bee\ntakes nectar from a flower\nwithout harming its beauty or fragrance—\na sage behaves the same way when in a village."},{"k":"sujato","t":"A bee takes the nectar\nand moves on, doing no damage\nto the flower's beauty and fragrance;\nand that's how a sage should walk in the village."}]},{"n":50,"vg":4,"pali":"Na paresaṁ vilomāni,\nna paresaṁ katākataṁ;\nAttanova avekkheyya,\nkatāni akatāni ca.","v":[{"k":"muller","t":"Not the perversities of others, not their sins of commission or omission, but his own misdeeds and negligences should a sage take notice of."},{"k":"wagiswara","t":"Not with other men's faults and other men's failings,\nNor the things they have done, nor the things left undone,\nShould the wise man be concerned;\nLet him look to his own things done and undone."},{"k":"kaviratna","t":"Let the aspirant observe not the perversities of others, nor what others have and have not done; rather should he consider what he has done and what he has yet to do."},{"k":"buddharakkhita","t":"Let none find fault with others; let none see the omissions and commissions of others. But let one see one's own acts, done and undone."},{"k":"thanissaro","t":"Focus,\nnot on the rudenesses of others,\nnot on what they've done\nor left undone,\nbut on what you\nhave & haven't done\nyourself."},{"k":"suddhaso","t":"Do not look at the faults of others—\nwhat they have or have not done;\nLook only at yourself—\nwhat you have or have not done."},{"k":"sujato","t":"Don't find fault with others,\nwith what they've done or left undone.\nYou should only watch yourself,\nwhat you've done or left undone."}]},{"n":51,"vg":4,"pali":"Yathāpi ruciraṁ pupphaṁ,\nvaṇṇavantaṁ agandhakaṁ;\nEvaṁ subhāsitā vācā,\naphalā hoti akubbato.","v":[{"k":"muller","t":"Like a beautiful flower, full of colour, but without scent, are the fine but fruitless words of him who does not act accordingly."},{"k":"wagiswara","t":"Fair is the flow'r with its hue and its colour;\nBut if it lack odour its beauty is hollow.\nSo fair are the words well-spoken,\nBut how empty the words which deeds do not follow."},{"k":"kaviratna","t":"Like unto a lovely flower which is exquisite in color, yet lacking in fragrance, even so prove futile the well-spoken words of the man who acts not up to them."},{"k":"buddharakkhita","t":"Like a beautiful flower full of color but without fragrance, even so, fruitless are the fair words of one who does not practice them."},{"k":"thanissaro","t":"Just like a blossom,\nbright colored\nbut scentless:\na well-spoken word\nis fruitless\nwhen not carried out."},{"k":"suddhaso","t":"Just like a lovely flower\nthat has beauty but no fragrance,\nwell-spoken words\nare fruitless when not acted out."},{"k":"sujato","t":"Just like a glorious flower\nthat's colorful but lacks fragrance;\neloquent speech is fruitless\nfor one who does not act on it."}]},{"n":52,"vg":4,"pali":"Yathāpi ruciraṁ pupphaṁ,\nVaṇṇavantaṁ sagandhakaṁ;\nEvaṁ subhāsitā vācā,\nSaphalā hoti kubbato.","v":[{"k":"muller","t":"But, like a beautiful flower, full of colour and full of scent, are the fine and fruitful words of him who acts accordingly."},{"k":"wagiswara","t":"Fair is the flow'r with its hue and its colour;\nBut if it have odour its beauty's not hollow;\nSo fair are the words well-spoken;\nWell-spoken indeed are the words which deeds follow."},{"k":"kaviratna","t":"Like unto a lovely flower of charming color and sweet fragrance, even so prove fruitful the words of him who acts according to them."},{"k":"buddharakkhita","t":"Like a beautiful flower full of color and also fragrant, even so, fruitful are the fair words of one who practices them."},{"k":"thanissaro","t":"Just like a blossom,\nbright colored\n& full of scent:\na well-spoken word\nis fruitful\nwhen well carried out."},{"k":"suddhaso","t":"Just like a lovely flower\nthat has both beauty and fragrance,\nwell-spoken words\nare fruitful when acted out."},{"k":"sujato","t":"Just like a glorious flower\nthat's both colorful and fragrant,\neloquent speech is fruitful\nfor one who acts on it."}]},{"n":53,"vg":4,"pali":"Yathāpi puppharāsimhā,\nkayirā mālāguṇe bahū;\nEvaṁ jātena maccena,\nkattabbaṁ kusalaṁ bahuṁ.","v":[{"k":"muller","t":"As many kinds of wreaths can be made from a heap of flowers, so many good things may be achieved by a mortal when once he is born."},{"k":"wagiswara","t":"As one from a heap of gathered flowers\nMakes many a garland, many a crown;\nSo by a mortal being\nMany a seed of good may be sown."},{"k":"kaviratna","t":"As many a garland can be strung from a mass of flowers, so should mortal man born in this world perform many wholesome deeds."},{"k":"buddharakkhita","t":"As from a great heap of flowers many garlands can be made, even so should many good deeds be done by one born a mortal."},{"k":"thanissaro","t":"Just as from a heap of flowers\nmany garland strands can be made,\neven so\none born & mortal\nshould do\n— with what's born & is mortal —\nmany a skillful thing."},{"k":"suddhaso","t":"Just as one might make many garlands\nfrom a heap of flowers,\nin the same way, between birth and death\none can do much that is wholesome."},{"k":"sujato","t":"Just as one would create many garlands\nfrom a heap of flowers,\nwhen a person has come to be born,\nthey should do many skillful things."}]},{"n":54,"vg":4,"pali":"Na pupphagandho paṭivātameti,\nNa candanaṁ tagaramallikā vā;\nSatañca gandho paṭivātameti,\nSabbā disā sappuriso pavāyati.","v":[{"k":"muller","t":"The scent of flowers does not travel against the wind, nor (that of) sandal-wood, or of Tagara and Mallika flowers; but the odour of good people travels even against the wind; a good man pervades every place."},{"k":"wagiswara","t":"The odour of flowers cannot prevail\n'Gainst the wind, nor of sandal and _tagara_ fair;\n'Gainst the wind goes the odour of saints;\nThe odour of saints goeth everywhere."},{"k":"kaviratna","t":"The fragrance of flowers does not travel against the wind, be it that of sandalwood, tagara, or jasmine. But the fragrance of the virtuous man travels even against the wind. The virtuous man pervades all directions with his purity."},{"k":"buddharakkhita","t":"Not the sweet smell of flowers, not even the fragrance of sandal, tagara, or jasmine blows against the wind. But the fragrance of the virtuous blows against the wind. Truly the virtuous man pervades all directions with the fragrance of his virtue. [9]"},{"k":"thanissaro","t":"No flower's scent\ngoes against the wind —\nnot sandalwood,\njasmine,\ntagara.\nBut the scent of the good\ndoes go against the wind.\nThe person of integrity\nwafts a scent\nin every direction."},{"k":"suddhaso","t":"The fragrance of a flower does not go against the wind;\nnor does the fragrance of sandalwood, milkwood, or jasmine.\nHowever, the fragrance of goodness does go against the wind;\na good person diffuses it in all directions."},{"k":"sujato","t":"The fragrance of flowers doesn't spread upwind,\nnor sandalwood, pinwheel, or jasmine;\nbut the fragrance of the good spreads upwind;\na true person's virtue spreads in every direction."}]},{"n":55,"vg":4,"pali":"Candanaṁ tagaraṁ vāpi,\nuppalaṁ atha vassikī;\nEtesaṁ gandhajātānaṁ,\nsīlagandho anuttaro.","v":[{"k":"muller","t":"Sandal-wood or Tagara, a lotus-flower, or a Vassiki, among these sorts of perfumes, the perfume of virtue is unsurpassed."},{"k":"wagiswara","t":"Sweet is the sandal and sweet is the _tagara_,\nAnd sweet of the lily the odour faint;\nBut of all sweet-savoured things\nSweetest by far is the scent of the saint."},{"k":"kaviratna","t":"Among all the fragrant scents, like sandalwood, tagara, the water lily and the wild jasmine, the fragrance of moral purity is foremost and unique."},{"k":"buddharakkhita","t":"Of all the fragrances — sandal, tagara, blue lotus and jasmine — the fragrance of virtue is the sweetest."},{"k":"thanissaro","t":"Sandalwood, tagara,\nlotus, & jasmine:\nAmong these scents,\nthe scent of virtue\nis unsurpassed."},{"k":"suddhaso","t":"Sandalwood or milkwood,\nlotus or jasmine,\ncompared to these kinds of fragrances,\nthe fragrance of virtue is unsurpassed."},{"k":"sujato","t":"Among all the fragrances—\nsandalwood or pinwheel\nor lotus or jasmine—\nthe fragrance of virtue is supreme."}]},{"n":56,"vg":4,"pali":"Appamatto ayaṁ gandho,\nyāyaṁ tagaracandanī;\nYo ca sīlavataṁ gandho,\nvāti devesu uttamo.","v":[{"k":"muller","t":"Mean is the scent that comes from Tagara and sandal-wood;--the perfume of those who possess virtue rises up to the gods as the highest."},{"k":"wagiswara","t":"How small a thing is the odour of wood\nOf the sandal or jasmine! How poor is their scent!\nYet the odour of saints prevails\nE'en 'mongst the gods, most excellent."},{"k":"kaviratna","t":"That scent of sandalwood, tagara plant (and other fragrant things) is of little account; whereas the aroma of the virtuous expands in a greater sphere, even up to the gods."},{"k":"buddharakkhita","t":"Faint is the fragrance of tagara and sandal, but excellent is the fragrance of the virtuous, wafting even amongst the gods."},{"k":"thanissaro","t":"Next to nothing, this fragrance\n— sandalwood, tagara —\nwhile the scent of the virtuous\nwafts to the gods,\nsupreme."},{"k":"suddhaso","t":"The fragrance of milkwood and sandalwood\nis insignificant;\nthe fragrance of virtue is the highest—\nit drifts amidst the angels."},{"k":"sujato","t":"Faint is the fragrance\nof sandal or pinwheel;\nbut the fragrance of the virtuous\nfloats to the highest gods."}]},{"n":57,"vg":4,"pali":"Tesaṁ sampannasīlānaṁ,\nappamādavihārinaṁ;\nSammadaññāvimuttānaṁ,\nmāro maggaṁ na vindati.","v":[{"k":"muller","t":"Of the people who possess these virtues, who live without thoughtlessness, and who are emancipated through true knowledge, Mara, the tempter, never finds the way."},{"k":"wagiswara","t":"Men who live righteously, men who live heedfully,\nPerfect in wisdom, rebirth have transcended:\nThough he search for the prints of their feet,\nDeath cannot find them: their journey is ended."},{"k":"kaviratna","t":"Mara (the Evil One) cannot approach the path of the virtuous, the vigilant, and those who are emancipated through wisdom."},{"k":"buddharakkhita","t":"Mara never finds the path of the truly virtuous, who abide in heedfulness and are freed by perfect knowledge."},{"k":"thanissaro","t":"Those consummate in virtue,\ndwelling in heedfulness,\nreleased through right knowing:\nMara can't follow their tracks."},{"k":"suddhaso","t":"The path of those who have perfect virtue,\nlive without negligence,\nand are liberated through right knowledge\ncannot be found by Māra."},{"k":"sujato","t":"For those accomplished in ethics,\nmeditating diligently,\nfreed through the highest knowledge,\nMāra cannot find their path."}]},{"n":58,"vg":4,"pali":"Yathā saṅkāradhānasmiṁ,\nujjhitasmiṁ mahāpathe;\nPadumaṁ tattha jāyetha,\nsucigandhaṁ manoramaṁ.","v":[{"k":"muller","t":"As on a heap of rubbish cast upon the highway the lily will grow full of sweet perfume and delight, thus the disciple of the truly enlightened Buddha shines forth by his knowledge among those who are like rubbish, among the people that walk in darkness."},{"k":"wagiswara","t":"On a heap of dung by the high road hurled,\nAs a lily may bloom and grow,\nDelighting the mind with its fragrance pure:\nSo, lit by the wisdom of those who know,\n'mid those who on the dung-hill grow\nA disciple shines out in the darkened world."},{"k":"kaviratna","t":"As upon a heap of rubbish, thrown on the highway, a lily grows and blooms, fragrant and elegant, so among the ignorant multitudes does the disciple of the Fully Enlightened One shine in resplendent wisdom."},{"k":"buddharakkhita","t":"Upon a heap of rubbish in the road-side ditch blooms a lotus, fragrant and pleasing."},{"k":"thanissaro","t":"As in a pile of rubbish\ncast by the side of a highway\na lotus might grow\nclean-smelling\npleasing the heart,\nso in the midst of the rubbish-like,\npeople run-of-the-mill & blind,\nthere dazzles with discernment\nthe disciple of the Rightly\nSelf-Awakened One."},{"k":"suddhaso","t":"Just as in a trash-heap\ndiscarded by the side of the road,\na lotus might bloom—\nof pure fragrance and delightful to the mind—"},{"k":"sujato","t":"From a heap of trash\ndiscarded on the highway,\na lotus might blossom,\nfragrant and delightful."}]},{"n":59,"vg":4,"pali":"Evaṁ saṅkārabhūtesu,\nandhabhūte puthujjane;\nAtirocati paññāya,\nsammāsambuddhasāvako.\nPupphavaggo catuttho.","v":[{"k":"muller","t":"As on a heap of rubbish cast upon the highway the lily will grow full of sweet perfume and delight, thus the disciple of the truly enlightened Buddha shines forth by his knowledge among those who are like rubbish, among the people that walk in darkness."},{"k":"wagiswara","t":"On a heap of dung by the high road hurled,\nAs a lily may bloom and grow,\nDelighting the mind with its fragrance pure:\nSo, lit by the wisdom of those who know,\n'mid those who on the dung-hill grow\nA disciple shines out in the darkened world."},{"k":"kaviratna","t":"As upon a heap of rubbish, thrown on the highway, a lily grows and blooms, fragrant and elegant, so among the ignorant multitudes does the disciple of the Fully Enlightened One shine in resplendent wisdom."},{"k":"buddharakkhita","t":"Even so, on the rubbish heap of blinded mortals the disciple of the Supremely Enlightened One shines resplendent in wisdom."},{"k":"thanissaro","t":"As in a pile of rubbish\ncast by the side of a highway\na lotus might grow\nclean-smelling\npleasing the heart,\nso in the midst of the rubbish-like,\npeople run-of-the-mill & blind,\nthere dazzles with discernment\nthe disciple of the Rightly\nSelf-Awakened One."},{"k":"suddhaso","t":"in the same way, amidst the trash-heap of beings—\nthe blind commoners—\na disciple of the Completely Awakened One\noutshines them with wisdom."},{"k":"sujato","t":"So too, among those thought of as trash,\na disciple of the perfect Buddha\noutshines with their wisdom\nthe blind ordinary folk."}]},{"n":60,"vg":5,"pali":"Dīghā jāgarato ratti,\ndīghaṁ santassa yojanaṁ;\nDīgho bālāna saṁsāro,\nsaddhammaṁ avijānataṁ.","v":[{"k":"muller","t":"Long is the night to him who is awake; long is a mile to him who is tired; long is life to the foolish who do not know the true law."},{"k":"wagiswara","t":"Long is the night to him that is waking,\nLong is a league to the traveller worn,\nLong is the coil of births\nFor fools that know not the truth of the Norm."},{"k":"kaviratna","t":"Long is the night to a sleepless person; long is the distance of a league to a tired person; long is the circle of rebirths to a fool who does not know the true Law."},{"k":"buddharakkhita","t":"Long is the night to the sleepless; long is the league to the weary. Long is worldly existence to fools who know not the Sublime Truth."},{"k":"thanissaro","t":"Long for the wakeful is the night.\nLong for the weary, a league.\nFor fools\nunaware of True Dhamma,\nsamsara\nis long."},{"k":"suddhaso","t":"Long is the night for one who is awake,\nlong is a yojana for one who is weary,\nlong is saṁsāra for fools\nwho do not understand the true Dhamma."},{"k":"sujato","t":"Long is the night for the wakeful;\nlong is the league for the weary;\nlong transmigrate the fools\nwho don't understand the true teaching."}]},{"n":61,"vg":5,"pali":"Carañce nādhigaccheyya,\nSeyyaṁ sadisamattano;\nEkacariyaṁ daḷhaṁ kayirā,\nNatthi bāle sahāyatā.","v":[{"k":"muller","t":"If a traveller does not meet with one who is his better, or his equal, let him firmly keep to his solitary journey; there is no companionship with a fool."},{"k":"wagiswara","t":"If one find not a comrade to join him in travel.\nEither like unto self or better than self,\nIt is safer to push on alone;\nWhat fellowship can there be with a fool?"},{"k":"kaviratna","t":"If a genuine seeker, who sets forth in search of a superior friend, does not come in contact with such a one or at least an equal, then he should resolutely choose the solitary course, for there can be no companionship with the ignorant."},{"k":"buddharakkhita","t":"Should a seeker not find a companion who is better or equal, let him resolutely pursue a solitary course; there is no fellowship with the fool."},{"k":"thanissaro","t":"If, in your course, you don't meet\nyour equal, your better,\nthen continue your course,\nfirmly,\nalone.\nThere's no fellowship with fools."},{"k":"suddhaso","t":"If you do not find a traveler\nwho is superior or equal to yourself,\nthen resolutely travel alone;\none cannot go with a fool."},{"k":"sujato","t":"If while wandering you find no partner\nequal or better than yourself,\nthen firmly resolve to wander alone—\nthere's no fellowship with fools."}]},{"n":62,"vg":5,"pali":"Puttā matthi dhanaṁ matthi,\niti bālo vihaññati;\nAttā hi attano natthi,\nkuto puttā kuto dhanaṁ.","v":[{"k":"muller","t":"\"These sons belong to me, and this wealth belongs to me,\" with such thoughts a fool is tormented. He himself does not belong to himself; how much less sons and wealth?"},{"k":"wagiswara","t":"\"I am father of sons! I am owner of wealth!\"\nThinks the fool in his folly and thereat is troubled.\nHe himself is not owner of self;\nMuch less is he owner of sons and of wealth."},{"k":"kaviratna","t":"\"I have children, I have wealth,\" thinking thus, the fool torments himself. But, when he is not the possessor of his own self, how then of children? How then of wealth?"},{"k":"buddharakkhita","t":"The fool worries, thinking, \"I have sons, I have wealth.\" Indeed, when he himself is not his own, whence are sons, whence is wealth?"},{"k":"thanissaro","t":"'I have sons, I have wealth' —\nthe fool torments himself.\nWhen even he himself\ndoesn't belong to himself,\nhow then sons?\nHow wealth?"},{"k":"suddhaso","t":"A fool is tormented\nby thoughts of children and wealth;\nbut since one does not even possess oneself,\nhow could one possess children and wealth?"},{"k":"sujato","t":"\"Sons are mine, wealth is mine\"—\nthus the fool frets.\nFor even your self is not your own,\nlet alone your sons or wealth."}]},{"n":63,"vg":5,"pali":"Yo bālo maññati bālyaṁ,\npaṇḍito vāpi tena so;\nBālo ca paṇḍitamānī,\nsa ve \"bālo\"ti vuccati.","v":[{"k":"muller","t":"The fool who knows his foolishness, is wise at least so far. But a fool who thinks himself wise, he is called a fool indeed."},{"k":"wagiswara","t":"Wise indeed is he that knoweth his folly;\nFool indeed is the fool that thinks himself wise."},{"k":"kaviratna","t":"The fool who knows of his ignorance, indeed, through that very consideration becomes a wise man. But that conceited fool who considers himself learned is, in fact, called a fool."},{"k":"buddharakkhita","t":"A fool who knows his foolishness is wise at least to that extent, but a fool who thinks himself wise is a fool indeed."},{"k":"thanissaro","t":"A fool with a sense of his foolishness\nis — at least to that extent — wise.\nBut a fool who thinks himself wise\nreally deserves to be called\na fool."},{"k":"suddhaso","t":"A fool who conceives of foolishness\nis wise in that regard;\nbut a fool who has the conceit of wisdom\ncan truly be called a fool."},{"k":"sujato","t":"The fool who thinks they're a fool\nis wise at least to that extent.\nBut the true fool is said to be one\nwho imagines that they are wise."}]},{"n":64,"vg":5,"pali":"Yāvajīvampi ce bālo,\npaṇḍitaṁ payirupāsati;\nNa so dhammaṁ vijānāti,\ndabbī sūparasaṁ yathā.","v":[{"k":"muller","t":"If a fool be associated with a wise man even all his life, he will perceive the truth as little as a spoon perceives the taste of soup."},{"k":"wagiswara","t":"Tho' a fool in his folly sit all his life long\nBy the side of a wise man, he never gets wiser,\nFor he knows not the Norm and its worth,\nAs the spoon never knoweth the taste of the broth."},{"k":"kaviratna","t":"A fool who associates with a wise man throughout his life may not know the Dhamma any more than the ladle the taste of soup."},{"k":"buddharakkhita","t":"Though all his life a fool associates with a wise man, he no more comprehends the Truth than a spoon tastes the flavor of the soup."},{"k":"thanissaro","t":"Even if for a lifetime\nthe fool stays with the wise,\nhe knows nothing of the Dhamma —\nas the ladle,\nthe taste of the soup."},{"k":"suddhaso","t":"Even if a fool spends a lifetime\nin the presence of the wise,\nthey do not understand the Dhamma,\njust as a spoon does not understand the flavor of soup."},{"k":"sujato","t":"Though a fool attends to the wise\neven for the rest of their life,\nthey still don't understand the teaching,\nlike a spoon the taste of the soup."}]},{"n":65,"vg":5,"pali":"Muhuttamapi ce viññū,\npaṇḍitaṁ payirupāsati;\nKhippaṁ dhammaṁ vijānāti,\njivhā sūparasaṁ yathā.","v":[{"k":"muller","t":"If an intelligent man be associated for one minute only with a wise man, he will soon perceive the truth, as the tongue perceives the taste of soup."},{"k":"wagiswara","t":"But a wise man that sits by the wise but a minute,\nQuickly learns of the Norm and its worth,\nAs the tongue quickly savours the taste of the broth."},{"k":"kaviratna","t":"As the tongue detects the taste of the broth, so the intelligent person who associates with a wise man even for a moment comes to realize the essence of the Law."},{"k":"buddharakkhita","t":"Though only for a moment a discerning person associates with a wise man, quickly he comprehends the Truth, just as the tongue tastes the flavor of the soup."},{"k":"thanissaro","t":"Even if for a moment,\nthe perceptive person stays with the wise,\nhe immediately knows the Dhamma —\nas the tongue,\nthe taste of the soup."},{"k":"suddhaso","t":"Even if a discerning person spends only a moment\nin the presence of the wise,\nthey quickly understand the Dhamma,\njust as a tongue understands the flavor of soup."},{"k":"sujato","t":"If a clever person attends to the wise\neven just for an hour or so,\nthey swiftly understand the teaching,\nlike a tongue the taste of the soup."}]},{"n":66,"vg":5,"pali":"Caranti bālā dummedhā,\namitteneva attanā;\nKarontā pāpakaṁ kammaṁ,\nyaṁ hoti kaṭukapphalaṁ.","v":[{"k":"muller","t":"Fools of little understanding have themselves for their greatest enemies, for they do evil deeds which must bear bitter fruits."},{"k":"wagiswara","t":"Fools fare up and down with themselves for their foe,\nAnd work evil deeds whose fruit will be bitter;"},{"k":"kaviratna","t":"The unwise, fools who are enemies to themselves, go about committing sinful deeds which produce bitter fruits."},{"k":"buddharakkhita","t":"Fools of little wit are enemies unto themselves as they move about doing evil deeds, the fruits of which are bitter."},{"k":"thanissaro","t":"Fools, their wisdom weak,\nare their own enemies\nas they go through life,\ndoing evil\nthat bears\nbitter fruit."},{"k":"suddhaso","t":"Unwise fools act as if\nthey are not even their own friends—\nthey perform evil actions\nwhich yield bitter fruit."},{"k":"sujato","t":"Fools and simpletons behave\nlike their own worst enemies,\ndoing wicked deeds\nthat ripen as bitter fruit."}]},{"n":67,"vg":5,"pali":"Na taṁ kammaṁ kataṁ sādhu,\nyaṁ katvā anutappati;\nYassa assumukho rodaṁ,\nvipākaṁ paṭisevati.","v":[{"k":"muller","t":"That deed is not well done of which a man must repent, and the reward of which he receives crying and with a tearful face."},{"k":"wagiswara","t":"Ill-done is the deed that brings sorrow in doing,\nWhose fruit they will meet with tears and annoy;"},{"k":"kaviratna","t":"Not well done is that deed which one, having performed, has to repent; whose consequence one has to face with tears and lamentation."},{"k":"buddharakkhita","t":"Ill done is that action of doing which one repents later, and the fruit of which one, weeping, reaps with tears."},{"k":"thanissaro","t":"It's not good,\nthe doing of the deed\nthat, once it's done,\nyou regret,\nwhose result you reap crying,\nyour face in tears."},{"k":"suddhaso","t":"It is not good to perform an action\nwhich one will later regret,\nwhen, weeping with a tearful face,\none experiences its result."},{"k":"sujato","t":"It's not good to do a deed\nthat plagues you later on,\nfor which you weep and wail,\nas its effect stays with you."}]},{"n":68,"vg":5,"pali":"Tañca kammaṁ kataṁ sādhu,\nyaṁ katvā nānutappati;\nYassa patīto sumano,\nvipākaṁ paṭisevati.","v":[{"k":"muller","t":"No, that deed is well done of which a man does not repent, and the reward of which he receives gladly and cheerfully."},{"k":"wagiswara","t":"Well done is the deed that brings pleasure in doing,\nWhose fruit they will welcome with gladness and joy."},{"k":"kaviratna","t":"Well done is that deed which one, having performed, does not repent, and whose consequence one experiences with delight and contentment."},{"k":"buddharakkhita","t":"Well done is that action of doing which one repents not later, and the fruit of which one reaps with delight and happiness."},{"k":"thanissaro","t":"It's good,\nthe doing of the deed\nthat, once it's done,\nyou don't regret,\nwhose result you reap gratified,\nhappy at heart."},{"k":"suddhaso","t":"But it is good to perform an action\nwhich one will not later regret,\nwhen, satisfied and uplifted,\none experiences its result."},{"k":"sujato","t":"It is good to do a deed\nthat doesn't plague you later on,\nthat gladdens and cheers,\nas its effect stays with you."}]},{"n":69,"vg":5,"pali":"Madhuṁvā maññati bālo,\nyāva pāpaṁ na paccati;\nYadā ca paccati pāpaṁ,\natha dukkhaṁ nigacchati.","v":[{"k":"muller","t":"As long as the evil deed done does not bear fruit, the fool thinks it is like honey; but when it ripens, then the fool suffers grief."},{"k":"wagiswara","t":"\"O! how sweet!\" thinks the fool, ere his wicked deed ripens.\nWhen his wicked deed ripens he knows what is sorrow."},{"k":"kaviratna","t":"So long as an evil deed does not mature (bring disastrous results), the fool thinks his deed to be sweet as honey. But, when his evil deed matures, he falls into untold misery."},{"k":"buddharakkhita","t":"So long as an evil deed has not ripened, the fool thinks it as sweet as honey. But when the evil deed ripens, the fool comes to grief."},{"k":"thanissaro","t":"As long as evil has yet to ripen,\nthe fool mistakes it for honey.\nBut when that evil ripens,\nthe fool falls into\npain."},{"k":"suddhaso","t":"A fool thinks that evil is sweet\nas long as its results have yet to fully manifest;\nbut when the results of that evil fully manifest,\nthen they descend into suffering."},{"k":"sujato","t":"The fool imagines that evil is sweet,\nso long as it has not yet ripened.\nBut as soon as that evil ripens,\nthey fall into suffering."}]},{"n":70,"vg":5,"pali":"Māse māse kusaggena,\nbālo bhuñjeyya bhojanaṁ;\nNa so saṅkhātadhammānaṁ,\nkalaṁ agghati soḷasiṁ.","v":[{"k":"muller","t":"Let a fool month after month eat his food (like an ascetic) with the tip of a blade of Kusa grass, yet he is not worth the sixteenth particle of those who have well weighed the law."},{"k":"wagiswara","t":"Tho' month after month with the blade of a sword-grass\nThe fool eats his rice grain by grain,\nNot one fourth of a quarter of good doth he gain\nSuch as those who are stablished in Dhamma obtain."},{"k":"kaviratna","t":"Though a fool (practicing austerity) may eat his food from the tip of a blade of kusa grass for months and months, he is not worth one-sixteenth part of those who have realized the Good Law."},{"k":"buddharakkhita","t":"Month after month a fool may eat his food with the tip of a blade of grass, but he still is not worth a sixteenth part of the those who have comprehended the Truth."},{"k":"thanissaro","t":"Month after month\nthe fool might eat\nonly a tip-of-grass measure of food,\nbut he wouldn't be worth\none sixteenth\nof those who've fathomed\nthe Dhamma."},{"k":"suddhaso","t":"Month after month\na fool might eat using the tip of a blade of grass;\nbut such a one is not worth even a sixteenth as much\nas those who comprehend the Dhamma."},{"k":"sujato","t":"Month after month a fool may eat\nfood from a grass-blade's tip;\nbut they'll never be worth a sixteenth part\nof one who has appraised the teaching."}]},{"n":71,"vg":5,"pali":"Na hi pāpaṁ kataṁ kammaṁ,\nSajjukhīraṁva muccati;\nḌahantaṁ bālamanveti,\nBhasmacchannova pāvako.","v":[{"k":"muller","t":"An evil deed, like newly-drawn milk, does not turn (suddenly); smouldering, like fire covered by ashes, it follows the fool."},{"k":"wagiswara","t":"Now an ill deed, like milk, doth not change into curds,\nBut it burneth the fool--a live coal 'neath the ashes."},{"k":"kaviratna","t":"As fresh-drawn milk from the cow does not soon curdle, so an evil deed does not produce immediate fruits. It follows the wrongdoer like a smoldering spark that burns throughout and then suddenly blazes up."},{"k":"buddharakkhita","t":"Truly, an evil deed committed does not immediately bear fruit, like milk that does not turn sour all at once. But smoldering, it follows the fool like fire covered by ashes."},{"k":"thanissaro","t":"An evil deed, when done,\ndoesn't — like ready milk —\ncome out right away.\nIt follows the fool,\nsmoldering\nlike a fire\nhidden in ashes."},{"k":"suddhaso","t":"Once an evil action has been performed,\nit is not released suddenly like milk;\nburning, it follows a fool,\nlike fire concealed by ash."},{"k":"sujato","t":"For a wicked deed that has been done\ndoes not curdle quickly like milk.\nSmoldering, it follows the fool,\nlike a fire smothered over with ash."}]},{"n":72,"vg":5,"pali":"Yāvadeva anatthāya,\nñattaṁ bālassa jāyati;\nHanti bālassa sukkaṁsaṁ,\nmuddhamassa vipātayaṁ.","v":[{"k":"muller","t":"And when the evil deed, after it has become known, brings sorrow to the fool, then it destroys his bright lot, nay, it cleaves his head."},{"k":"wagiswara","t":"Since his knowledge is born to a fool all in vain,\nHis good luck is lost to him wholly;\nOn his own head it falls; he is crushed by his folly."},{"k":"kaviratna","t":"Whatever knowledge a fool acquires causes him only harm. It cleaves his head and destroys his good nature (through conceit)."},{"k":"buddharakkhita","t":"To his own ruin the fool gains knowledge, for it cleaves his head and destroys his innate goodness."},{"k":"thanissaro","t":"Only for his ruin\ndoes renown come to the fool.\nIt ravages his bright fortune\n& rips his head apart."},{"k":"suddhaso","t":"It brings no benefit\nwhen fame comes to a fool;\nit destroys their good traits\nand tears apart their head."},{"k":"sujato","t":"Whatever fame a fool may get,\nit only gives rise to harm.\nWhatever good features they have it ruins,\nand blows their head into bits."}]},{"n":73,"vg":5,"pali":"Asantaṁ bhāvanamiccheyya,\nPurekkhārañca bhikkhusu;\nĀvāsesu ca issariyaṁ,\nPūjaṁ parakulesu ca.","v":[{"k":"muller","t":"Let the fool wish for a false reputation, for precedence among the Bhikshus, for lordship in the convents, for worship among other people!"},{"k":"wagiswara","t":"If a fool long for credit that is not his due,\nChief seats in the monks' hall, respect from the Order,\nAnd worship from laymen desiring;\n\"Let the monks and the laymen my deeds hold in honour\nAnd in all things obey me, whate'er I may will--\"\nIf such be the thoughts of the fool,\nHis pride and his longing increase in him still."},{"k":"kaviratna","t":"Unwise is the monk who desires undue adoration from others, lordship over other monks, authority among the monastic dwellings and homage even from outside groups. Moreover, he thinks, \"May both laymen and monks highly esteem my action! May they be subject to me in all actions, great or small.\" Such is the grasping desire of a worldly monk whose haughtiness and conceit ever increase."},{"k":"buddharakkhita","t":"The fool seeks undeserved reputation, precedence among monks, authority over monasteries, and honor among householders."},{"k":"thanissaro","t":"He would want unwarranted status,\npreeminence among monks,\nauthority among monasteries,\nhomage from lay families."},{"k":"suddhaso","t":"A fool wishes for a false existence—\npreeminence among monks,\ndominion in residences,\nand honor among other families."},{"k":"sujato","t":"They'd seek the esteem that they lack,\nand status among the mendicants;\nauthority over monasteries,\nand honor among other families."}]},{"n":74,"vg":5,"pali":"Mameva kata maññantu,\ngihī pabbajitā ubho;\nMamevātivasā assu,\nkiccākiccesu kismici;\nIti bālassa saṅkappo,\nicchā māno ca vaḍḍhati.","v":[{"k":"muller","t":"\"May both the layman and he who has left the world think that this is done by me; may they be subject to me in everything which is to be done or is not to be done,\" thus is the mind of the fool, and his desire and pride increase."},{"k":"wagiswara","t":"If a fool long for credit that is not his due,\nChief seats in the monks' hall, respect from the Order,\nAnd worship from laymen desiring;\n\"Let the monks and the laymen my deeds hold in honour\nAnd in all things obey me, whate'er I may will--\"\nIf such be the thoughts of the fool,\nHis pride and his longing increase in him still."},{"k":"kaviratna","t":"Unwise is the monk who desires undue adoration from others, lordship over other monks, authority among the monastic dwellings and homage even from outside groups. Moreover, he thinks, \"May both laymen and monks highly esteem my action! May they be subject to me in all actions, great or small.\" Such is the grasping desire of a worldly monk whose haughtiness and conceit ever increase."},{"k":"buddharakkhita","t":"\"Let both laymen and monks think that it was done by me. In every work, great and small, let them follow me\" — such is the ambition of the fool; thus his desire and pride increase."},{"k":"thanissaro","t":"'Let householders & those gone forth\nboth think that this\nwas done by me alone.\nMay I alone determine\nwhat's a duty, what's not':\nthe resolve of a fool\nas they grow —\nhis desire & pride."},{"k":"suddhaso","t":"\"May both renunciants and laypeople\nthink it was done by me alone;\nmay I alone have the highest authority,\nin determining what should or should not be done.\"\nIn this way,\nthe attitude, desire, and conceit of a fool grows."},{"k":"sujato","t":"\"Let both layfolk and renunciants think\nthe work was done by me alone.\nIn anything at all that's to be done,\nlet them fall under my sway alone.\"\nSo thinks the fool,\ntheir greed and pride only growing."}]},{"n":75,"vg":5,"pali":"Aññā hi lābhūpanisā,\naññā nibbānagāminī;\nEvametaṁ abhiññāya,\nbhikkhu buddhassa sāvako;\nSakkāraṁ nābhinandeyya,\nvivekamanubrūhaye.\nBālavaggo pañcamo.","v":[{"k":"muller","t":"\"One is the road that leads to wealth, another the road that leads to Nirvana;\" if the Bhikshu, the disciple of Buddha, has learnt this, he will not yearn for honour, he will strive after separation from the world."},{"k":"wagiswara","t":"\"Success here is one thing, Nibbāna another:\"\nWhen a monk, the Buddha's disciple, is sure\nOf this truth, he delights not in honour, eschews\nThe ways of the world and lives a recluse."},{"k":"kaviratna","t":"One path leads to worldly gain and honor; quite another path leads to nirvana. Having realized this truth, let not the monk, the true follower of the Enlightened One, yearn for homage from others, but let him cultivate serenity of mind and dispassion."},{"k":"buddharakkhita","t":"One is the quest for worldly gain, and quite another is the path to Nibbana. Clearly understanding this, let not the monk, the disciple of the Buddha, be carried away by worldly acclaim, but develop detachment instead."},{"k":"thanissaro","t":"The path to material gain\ngoes one way,\nthe way to Unbinding,\nanother.\nRealizing this, the monk,\na disciple to the Awakened One,\nshould not relish offerings,\nshould cultivate seclusion\ninstead."},{"k":"suddhaso","t":"Knowledge is the cause of gain,\nknowledge leads to Nibbāna;\nsince this is exactly what\na monastic disciple of the Buddha understands,\nthey do not delight in acclaim;\nthey devote themselves to seclusion."},{"k":"sujato","t":"For the means to profit and the path to quenching\nare two quite different things.\nA mendicant disciple of the Buddha,\nunderstanding what this really means,\nwould never delight in honors,\nbut rather would foster seclusion."}]},{"n":76,"vg":6,"pali":"Nidhīnaṁva pavattāraṁ,\nyaṁ passe vajjadassinaṁ;\nNiggayhavādiṁ medhāviṁ,\ntādisaṁ paṇḍitaṁ bhaje;\nTādisaṁ bhajamānassa,\nseyyo hoti na pāpiyo.","v":[{"k":"muller","t":"If you see an intelligent man who tells you where true treasures are to be found, who shows what is to be avoided, and administers reproofs, follow that wise man; it will be better, not worse, for those who follow him."},{"k":"wagiswara","t":"If thou see a man of wisdom,\nLike a guide to treasure-trove,\nPointing out thy faults and failings,\nFollow him; such company\nBrings prosperity, not woe."},{"k":"kaviratna","t":"The disciple should associate with a wise friend, who detects and censures his faults, and who points out virtues as a guide tells of buried treasures. There is happiness, not woe, to him who associates with such an intelligent friend."},{"k":"buddharakkhita","t":"Should one find a man who points out faults and who reproves, let him follow such a wise and sagacious person as one would a guide to hidden treasure. It is always better, and never worse, to cultivate such an association."},{"k":"thanissaro","t":"Regard him as one who\npoints out\ntreasure,\nthe wise one who\nseeing your faults\nrebukes you.\nStay with this sort of sage.\nFor the one who stays\nwith a sage of this sort,\nthings get better,\nnot worse."},{"k":"suddhaso","t":"Like a person who leads you to hidden treasure:\nthis is how to see a person who points out your faults.\nA wise person who tells you what you need to subdue\nis the kind of person you should associate with.\nAssociating with that kind of person\nis always for the better and never for the worse."},{"k":"sujato","t":"Regard one who sees your faults\nas a guide to a hidden treasure.\nStay close to one so wise and astute\nwho corrects you when you need it.\nSticking close to such an impartial person,\nthings get better, not worse."}]},{"n":77,"vg":6,"pali":"Ovadeyyānusāseyya,\nasabbhā ca nivāraye;\nSatañhi so piyo hoti,\nasataṁ hoti appiyo.","v":[{"k":"muller","t":"Let him admonish, let him teach, let him forbid what is improper!--he will be beloved of the good, by the bad he will be hated."},{"k":"wagiswara","t":"He who gives advice and teaching,\nAnd restrains thy feet from wrong,\nBy the righteous is beloved,\nBut the wicked love him not."},{"k":"kaviratna","t":"The man who exhorts, instructs and dissuades his fellowmen from unworthy acts is dear to the virtuous and hated by the wicked."},{"k":"buddharakkhita","t":"Let him admonish, instruct and shield one from wrong; he, indeed, is dear to the good and detestable to the evil."},{"k":"thanissaro","t":"Let him admonish, instruct,\ndeflect you\naway from poor manners.\nTo the good, he's endearing;\nto the bad, he's not."},{"k":"suddhaso","t":"A person might advise you, instruct you,\nand keep you away from what is not good;\nThey are liked by those who are good,\nand not liked by those who are not good."},{"k":"sujato","t":"Advise and instruct;\ncurb wickedness:\nfor you shall be loved by the good,\nand disliked by the bad."}]},{"n":78,"vg":6,"pali":"Na bhaje pāpake mitte,\nna bhaje purisādhame;\nBhajetha mitte kalyāṇe,\nbhajetha purisuttame.","v":[{"k":"muller","t":"Do not have evil-doers for friends, do not have low people for friends: have virtuous people for friends, have for friends the best of men."},{"k":"wagiswara","t":"Have no fellowship with evil;\nMake no friends among the vile;\nMake the virtuous thy companions;\nFollow thou the Perfect Men."},{"k":"kaviratna","t":"Do not keep company with evildoing friends nor with people who are base; associate with the good, associate with the best of men."},{"k":"buddharakkhita","t":"Do not associate with evil companions; do not seek the fellowship of the vile. Associate with the good friends; seek the fellowship of noble men."},{"k":"thanissaro","t":"Don't associate with bad friends.\nDon't associate with the low.\nAssociate with admirable friends.\nAssociate with the best."},{"k":"suddhaso","t":"Do not associate with evil friends,\ndo not associate with lowly people;\nassociate with good spiritual friends\nand with the highest of people."},{"k":"sujato","t":"Don't mix with bad friends,\nnor with the worst of men.\nMix with spiritual friends,\nand with the best of men."}]},{"n":79,"vg":6,"pali":"Dhammapīti sukhaṁ seti,\nvippasannena cetasā;\nAriyappavedite dhamme,\nsadā ramati paṇḍito.","v":[{"k":"muller","t":"He who drinks in the law lives happily with a serene mind: the sage rejoices always in the law, as preached by the elect (Ariyas)."},{"k":"wagiswara","t":"They who drink the Good Norm's nectar\nLive in bliss with tranquil mind;\nIn the Norm by saints expounded\nWise men ever take delight."},{"k":"kaviratna","t":"One who drinks the nectar of the Good Law lives happily with a tranquil mind. The wise man ever delights in the Dhamma as realized by the Noble Ones."},{"k":"buddharakkhita","t":"He who drinks deep the Dhamma lives happily with a tranquil mind. The wise man ever delights in the Dhamma made known by the Noble One (the Buddha)."},{"k":"thanissaro","t":"Drinking the Dhamma,\nrefreshed by the Dhamma,\none sleeps at ease\nwith clear awareness & calm.\nIn the Dhamma revealed\nby the noble ones,\nthe wise person\nalways delights."},{"k":"suddhaso","t":"When one enjoys the Dhamma, then one sleeps happily,\nwith a clear mind;\na wise person always appreciates\nthe Dhamma proclaimed by the noble ones."},{"k":"sujato","t":"Through joy in the teaching you sleep at ease,\nwith clear and confident heart.\nAn astute person always delights in the teaching\nproclaimed by the Noble One."}]},{"n":80,"vg":6,"pali":"Udakañhi nayanti nettikā,\nUsukārā namayanti tejanaṁ;\nDāruṁ namayanti tacchakā,\nAttānaṁ damayanti paṇḍitā.","v":[{"k":"muller","t":"Well-makers lead the water (wherever they like); fletchers bend the arrow; carpenters bend a log of wood; wise people fashion themselves."},{"k":"wagiswara","t":"Irrigators guide the waters,\nFletchers straighten out the shaft,\nCarpenters unwarp the timber,\nBut the wise subdue themselves."},{"k":"kaviratna","t":"Irrigators conduct the water wherever they wish; fletchers shape the shafts; carpenters work (1) the wood, and wise men discipline themselves."},{"k":"buddharakkhita","t":"Irrigators regulate the rivers; fletchers straighten the arrow shaft; carpenters shape the wood; the wise control themselves."},{"k":"thanissaro","t":"Irrigators guide the water.\nFletchers shape the arrow shaft.\nCarpenters shape the wood.\nThe wise control\nthemselves."},{"k":"suddhaso","t":"Irrigators guide water,\nfletchers shape arrows,\ncarpenters shape wood,\nthe wise train themselves."},{"k":"sujato","t":"Irrigators guide water,\nfletchers straighten arrows,\ncarpenters carve timber,\nthe astute tame themselves."}]},{"n":81,"vg":6,"pali":"Selo yathā ekaghano,\nvātena na samīrati;\nEvaṁ nindāpasaṁsāsu,\nna samiñjanti paṇḍitā.","v":[{"k":"muller","t":"As a solid rock is not shaken by the wind, wise people falter not amidst blame and praise."},{"k":"wagiswara","t":"As the solid rock for ever\nRests unshaken by the wind,\nWise men rest unwavering,\nTroubled not by praise or blame."},{"k":"kaviratna","t":"As a solid rock is not shaken by the wind, so the wise are not shaken by censure or praise."},{"k":"buddharakkhita","t":"Just as a solid rock is not shaken by the storm, even so the wise are not affected by praise or blame."},{"k":"thanissaro","t":"As a single slab of rock\nwon't budge in the wind,\nso the wise are not moved\nby praise,\nby blame."},{"k":"suddhaso","t":"Just as the wind\ndoes not move solid stone,\npraise and criticism\ndo not disturb the wise."},{"k":"sujato","t":"As the wind cannot stir\na solid mass of rock,\nso too blame and praise\ndo not affect the wise."}]},{"n":82,"vg":6,"pali":"Yathāpi rahado gambhīro,\nvippasanno anāvilo;\nEvaṁ dhammāni sutvāna,\nvippasīdanti paṇḍitā.","v":[{"k":"muller","t":"Wise people, after they have listened to the laws, become serene, like a deep, smooth, and still lake."},{"k":"wagiswara","t":"As a deep clear pool of water\nLies unruffled by the wind,\nTo the Good Norm listening\nWise men reach tranquillity."},{"k":"kaviratna","t":"The wise, having hearkened to the Good Law, become serene like unto a deep, calm and crystal-clear lake."},{"k":"buddharakkhita","t":"On hearing the Teachings, the wise become perfectly purified, like a lake deep, clear and still."},{"k":"thanissaro","t":"Like a deep lake,\nclear, unruffled, & calm:\nso the wise become clear,\ncalm,\non hearing words of the Dhamma."},{"k":"suddhaso","t":"Like a deep lake,\nclear and undisturbed,\nwhen the wise hear the Dhamma\nthey attain clarity."},{"k":"sujato","t":"Like a deep lake,\nclear and unclouded,\nso clear are the astute\nwhen they hear the teachings."}]},{"n":83,"vg":6,"pali":"Sabbattha ve sappurisā cajanti,\nNa kāmakāmā lapayanti santo;\nSukhena phuṭṭhā atha vā dukhena,\nNa uccāvacaṁ paṇḍitā dassayanti.","v":[{"k":"muller","t":"Good people walk on whatever befall, the good do not prattle, longing for pleasure; whether touched by happiness or sorrow wise people never appear elated or depressed."},{"k":"wagiswara","t":"When the good men go about,\nSensual babble is not theirs;\nThey, when touched by pain or pleasure,\nShow a calm untroubled face."},{"k":"kaviratna","t":"Good men abandon lusting after things; they take no pleasure in sensual speech; when touched by happiness or sorrow, the wise show no elation or dejection."},{"k":"buddharakkhita","t":"The good renounce (attachment for) everything. The virtuous do not prattle with a yearning for pleasures. The wise show no elation or depression when touched by happiness or sorrow."},{"k":"thanissaro","t":"Everywhere, truly,\nthose of integrity\nstand apart.\nThey, the good,\ndon't chatter in hopes\nof favor or gains.\nWhen touched\nnow by pleasure,\nnow pain,\nthe wise give no sign\nof high\nor low."},{"k":"suddhaso","t":"Good people let go of everything;\nthe peaceful do not prattle about sensuality.\nWhether they are touched by pleasure or pain,\nneither elation nor depression can be seen in the wise."},{"k":"sujato","t":"True persons give up everything,\nthey don't cajole for the things they desire.\nThough touched by sadness or happiness,\nthe astute appear neither depressed nor elated."}]},{"n":84,"vg":6,"pali":"Na attahetu na parassa hetu,\nNa puttamicche na dhanaṁ na raṭṭhaṁ;\nNa iccheyya adhammena samiddhimattano,\nSa sīlavā paññavā dhammiko siyā.","v":[{"k":"muller","t":"If, whether for his own sake, or for the sake of others, a man wishes neither for a son, nor for wealth, nor for lordship, and if he does not wish for his own success by unfair means, then he is good, wise, and virtuous."},{"k":"wagiswara","t":"Not for self and not for others\nDo they long for sons or wealth,\nNot for rule, nor by injustice\nSelf-advancement to attain;\nRighteous, wise and just are they."},{"k":"kaviratna","t":"For the sake of oneself, or for the sake of another, one should not long for a son, wealth or a kingdom. He who does not crave success or prosperity by wrongful means is indeed virtuous, wise and honorable."},{"k":"buddharakkhita","t":"He is indeed virtuous, wise, and righteous who neither for his own sake nor for the sake of another (does any wrong), who does not crave for sons, wealth, or kingdom, and does not desire success by unjust means."},{"k":"thanissaro","t":"One who wouldn't —\nnot for his own sake\nnor that of another —\nhanker for\nwealth,\na son,\na kingdom,\nhis own fulfillment,\nby unrighteous means:\nhe is righteous, rich\nin virtue,\ndiscernment."},{"k":"suddhaso","t":"Whether because of oneself or because of another,\none should not wish to obtain children, wealth, lordship, or personal success\nin ways contrary to Dhamma.\nInstead let one be virtuous, wise, and in accord with Dhamma."},{"k":"sujato","t":"Never wish for success by unjust means,\nfor your own sake or that of another,\ndesiring children, wealth, or nation;\nrather, be virtuous, wise, and just."}]},{"n":85,"vg":6,"pali":"Appakā te manussesu,\nye janā pāragāmino;\nAthāyaṁ itarā pajā,\ntīramevānudhāvati.","v":[{"k":"muller","t":"Few are there among men who arrive at the other shore (become Arhats); the other people here run up and down the shore."},{"k":"wagiswara","t":"Few are they among us mortals\nWho have reached the further shore\nOver yonder. But we others\nOn this side fare up and down."},{"k":"kaviratna","t":"Few among men cross over to the further shore; the multitudes who remain run to and fro on this shore."},{"k":"buddharakkhita","t":"Few among men are those who cross to the farther shore. The rest, the bulk of men, only run up and down the hither bank."},{"k":"thanissaro","t":"Few are the people\nwho reach the Far Shore.\nThese others\nsimply scurry along\nthis shore.\n\nBut those who practice Dhamma\nin line with the well-taught Dhamma,\nwill cross over the realm of Death\nso hard to transcend."},{"k":"suddhaso","t":"Few are the humans\nwho go beyond.\nMost people\nonly run around on the shore."},{"k":"sujato","t":"Few are those among humans\nwho cross to the far shore.\nThe rest just run around\non the near shore."}]},{"n":86,"vg":6,"pali":"Ye ca kho sammadakkhāte,\ndhamme dhammānuvattino;\nTe janā pāramessanti,\nmaccudheyyaṁ suduttaraṁ.","v":[{"k":"muller","t":"But those who, when the law has been well preached to them, follow the law, will pass across the dominion of death, however difficult to overcome."},{"k":"wagiswara","t":"They who hold fast to the teaching\nOf the Norm expounded well\nThey shall reach the shore and pass\nThe realm of Death so hard to cross."},{"k":"kaviratna","t":"Those who live according to the Dhamma which has been well proclaimed (by the Buddha) will cross over the impassable realm of death to the further shore."},{"k":"buddharakkhita","t":"But those who act according to the perfectly taught Dhamma will cross the realm of Death, so difficult to cross."},{"k":"thanissaro","t":"Few are the people\nwho reach the Far Shore.\nThese others\nsimply scurry along\nthis shore.\n\nBut those who practice Dhamma\nin line with the well-taught Dhamma,\nwill cross over the realm of Death\nso hard to transcend.\n\nForsaking dark practices,\nthe wise person\nshould develop the bright,\nhaving gone from home\nto no-home\nin seclusion, so hard to enjoy.\n\nThere he should wish for delight,\ndiscarding sensuality —\nhe who has nothing.\nHe should cleanse himself — wise —\nof what defiles the mind.\n\nWhose minds are well-developed\nin the factors of self-awakening,\nwho delight in non-clinging,\nrelinquishing grasping —\nresplendent,\ntheir effluents ended:\nthey, in the world,\nare Unbound."},{"k":"suddhaso","t":"Those who act in accordance\nwith the well-explained Dhamma\nwill go beyond the mortal realm\nso difficult to escape."},{"k":"sujato","t":"When the teaching is well explained,\nthose who practice accordingly\nwill cross over\nDeath's dominion so hard to pass."}]},{"n":87,"vg":6,"pali":"Kaṇhaṁ dhammaṁ vippahāya,\nSukkaṁ bhāvetha paṇḍito;\nOkā anokamāgamma,\nViveke yattha dūramaṁ.","v":[{"k":"muller","t":"A wise man should leave the dark state (of ordinary life), and follow the bright state (of the Bhikshu). After going from his home to a homeless state, he should in his retirement look for enjoyment where there seemed to be no enjoyment. Leaving all pleasures behind, and calling nothing his own, the wise man should purge himself from all the troubles of the mind."},{"k":"wagiswara","t":"Giving up the state of darkness,\nLet the wise embrace the pure;\nGiving up home for the homeless\nLoneliness, where joys are rare,\nLet him long for bliss unbounded\nCasting all desire aside,\nOwning naught, and, firm in wisdom,\nCleanse his heart from passion's stain."},{"k":"kaviratna","t":"Having abandoned the ways of darkness, let the wise follow the light. Having come from home to homelessness, let him enjoy the bliss of solitude, so difficult to achieve."},{"k":"buddharakkhita","t":"Abandoning the dark way, let the wise man cultivate the bright path. Having gone from home to homelessness, let him yearn for that delight in detachment, so difficult to enjoy. Giving up sensual pleasures, with no attachment, let the wise man cleanse himself of defilements of the mind."},{"k":"thanissaro","t":"Few are the people\nwho reach the Far Shore.\nThese others\nsimply scurry along\nthis shore.\n\nBut those who practice Dhamma\nin line with the well-taught Dhamma,\nwill cross over the realm of Death\nso hard to transcend.\n\nForsaking dark practices,\nthe wise person\nshould develop the bright,\nhaving gone from home\nto no-home\nin seclusion, so hard to enjoy.\n\nThere he should wish for delight,\ndiscarding sensuality —\nhe who has nothing.\nHe should cleanse himself — wise —\nof what defiles the mind.\n\nWhose minds are well-developed\nin the factors of self-awakening,\nwho delight in non-clinging,\nrelinquishing grasping —\nresplendent,\ntheir effluents ended:\nthey, in the world,\nare Unbound."},{"k":"suddhaso","t":"Abandon dark things and develop bright things;\na wise person\nleaves home for homelessness\nand lives in seclusion, where it is difficult to find satisfaction."},{"k":"sujato","t":"Rid of dark qualities,\nan astute person should develop the bright.\nLeaving home behind\nfor the seclusion so hard to enjoy,"}]},{"n":88,"vg":6,"pali":"Tatrābhiratimiccheyya,\nhitvā kāme akiñcano;\nPariyodapeyya attānaṁ,\ncittaklesehi paṇḍito.","v":[{"k":"muller","t":"A wise man should leave the dark state (of ordinary life), and follow the bright state (of the Bhikshu). After going from his home to a homeless state, he should in his retirement look for enjoyment where there seemed to be no enjoyment. Leaving all pleasures behind, and calling nothing his own, the wise man should purge himself from all the troubles of the mind."},{"k":"wagiswara","t":"Giving up the state of darkness,\nLet the wise embrace the pure;\nGiving up home for the homeless\nLoneliness, where joys are rare,\nLet him long for bliss unbounded\nCasting all desire aside,\nOwning naught, and, firm in wisdom,\nCleanse his heart from passion's stain."},{"k":"kaviratna","t":"He should focus his mind upon that exalted state (nirvana). Having given up all sense pleasures, possessing nothing, let the wise, cleansing the mind from defilements, purify the self."},{"k":"buddharakkhita","t":"Abandoning the dark way, let the wise man cultivate the bright path. Having gone from home to homelessness, let him yearn for that delight in detachment, so difficult to enjoy. Giving up sensual pleasures, with no attachment, let the wise man cleanse himself of defilements of the mind."},{"k":"thanissaro","t":"Forsaking dark practices,\nthe wise person\nshould develop the bright,\nhaving gone from home\nto no-home\nin seclusion, so hard to enjoy.\n\nThere he should wish for delight,\ndiscarding sensuality —\nhe who has nothing.\nHe should cleanse himself — wise —\nof what defiles the mind."},{"k":"suddhaso","t":"One who has nothing could hope to find satisfaction there,\nafter abandoning sensuality;\na wise person would cleanse themselves\nof mental defilements."},{"k":"sujato","t":"try to find satisfaction there,\nhaving left behind sensual pleasures.\nOwning nothing, an astute person\nwould cleanse themselves of mental corruptions."}]},{"n":89,"vg":6,"pali":"Yesaṁ sambodhiyaṅgesu,\nsammā cittaṁ subhāvitaṁ;\nĀdānapaṭinissagge,\nanupādāya ye ratā;\nKhīṇāsavā jutimanto,\nte loke parinibbutā.\nPaṇḍitavaggo chaṭṭho.","v":[{"k":"muller","t":"Those whose mind is well grounded in the (seven) elements of knowledge, who without clinging to anything, rejoice in freedom from attachment, whose appetites have been conquered, and who are full of light, are free (even) in this world."},{"k":"wagiswara","t":"They whose mind is rightly tempered\nIn the Wisdom's seven ways,\nWho have left desire behind them,\nVoid of clinging, they rejoicing\nPassionless and all-resplendent,\nEven in this world are freed."},{"k":"kaviratna","t":"Those whose minds are well fixed upon the elements of enlightenment (sambodhi),(2) who, without hankering after anything, glory in renunciation, whose biases are extinguished, who are full of light, they indeed have attained the bliss of nirvana in this very world."},{"k":"buddharakkhita","t":"Those whose minds have reached full excellence in the factors of enlightenment, who, having renounced acquisitiveness, rejoice in not clinging to things — rid of cankers, glowing with wisdom, they have attained Nibbana in this very life. [10]"},{"k":"thanissaro","t":"Whose minds are well-developed\nin the factors of self-awakening,\nwho delight in non-clinging,\nrelinquishing grasping —\nresplendent,\ntheir effluents ended:\nthey, in the world,\nare Unbound."},{"k":"suddhaso","t":"Those who have developed the factors of awakening\ncorrectly and thoroughly,\nwho have taken up relinquishment,\nwho appreciate non-grasping,\nand have eliminated their corruptions—\nsuch radiant beings have attained Nibbāna in this world."},{"k":"sujato","t":"Those whose minds are rightly developed\nin the awakening factors;\nwho, letting go of attachments,\ndelight in not grasping:\nwith defilements ended, brilliant,\nthey are quenched in this world."}]},{"n":90,"vg":7,"pali":"Gataddhino visokassa,\nvippamuttassa sabbadhi;\nSabbaganthappahīnassa,\npariḷāho na vijjati.","v":[{"k":"muller","t":"There is no suffering for him who has finished his journey, and abandoned grief, who has freed himself on all sides, and thrown off all fetters."},{"k":"wagiswara","t":"He for whom life's journey's over, free from sorrow, free from pain\nWho has all the knots unfastened, suffering knows not again."},{"k":"kaviratna","t":"The fever of passion afflicts not the holy one (arahant), who has completed his samsaric journey (cycle of rebirths), who is free from sorrow, absolutely emancipated, and who has destroyed all knots of attachment."},{"k":"buddharakkhita","t":"The fever of passion exists not for him who has completed the journey, who is sorrowless and wholly set free, and has broken all ties."},{"k":"thanissaro","t":"In one who\nhas gone the full distance,\nis free from sorrow,\nis fully released\nin all respects,\nhas abandoned all bonds:\nno fever is found."},{"k":"suddhaso","t":"In one who has completed the journey, is free of sorrow,\nhas been completely liberated in every way,\nand has abandoned all ties,\nno fever can be found."},{"k":"sujato","t":"At journey's end, rid of sorrow;\neverywhere free,\nall ties given up,\nno fever is found in them."}]},{"n":91,"vg":7,"pali":"Uyyuñjanti satīmanto,\nna nikete ramanti te;\nHaṁsāva pallalaṁ hitvā,\nokamokaṁ jahanti te.","v":[{"k":"muller","t":"They depart with their thoughts well-collected, they are not happy in their abode; like swans who have left their lake, they leave their house and home."},{"k":"wagiswara","t":"Household life for them no joys hath; striving and intent in mind\nAs the swan deserts the marshes, every home they leave behind."},{"k":"kaviratna","t":"Mindful ones constantly strive, they do not cling to a dwelling place; like swans that abandon a lake, the holy ones abandon house and home."},{"k":"buddharakkhita","t":"The mindful ones exert themselves. They are not attached to any home; like swans that abandon the lake, they leave home after home behind."},{"k":"thanissaro","t":"The mindful keep active,\ndon't delight in settling back.\nThey renounce every home,\nevery home,\nlike swans taking off from a lake."},{"k":"suddhaso","t":"Mindfully they strive upwards,\nthey do not appreciate settling;\nLike swans leaving behind a lake,\nthey abandon home after home."},{"k":"sujato","t":"The mindful apply themselves;\nthey delight in no abode.\nLike a swan gone from the marsh,\nthey leave home after home behind."}]},{"n":92,"vg":7,"pali":"Yesaṁ sannicayo natthi,\nye pariññātabhojanā;\nSuññato animitto ca,\nvimokkho yesaṁ gocaro;\nĀkāseva sakuntānaṁ,\ngati tesaṁ durannayā.","v":[{"k":"muller","t":"Men who have no riches, who live on recognised food, who have perceived void and unconditioned freedom (Nirvana), their path is difficult to understand, like that of birds in the air."},{"k":"wagiswara","t":"They who gather up no treasure, feeding on the food that's known,\nThey who range in mind the Void, the unconditioned formless Space,\nAs the bird's path in the ether, so their ways are hard to trace."},{"k":"kaviratna","t":"Those who have no accumulation (of worldly possessions), who have a well-regulated diet, who are within range of perfect deliverance through realization of the Void and the conditionlessness of all forms (sunnata and animitta), their holy path is as difficult to trace as is the track of birds in the air."},{"k":"buddharakkhita","t":"Those who do not accumulate and are wise regarding food, whose object is the Void, the Unconditioned Freedom — their track cannot be traced, like that of birds in the air."},{"k":"thanissaro","t":"He whose senses are steadied\nlike stallions\nwell-trained by the charioteer,\nhis conceit abandoned,\nfree of effluent,\nSuch:\neven devas adore him."},{"k":"suddhaso","t":"Those who have no stockpile,\nwho have completely understood eating,\nwhose domain is emptiness\nand objectless liberation—\nlike birds in the sky,\ntheir movement is hard to follow."},{"k":"sujato","t":"Those with nothing stored up,\nwho have understood their food,\nwhose domain is the liberation\nof the signless and the empty:\ntheir path is hard to trace,\nlike birds in the sky."}]},{"n":93,"vg":7,"pali":"Yassāsavā parikkhīṇā,\nāhāre ca anissito;\nSuññato animitto ca,\nvimokkho yassa gocaro;\nĀkāseva sakuntānaṁ,\npadaṁ tassa durannayaṁ.","v":[{"k":"muller","t":"He whose appetites are stilled, who is not absorbed in enjoyment, who has perceived void and unconditioned freedom (Nirvana), his path is difficult to understand, like that of birds in the air."},{"k":"wagiswara","t":"They whose taints are all evanished, independent of support,\nThey who range in mind the Void, the unconditioned, formless Space,\nAs the bird's path in the ether, so their tracks are hard to trace."},{"k":"kaviratna","t":"He whose mental attachments are extinguished, who is not immoderate in food, who is within range of perfect deliverance through realization of the Void and the conditionlessness of all forms, his holy path is as difficult to trace as is the track of birds in the air."},{"k":"buddharakkhita","t":"He whose cankers are destroyed and who is not attached to food, whose object is the Void, the Unconditioned Freedom — his path cannot be traced, like that of birds in the air."},{"k":"thanissaro","t":"He whose senses are steadied\nlike stallions\nwell-trained by the charioteer,\nhis conceit abandoned,\nfree of effluent,\nSuch:\neven devas adore him.\n\nLike the earth, he doesn't react —\ncultured,\nSuch,\nlike Indra's pillar,\nlike a lake free of mud.\nFor him\n— Such —\nthere's no traveling on.\n\nCalm is his mind,\ncalm his speech\n& his deed:\none who's released through right knowing,\npacified,\nSuch."},{"k":"suddhaso","t":"One who has completely eliminated their influences\nand is not dependent on consumption,\nwhose domain is emptiness\nand objectless liberation—\nlike birds in the sky,\ntheir path is hard to follow."},{"k":"sujato","t":"One whose defilements have ended;\nwho's not attached to food;\nwhose domain is the liberation\nof the signless and the empty:\ntheir track is hard to trace,\nlike birds in the sky."}]},{"n":94,"vg":7,"pali":"Yassindriyāni samathaṅgatāni,\nAssā yathā sārathinā sudantā;\nPahīnamānassa anāsavassa,\nDevāpi tassa pihayanti tādino.","v":[{"k":"muller","t":"The gods even envy him whose senses, like horses well broken in by the driver, have been subdued, who is free from pride, and free from appetites."},{"k":"wagiswara","t":"He whose senses now are tranquil, like a horse by trainer tamed\n(Pride struck off, the taints evanished), to the very gods is famed."},{"k":"kaviratna","t":"He whose senses are subdued, like horses well trained by a charioteer, whose pride is destroyed and who is free from corruption, even the gods cherish such a one."},{"k":"buddharakkhita","t":"Even the gods hold dear the wise one, whose senses are subdued like horses well trained by a charioteer, whose pride is destroyed and who is free from the cankers."},{"k":"thanissaro","t":"He whose senses are steadied\nlike stallions\nwell-trained by the charioteer,\nhis conceit abandoned,\nfree of effluent,\nSuch:\neven devas adore him.\n\nLike the earth, he doesn't react —\ncultured,\nSuch,\nlike Indra's pillar,\nlike a lake free of mud.\nFor him\n— Such —\nthere's no traveling on.\n\nCalm is his mind,\ncalm his speech\n& his deed:\none who's released through right knowing,\npacified,\nSuch."},{"k":"suddhaso","t":"One whose faculties are peaceful,\nlike a horse well-trained by a charioteer,\nwho has abandoned conceit and is free of influences,\nis envied even by the angels."},{"k":"sujato","t":"Whose faculties have become serene,\nlike horses tamed by a charioteer,\nwho has abandoned conceit and defilements;\nthe unaffected one is envied by even the gods."}]},{"n":95,"vg":7,"pali":"Pathavisamo no virujjhati,\nIndakhilupamo tādi subbato;\nRahadova apetakaddamo,\nSaṁsārā na bhavanti tādino.","v":[{"k":"muller","t":"Such a one who does his duty is tolerant like the earth, like Indra's bolt; he is like a lake without mud; no new births are in store for him."},{"k":"wagiswara","t":"Like the solid ground unshaken, like the threshold of a door,\nLike a pool by mud unsullied, such a saint is born no more."},{"k":"kaviratna","t":"He who is unperturbed like the earth, who is steadfast like Indra's post (in the portal of a city), whose character is as pure and translucent as a clear lake, to such a holy one there are no further cycles of rebirth (samsara)."},{"k":"buddharakkhita","t":"There is no more worldly existence for the wise one who, like the earth, resents nothing, who is firm as a high pillar and as pure as a deep pool free from mud."},{"k":"thanissaro","t":"Like the earth, he doesn't react —\ncultured,\nSuch,\nlike Indra's pillar,\nlike a lake free of mud.\nFor him\n— Such —\nthere's no traveling on."},{"k":"suddhaso","t":"One who, like the earth, opposes nothing,\nwho is as stable as a pillar, practicing well,\nwho is like a lake with no trace of mud—\nsuch beings are not reborn in saṁsāra."},{"k":"sujato","t":"Undisturbed like the earth,\ntrue to their vows, steady as Indra's pillar,\nlike a lake clear of mud;\nsuch a one does not transmigrate."}]},{"n":96,"vg":7,"pali":"Santaṁ tassa manaṁ hoti,\nsantā vācā ca kamma ca;\nSammadaññāvimuttassa,\nupasantassa tādino.","v":[{"k":"muller","t":"His thought is quiet, quiet are his word and deed, when he has obtained freedom by true knowledge, when he has thus become a quiet man."},{"k":"wagiswara","t":"Calm the mind of such a being, calm his thoughts and words and deeds,\nSet free by the perfect knowledge, liberated from life's needs."},{"k":"kaviratna","t":"His mind becomes calm. His word and deed are calm. Such is the state of tranquillity of one who has attained to deliverance through the realization of truth."},{"k":"buddharakkhita","t":"Calm is his thought, calm his speech, and calm his deed, who, truly knowing, is wholly freed, perfectly tranquil and wise."},{"k":"thanissaro","t":"Calm is his mind,\ncalm his speech\n& his deed:\none who's released through right knowing,\npacified,\nSuch."},{"k":"suddhaso","t":"One whose mind is peaceful,\nwhose speech and actions are peaceful,\nand who is liberated through right knowledge—\nsuch a person is at peace."},{"k":"sujato","t":"Their mind is peaceful,\npeaceful are their speech and deeds.\nSuch a one is at peace,\nrightly freed through enlightenment."}]},{"n":97,"vg":7,"pali":"Assaddho akataññū ca,\nsandhicchedo ca yo naro;\nHatāvakāso vantāso,\nsa ve uttamaporiso.","v":[{"k":"muller","t":"The man who is free from credulity, but knows the uncreated, who has cut all ties, removed all temptations, renounced all desires, he is the greatest of men."},{"k":"wagiswara","t":"Self-dependent, self-sufficing, knower of the Uncreate\nWho hath loosed the bonds of action, from the chain of births set free,\nAll desires are fallen from him, noblest of all beings he."},{"k":"kaviratna","t":"He who is not credulous, who knows the nature of the Uncreated (akata), who has severed all the bonds (of rebirth), who has destroyed all the influxes of evil and given up all cravings, he, indeed, is noblest among men."},{"k":"buddharakkhita","t":"The man who is without blind faith, who knows the Uncreated, who has severed all links, destroyed all causes (for karma, good and evil), and thrown out all desires — he, truly, is the most excellent of men. [11]"},{"k":"thanissaro","t":"The man\nfaithless / beyond conviction\nungrateful / knowing the Unmade\na burglar / who has severed connections\nwho's destroyed\nhis chances / conditions\nwho eats vomit: / has disgorged expectations:\nthe ultimate person."},{"k":"suddhaso","t":"One who is beyond faith, knows the Unmade,\nhas severed all ties,\nhas expelled defilement, and has rejected longing—\nthis is truly the best person."},{"k":"sujato","t":"Lacking faith, a house-breaker,\none who acknowledges nothing,\npurged of hope, they've wasted their chance:\nthat is indeed the supreme person!"}]},{"n":98,"vg":7,"pali":"Gāme vā yadi vāraññe,\nNinne vā yadi vā thale;\nYattha arahanto viharanti,\nTaṁ bhūmirāmaṇeyyakaṁ.","v":[{"k":"muller","t":"In a hamlet or in a forest, in the deep water or on the dry land, wherever venerable persons (Arhanta) dwell, that place is delightful."},{"k":"wagiswara","t":"In the village or the forest, on the water or the ground,\nWhere the worthy ones are dwelling, there the earth's delights are found."},{"k":"kaviratna","t":"That spot is truly delightful where the Holy Ones (arahant) reside, be it village or forest, valley or high ground."},{"k":"buddharakkhita","t":"Inspiring, indeed, is that place where Arahants dwell, be it a village, a forest, a vale, or a hill."},{"k":"thanissaro","t":"In village or wilds,\nvalley, plateau:\nthat place is delightful\nwhere arahants dwell."},{"k":"suddhaso","t":"Whether it is in a village or in the wilderness,\nin lowlands or highlands—\nany place where an arahant lives\nis a place worth appreciating."},{"k":"sujato","t":"Whether in village or wilderness,\nin a valley or the uplands,\nwherever the perfected ones live\nis a delightful place."}]},{"n":99,"vg":7,"pali":"Ramaṇīyāni araññāni,\nyattha na ramatī jano;\nVītarāgā ramissanti,\nna te kāmagavesino.\nArahantavaggo sattamo.","v":[{"k":"muller","t":"Forests are delightful; where the world finds no delight, there the passionless will find delight, for they look not for pleasures."},{"k":"wagiswara","t":"Ah! delightful are the forests! where the worldling finds no joy,\nThere the passionless find pleasure, whom the senses do not cloy."},{"k":"kaviratna","t":"Charming are the forests which do not attract the multitudes. But the holy ones, free from attachments, find delight in them for they are not seekers after the allurements of the senses."},{"k":"buddharakkhita","t":"Inspiring are the forests in which worldlings find no pleasure. There the passionless will rejoice, for they seek no sensual pleasures."},{"k":"thanissaro","t":"Delightful wilds\nwhere the crowds don't delight,\nthose free from passion\ndelight,\nfor they're not searching\nfor sensual pleasures."},{"k":"suddhaso","t":"It is possible to appreciate the wilderness areas\nthat most people do not appreciate;\none who is free of passion will appreciate them,\nsince they do not seek sensuality."},{"k":"sujato","t":"Delightful are the wildernesses\nwhere no people delight.\nThose free of greed will delight there,\nnot those who seek sensual pleasures."}]},{"n":100,"vg":8,"pali":"Sahassamapi ce vācā,\nanatthapadasaṁhitā;\nEkaṁ atthapadaṁ seyyo,\nyaṁ sutvā upasammati.","v":[{"k":"muller","t":"Even though a speech be a thousand (of words), but made up of senseless words, one word of sense is better, which if a man hears, he becomes quiet."},{"k":"wagiswara","t":"Tho' one's speech be a thousand words,\nVain words all strung together,\nBetter a single phrase\nWhich calms the one that hears."},{"k":"kaviratna","t":"A single word full of meaning, hearing which one becomes at peace, is better than a thousand words which are empty of meaning."},{"k":"buddharakkhita","t":"Better than a thousand useless words is one useful word, hearing which one attains peace."},{"k":"thanissaro","t":"Better\nthan if there were thousands\nof meaningless words is\none\nmeaningful\nword\nthat on hearing\nbrings peace."},{"k":"suddhaso","t":"Rather than a thousand sayings\nnot connected to the goal,\nit is better to have just one sentence about the goal\nif one reaches peace after hearing it."},{"k":"sujato","t":"Better than a thousand\nmeaningless sayings\nis a single meaningful saying,\nhearing which brings you peace."}]},{"n":101,"vg":8,"pali":"Sahassamapi ce gāthā,\nanatthapadasaṁhitā;\nEkaṁ gāthāpadaṁ seyyo,\nyaṁ sutvā upasammati.","v":[{"k":"muller","t":"Even though a Gatha (poem) be a thousand (of words), but made up of senseless words, one word of a Gatha is better, which if a man hears, he becomes quiet."},{"k":"wagiswara","t":"Tho' a song have a thousand words,\nVain words all strung together,\nBetter a single verse\nWhich calms the one that hears."},{"k":"kaviratna","t":"A single couplet pregnant with meaning, hearing which one becomes at peace, is better than a thousand couplets composed of meaningless words."},{"k":"buddharakkhita","t":"Better than a thousand useless verses is one useful verse, hearing which one attains peace."},{"k":"thanissaro","t":"Better\nthan if there were thousands\nof meaningless verses is\none\nmeaningful\nverse\nthat on hearing\nbrings peace."},{"k":"suddhaso","t":"Rather than a thousand poems\nnot connected to the goal,\nit is better to have just one line of a poem\nif one reaches peace after hearing it."},{"k":"sujato","t":"Better than a thousand\nmeaningless verses\nis a single meaningful verse,\nhearing which brings you peace."}]},{"n":102,"vg":8,"pali":"Yo ca gāthā sataṁ bhāse,\nanatthapadasaṁhitā;\nEkaṁ dhammapadaṁ seyyo,\nyaṁ sutvā upasammati.","v":[{"k":"muller","t":"Though a man recite a hundred Gathas made up of senseless words, one word of the law is better, which if a man hears, he becomes quiet."},{"k":"wagiswara","t":"Tho' one utter a hundred songs,\nVain words all strung together,\nBetter one verse of the Norm\nWhich brings peace to the hearer."},{"k":"kaviratna","t":"One word of the Dhamma, hearing which one becomes at peace, is better than the utterance of a hundred verses which consist of superficial words."},{"k":"buddharakkhita","t":"Better than reciting a hundred meaningless verses is the reciting of one verse of Dhamma, hearing which one attains peace."},{"k":"thanissaro","t":"And better than chanting hundreds\nof meaningless verses is\none\nDhamma-saying\nthat on hearing\nbrings peace."},{"k":"suddhaso","t":"One might utter a hundred poems\nnot connected to the goal;\nit is better to have just one line of Dhamma\nif one reaches peace after hearing it."},{"k":"sujato","t":"Better than reciting\na hundred meaningless verses\nis a single saying of Dhamma,\nhearing which brings you peace."}]},{"n":103,"vg":8,"pali":"Yo sahassaṁ sahassena,\nsaṅgāme mānuse jine;\nEkañca jeyyamattānaṁ,\nsa ve saṅgāmajuttamo.","v":[{"k":"muller","t":"If one man conquer in battle a thousand times thousand men, and if another conquer himself, he is the greatest of conquerors."},{"k":"wagiswara","t":"Tho' one conquer a thousand times\nA thousand men in battle,\nWho conquers self alone\nIs the best of conquerors."},{"k":"kaviratna","t":"Though one were to conquer a million men in battle, that man who conquers himself is the greater victor."},{"k":"buddharakkhita","t":"Though one may conquer a thousand times a thousand men in battle, yet he indeed is the noblest victor who conquers himself."},{"k":"thanissaro","t":"Greater in battle\nthan the man who would conquer\na thousand-thousand men,\nis he who would conquer\njust one —\nhimself."},{"k":"suddhaso","t":"One might subjugate a million people\nin battle,\nbut one who subjugates oneself\nhas won the ultimate victory."},{"k":"sujato","t":"The supreme conqueror is\nnot he who conquers a million men in battle,\nbut he who conquers a single man:\nhimself."}]},{"n":104,"vg":8,"pali":"Attā have jitaṁ seyyo,\nyā cāyaṁ itarā pajā;\nAttadantassa posassa,\nniccaṁ saññatacārino.","v":[{"k":"muller","t":"One's own self conquered is better than all other people; not even a god, a Gandharva, not Mara with Brahman could change into defeat the victory of a man who has vanquished himself, and always lives under restraint."},{"k":"wagiswara","t":"Tis better to conquer self\nThan all this multitude;\nIf one be self-subdued\nAnd ever self-controlled,"},{"k":"kaviratna","t":"To overcome one's own self is indeed better than to conquer others."},{"k":"buddharakkhita","t":"Self-conquest is far better than the conquest of others. Not even a god, an angel, Mara or Brahma can turn into defeat the victory of a person who is self-subdued and ever restrained in conduct. [12]"},{"k":"thanissaro","t":"Better to conquer yourself\nthan others.\nWhen you've trained yourself,\nliving in constant self-control,\nneither a deva nor gandhabba,\nnor a Mara banded with Brahmas,\ncould turn that triumph\nback into defeat."},{"k":"suddhaso","t":"It is better to subjugate yourself\nthan other people,\nfor one who is self-trained\nalways acts with restraint."},{"k":"sujato","t":"It is surely better to conquer oneself\nthan all those other folk.\nWhen a person has tamed themselves,\nalways living restrained,"}]},{"n":105,"vg":8,"pali":"Neva devo na gandhabbo,\nna māro saha brahmunā;\nJitaṁ apajitaṁ kayirā,\ntathārūpassa jantuno.","v":[{"k":"muller","t":"One's own self conquered is better than all other people; not even a god, a Gandharva, not Mara with Brahman could change into defeat the victory of a man who has vanquished himself, and always lives under restraint."},{"k":"wagiswara","t":"Not the gods or demi-gods\nNor the Lord of the world below\nNor the God Supreme have power\nTo undo his victory."},{"k":"kaviratna","t":"To overcome one's own self is indeed better than to conquer others."},{"k":"buddharakkhita","t":"Self-conquest is far better than the conquest of others. Not even a god, an angel, Mara or Brahma can turn into defeat the victory of a person who is self-subdued and ever restrained in conduct. [12]"},{"k":"thanissaro","t":"Greater in battle\nthan the man who would conquer\na thousand-thousand men,\nis he who would conquer\njust one —\nhimself.\n\nBetter to conquer yourself\nthan others.\nWhen you've trained yourself,\nliving in constant self-control,\nneither a deva nor gandhabba,\nnor a Mara banded with Brahmas,\ncould turn that triumph\nback into defeat."},{"k":"suddhaso","t":"No angel or fairy,\ndemon or god,\ncan turn such a person's\nvictory into defeat."},{"k":"sujato","t":"no god nor centaur,\nnor Māra nor divinity,\ncan undo the victory\nof such a personage."}]},{"n":106,"vg":8,"pali":"Māse māse sahassena,\nyo yajetha sataṁ samaṁ;\nEkañca bhāvitattānaṁ,\nmuhuttamapi pūjaye;\nSāyeva pūjanā seyyo,\nyañce vassasataṁ hutaṁ.","v":[{"k":"muller","t":"If a man for a hundred years sacrifice month after month with a thousand, and if he but for one moment pay homage to a man whose soul is grounded (in true knowledge), better is that homage than sacrifice for a hundred years."},{"k":"wagiswara","t":"Tho' one for a hundred years\nMonth after month should pray\nWith a thousand offerings,\nYet if for a moment's space\nHe worship the feet of one\nWhose self is self-subdued,\nHis worship is better far\nThan his age-long offerings."},{"k":"kaviratna","t":"Were a man month after month for a hundred years to offer sacrifices by the thousands, and were he to pay homage even for a moment to one who is self-governed, that homage is superior to the sacrifices of a hundred years."},{"k":"buddharakkhita","t":"Though month after month for a hundred years one should offer sacrifices by the thousands, yet if only for a moment one should worship those of perfected minds that honor is indeed better than a century of sacrifice."},{"k":"thanissaro","t":"You could, month by month,\nat a cost of thousands,\nconduct sacrifices\na hundred times,\nor\npay a single moment's homage\nto one person,\nself-cultivated.\nBetter than a hundred years of sacrifices\nwould that act of homage be."},{"k":"suddhaso","t":"Every month one might conduct\na hundred sacrifices worth thousands;\nOr for a single moment\none could pay homage to a self-developed person.\nThat homage is better\nthan a hundred years of sacrifices."},{"k":"sujato","t":"Rather than a thousandfold sacrifice,\nevery month for a full century,\nit's better to honor for a single hour\none who has developed themselves.\nThat offering is better\nthan the hundred year sacrifice."}]},{"n":107,"vg":8,"pali":"Yo ca vassasataṁ jantu,\naggiṁ paricare vane;\nEkañca bhāvitattānaṁ,\nmuhuttamapi pūjaye;\nSāyeva pūjanā seyyo,\nyañce vassasataṁ hutaṁ.","v":[{"k":"muller","t":"If a man for a hundred years worship Agni (fire) in the forest, and if he but for one moment pay homage to a man whose soul is grounded (in true knowledge), better is that homage than sacrifice for a hundred years."},{"k":"wagiswara","t":"Tho' a hundred years in the woods\nOne tend the sacred fire,\nYet if for a moment's space\nHe worship the feet of one\nWhose self is self-subdued;\nSuch worship is better far\nThan his age-long offerings"},{"k":"kaviratna","t":"Were a man for a hundred years to tend the sacrificial fire in the forest, and were he to pay homage even for a moment to one who is self-governed, that homage is superior to the fire-sacrifice of a hundred years."},{"k":"buddharakkhita","t":"Though for a hundred years one should tend the sacrificial fire in the forest, yet if only for a moment one should worship those of perfected minds, that worship is indeed better than a century of sacrifice."},{"k":"thanissaro","t":"You could, for a hundred years,\nlive in a forest\ntending a fire,\nor\npay a single moment's homage\nto one person,\nself-cultivated.\nBetter than a hundred years of sacrifices\nwould that act of homage be."},{"k":"suddhaso","t":"One might spend a hundred years\ntending to a fire in a forest;\nor for a single moment\none could pay homage to a self-developed person.\nThat homage is better\nthan a hundred years of sacrifices."},{"k":"sujato","t":"Rather than serve the sacred flame\nin the forest for a hundred years,\nit's better to honor for a single hour\na personage who has developed themselves.\nThat offering is better\nthan the hundred year sacrifice."}]},{"n":108,"vg":8,"pali":"Yaṁ kiñci yiṭṭhaṁ va hutaṁ va loke,\nSaṁvaccharaṁ yajetha puññapekkho;\nSabbampi taṁ na catubhāgameti,\nAbhivādanā ujjugatesu seyyo.","v":[{"k":"muller","t":"Whatever a man sacrifice in this world as an offering or as an oblation for a whole year in order to gain merit, the whole of it is not worth a quarter (a farthing); reverence shown to the righteous is better."},{"k":"wagiswara","t":"Not all the sacrifice\nThat is offered in all the world\nFor a year, with a view to gain,\nIs worth a single quarter\nOf the worship that is paid\nTo the upright holy man."},{"k":"kaviratna","t":"Whatever offering or sacrifice a person, who is desirous of gaining merit, may make throughout the course of a year, that is not worth one fourth of the merit acquired by homage paid to one of upright life."},{"k":"buddharakkhita","t":"Whatever gifts and oblations one seeking merit might offer in this world for a whole year, all that is not worth one fourth of the merit gained by revering the Upright Ones, which is truly excellent."},{"k":"thanissaro","t":"Everything offered\nor sacrificed in the world\nfor an entire year by one seeking merit\ndoesn't come to a fourth.\nBetter to pay respect\nto those who've gone\nthe straight way."},{"k":"suddhaso","t":"One could make any kind of offering or sacrifice in the world\nfor a year, pursuing merit;\nbut all of that is not even a quarter as good\nas honoring those who are upright."},{"k":"sujato","t":"Whatever sacrifice or offering in the world\na seeker of merit may make for a year,\nnone of it is worth a quarter\nof bowing to the sincere."}]},{"n":109,"vg":8,"pali":"Abhivādanasīlissa,\nniccaṁ vuḍḍhāpacāyino;\nCattāro dhammā vaḍḍhanti,\nāyu vaṇṇo sukhaṁ balaṁ.","v":[{"k":"muller","t":"He who always greets and constantly reveres the aged, four things will increase to him, viz. life, beauty, happiness, power."},{"k":"wagiswara","t":"Whoso hath reverence\nFor those advanced in years,\nFour blessings thrive for him,\nLife, beauty, bliss and strength."},{"k":"kaviratna","t":"In him, who always honors and respects the aged, four conditions will increase: longevity, beauty, happiness and strength."},{"k":"buddharakkhita","t":"To one ever eager to revere and serve the elders, these four blessing accrue: long life and beauty, happiness and power."},{"k":"thanissaro","t":"If you're respectful by habit,\nconstantly honoring the worthy,\nfour things increase:\nlong life, beauty,\nhappiness, strength."},{"k":"suddhaso","t":"For one who is virtuous, respectful,\nand always reverential towards the elderly,\nfour things increase:\nvitality, beauty, pleasure, and strength."},{"k":"sujato","t":"For one in the habit of bowing,\nalways honoring the elders,\nfour blessings grow:\nlifespan, beauty, happiness, and strength."}]},{"n":110,"vg":8,"pali":"Yo ca vassasataṁ jīve,\ndussīlo asamāhito;\nEkāhaṁ jīvitaṁ seyyo,\nsīlavantassa jhāyino.","v":[{"k":"muller","t":"But he who lives a hundred years, vicious and unrestrained, a life of one day is better if a man is virtuous and reflecting."},{"k":"wagiswara","t":"Tho' one live a hundred years,\nImmoral, uncontrolled,\n'Tis better to live for a day,\nMoral and well controlled."},{"k":"kaviratna","t":"One day's life of an Arhat who is virtuous and contemplative is better than a hundred years of life of one who is dissolute and of uncontrolled mind."},{"k":"buddharakkhita","t":"Better it is to live one day virtuous and meditative than to live a hundred years immoral and uncontrolled."},{"k":"thanissaro","t":"Better than a hundred years\nlived without virtue, uncentered, is\none day\nlived by a virtuous person\nabsorbed in jhana."},{"k":"suddhaso","t":"Better than living for a hundred years\nwithout virtue and concentration,\nis living for one day\nas a virtuous meditator."},{"k":"sujato","t":"Better to live a single day\nethical and absorbed in meditation\nthan to live a hundred years\nunethical and lacking immersion."}]},{"n":111,"vg":8,"pali":"Yo ca vassasataṁ jīve,\nduppañño asamāhito;\nEkāhaṁ jīvitaṁ seyyo,\npaññavantassa jhāyino.","v":[{"k":"muller","t":"And he who lives a hundred years, ignorant and unrestrained, a life of one day is better if a man is wise and reflecting."},{"k":"wagiswara","t":"Tho' one live a hundred years\nFoolish and uncontrolled,\n'Tis better to live for a day\nWisely and well controlled."},{"k":"kaviratna","t":"One day's life of him who is wise and contemplative is better than a life of a hundred years of one who is unwise and of uncontrolled mind."},{"k":"buddharakkhita","t":"Better it is to live one day wise and meditative than to live a hundred years foolish and uncontrolled."},{"k":"thanissaro","t":"And better than a hundred years\nlived undiscerning, uncentered, is\none day\nlived by a discerning person\nabsorbed in jhana."},{"k":"suddhaso","t":"Better than living for a hundred years\nwithout wisdom and concentration,\nis living for one day\nas a wise meditator."},{"k":"sujato","t":"Better to live a single day\nwise and absorbed in meditation\nthan to live a hundred years\nwitless and lacking immersion."}]},{"n":112,"vg":8,"pali":"Yo ca vassasataṁ jīve,\nkusīto hīnavīriyo;\nEkāhaṁ jīvitaṁ seyyo,\nvīriyamārabhato daḷhaṁ.","v":[{"k":"muller","t":"And he who lives a hundred years, idle and weak, a life of one day is better if a man has attained firm strength."},{"k":"wagiswara","t":"Tho' one live a hundred years\nListless and lacking zeal,\n'Tis better to live for a day\nWhile striving manfully."},{"k":"kaviratna","t":"One day's life of a person who is vigorous and resolute is better than a life of a hundred years of him who is weak and indolent."},{"k":"buddharakkhita","t":"Better it is to live one day strenuous and resolute than to live a hundred years sluggish and dissipated."},{"k":"thanissaro","t":"And better than a hundred years\nlived apathetic & unenergetic, is\none day\nlived energetic & firm."},{"k":"suddhaso","t":"Better than living for a hundred years\nwith laziness and indolence,\nis living for one day\nwith determination and resolve."},{"k":"sujato","t":"Better to live a single day\nenergetic and strong,\nthan to live a hundred years\nlazy and lacking energy."}]},{"n":113,"vg":8,"pali":"Yo ca vassasataṁ jīve,\napassaṁ udayabbayaṁ;\nEkāhaṁ jīvitaṁ seyyo,\npassato udayabbayaṁ.","v":[{"k":"muller","t":"And he who lives a hundred years, not seeing beginning and end, a life of one day is better if a man sees beginning and end."},{"k":"wagiswara","t":"Tho' one live a hundred years\nBlind to the rise and fall,\n'Tis better to live for a day\nSeeing the rise and fall."},{"k":"kaviratna","t":"A single day's life of one who clearly sees the origin and cessation (of all composite things), is better than a hundred years of life of him who does not perceive the origin and cessation of things."},{"k":"buddharakkhita","t":"Better it is to live one day seeing the rise and fall of things than to live a hundred years without ever seeing the rise and fall of things."},{"k":"thanissaro","t":"And better than a hundred years\nlived without seeing\narising & passing away, is\none day\nlived seeing\narising & passing away."},{"k":"suddhaso","t":"Better than living for a hundred years\nwithout seeing arising and vanishing,\nis living for one day\nwhile seeing arising and vanishing."},{"k":"sujato","t":"Better to live a single day\nseeing rise and fall\nthan to live a hundred years\nblind to rise and fall."}]},{"n":114,"vg":8,"pali":"Yo ca vassasataṁ jīve,\napassaṁ amataṁ padaṁ;\nEkāhaṁ jīvitaṁ seyyo,\npassato amataṁ padaṁ.","v":[{"k":"muller","t":"And he who lives a hundred years, not seeing the immortal place, a life of one day is better if a man sees the immortal place."},{"k":"wagiswara","t":"Tho' one live a hundred years\nAnd see not the Deathless State,\n'Tis better to live for a day\nAnd see the Deathless State."},{"k":"kaviratna","t":"A single day's life of one who perceives the immortal state is far better than if one were to live a hundred years without perceiving this state."},{"k":"buddharakkhita","t":"Better it is to live one day seeing the Deathless than to live a hundred years without ever seeing the Deathless."},{"k":"thanissaro","t":"And better than a hundred years\nlived without seeing\nthe Deathless state, is\none day\nlived seeing\nthe Deathless state."},{"k":"suddhaso","t":"Better than living for a hundred years\nwithout seeing the path to the deathless,\nis living for one day\nwhile seeing the path to the deathless."},{"k":"sujato","t":"Better to live a single day\nseeing the state free of death\nthan to live a hundred years\nblind to the state free of death."}]},{"n":115,"vg":8,"pali":"Yo ca vassasataṁ jīve,\napassaṁ dhammamuttamaṁ;\nEkāhaṁ jīvitaṁ seyyo,\npassato dhammamuttamaṁ.\nSahassavaggo aṭṭhamo.","v":[{"k":"muller","t":"And he who lives a hundred years, not seeing the highest law, a life of one day is better if a man sees the highest law."},{"k":"wagiswara","t":"Tho' one live a hundred years\nAnd see not the Norm Supreme,\n'Tis better to live for a day\nAnd see the Norm Supreme."},{"k":"kaviratna","t":"A single day's life of one who realizes the Sublime Truth is indeed better than a life of a hundred years of one who does not realize the Sublime Truth."},{"k":"buddharakkhita","t":"Better it is to live one day seeing the Supreme Truth than to live a hundred years without ever seeing the Supreme Truth."},{"k":"thanissaro","t":"And better than a hundred years\nlived without seeing\nthe ultimate Dhamma, is\none day\nlived seeing\nthe ultimate Dhamma."},{"k":"suddhaso","t":"Better than living for a hundred years\nwithout seeing the ultimate truth,\nis living for one day\nwhile seeing the ultimate truth."},{"k":"sujato","t":"Better to live a single day\nseeing the supreme teaching\nthan to live a hundred years\nblind to the supreme teaching."}]},{"n":116,"vg":9,"pali":"Abhittharetha kalyāṇe,\npāpā cittaṁ nivāraye;\nDandhañhi karoto puññaṁ,\npāpasmiṁ ramatī mano.","v":[{"k":"muller","t":"If a man would hasten towards the good, he should keep his thought away from evil; if a man does what is good slothfully, his mind delights in evil."},{"k":"wagiswara","t":"Haste to do good; thy thoughts from ill restrain;\nSloth in good deeds makes one for evil fain."},{"k":"kaviratna","t":"Make haste in doing good and restrain the mind from evil; if one is slow in doing good, the mind finds delight in evil."},{"k":"buddharakkhita","t":"Hasten to do good; restrain your mind from evil. He who is slow in doing good, his mind delights in evil."},{"k":"thanissaro","t":"Be quick in doing\nwhat's admirable.\nRestrain your mind\nfrom what's evil.\nWhen you're slow\nin making merit,\nevil delights the mind."},{"k":"suddhaso","t":"Rush to do good,\nkeep the mind back from evil.\nOne who is slow to do good\nappreciates evil."},{"k":"sujato","t":"Rush to do good,\nshield your mind from evil;\nfor when you're slow to do good,\nyour thoughts delight in wickedness."}]},{"n":117,"vg":9,"pali":"Pāpañce puriso kayirā,\nNa naṁ kayirā punappunaṁ;\nNa tamhi chandaṁ kayirātha,\nDukkho pāpassa uccayo.","v":[{"k":"muller","t":"If a man commits a sin, let him not do it again; let him not delight in sin: pain is the outcome of evil."},{"k":"wagiswara","t":"If thou do ill, cease, and thy sin forgo;\nTake not delight therein; ill deeds bring woe."},{"k":"kaviratna","t":"If a man commits evil let him not repeat it again and again; let him not delight in it, for the accumulation of sin brings suffering."},{"k":"buddharakkhita","t":"Should a person commit evil, let him not do it again and again. Let him not find pleasure therein, for painful is the accumulation of evil."},{"k":"thanissaro","t":"If a person does evil,\nhe shouldn't do it again & again,\nshouldn't develop a penchant for it.\nTo accumulate evil\nbrings pain."},{"k":"suddhaso","t":"If a person does something evil\nthey should not do it again.\nTake no interest in it;\nthe accumulation of evil is suffering."},{"k":"sujato","t":"If you do something bad,\ndon't do it again and again,\ndon't set your heart on it,\nfor piling up evil is suffering."}]},{"n":118,"vg":9,"pali":"Puññañce puriso kayirā,\nkayirā naṁ punappunaṁ;\nTamhi chandaṁ kayirātha,\nsukho puññassa uccayo.","v":[{"k":"muller","t":"If a man does what is good, let him do it again; let him delight in it: happiness is the outcome of good."},{"k":"wagiswara","t":"If thou do good, thy life in good employ;\nTake thou delight therein; good deeds bring joy."},{"k":"kaviratna","t":"If a man commits a meritorious deed, let him perform it again and again; let him develop a longing for doing good; happiness is the outcome of the accumulation of merit."},{"k":"buddharakkhita","t":"Should a person do good, let him do it again and again. Let him find pleasure therein, for blissful is the accumulation of good."},{"k":"thanissaro","t":"If a person makes merit,\nhe should do it again & again,\nshould develop a penchant for it.\nTo accumulate merit\nbrings ease."},{"k":"suddhaso","t":"If a person does something good\nthey should do it again.\nTake an interest in it;\nthe accumulation of merit is pleasant."},{"k":"sujato","t":"If you do something good,\ndo it again and again,\nset your heart on it,\nfor piling up goodness is joyful."}]},{"n":119,"vg":9,"pali":"Pāpopi passati bhadraṁ,\nYāva pāpaṁ na paccati;\nYadā ca paccati pāpaṁ,\nAtha pāpo pāpāni passati.","v":[{"k":"muller","t":"Even an evil-doer sees happiness as long as his evil deed has not ripened; but when his evil deed has ripened, then does the evil-doer see evil."},{"k":"wagiswara","t":"Sinners see bliss while their ill deeds are green;\nWhen the sin ripens, sorrow then is seen."},{"k":"kaviratna","t":"Even the wrongdoer finds some happiness so long as (the fruit of) his misdeed does not mature; but when it does mature, then he sees its evil results."},{"k":"buddharakkhita","t":"It may be well with the evil-doer as long as the evil ripens not. But when it does ripen, then the evil-doer sees (the painful results of) his evil deeds."},{"k":"thanissaro","t":"Even the evil\nmeet with good fortune\nas long as their evil\nhas yet to mature.\nBut when it's matured\nthat's when they meet\nwith evil."},{"k":"suddhaso","t":"One sees evil as good\nas long as its results have yet to fully manifest;\nbut when the results of that evil fully manifest,\nthen one sees evil as evil."},{"k":"sujato","t":"Even the wicked see good things,\nso long as their wickedness has not ripened.\nBut as soon as that wickedness ripens,\nthen the wicked see wicked things."}]},{"n":120,"vg":9,"pali":"Bhadropi passati pāpaṁ,\nYāva bhadraṁ na paccati;\nYadā ca paccati bhadraṁ,\nAtha bhadro bhadrāni passati.","v":[{"k":"muller","t":"Even a good man sees evil days, as long as his good deed has not ripened; but when his good deed has ripened, then does the good man see happy days."},{"k":"wagiswara","t":"Good men see ill while their good deeds are green;\nWhen the good ripens, happiness is seen."},{"k":"kaviratna","t":"Even the doer of good deeds knows evil (days) so long as his merit has not matured; but when his merit has fully matured, then he sees the happy results of his meritorious deeds."},{"k":"buddharakkhita","t":"It may be ill with the doer of good as long as the good ripens not. But when it does ripen, then the doer of good sees (the pleasant results of) his good deeds."},{"k":"thanissaro","t":"Even the good\nmeet with bad fortune\nas long as their good\nhas yet to mature.\nBut when it's matured\nthat's when they meet\nwith good fortune."},{"k":"suddhaso","t":"One sees good as evil\nas long as its results have yet to fully manifest;\nbut when the results of that good fully manifest,\nthen one sees good as good."},{"k":"sujato","t":"Even the good see wicked things,\nso long as their goodness has not ripened.\nBut as soon as that goodness ripens,\nthen the good see good things."}]},{"n":121,"vg":9,"pali":"Māvamaññetha pāpassa,\nna mantaṁ āgamissati;\nUdabindunipātena,\nudakumbhopi pūrati;\nBālo pūrati pāpassa,\nthokaṁ thokampi ācinaṁ.","v":[{"k":"muller","t":"Let no man think lightly of evil, saying in his heart, It will not come nigh unto me. Even by the falling of water-drops a water-pot is filled; the fool becomes full of evil, even if he gather it little by little."},{"k":"wagiswara","t":"Think not of ill: \"It cannot be my fate\";\nAs drop by drop the water fills the pot,\nSo slowly good men good accumulate."},{"k":"kaviratna","t":"Do not think lightly of evil, saying, \"It will not come to me.\" By the constant fall of waterdrops, a pitcher is filled; likewise the unwise person, accumulating evil little by little, becomes full of evil."},{"k":"buddharakkhita","t":"Think not lightly of evil, saying, \"It will not come to me.\" Drop by drop is the water pot filled. Likewise, the fool, gathering it little by little, fills himself with evil."},{"k":"thanissaro","t":"Don't underestimate evil\n('It won't amount to much').\nA water jar fills,\neven with water\nfalling in drops.\nWith evil — even if\nbit\nby\nbit,\nhabitually —\nthe fool fills himself full."},{"k":"suddhaso","t":"Do not disregard evil,\nthinking it will have no consequence.\nJust as falling drops of water\nfill up a bucket,\na fool becomes full of evil\ncollecting it little by little."},{"k":"sujato","t":"Think not lightly of evil,\nthat it won't come back to you.\nThe pot is filled with water\nfalling drop by drop;\nthe fool is filled with wickedness\npiled up bit by bit."}]},{"n":122,"vg":9,"pali":"Māvamaññetha puññassa,\nna mandaṁ āgamissati;\nUdabindunipātena,\nudakumbhopi pūrati;\nDhīro pūrati puññassa,\nthokaṁ thokampi ācinaṁ.","v":[{"k":"muller","t":"Let no man think lightly of good, saying in his heart, It will not come nigh unto me. Even by the falling of water-drops a water-pot is filled; the wise man becomes full of good, even if he gather it little by little."},{"k":"wagiswara","t":"Think not of good: \"It cannot be my fate\";\nAs drop by drop the water fills the pot,\nSo slowly bad men woes accumulate."},{"k":"kaviratna","t":"Do not think lightly of merit, saying, \"It will not come to me.\" By the constant fall of waterdrops, a pitcher is filled; likewise the wise person, accumulating merit little by little, becomes full of merit."},{"k":"buddharakkhita","t":"Think not lightly of good, saying, \"It will not come to me.\" Drop by drop is the water pot filled. Likewise, the wise man, gathering it little by little, fills himself with good."},{"k":"thanissaro","t":"Don't underestimate merit\n('It won't amount to much').\nA water jar fills,\neven with water\nfalling in drops.\nWith merit — even if\nbit\nby\nbit,\nhabitually —\nthe enlightened one fills himself full."},{"k":"suddhaso","t":"Do not disregard merit,\nthinking it will have no consequence.\nJust as falling drops of water\nfill up a bucket,\na sage becomes full of merit\ncollecting it little by little."},{"k":"sujato","t":"Think not lightly of goodness,\nthat it won't come back to you.\nThe pot is filled with water\nfalling drop by drop;\nthe attentive one is filled with goodness\npiled up bit by bit."}]},{"n":123,"vg":9,"pali":"Vāṇijova bhayaṁ maggaṁ,\nappasattho mahaddhano;\nVisaṁ jīvitukāmova,\npāpāni parivajjaye.","v":[{"k":"muller","t":"Let a man avoid evil deeds, as a merchant, if he has few companions and carries much wealth, avoids a dangerous road; as a man who loves life avoids poison."},{"k":"wagiswara","t":"Just as the lord of some rich caravan,\nWhose guard is scanty, fears the highwayman;\nAs one who loves his life must poison shun,\nBe wise and guard 'gainst evil deeds begun."},{"k":"kaviratna","t":"As a merchant who has limited escort, yet carries much wealth, avoids a perilous road, as a man who is desirous of living long avoids poison, so in the same way should the wise shun evil."},{"k":"buddharakkhita","t":"Just as a trader with a small escort and great wealth would avoid a perilous route, or just as one desiring to live avoids poison, even so should one shun evil."},{"k":"thanissaro","t":"Like a merchant with a small\nbut well-laden caravan\n— a dangerous road,\nlike a person who loves life\n— a poison,\none should avoid\n— evil deeds."},{"k":"suddhaso","t":"Just as a wealthy merchant with little protection\navoids a dangerous road,\njust as one who wishes to live avoids poison,\none should avoid evil."},{"k":"sujato","t":"Avoid wickedness,\nas a merchant with rich cargo and small escort\nwould avoid a dangerous road,\nor one who loves life would avoid drinking poison."}]},{"n":124,"vg":9,"pali":"Pāṇimhi ce vaṇo nāssa,\nhareyya pāṇinā visaṁ;\nNābbaṇaṁ visamanveti,\nnatthi pāpaṁ akubbato.","v":[{"k":"muller","t":"He who has no wound on his hand, may touch poison with his hand; poison does not affect one who has no wound; nor is there evil for one who does not commit evil."},{"k":"wagiswara","t":"Thou mayest poison handle if thy palm\nContain no wound; whole skin no poison fears;\nThere is no ill for him that doth no harm."},{"k":"kaviratna","t":"If one does not have a wound in his hand, he may carry poison in his palm. Poison does not affect him who has no wound. There is no ill effect for the person who does no wrong."},{"k":"buddharakkhita","t":"If on the hand there is no wound, one may carry even poison in it. Poison does not affect one who is free from wounds. For him who does no evil, there is no ill."},{"k":"thanissaro","t":"If there's no wound on the hand,\nthat hand can hold poison.\nPoison won't penetrate\nwhere there's no wound.\nThere's no evil\nfor those who don't do it."},{"k":"suddhaso","t":"If a hand is unwounded\nthen it can take away poison;\npoison cannot affect one who has no wound.\nNo evil comes to one who does none."},{"k":"sujato","t":"You can carry poison in your hand\nif it has no wound,\nfor poison does not infect without a wound;\nnothing bad happens unless you do bad."}]},{"n":125,"vg":9,"pali":"Yo appaduṭṭhassa narassa dussati,\nSuddhassa posassa anaṅgaṇassa;\nTameva bālaṁ pacceti pāpaṁ,\nSukhumo rajo paṭivātaṁva khitto.","v":[{"k":"muller","t":"If a man offend a harmless, pure, and innocent person, the evil falls back upon that fool, like light dust thrown up against the wind."},{"k":"wagiswara","t":"Who on a harmless creature worketh pain,\nIn whom no fault, in whom no ill is found,\nUpon that fool his evil deeds rebound\nAs fine dust cast i' the wind falls back again."},{"k":"kaviratna","t":"Whoever offends an innocent, pure and faultless person, the evil (of his act) rebounds on that fool, even as fine dust thrown against the wind."},{"k":"buddharakkhita","t":"Like fine dust thrown against the wind, evil falls back upon that fool who offends an inoffensive, pure and guiltless man."},{"k":"thanissaro","t":"Whoever harasses\nan innocent man,\na man pure, without blemish:\nthe evil comes right back to the fool\nlike fine dust\nthrown against the wind."},{"k":"suddhaso","t":"If one abuses\na faultless, pure, and flawless person,\nthen evil will come back to that fool,\nlike fine dust thrown against the wind."},{"k":"sujato","t":"Whoever wrongs a man who has done no wrong,\na pure man who has not a blemish,\nthe evil backfires on the fool,\nlike fine dust thrown upwind."}]},{"n":126,"vg":9,"pali":"Gabbhameke uppajjanti,\nnirayaṁ pāpakammino;\nSaggaṁ sugatino yanti,\nparinibbanti anāsavā.","v":[{"k":"muller","t":"Some people are born again; evil-doers go to hell; righteous people go to heaven; those who are free from all worldly desires attain Nirvana."},{"k":"wagiswara","t":"Some men by birth a life on earth attain;\nThe wicked go to hell, the good to heaven;\nBut holy saints are never born again."},{"k":"kaviratna","t":"(After death), some are reborn in the womb; evildoers are born in hell; those who commit meritorious deeds go to heaven; and those who are free from worldly desires realize nirvana."},{"k":"buddharakkhita","t":"Some are born in the womb; the wicked are born in hell; the devout go to heaven; the stainless pass into Nibbana."},{"k":"thanissaro","t":"Some are born in the human womb,\nevildoers in hell,\nthose on the good course go\n\nto heaven,\nwhile those without effluent:\n\ntotally unbound."},{"k":"suddhaso","t":"Some people arise in wombs;\nevildoers, in hell;\nthose on the right course go to heaven;\nthe uncorrupted attain Nibbāna."},{"k":"sujato","t":"Some are born in a womb;\nevildoers go to hell;\nthe virtuous go to heaven;\nthe undefiled are fully extinguished."}]},{"n":127,"vg":9,"pali":"Na antalikkhe na samuddamajjhe,\nNa pabbatānaṁ vivaraṁ pavissa;\nNa vijjatī so jagatippadeso,\nYatthaṭṭhito mucceyya pāpakammā.","v":[{"k":"muller","t":"Not in the sky, not in the midst of the sea, not if we enter into the clefts of the mountains, is there known a spot in the whole world where a man might be freed from an evil deed."},{"k":"wagiswara","t":"Not in the air nor middle of the sea,\nNor entering a mountain cave to hide,\nNor anywhere on earth can'st thou abide\nWhere from thy ill deeds thou can'st set thee free."},{"k":"kaviratna","t":"Not in the sky, not in the middle of the ocean, not even in the cave of a mountain, should one seek refuge, for there exists no place in the world where one can escape the effects of wrongdoing."},{"k":"buddharakkhita","t":"Neither in the sky nor in mid-ocean, nor by entering into mountain clefts, nowhere in the world is there a place where one may escape from the results of evil deeds."},{"k":"thanissaro","t":"Not up in the air,\nnor in the middle of the sea,\nnor going into a cleft in the mountains\n— nowhere on earth —\nis a spot to be found\nwhere you could stay & escape\nyour evil deed."},{"k":"suddhaso","t":"Not by going into the sky, or into the ocean,\nor into a mountain cleft,\nor anywhere in the world,\ncan one find a place where one is free from one's evil deeds."},{"k":"sujato","t":"Not in midair, nor mid-ocean,\nnor hiding in a mountain cleft;\nyou'll find no place on the planet\nto escape your wicked deeds."}]},{"n":128,"vg":9,"pali":"Na antalikkhe na samuddamajjhe,\nNa pabbatānaṁ vivaraṁ pavissa;\nNa vijjatī so jagatippadeso,\nYatthaṭṭhitaṁ nappasaheyya maccu.\nPāpavaggo navamo.","v":[{"k":"muller","t":"Not in the sky, not in the midst of the sea, not if we enter into the clefts of the mountains, is there known a spot in the whole world where death could not overcome (the mortal)."},{"k":"wagiswara","t":"Not in the air nor middle of the sea,\nNor entering a mountain cave to hide,\nNor anywhere on earth can'st thou abide\nWhere death shall not pursue and conquer thee."},{"k":"kaviratna","t":"Not in the sky, not in the middle of the ocean, not even in the cave of a mountain, should one seek refuge, for there exists no place in the world where one will not be overpowered by death."},{"k":"buddharakkhita","t":"Neither in the sky nor in mid-ocean, nor by entering into mountain clefts, nowhere in the world is there a place where one will not be overcome by death."},{"k":"thanissaro","t":"Not up in the air,\nnor in the middle of the sea,\nnor going into a cleft in the mountains\n— nowhere on earth —\nis a spot to be found\nwhere you could stay & not succumb\nto death."},{"k":"suddhaso","t":"Not by going into the sky, or into the ocean,\nor into a mountain cleft,\nor anywhere in the world,\ncan one find a place where one is not caught by death."},{"k":"sujato","t":"Not in midair, nor mid-ocean,\nnor hiding in a mountain cleft;\nyou'll find no place on the planet\nwhere you won't be vanquished by death."}]},{"n":129,"vg":10,"pali":"Sabbe tasanti daṇḍassa,\nsabbe bhāyanti maccuno;\nAttānaṁ upamaṁ katvā,\nna haneyya na ghātaye.","v":[{"k":"muller","t":"All men tremble at punishment, all men fear death; remember that you are like unto them, and do not kill, nor cause slaughter."},{"k":"wagiswara","t":"All beings fear the rod, all fear to die;\nRegard them as thyself; strike not nor slay."},{"k":"kaviratna","t":"All tremble before the rod of punishment; all fear death; likening others to oneself, one should neither slay nor cause to slay."},{"k":"buddharakkhita","t":"All tremble at violence; all fear death. Putting oneself in the place of another, one should not kill nor cause another to kill."},{"k":"thanissaro","t":"All\ntremble at the rod,\nall\nare fearful of death.\nDrawing the parallel to\nyourself,\nneither kill nor get others to kill."},{"k":"suddhaso","t":"Everyone dreads violence,\neveryone fears death;\nrecognizing that you are similar,\ndo not harm or cause others to harm."},{"k":"sujato","t":"All tremble at the rod,\nall fear death.\nTreating others like oneself,\nneither kill nor incite to kill."}]},{"n":130,"vg":10,"pali":"Sabbe tasanti daṇḍassa,\nsabbesaṁ jīvitaṁ piyaṁ;\nAttānaṁ upamaṁ katvā,\nna haneyya na ghātaye.","v":[{"k":"muller","t":"All men tremble at punishment, all men love life; remember that thou art like unto them, and do not kill, nor cause slaughter."},{"k":"wagiswara","t":"All beings fear the rod; all love their life;\nRegard them as thyself; strike not nor slay."},{"k":"kaviratna","t":"All tremble before the rod of punishment; for all life is dear; likening others to oneself, one should neither slay nor cause to slay."},{"k":"buddharakkhita","t":"All tremble at violence; life is dear to all. Putting oneself in the place of another, one should not kill nor cause another to kill."},{"k":"thanissaro","t":"All\ntremble at the rod,\nall\nhold their life dear.\nDrawing the parallel to\nyourself,\nneither kill nor get others to kill."},{"k":"suddhaso","t":"Everyone dreads violence,\neveryone likes to live;\nrecognizing that you are similar,\ndo not harm or cause others to harm."},{"k":"sujato","t":"All tremble at the rod,\nall love life.\nTreating others like oneself,\nneither kill nor incite to kill."}]},{"n":131,"vg":10,"pali":"Sukhakāmāni bhūtāni,\nyo daṇḍena vihiṁsati;\nAttano sukhamesāno,\npecca so na labhate sukhaṁ.","v":[{"k":"muller","t":"He who seeking his own happiness punishes or kills beings who also long for happiness, will not find happiness after death."},{"k":"wagiswara","t":"Whoso treats pleasure-loving creatures ill,\nWhen he seeks bliss for self he shall not find it."},{"k":"kaviratna","t":"He who, desirous of happiness for himself, torments with a rod others who are likewise seeking enjoyment, shall not obtain happiness in the hereafter."},{"k":"buddharakkhita","t":"One who, while himself seeking happiness, oppresses with violence other beings who also desire happiness, will not attain happiness hereafter."},{"k":"thanissaro","t":"Whoever takes a rod\nto harm living beings desiring ease,\nwhen he himself is looking for ease,\nwill meet with no ease after death."},{"k":"suddhaso","t":"Beings want pleasure;\nif one harms them with violence\nwhile seeking pleasure for oneself,\none will find no pleasure in the future."},{"k":"sujato","t":"Creatures love happiness,\nso if you harm them with a stick\nin search of your own happiness,\nafter death you won't find happiness."}]},{"n":132,"vg":10,"pali":"Sukhakāmāni bhūtāni,\nyo daṇḍena na hiṁsati;\nAttano sukhamesāno,\npecca so labhate sukhaṁ.","v":[{"k":"muller","t":"He who seeking his own happiness does not punish or kill beings who also long for happiness, will find happiness after death."},{"k":"wagiswara","t":"Whoso treats pleasure-loving creatures well,\nWhen he seeks happiness for self shall find it."},{"k":"kaviratna","t":"He who, desirous of happiness for himself, does not torment others who likewise long for happiness, shall obtain happiness in the hereafter."},{"k":"buddharakkhita","t":"One who, while himself seeking happiness, does not oppress with violence other beings who also desire happiness, will find happiness hereafter."},{"k":"thanissaro","t":"Whoever doesn't take a rod\nto harm living beings desiring ease,\nwhen he himself is looking for ease,\nwill meet with ease after death."},{"k":"suddhaso","t":"Beings want pleasure;\nif one does not harm them with violence\nwhile seeking pleasure for oneself,\none will find pleasure in the future."},{"k":"sujato","t":"Creatures love happiness,\nso if you don't harm them with a stick\nin search of your own happiness,\nafter death you will find happiness."}]},{"n":133,"vg":10,"pali":"Māvoca pharusaṁ kañci,\nvuttā paṭivadeyyu taṁ;\nDukkhā hi sārambhakathā,\npaṭidaṇḍā phuseyyu taṁ.","v":[{"k":"muller","t":"Do not speak harshly to anybody; those who are spoken to will answer thee in the same way. Angry speech is painful, blows for blows will touch thee."},{"k":"wagiswara","t":"Use not harsh speech; when harshly spoken to\nMen may retort; painful are quarrellings,\nAnd punishment may follow thy harsh words."},{"k":"kaviratna","t":"Do not speak harshly to anyone; those thus spoken to will retaliate in kind; discordant indeed will be the response, and soon retribution will overtake you."},{"k":"buddharakkhita","t":"Speak not harshly to anyone, for those thus spoken to might retort. Indeed, angry speech hurts, and retaliation may overtake you."},{"k":"thanissaro","t":"Speak harshly to no one,\nor the words will be thrown\nright back at you.\nContentious talk is painful,\nfor you get struck by rods in return."},{"k":"suddhaso","t":"Say no harsh words to anyone;\nthey might respond in kind.\nHostile speech is painful,\nand it may provoke a violent response."},{"k":"sujato","t":"Don't speak harshly,\nthey may speak harshly back.\nFor aggressive speech is painful,\nand the rod may spring back on you."}]},{"n":134,"vg":10,"pali":"Sace neresi attānaṁ,\nkaṁso upahato yathā;\nEsa pattosi nibbānaṁ,\nsārambho te na vijjati.","v":[{"k":"muller","t":"If, like a shattered metal plate (gong), thou utter not, then thou hast reached Nirvana; contention is not known to thee."},{"k":"wagiswara","t":"If thou can'st keep thy tongue from wagging oft,\nSilent as some cracked gong, thou hast thereby\nNibbāna won; no brawling is in thee."},{"k":"kaviratna","t":"If you can make yourself as silent as a shattered bronze gong, then you have attained to the peace of nirvana, for now there is no discord in you."},{"k":"buddharakkhita","t":"If, like a broken gong, you silence yourself, you have approached Nibbana, for vindictiveness is no longer in you."},{"k":"thanissaro","t":"If, like a flattened metal pot\nyou don't resound,\nyou've attained an Unbinding;\nin you there's found\nno contention."},{"k":"suddhaso","t":"If you are non-reactive,\nlike a broken bell,\nthen you have reached Nibbāna\nand no conflict can be found in you."},{"k":"sujato","t":"If you still yourself\nlike a broken gong,\nyou reach extinguishment\nand know no conflict."}]},{"n":135,"vg":10,"pali":"Yathā daṇḍena gopālo,\ngāvo pājeti gocaraṁ;\nEvaṁ jarā ca maccu ca,\nāyuṁ pājenti pāṇinaṁ.","v":[{"k":"muller","t":"As a cowherd with his staff drives his cows into the stable, so do Age and Death drive the life of men."},{"k":"wagiswara","t":"As with a stick the herdsman drives his kine,\nSo death and age compel the lives of men."},{"k":"kaviratna","t":"As a cowherd with his rod drives cattle to the pasture, so do old age and death drive the lives of sentient beings."},{"k":"buddharakkhita","t":"Just as a cowherd drives the cattle to pasture with a staff, so do old age and death drive the life force of beings (from existence to existence)."},{"k":"thanissaro","t":"As a cowherd with a rod\ndrives cows to the field,\nso aging & death\ndrive the life\nof living beings."},{"k":"suddhaso","t":"Just as a cowherd, using a stick,\nherds cattle through a pasture,\nin the same way, decrepitude and death\nherd the living through life."},{"k":"sujato","t":"As a cowherd drives the cows\nto pasture with the rod,\nso too old age and death\ndrive life from living beings."}]},{"n":136,"vg":10,"pali":"Atha pāpāni kammāni,\nkaraṁ bālo na bujjhati;\nSehi kammehi dummedho,\naggidaḍḍhova tappati.","v":[{"k":"muller","t":"A fool does not know when he commits his evil deeds: but the wicked man burns by his own deeds, as if burnt by fire."},{"k":"wagiswara","t":"The fool in doing ill knows not his folly;\nHis own deeds, like a fire, the fool consume."},{"k":"kaviratna","t":"When a person ignorant (of the Dhamma) commits evil deeds, he does not realize their nature. The stupid man burns (suffers) through these deeds as if consumed by fire."},{"k":"buddharakkhita","t":"When the fool commits evil deeds, he does not realize (their evil nature). The witless man is tormented by his own deeds, like one burnt by fire."},{"k":"thanissaro","t":"When doing evil deeds,\nthe fool is oblivious.\nThe dullard\nis tormented\nby his own deeds,\nas if burned by a fire."},{"k":"suddhaso","t":"Performing evil actions,\na fool does not attain awakening.\nThe unwise person is tormented by those actions\nas if burned by fire."},{"k":"sujato","t":"The fool does not understand\nthe evil that they do.\nBut because of those deeds, that simpleton\nis tormented as if burnt by fire."}]},{"n":137,"vg":10,"pali":"Yo daṇḍena adaṇḍesu,\nappaduṭṭhesu dussati;\nDasannamaññataraṁ ṭhānaṁ,\nkhippameva nigacchati.","v":[{"k":"muller","t":"He who inflicts pain on innocent and harmless persons, will soon come to one of these ten states:"},{"k":"wagiswara","t":"He who offends the harmless innocent\nSoon reaches one of these ten states of woe;"},{"k":"kaviratna","t":"He who inflicts punishment upon those who do not deserve it, and hurts those who are harmless, such a person will soon come to face one of these ten states:"},{"k":"buddharakkhita","t":"He who inflicts violence on those who are unarmed, and offends those who are inoffensive, will soon come upon one of these ten states:"},{"k":"thanissaro","t":"Whoever, with a rod,\nharasses an innocent man, unarmed,\nquickly falls into any of ten things:\n\nharsh pains, devastation, a broken body, grave illness,\nmental derangement, trouble with the government,\nviolent slander, relatives lost, property dissolved,\nhouses burned down.\n\nAt the break-up of the body\nthis one with no discernment,\nreappears in\nhell."},{"k":"suddhaso","t":"One who is violent towards the nonviolent,\none who harms the harmless,\nwill soon experience\none of ten consequences:"},{"k":"sujato","t":"One who violently attacks\nthe peaceful and the innocent\nswiftly falls\nto one of ten bad states:"}]},{"n":138,"vg":10,"pali":"Vedanaṁ pharusaṁ jāniṁ,\nsarīrassa va bhedanaṁ;\nGarukaṁ vāpi ābādhaṁ,\ncittakkhepaṁ va pāpuṇe.","v":[{"k":"muller","t":"He will have cruel suffering, loss, injury of the body, heavy affliction, or loss of mind,"},{"k":"wagiswara","t":"Sharp pain, disease, or bodily decay,\nGrievous disaster, or a mind distraught;"},{"k":"kaviratna","t":"He may soon come to terrible pain, great deprivations, physical injury, deep-rooted ailment or mental disorder, the wrath of the monarch or a dreadful accusation, loss of relatives, the complete destruction of wealth, or a sudden fire may break out and burn his houses. After the dissolution of his physical body, he will surely be born in hell."},{"k":"buddharakkhita","t":"Sharp pain, or disaster, bodily injury, serious illness, or derangement of mind, trouble from the government, or grave charges, loss of relatives, or loss of wealth, or houses destroyed by ravaging fire; upon dissolution of the body that ignorant man is born in hell."},{"k":"thanissaro","t":"Whoever, with a rod,\nharasses an innocent man, unarmed,\nquickly falls into any of ten things:\n\nharsh pains, devastation, a broken body, grave illness,\nmental derangement, trouble with the government,\nviolent slander, relatives lost, property dissolved,\nhouses burned down.\n\nAt the break-up of the body\nthis one with no discernment,\nreappears in\nhell."},{"k":"suddhaso","t":"Harsh sensations, deprivation,\nphysical injury,\nsevere illness,\nmental derangement,"},{"k":"sujato","t":"harsh pain; loss;\nthe breakup of the body;\nserious illness;\nmental distress;"}]},{"n":139,"vg":10,"pali":"Rājato vā upasaggaṁ,\nAbbhakkhānaṁ va dāruṇaṁ;\nParikkhayaṁ va ñātīnaṁ,\nBhogānaṁ va pabhaṅguraṁ.","v":[{"k":"muller","t":"Or a misfortune coming from the king, or a fearful accusation, or loss of relations, or destruction of treasures,"},{"k":"wagiswara","t":"Oppression by the king, or calumny,\nLoss of relations, loss of all his wealth,"},{"k":"kaviratna","t":"He may soon come to terrible pain, great deprivations, physical injury, deep-rooted ailment or mental disorder, the wrath of the monarch or a dreadful accusation, loss of relatives, the complete destruction of wealth, or a sudden fire may break out and burn his houses. After the dissolution of his physical body, he will surely be born in hell."},{"k":"buddharakkhita","t":"Sharp pain, or disaster, bodily injury, serious illness, or derangement of mind, trouble from the government, or grave charges, loss of relatives, or loss of wealth, or houses destroyed by ravaging fire; upon dissolution of the body that ignorant man is born in hell."},{"k":"thanissaro","t":"Whoever, with a rod,\nharasses an innocent man, unarmed,\nquickly falls into any of ten things:\n\nharsh pains, devastation, a broken body, grave illness,\nmental derangement, trouble with the government,\nviolent slander, relatives lost, property dissolved,\nhouses burned down.\n\nAt the break-up of the body\nthis one with no discernment,\nreappears in\nhell."},{"k":"suddhaso","t":"legal trouble,\nsevere accusations,\nloss of relatives,\ndissipation of wealth,"},{"k":"sujato","t":"hazards from rulers;\nvicious slander;\nloss of kin;\ndestruction of wealth;"}]},{"n":140,"vg":10,"pali":"Atha vāssa agārāni,\naggi ḍahati pāvako;\nKāyassa bhedā duppañño,\nnirayaṁ sopapajjati.","v":[{"k":"muller","t":"Or lightning-fire will burn his houses; and when his body is destroyed, the fool will go to hell."},{"k":"wagiswara","t":"His house burned by a thunderbolt or fire;\nAt death, poor fool, he finds rebirth in hell."},{"k":"kaviratna","t":"He may soon come to terrible pain, great deprivations, physical injury, deep-rooted ailment or mental disorder, the wrath of the monarch or a dreadful accusation, loss of relatives, the complete destruction of wealth, or a sudden fire may break out and burn his houses. After the dissolution of his physical body, he will surely be born in hell."},{"k":"buddharakkhita","t":"Sharp pain, or disaster, bodily injury, serious illness, or derangement of mind, trouble from the government, or grave charges, loss of relatives, or loss of wealth, or houses destroyed by ravaging fire; upon dissolution of the body that ignorant man is born in hell."},{"k":"thanissaro","t":"Whoever, with a rod,\nharasses an innocent man, unarmed,\nquickly falls into any of ten things:\n\nharsh pains, devastation, a broken body, grave illness,\nmental derangement, trouble with the government,\nviolent slander, relatives lost, property dissolved,\nhouses burned down.\n\nAt the break-up of the body\nthis one with no discernment,\nreappears in\nhell."},{"k":"suddhaso","t":"or their house\ncatching on fire.\nThen, when the fool is separated from their body,\nthey will reappear in hell."},{"k":"sujato","t":"or else their home\nis consumed by fire.\nWhen their body breaks up, that witless person\nis reborn in hell."}]},{"n":141,"vg":10,"pali":"Na naggacariyā na jaṭā na paṅkā,\nNānāsakā thaṇḍilasāyikā vā;\nRajojallaṁ ukkuṭikappadhānaṁ,\nSodhenti maccaṁ avitiṇṇakaṅkhaṁ.","v":[{"k":"muller","t":"Not nakedness, not platted hair, not dirt, not fasting, or lying on the earth, not rubbing with dust, not sitting motionless, can purify a mortal who has not overcome desires."},{"k":"wagiswara","t":"Not nakedness, nor matted hair nor filth,\nNot fasting long, nor lying on the ground,\nNot dust and dirt, nor squatting on the heels.\nCan cleanse the mortal that is full of doubt."},{"k":"kaviratna","t":"Neither nakedness, nor matted locks; neither applying mud (all over the body), nor fasting, nor lying on the bare earth; neither besmearing oneself with soot, nor squatting on one's heels, can purify a man who has not got rid of his doubts."},{"k":"buddharakkhita","t":"Neither going about naked, nor matted locks, nor filth, nor fasting, nor lying on the ground, nor smearing oneself with ashes and dust, nor sitting on the heels (in penance) can purify a mortal who has not overcome doubt."},{"k":"thanissaro","t":"Neither nakedness nor matted hair\nnor mud nor the refusal of food\nnor sleeping on the bare ground\nnor dust & dirt nor squatting austerities\ncleanses the mortal\nwho's not gone beyond doubt.\n\nIf, though adorned, one lives in tune\nwith the chaste life\n— calmed, tamed, & assured —\nhaving put down the rod toward all beings,\nhe's a contemplative\na brahman\na monk."},{"k":"suddhaso","t":"Nudity, tangled hair, filth,\nfasting, sleeping on the ground,\nsquatting in the mud -\nthese cannot purify a mortal who has not yet gone beyond doubt."},{"k":"sujato","t":"Not nudity, nor matted hair, nor mud,\nnor fasting, nor lying on bare ground,\nnor wearing dust and dirt, or squatting on the heels,\nwill cleanse a mortal not free of doubt."}]},{"n":142,"vg":10,"pali":"Alaṅkato cepi samaṁ careyya,\nSanto danto niyato brahmacārī;\nSabbesu bhūtesu nidhāya daṇḍaṁ,\nSo brāhmaṇo so samaṇo sa bhikkhu.","v":[{"k":"muller","t":"He who, though dressed in fine apparel, exercises tranquillity, is quiet, subdued, restrained, chaste, and has ceased to find fault with all other beings, he indeed is a Brahmana, an ascetic (sramana), a friar (bhikshu)."},{"k":"wagiswara","t":"But one that lives a calm and tranquil life,\nThough gaily decked, if tamed, restrained, he live\nWalking the holy path in righteousness,\nLaying aside all harm to living things,\nTrue mendicant, ascetic, Brāhmin he!"},{"k":"kaviratna","t":"Even though a person be dressed in fine clothes, if he develops tranquillity, is quiet, self-disciplined, resolute and practices celibacy, and abstains from injuring all other beings, he is indeed a Brahman, an ascetic and a monk."},{"k":"buddharakkhita","t":"Even though he be well-attired, yet if he is poised, calm, controlled and established in the holy life, having set aside violence towards all beings — he, truly, is a holy man, a renunciate, a monk."},{"k":"thanissaro","t":"Neither nakedness nor matted hair\nnor mud nor the refusal of food\nnor sleeping on the bare ground\nnor dust & dirt nor squatting austerities\ncleanses the mortal\nwho's not gone beyond doubt.\n\nIf, though adorned, one lives in tune\nwith the chaste life\n— calmed, tamed, & assured —\nhaving put down the rod toward all beings,\nhe's a contemplative\na brahman\na monk."},{"k":"suddhaso","t":"However, if one who wears adornments is well-behaved,\npeaceful, restrained, committed to spiritual practice,\nand has renounced violence towards all beings,\nthen they are a saint, a contemplative, a monk."},{"k":"sujato","t":"Dressed up they may be, but if they live well—\npeaceful, tamed, committed to the spiritual path,\nhaving laid aside violence towards all creatures—\nthey are a brahmin, an ascetic, a mendicant."}]},{"n":143,"vg":10,"pali":"Hirīnisedho puriso,\nkoci lokasmi vijjati;\nYo niddaṁ apabodheti,\nasso bhadro kasāmiva.","v":[{"k":"muller","t":"Is there in this world any man so restrained by humility that he does not mind reproof, as a well-trained horse the whip?"},{"k":"wagiswara","t":"Who in this world is so restrained by shame\nThat, like a thoroughbred flicked by the whip.\nHe can think lightly of the lash of blame?"},{"k":"kaviratna","t":"Is there any man in this world so self-restrained through modesty that he avoids censure as a self-respecting horse avoids the whip?"},{"k":"buddharakkhita","t":"Only rarely is there a man in this world who, restrained by modesty, avoids reproach, as a thoroughbred horse avoids the whip."},{"k":"thanissaro","t":"Who in the world\nis a man constrained by conscience,\nwho awakens to censure\nlike a fine stallion to the whip?"},{"k":"suddhaso","t":"What person can be found in this world\nthat is restrained by conscience?\nWho wakes up when criticized,\nlike a fine horse struck by a whip?"},{"k":"sujato","t":"Can a person constrained by conscience\nbe found in the world?\nWho shies away from blame,\nlike a fine horse from the whip?"}]},{"n":144,"vg":10,"pali":"Asso yathā bhadro kasāniviṭṭho,\nĀtāpino saṁvegino bhavātha;\nSaddhāya sīlena ca vīriyena ca,\nSamādhinā dhammavinicchayena ca;\nSampannavijjācaraṇā patissatā,\nJahissatha dukkhamidaṁ anappakaṁ.","v":[{"k":"muller","t":"Like a well-trained horse when touched by the whip, be ye active and lively, and by faith, by virtue, by energy, by meditation, by discernment of the law you will overcome this great pain (of reproof), perfect in knowledge and in behaviour, and never forgetful."},{"k":"wagiswara","t":"By faith and virtue, energy, and mind\nIn perfect balance, searching of the Norm,\nPerfect in knowledge and good practices,\nPerfect in concentration of your thoughts,\nYe shall strike off this multitude of woes."},{"k":"kaviratna","t":"As a well-trained horse when touched by the whip, even so be you strenuous and eager. By devotion, virtue, effort, concentration, and by the critical investigation of truth (dhamma) may you abandon this great suffering (of samsara), perfect in wisdom, conduct and awareness."},{"k":"buddharakkhita","t":"Like a thoroughbred horse touched by the whip, be strenuous, be filled with spiritual yearning. By faith and moral purity, by effort and meditation, by investigation of the truth, by being rich in knowledge and virtue, and by being mindful, destroy this unlimited suffering."},{"k":"thanissaro","t":"Like a fine stallion\nstruck with a whip,\nbe ardent & chastened.\nThrough conviction\nvirtue, persistence,\nconcentration, judgment,\nconsummate in knowledge & conduct,\nmindful,\nyou'll abandon this not-insignificant pain."},{"k":"suddhaso","t":"Like a fine horse struck by a whip,\nbe ardent and filled with urgency.\nBy means of faith, virtue, determination,\nconcentration, investigation of Dhamma,\nperfect knowledge, perfect conduct, and thorough awareness,\nabandon this immense suffering."},{"k":"sujato","t":"Like a fine horse under the whip,\nbe keen and full of urgency.\nWith faith, ethics, and energy,\nimmersion, and investigation of principles,\naccomplished in knowledge and conduct, mindful,\ngive up this vast suffering."}]},{"n":145,"vg":10,"pali":"Udakañhi nayanti nettikā,\nUsukārā namayanti tejanaṁ;\nDāruṁ namayanti tacchakā,\nAttānaṁ damayanti subbatā.\nDaṇḍavaggo dasamo.","v":[{"k":"muller","t":"Well-makers lead the water (wherever they like); fletchers bend the arrow; carpenters bend a log of wood; good people fashion themselves."},{"k":"wagiswara","t":"As cultivators guide the water-course,\nAs fletchers straighten out the arrow-shaft,\nAs carpenters warp timber to their needs,\nSo righteous men subdue and train themselves."},{"k":"kaviratna","t":"Irrigators conduct water wherever they wish; fletchers shape the shafts; carpenters work the wood, and wise men discipline themselves."},{"k":"buddharakkhita","t":"Irrigators regulate the waters, fletchers straighten arrow shafts, carpenters shape wood, and the good control themselves."},{"k":"thanissaro","t":"Irrigators guide the water.\nFletchers shape the arrow shaft.\nCarpenters shape the wood.\nThose of good practices control\nthemselves."},{"k":"suddhaso","t":"Irrigators guide water,\nfletchers shape arrows,\ncarpenters shape wood,\nthose who practice well train themselves."},{"k":"sujato","t":"While irrigators guide water,\nfletchers shape arrows,\nand carpenters carve timber—\nthose true to their vows tame themselves."}]},{"n":146,"vg":11,"pali":"Ko nu hāso kimānando,\nniccaṁ pajjalite sati;\nAndhakārena onaddhā,\npadīpaṁ na gavesatha.","v":[{"k":"muller","t":"How is there laughter, how is there joy, as this world is always burning? Why do you not seek a light, ye who are surrounded by darkness?"},{"k":"wagiswara","t":"Laugh ye, rejoice ye, when this world is burning?\nO wrapped in darkness, will ye not seek light?"},{"k":"kaviratna","t":"Why laugh, why be jubilant, when all is constantly burning (with desires)? Should you not seek the light of wisdom when you are enveloped by the darkness of ignorance?"},{"k":"buddharakkhita","t":"When this world is ever ablaze, why this laughter, why this jubilation? Shrouded in darkness, will you not see the light?"},{"k":"thanissaro","t":"What laughter, why joy,\nwhen constantly aflame?\nEnveloped in darkness,\ndon't you look for a lamp?"},{"k":"suddhaso","t":"Who can laugh, who can delight,\nsince this is always on fire?\nObscured by darkness,\nyou do not search for light."},{"k":"sujato","t":"What is joy, what is laughter,\nwhen the flames are ever burning?\nSwathed in darkness,\nwould you not seek a light?"}]},{"n":147,"vg":11,"pali":"Passa cittakataṁ bimbaṁ,\narukāyaṁ samussitaṁ;\nĀturaṁ bahusaṅkappaṁ,\nyassa natthi dhuvaṁ ṭhiti.","v":[{"k":"muller","t":"Look at this dressed-up lump, covered with wounds, joined together, sickly, full of many thoughts, which has no strength, no hold!"},{"k":"wagiswara","t":"Behold this body decked, a mass of sores,\nSickly and swayed by multitudinous thoughts.\nImpermanent, unstable, uncomposed!"},{"k":"kaviratna","t":"Behold this illusory human image, embellished (by rich attire and jewels), full of corruptions, a structure of bones, liable to constant illness, full of countless hankerings, in which there is nothing permanent or stable."},{"k":"buddharakkhita","t":"Behold this body — a painted image, a mass of heaped up sores, infirm, full of hankering — of which nothing is lasting or stable!"},{"k":"thanissaro","t":"Look at the beautified image,\na heap of festering wounds, shored up:\nill, but the object\nof many resolves,\nwhere there is nothing\nlasting or sure."},{"k":"suddhaso","t":"See that the mind has been made a puppet,\ndamaged with arrogance,\nafflicted with excessive thought,\nlacking stability and composure."},{"k":"sujato","t":"See this fancy puppet,\na body built of sores,\ndiseased, obsessed over,\nin which nothing lasts at all."}]},{"n":148,"vg":11,"pali":"Parijiṇṇamidaṁ rūpaṁ,\nroganīḷaṁ pabhaṅguraṁ;\nBhijjati pūtisandeho,\nmaraṇantañhi jīvitaṁ.","v":[{"k":"muller","t":"This body is wasted, full of sickness, and frail; this heap of corruption breaks to pieces, life indeed ends in death."},{"k":"wagiswara","t":"Poor worn-out carcase, home of sicknesses,\nFragile, corrupting mass, mere life in death!"},{"k":"kaviratna","t":"This frail form is a nest of diseases. It is fragile and putrid. It disintegrates and death is the end of life."},{"k":"buddharakkhita","t":"Fully worn out is this body, a nest of disease, and fragile. This foul mass breaks up, for death is the end of life."},{"k":"thanissaro","t":"Worn out is this body,\na nest of diseases, dissolving.\nThis putrid conglomeration\nis bound to break up,\nfor life is hemmed in with death."},{"k":"suddhaso","t":"This body is decrepit,\nfragile, a nest of disease,\na putrid heap that falls apart,\nsince life ends in death."},{"k":"sujato","t":"This body is decrepit and frail,\na nest of disease.\nThis foul carcass falls apart,\nfor life ends in death."}]},{"n":149,"vg":11,"pali":"Yānimāni apatthāni,\nalābūneva sārade;\nKāpotakāni aṭṭhīni,\ntāni disvāna kā rati.","v":[{"k":"muller","t":"Those white bones, like gourds thrown away in the autumn, what pleasure is there in looking at them?"},{"k":"wagiswara","t":"What joy to look upon these bleached bones,\nLike useless gourds in autumn thrown aside!--"},{"k":"kaviratna","t":"These dove-grey bones are like unto the gourds thrown away in the autumnal season. What pleasure is there in looking at them?"},{"k":"buddharakkhita","t":"These dove-colored bones are like gourds that lie scattered about in autumn. Having seen them, how can one seek delight?"},{"k":"thanissaro","t":"On seeing these bones\ndiscarded\nlike gourds in the fall,\npigeon-gray:\nwhat delight?"},{"k":"suddhaso","t":"Set aside\nlike gourds in autumn -\nwhen seeing these faded bones,\nwhat appreciation can there be?"},{"k":"sujato","t":"These dove-grey bones\nare tossed away like\ndried gourds in the autumn—\nwhat joy is there in such a sight?"}]},{"n":150,"vg":11,"pali":"Aṭṭhīnaṁ nagaraṁ kataṁ,\nmaṁsalohitalepanaṁ;\nYattha jarā ca maccu ca,\nmāno makkho ca ohito.","v":[{"k":"muller","t":"After a stronghold has been made of the bones, it is covered with flesh and blood, and there dwell in it old age and death, pride and deceit."},{"k":"wagiswara","t":"A township built of bones and plastered o'er\nWith flesh and blood, the home and dwelling-place\nOf age and death, pride and hypocrisy!"},{"k":"kaviratna","t":"Here is a citadel built of bones, plastered with flesh and blood, wherein are concealed decay, death, vanity and deceit."},{"k":"buddharakkhita","t":"This city (body) is built of bones, plastered with flesh and blood; within are decay and death, pride and jealousy."},{"k":"thanissaro","t":"A city made of bones,\nplastered over with flesh & blood,\nwhose hidden treasures are:\npride & contempt,\naging & death."},{"k":"suddhaso","t":"Like a city made of bones,\nwrapped in meat and blood,\na place of decay and death,\nconceit and contempt."},{"k":"sujato","t":"In this city built of bones,\nplastered with flesh and blood,\nold age and death are stashed away,\nalong with conceit and contempt."}]},{"n":151,"vg":11,"pali":"Jīranti ve rājarathā sucittā,\nAtho sarīrampi jaraṁ upeti;\nSatañca dhammo na jaraṁ upeti,\nSanto have sabbhi pavedayanti.","v":[{"k":"muller","t":"The brilliant chariots of kings are destroyed, the body also approaches destruction, but the virtue of good people never approaches destruction,--thus do the good say to the good."},{"k":"wagiswara","t":"Just as a royal chariot gaily decked\nFalls to decay, so grows this body old;\nBut Truth and Norm old age cannot assail,\nThe holy ones indeed know no decay."},{"k":"kaviratna","t":"The gaily decorated royal chariots wear out. So likewise does this body. But the truth of the righteous does not wear out with age. Thus do the enlightened proclaim it to the wise."},{"k":"buddharakkhita","t":"Even gorgeous royal chariots wear out, and indeed this body too wears out. But the Dhamma of the Good does not age; thus the Good make it known to the good."},{"k":"thanissaro","t":"Even royal chariots\nwell-embellished\nget run down,\nand so does the body\nsuccumb to old age.\nBut the Dhamma of the good\ndoesn't succumb to old age:\nthe good let the civilized know."},{"k":"suddhaso","t":"Even splendid royal chariots wear out;\nso too, this body decays.\nBut the true Dhamma never decays:\nit is made known by those who are peaceful and virtuous."},{"k":"sujato","t":"Fancy chariots of kings wear out,\nand even this body gets old.\nBut the truth of the good never gets old—\nso the good proclaim to the good."}]},{"n":152,"vg":11,"pali":"Appassutāyaṁ puriso,\nbalībaddhova jīrati;\nMaṁsāni tassa vaḍḍhanti,\npaññā tassa na vaḍḍhati.","v":[{"k":"muller","t":"A man who has learnt little, grows old like an ox; his flesh grows, but his knowledge does not grow."},{"k":"wagiswara","t":"Just like an ox, the witless man grows old;\nHis flesh grows, but his wits do not increase."},{"k":"kaviratna","t":"The man of little spiritual learning grows like an ox; his flesh increases, but his wisdom does not."},{"k":"buddharakkhita","t":"The man of little learning grows old like a bull. He grows only in bulk, but, his wisdom does not grow."},{"k":"thanissaro","t":"This unlistening man\nmatures like an ox.\nHis muscles develop,\nhis discernment not."},{"k":"suddhaso","t":"A person who has learned little\nages like an ox:\ntheir muscles grow\nbut their wisdom does not."},{"k":"sujato","t":"A person of little learning\nages like an ox—\ntheir flesh grows,\nbut not their wisdom."}]},{"n":153,"vg":11,"pali":"Anekajātisaṁsāraṁ,\nsandhāvissaṁ anibbisaṁ;\nGahakāraṁ gavesanto,\ndukkhā jāti punappunaṁ.","v":[{"k":"muller","t":"Looking for the maker of this tabernacle, I shall have to run through a course of many births, so long as I do not find (him); and painful is birth again and again. But now, maker of the tabernacle, thou hast been seen; thou shalt not make up this tabernacle again. All thy rafters are broken, thy ridge-pole is sundered; the mind, approaching the Eternal (visankhara, nirvana), has attained to the extinction of all desires."},{"k":"wagiswara","t":"Thro' many a round of birth and death I ran,\nNor found the builder that I sought. Life's stream\nIs birth and death and birth, with sorrow filled.\nNow, housebuilder, thou'rt seen! No more shalt build!\nBroken are all thy rafters, split thy beam!\nAll that made up this mortal self is gone;\nMind hath slain craving; I have crossed the stream!"},{"k":"kaviratna","t":"For countless births have I passed through this cycle of births and deaths, seeking the builder of this tabernacle, but in vain. Sorrowful indeed is this cyclic repetition of births."},{"k":"buddharakkhita","t":"Through many a birth in samsara have I wandered in vain, seeking the builder of this house (of life). Repeated birth is indeed suffering!"},{"k":"thanissaro","t":"Through the round of many births I roamed\nwithout reward,\nwithout rest,\nseeking the house-builder.\nPainful is birth\nagain & again.\n\nHouse-builder, you're seen!\nYou will not build a house again.\nAll your rafters broken,\nthe ridge pole dismantled,\nimmersed in dismantling, the mind\nhas attained to the end of craving."},{"k":"suddhaso","t":"Wandering through many lives,\nseeking but not finding\nthe builder of this house -\nrepeatedly experiencing the suffering of birth."},{"k":"sujato","t":"Transmigrating through countless rebirths,\nI've journeyed without reward,\nsearching for the house-builder;\npainful is birth again and again."}]},{"n":154,"vg":11,"pali":"Gahakāraka diṭṭhosi,\npuna gehaṁ na kāhasi;\nSabbā te phāsukā bhaggā,\ngahakūṭaṁ visaṅkhataṁ;\nVisaṅkhāragataṁ cittaṁ,\ntaṇhānaṁ khayamajjhagā.","v":[{"k":"muller","t":"Looking for the maker of this tabernacle, I shall have to run through a course of many births, so long as I do not find (him); and painful is birth again and again. But now, maker of the tabernacle, thou hast been seen; thou shalt not make up this tabernacle again. All thy rafters are broken, thy ridge-pole is sundered; the mind, approaching the Eternal (visankhara, nirvana), has attained to the extinction of all desires."},{"k":"wagiswara","t":"Thro' many a round of birth and death I ran,\nNor found the builder that I sought. Life's stream\nIs birth and death and birth, with sorrow filled.\nNow, housebuilder, thou'rt seen! No more shalt build!\nBroken are all thy rafters, split thy beam!\nAll that made up this mortal self is gone;\nMind hath slain craving; I have crossed the stream!"},{"k":"kaviratna","t":"O builder of the house, I have seen you; you shall not build the house again. All the rafters are broken; the ridgepole is sundered. Mind has arrived at dissolution (nirvana), having attained the extinction of all cravings (tanha)."},{"k":"buddharakkhita","t":"O house-builder, you are seen! You will not build this house again. For your rafters are broken and your ridgepole shattered. My mind has reached the Unconditioned; I have attained the destruction of craving. [13]"},{"k":"thanissaro","t":"Through the round of many births I roamed\nwithout reward,\nwithout rest,\nseeking the house-builder.\nPainful is birth\nagain & again.\n\nHouse-builder, you're seen!\nYou will not build a house again.\nAll your rafters broken,\nthe ridge pole dismantled,\nimmersed in dismantling, the mind\nhas attained to the end of craving."},{"k":"suddhaso","t":"House-builder, you have been seen!\nYou will build no house again.\nAll your rafters are broken,\nthe roof-peak dismantled.\nThe mind has gone to the unconditioned -\nthe elimination of craving has been reached."},{"k":"sujato","t":"I've seen you, house-builder!\nYou won't build a house again!\nYour rafters are all broken,\nyour roof-peak demolished.\nThe mind, set on demolition,\nhas reached the end of cravings."}]},{"n":155,"vg":11,"pali":"Acaritvā brahmacariyaṁ,\naladdhā yobbane dhanaṁ;\nJiṇṇakoñcāva jhāyanti,\nkhīṇamaccheva pallale.","v":[{"k":"muller","t":"Men who have not observed proper discipline, and have not gained treasure in their youth, perish like old herons in a lake without fish."},{"k":"wagiswara","t":"They who in youth have never trod the way\nOf righteousness, nor garnered wisdom's store.\nLike herons in a fishless pool decay."},{"k":"kaviratna","t":"Those who do not practice self-discipline, who do not acquire wealth in their youth, when they become old, pine away, like old herons in a dried-up lake where there are no fish."},{"k":"buddharakkhita","t":"Those who in youth have not led the holy life, or have failed to acquire wealth, languish like old cranes in the pond without fish."},{"k":"thanissaro","t":"Neither living the chaste life\nnor gaining wealth in their youth,\nthey waste away like old herons\nin a dried-up lake\ndepleted of fish."},{"k":"suddhaso","t":"Those who have neither lived a spiritual life\nnor acquired wealth during their youth,\nWaste away like old herons\nby a fishless pond."},{"k":"sujato","t":"When young they spurned the spiritual path\nand failed to earn any wealth.\nNow they brood like old cranes\nin a pond bereft of fish."}]},{"n":156,"vg":11,"pali":"Acaritvā brahmacariyaṁ,\naladdhā yobbane dhanaṁ;\nSenti cāpātikhīṇāva,\npurāṇāni anutthunaṁ.\nJarāvaggo ekādasamo.","v":[{"k":"muller","t":"Men who have not observed proper discipline, and have not gained treasure in their youth, lie, like broken bows, sighing after the past."},{"k":"wagiswara","t":"They who in youth have never trod the way\nOf righteousness, nor garnered wisdom's store.\nLike broken bows, lie weeping their lost day."},{"k":"kaviratna","t":"Those who do not practice self-discipline, who do not acquire wealth in their youth, lie like broken arrows, lamenting the deeds of the past."},{"k":"buddharakkhita","t":"Those who in youth have not lead the holy life, or have failed to acquire wealth, lie sighing over the past, like worn out arrows (shot from) a bow."},{"k":"thanissaro","t":"Neither living the chaste life\nnor gaining wealth in their youth,\nthey lie around,\nmisfired from the bow,\nsighing over old times."},{"k":"suddhaso","t":"Those who have neither lived a spiritual life\nnor acquired wealth during their youth,\nlay around like wasted arrows,\nlamenting the past."},{"k":"sujato","t":"When young they spurned the spiritual path\nand failed to earn any wealth.\nNow they lie like spent arrows,\nbemoaning over things past."}]},{"n":157,"vg":12,"pali":"Attānañce piyaṁ jaññā,\nrakkheyya naṁ surakkhitaṁ;\nTiṇṇaṁ aññataraṁ yāmaṁ,\npaṭijaggeyya paṇḍito.","v":[{"k":"muller","t":"If a man hold himself dear, let him watch himself carefully; during one at least out of the three watches a wise man should be watchful."},{"k":"wagiswara","t":"Hast thou regard for self? Then keep thyself well guarded.\nBe wise and keep good watch for one of the three watches."},{"k":"kaviratna","t":"If a man esteems the self, let him guard himself with great care. Let the wise man keep vigil over himself, in one of the three watches (of life or of the night)."},{"k":"buddharakkhita","t":"If one holds oneself dear, one should diligently watch oneself. Let the wise man keep vigil during any of the three watches of the night."},{"k":"thanissaro","t":"If you hold yourself dear\nthen guard, guard yourself well.\nThe wise person would stay awake\nnursing himself\nin any of the three watches of the night,\nthe three stages of life."},{"k":"suddhaso","t":"If one values oneself,\nthen one should guard oneself well;\nduring any of the three phases of the night,\na wise person should remain alert."},{"k":"sujato","t":"If you knew your self as beloved,\nyou'd look after it so well.\nIn one of the night's three watches,\nan astute person would remain alert."}]},{"n":158,"vg":12,"pali":"Attānameva paṭhamaṁ,\npatirūpe nivesaye;\nAthaññamanusāseyya,\nna kilisseyya paṇḍito.","v":[{"k":"muller","t":"Let each man direct himself first to what is proper, then let him teach others; thus a wise man will not suffer."},{"k":"wagiswara","t":"First ground thyself in fitness; next, another teach.\nThus shalt thou wisdom gain and suffer no reproach."},{"k":"kaviratna","t":"Let each first firmly establish himself in right conduct, then only may he admonish others. Such a wise man does not suffer blemish."},{"k":"buddharakkhita","t":"One should first establish oneself in what is proper; then only should one instruct others. Thus the wise man will not be reproached."},{"k":"thanissaro","t":"First\nhe'd settle himself\nin what is correct,\nonly then\nteach others.\nHe wouldn't stain his name\n: he is wise."},{"k":"suddhaso","t":"First one should settles oneself\nin what is proper,\nthen one may instruct others;\na wise person should not become defiled."},{"k":"sujato","t":"The astute would avoid being corrupted\nby first grounding themselves\nin what is suitable,\nand then instructing others."}]},{"n":159,"vg":12,"pali":"Attānañce tathā kayirā,\nyathāññamanusāsati;\nSudanto vata dametha,\nattā hi kira duddamo.","v":[{"k":"muller","t":"If a man make himself as he teaches others to be, then, being himself well subdued, he may subdue (others); one's own self is indeed difficult to subdue."},{"k":"wagiswara","t":"First carry out thyself whate'er thou teachest others.\nSelf-tamed, thou'lt tame another; but self is hard to tame."},{"k":"kaviratna","t":"Let a man mold himself into what he admonishes others to be. Thus well-controlled he can control others. It is extremely difficult indeed to control one's own self."},{"k":"buddharakkhita","t":"One should do what one teaches others to do; if one would train others, one should be well controlled oneself. Difficult, indeed, is self-control."},{"k":"thanissaro","t":"If you'd mold yourself\nthe way you teach others,\nthen, well-trained,\ngo ahead & tame —\nfor, as they say,\nwhat's hard to tame is you\nyourself."},{"k":"suddhaso","t":"One should act the same way\nthat one instructs others to act;\none who is well-trained can train others -\nfor it is truly hard to train oneself."},{"k":"sujato","t":"If one were to treat oneself\nas one instructs another,\nthe well-tamed indeed would tame:\nfor the self, it seems, is hard to tame."}]},{"n":160,"vg":12,"pali":"Attā hi attano nātho,\nko hi nātho paro siyā;\nAttanā hi sudantena,\nnāthaṁ labhati dullabhaṁ.","v":[{"k":"muller","t":"Self is the lord of self, who else could be the lord? With self well subdued, a man finds a lord such as few can find."},{"k":"wagiswara","t":"Self is the lord of self; who else could be the lord?\nBy taming self one gains a lord most hard to gain."},{"k":"kaviratna","t":"The self is the master of the self. Who else can that master be? With the self fully subdued, one obtains the sublime refuge which is very difficult to achieve."},{"k":"buddharakkhita","t":"One truly is the protector of oneself; who else could the protector be? With oneself fully controlled, one gains a mastery that is hard to gain."},{"k":"thanissaro","t":"Your own self is\nyour own mainstay,\nfor who else could your mainstay be?\nWith you yourself well-trained\nyou obtain the mainstay\nhard to obtain."},{"k":"suddhaso","t":"One is one's own protector -\nhow could another protect you?\nOne who has trained oneself well\nhas acquired a protector that is truly hard to acquire."},{"k":"sujato","t":"One is indeed the lord of oneself,\nfor who else would be one's lord?\nBy means of a well-tamed self,\none gains a lord that's rare indeed."}]},{"n":161,"vg":12,"pali":"Attanā hi kataṁ pāpaṁ,\nAttajaṁ attasambhavaṁ;\nAbhimatthati dummedhaṁ,\nVajiraṁvasmamayaṁ maṇiṁ.","v":[{"k":"muller","t":"The evil done by oneself, self-begotten, self-bred, crushes the foolish, as a diamond breaks a precious stone."},{"k":"wagiswara","t":"The evil done by self, self-born and self-begotten,\nCrushes the senseless fool, as a bolt the jar of stone."},{"k":"kaviratna","t":"The sin committed by oneself, born of oneself, produced by oneself, crushes the evil-minded one as the diamond cuts the precious stone."},{"k":"buddharakkhita","t":"The evil a witless man does by himself, born of himself and produced by himself, grinds him as a diamond grinds a hard gem."},{"k":"thanissaro","t":"The evil he himself has done\n— self-born, self-created —\ngrinds down the dullard,\nas a diamond, a precious stone."},{"k":"suddhaso","t":"Evil is done by oneself,\nborn from oneself, produced by oneself;\nin this way a fool self-destructs,\nlike a diamond cutting through stone."},{"k":"sujato","t":"For the evil that is done by oneself,\nborn and produced in oneself,\ngrinds down a simpleton,\nas diamond grinds a lesser gem."}]},{"n":162,"vg":12,"pali":"Yassa accantadussilyaṁ,\nmāluvā sālamivotthataṁ;\nKaroti so tathattānaṁ,\nyathā naṁ icchatī diso.","v":[{"k":"muller","t":"He whose wickedness is very great brings himself down to that state where his enemy wishes him to be, as a creeper does with the tree which it surrounds."},{"k":"wagiswara","t":"He who is choked by sins, as a creeper chokes a tree,\nDoth to himself what e'en his foes would have him do."},{"k":"kaviratna","t":"As the parasitic maluva creeper destroys the sal tree which it entwines, so the immoral conduct of a man gradually makes of him what his enemy would have him be."},{"k":"buddharakkhita","t":"Just as a single creeper strangles the tree on which it grows, even so, a man who is exceedingly depraved harms himself as only an enemy might wish."},{"k":"thanissaro","t":"When overspread by extreme vice —\nlike a sal tree by a vine —\nyou do to yourself\nwhat an enemy would wish."},{"k":"suddhaso","t":"One who is excessively immoral,\nlike a tree overgrown by vines,\ndoes to oneself\nwhat an enemy wants."},{"k":"sujato","t":"One choked by immorality,\nas a sal tree by a creeper,\ndoes to themselves\nwhat a foe only wishes."}]},{"n":163,"vg":12,"pali":"Sukarāni asādhūni,\nattano ahitāni ca;\nYaṁ ve hitañca sādhuñca,\ntaṁ ve paramadukkaraṁ.","v":[{"k":"muller","t":"Bad deeds, and deeds hurtful to ourselves, are easy to do; what is beneficial and good, that is very difficult to do."},{"k":"wagiswara","t":"Easy is ill to do and harmful to oneself;\nBut what is good and wholesome, that is hard to do."},{"k":"kaviratna","t":"It is quite easy to perform evil deeds which are not beneficial to oneself. But it is extremely difficult to perform a deed which is righteous and beneficial."},{"k":"buddharakkhita","t":"Easy to do are things that are bad and harmful to oneself. But exceedingly difficult to do are things that are good and beneficial."},{"k":"thanissaro","t":"They're easy to do —\nthings of no good\n& no use to yourself.\nWhat's truly useful & good\nis truly harder than hard to do."},{"k":"suddhaso","t":"It is easy to do things that are worthless\nand of no benefit to oneself;\nbut to do what is beneficial and worthwhile\nis extremely difficult."},{"k":"sujato","t":"It's easy to do bad things\nharmful to oneself,\nbut good things that are helpful\nare the hardest things to do."}]},{"n":164,"vg":12,"pali":"Yo sāsanaṁ arahataṁ,\nariyānaṁ dhammajīvinaṁ;\nPaṭikkosati dummedho,\ndiṭṭhiṁ nissāya pāpikaṁ;\nPhalāni kaṭṭhakasseva,\nattaghātāya phallati.","v":[{"k":"muller","t":"The foolish man who scorns the rule of the venerable (Arahat), of the elect (Ariya), of the virtuous, and follows false doctrine, he bears fruit to his own destruction, like the fruits of the Katthaka reed."},{"k":"wagiswara","t":"Whose rejects the words of noble righteous saints\nOn his own head brings ruin by his perversity,\nAs bamboo trees put forth their fruit and die away."},{"k":"kaviratna","t":"If an evil-minded one, by reason of his false views, reviles the teaching of the Arhats, the Noble Ones, and the virtuous, verily he brings forth the fruit of his own destruction, even as does the katthaka reed."},{"k":"buddharakkhita","t":"Whoever, on account of perverted views, scorns the Teaching of the Perfected Ones, the Noble and Righteous Ones — that fool, like the bamboo, produces fruits only for self destruction. [14]"},{"k":"thanissaro","t":"The teaching of those who live the Dhamma,\nworthy ones, noble:\nwhoever maligns it\n— a dullard,\ninspired by evil view —\nbears fruit for his own destruction,\nlike the fruiting of the bamboo."},{"k":"suddhaso","t":"A foolish person who,\nbased on a harmful perspective,\nreviles the teachings\nof the Worthy One,\nbrings about their own destruction\nlike a monocarpic plant."},{"k":"sujato","t":"On account of wicked views—\nscorning the guidance\nof the perfected ones,\nthe noble ones living righteously—\nthe idiot begets their own self's demise,\nlike the bamboo bearing fruit."}]},{"n":165,"vg":12,"pali":"Attanā hi kataṁ pāpaṁ,\nattanā saṅkilissati;\nAttanā akataṁ pāpaṁ,\nattanāva visujjhati;\nSuddhī asuddhi paccattaṁ,\nnāñño aññaṁ visodhaye.","v":[{"k":"muller","t":"By oneself the evil is done, by oneself one suffers; by oneself evil is left undone, by oneself one is purified. Purity and impurity belong to oneself, no one can purify another."},{"k":"wagiswara","t":"By self is evil done; by self is one defiled;\nIll deeds not done by self to self bring purity;\nEach for himself is pure; each for himself impure;\nThou can'st not cleanse another man's impurity."},{"k":"kaviratna","t":"By self alone is evil done; by self alone is one defiled; by self alone is evil not done; by self alone is one purified. Purity and impurity depend on oneself; no one can purify another."},{"k":"buddharakkhita","t":"By oneself is evil done; by oneself is one defiled. By oneself is evil left undone; by oneself is one made pure. Purity and impurity depend on oneself; no one can purify another."},{"k":"thanissaro","t":"Evil is done by oneself\n\nby oneself is one defiled.\nEvil is left undone by oneself\n\nby oneself is one cleansed.\nPurity & impurity are one's own doing.\nNo one purifies another.\nNo other purifies one."},{"k":"suddhaso","t":"By oneself evil is done,\nby oneself one becomes defiled;\nby oneself evil is not done,\nby oneself one becomes purified;\npurity and impurity depend on oneself -\nno one can purify another."},{"k":"sujato","t":"For it is by oneself that evil's done,\none is corrupted by oneself.\nIt's by oneself that evil's not done,\none is purified by oneself.\nPurity and impurity are personal matters,\nno one can purify another."}]},{"n":166,"vg":12,"pali":"Attadatthaṁ paratthena,\nbahunāpi na hāpaye;\nAttadatthamabhiññāya,\nsadatthapasuto siyā.\nAttavaggo dvādasamo.","v":[{"k":"muller","t":"Let no one forget his own duty for the sake of another's, however great; let a man, after he has discerned his own duty, be always attentive to his duty."},{"k":"wagiswara","t":"Mind thy affairs, not others', however great they be;\nRight knowledge of one's own brings more prosperity."},{"k":"kaviratna","t":"However much one is engaged in activities for the good of others, one should not neglect his own (spiritual) purpose. Having discerned one's own task, let him apply himself to that task with diligence."},{"k":"buddharakkhita","t":"Let one not neglect one's own welfare for the sake of another, however great. Clearly understanding one's own welfare, let one be intent upon the good."},{"k":"thanissaro","t":"Don't sacrifice your own welfare\nfor that of another,\nno matter how great.\nRealizing your own true welfare,\nbe intent on just that."},{"k":"suddhaso","t":"One should not abandon one's own welfare\nfor the sake of others, no matter how many;\nhaving understood one's own welfare,\none should be intent upon it."},{"k":"sujato","t":"Never neglect what is good for yourself\nfor the sake of another, however great.\nKnowing well what is good for yourself,\nbe intent upon your heart's goal."}]},{"n":167,"vg":13,"pali":"Hīnaṁ dhammaṁ na seveyya,\npamādena na saṁvase;\nMicchādiṭṭhiṁ na seveyya,\nna siyā lokavaḍḍhano.","v":[{"k":"muller","t":"Do not follow the evil law! Do not live on in thoughtlessness! Do not follow false doctrine! Be not a friend of the world."},{"k":"wagiswara","t":"Follow not the way unworthy;\nLive not thou in slothfulness;\nLet not doctrines false allure thee;\nTurn thy thoughts from worldliness."},{"k":"kaviratna","t":"Let no one follow a degraded course of existence, nor live in indolence; let him not follow false views, nor be a person who prolongs his worldly existence."},{"k":"buddharakkhita","t":"Follow not the vulgar way; live not in heedlessness; hold not false views; linger not long in worldly existence."},{"k":"thanissaro","t":"Don't associate with lowly qualities.\nDon't consort with heedlessness.\nDon't associate with wrong views.\nDon't busy yourself with the world."},{"k":"suddhaso","t":"One should not participate in inferior teachings,\none should not live negligently,\none should not participate in wrong view,\none should not increase worldliness."},{"k":"sujato","t":"Don't resort to lowly things,\ndon't abide in negligence,\ndon't resort to wrong views,\ndon't perpetuate the world."}]},{"n":168,"vg":13,"pali":"Uttiṭṭhe nappamajjeyya,\ndhammaṁ sucaritaṁ care;\nDhammacārī sukhaṁ seti,\nasmiṁ loke paramhi ca.","v":[{"k":"muller","t":"Rouse thyself! do not be idle! Follow the law of virtue! The virtuous rests in bliss in this world and in the next."},{"k":"wagiswara","t":"Stand! Arise! Throw sloth away;\nFollow the path of righteousness;\nHappy he who walks aright,\nHere and in the world to come."},{"k":"kaviratna","t":"Awake! Be not heedless. Follow the truth (dhamma). He who embarks upon the path of truth lives happily in this world and in the hereafter."},{"k":"buddharakkhita","t":"Arise! Do not be heedless! Lead a righteous life. The righteous live happily both in this world and the next."},{"k":"thanissaro","t":"Get up! Don't be heedless.\nLive the Dhamma well.\nOne who lives the Dhamma\nsleeps with ease\nin this world & the next."},{"k":"suddhaso","t":"One should apply effort, one should not be negligent,\none should practice Dhamma well;\none who practices the Dhamma rests happily,\nin this world and the next."},{"k":"sujato","t":"Get up, don't be heedless,\nlive by principle, with good conduct.\nFor one of good conduct sleeps at ease,\nin this world and the next."}]},{"n":169,"vg":13,"pali":"Dhammaṁ care sucaritaṁ,\nna naṁ duccaritaṁ care;\nDhammacārī sukhaṁ seti,\nasmiṁ loke paramhi ca.","v":[{"k":"muller","t":"Follow the law of virtue; do not follow that of sin. The virtuous rests in bliss in this world and in the next."},{"k":"wagiswara","t":"Stand! Arise! Throw sloth away;\nFollow the path of righteousness;\nHappy he who walks aright,\nHere and in the world to come."},{"k":"kaviratna","t":"Follow the law of morality; do not follow the law of immorality; he who embarks upon the path of truth lives happily in this world and in the hereafter."},{"k":"buddharakkhita","t":"Lead a righteous life; lead not a base life. The righteous live happily both in this world and the next."},{"k":"thanissaro","t":"Live the Dhamma well.\nDon't live it badly.\nOne who lives the Dhamma\nsleeps with ease\nin this world & the next."},{"k":"suddhaso","t":"One should practice Dhamma well,\none should not engage in misconduct;\none who practices the Dhamma rests happily,\nin this world and the next."},{"k":"sujato","t":"Live by principle, with good conduct,\ndon't conduct yourself badly.\nFor one of good conduct sleeps at ease,\nin this world and the next."}]},{"n":170,"vg":13,"pali":"Yathā pubbuḷakaṁ passe,\nyathā passe marīcikaṁ;\nEvaṁ lokaṁ avekkhantaṁ,\nmaccurājā na passati.","v":[{"k":"muller","t":"Look upon the world as a bubble, look upon it as a mirage: the king of death does not see him who thus looks down upon the world."},{"k":"wagiswara","t":"As a bubble on the water,\nAs a phantom of the sands,\nHim who thus the world despiseth,\nDeath the king cannot behold."},{"k":"kaviratna","t":"Look upon the world as a bubble, regard it as a mirage; who thus perceives the world, him Mara, the king of death, does not see."},{"k":"buddharakkhita","t":"One who looks upon the world as a bubble and a mirage, him the King of Death sees not."},{"k":"thanissaro","t":"See it as a bubble,\nsee it as a mirage:\none who regards the world this way\nthe King of Death doesn't see."},{"k":"suddhaso","t":"Like seeing a bubble,\nlike seeing a mirage -\none who regards the world in this way\nis not seen by the Lord of Death."},{"k":"sujato","t":"Look upon the world\nas a bubble\nor a mirage,\nthen the King of Death won't see you."}]},{"n":171,"vg":13,"pali":"Etha passathimaṁ lokaṁ,\ncittaṁ rājarathūpamaṁ;\nYattha bālā visīdanti,\nnatthi saṅgo vijānataṁ.","v":[{"k":"muller","t":"Come, look at this glittering world, like unto a royal chariot; the foolish are immersed in it, but the wise do not touch it."},{"k":"wagiswara","t":"Lo! this world in all its splendour,\nLike a royal car adorned,\nWherein many a fool is seated,\nHath no power to bind the wise."},{"k":"kaviratna","t":"Come, behold this world, resplendent like unto a royal chariot. Fools are immersed in it; but the wise have no attachment for it."},{"k":"buddharakkhita","t":"Come! Behold this world, which is like a decorated royal chariot. Here fools flounder, but the wise have no attachment to it."},{"k":"thanissaro","t":"Come look at this world\nall decked out\nlike a royal chariot,\nwhere fools plunge in,\nwhile those who know\ndon't cling."},{"k":"suddhaso","t":"Come, look at this world,\nas splendid as a royal chariot,\nwhere fools become immersed,\nbut the conscious do not stick."},{"k":"sujato","t":"Come, see this world decked out\nlike a fancy royal chariot.\nHere fools founder,\nbut the discerning are not chained."}]},{"n":172,"vg":13,"pali":"Yo ca pubbe pamajjitvā,\npacchā so nappamajjati;\nSomaṁ lokaṁ pabhāseti,\nabbhā muttova candimā.","v":[{"k":"muller","t":"He who formerly was reckless and afterwards became sober, brightens up this world, like the moon when freed from clouds."},{"k":"wagiswara","t":"He who formerly was slothful,\nBut is slothful now no more,\nLighteth up the world with splendour,\nAs the moon from clouds released."},{"k":"kaviratna","t":"He who formerly was heedless, but, after due consideration, becomes vigilant, illumines the world as the moon freed from a cloud."},{"k":"buddharakkhita","t":"He who having been heedless is heedless no more, illuminates this world like the moon freed from clouds."},{"k":"thanissaro","t":"Who once was heedless,\nbut later is not,\nbrightens the world\nlike the moon set free from a cloud."},{"k":"suddhaso","t":"One who previously was negligent\nbut now is not\nilluminates this world\nlike the moon set free from a cloud."},{"k":"sujato","t":"He who once was heedless,\nbut turned to heedfulness,\nlights up the world\nlike the moon freed from clouds."}]},{"n":173,"vg":13,"pali":"Yassa pāpaṁ kataṁ kammaṁ,\nkusalena pidhīyati;\nSomaṁ lokaṁ pabhāseti,\nabbhā muttova candimā.","v":[{"k":"muller","t":"He whose evil deeds are covered by good deeds, brightens up this world, like the moon when freed from clouds."},{"k":"wagiswara","t":"He who, having once done evil,\nCovers up his ill with good,\nLighteth up the world with splendour,\nAs the moon from clouds released."},{"k":"kaviratna","t":"He whose evil deeds are superseded by meritorious deeds, illumines the world as the moon freed from a cloud."},{"k":"buddharakkhita","t":"He, who by good deeds covers the evil he has done, illuminates this world like the moon freed from clouds."},{"k":"thanissaro","t":"His evil-done deed\nis replaced with skillfulness:\nhe brightens the world\nlike the moon set free from a cloud."},{"k":"suddhaso","t":"One who replaces their evil deeds\nwith wholesome ones\nilluminates this world\nlike the moon set free from a cloud."},{"k":"sujato","t":"Someone whose bad deed\nis supplanted by the good,\nlights up the world,\nlike the moon freed from clouds."}]},{"n":174,"vg":13,"pali":"Andhabhūto ayaṁ loko,\ntanukettha vipassati;\nSakuṇo jālamuttova,\nappo saggāya gacchati.","v":[{"k":"muller","t":"This world is dark, few only can see here; a few only go to heaven, like birds escaped from the net."},{"k":"wagiswara","t":"All this world is wrapped in darkness;\nFew be they that are not blind;\nLike the birds that 'scape the fowler,\nFew be they that go to heaven."},{"k":"kaviratna","t":"This world is blind. Few are they who can see things as they are. As birds escaped from the net, few go to heaven."},{"k":"buddharakkhita","t":"Blind is the world; here only a few possess insight. Only a few, like birds escaping from the net, go to realms of bliss."},{"k":"thanissaro","t":"Blinded this world —\nhow few here see clearly!\nJust as birds who've escaped\nfrom a net are\nfew, few\nare the people\nwho make it to heaven."},{"k":"suddhaso","t":"This world has become blind;\nrare are those who see clearly.\nLike a bird freed from a net,\nfew go to heaven."},{"k":"sujato","t":"Blind is the world,\nfew are those who clearly see.\nOnly a handful go to heaven,\nlike a bird freed from a net."}]},{"n":175,"vg":13,"pali":"Haṁsādiccapathe yanti,\nākāse yanti iddhiyā;\nNīyanti dhīrā lokamhā,\njetvā māraṁ savāhiniṁ.","v":[{"k":"muller","t":"The swans go on the path of the sun, they go through the ether by means of their miraculous power; the wise are led out of this world, when they have conquered Mara and his train."},{"k":"wagiswara","t":"Lo! the swans fly on the sun's path,\nFly by magic through the air;\nWise men from the world departing\nConquer Death and all his hosts."},{"k":"kaviratna","t":"Swans fly in the path of the sun; those who possess psychic powers (iddhi) go through the air. The wise, having conquered Mara and his hosts, go forth out of this world."},{"k":"buddharakkhita","t":"Swans fly on the path of the sun; men pass through the air by psychic powers; the wise are led away from the world after vanquishing Mara and his host."},{"k":"thanissaro","t":"Swans fly the path of the sun;\nthose with the power fly through space;\nthe enlightened flee from the world,\nhaving defeated the armies of Mara."},{"k":"suddhaso","t":"Like swans moving through the air,\nlike mystics moving through the sky,\nthe wise leave this world,\nhaving defeated Māra and his army."},{"k":"sujato","t":"Swans fly by the sun's path,\npsychic sages fly through space.\nThe attentive leave the world,\nhaving vanquished Māra with his legions."}]},{"n":176,"vg":13,"pali":"Ekaṁ dhammaṁ atītassa,\nmusāvādissa jantuno;\nVitiṇṇaparalokassa,\nnatthi pāpaṁ akāriyaṁ.","v":[{"k":"muller","t":"If a man has transgressed one law, and speaks lies, and scoffs at another world, there is no evil he will not do."},{"k":"wagiswara","t":"He who by false words transgressing\nBreaks one tittle of the Norm;\nHe who future life renounceth\nEvery wicked deed will do."},{"k":"kaviratna","t":"There is no sin that a man will not commit who utters falsehood, who has transgressed the one law of truthfulness (dhamma), and who has rejected the other world."},{"k":"buddharakkhita","t":"For a liar who has violated the one law (of truthfulness) who holds in scorn the hereafter, there is no evil that he cannot do."},{"k":"thanissaro","t":"The person who tells a lie,\nwho transgresses in this one thing,\ntranscending concern for the world beyond:\nthere's no evil\nhe might not do."},{"k":"suddhaso","t":"There is no evil\nthat cannot be done\nby one who tells lies\nand disregards the afterlife."},{"k":"sujato","t":"When a personage, spurning the hereafter,\ntransgresses in just one thing—\nlying—\nthere is no evil they would not do."}]},{"n":177,"vg":13,"pali":"Na ve kadariyā devalokaṁ vajanti,\nBālā have nappasaṁsanti dānaṁ;\nDhīro ca dānaṁ anumodamāno,\nTeneva so hoti sukhī parattha.","v":[{"k":"muller","t":"The uncharitable do not go to the world of the gods; fools only do not praise liberality; a wise man rejoices in liberality, and through it becomes blessed in the other world."},{"k":"wagiswara","t":"Those who covet reach not heaven;\nFools care not for charity;\nHe who charity approveth\nReacheth heavenly joy thereby."},{"k":"kaviratna","t":"Indeed the miserly do not go to the world of the gods; the foolish do not praise liberality. But the wise man who takes pleasure in giving, through that very act becomes happy in the next world."},{"k":"buddharakkhita","t":"Truly, misers fare not to heavenly realms; nor, indeed, do fools praise generosity. But the wise man rejoices in giving, and by that alone does he become happy hereafter."},{"k":"thanissaro","t":"No misers go\nto the world of the devas.\nThose who don't praise giving\nare fools.\nThe enlightened\nexpress their approval for giving\nand so find ease\nin the world beyond."},{"k":"suddhaso","t":"Stingy fools, those who do not praise giving,\ndo not go the deva-world.\nThe wise rejoice in giving,\nand because of that they are happy hereafter."},{"k":"sujato","t":"The miserly don't ascend to heaven,\nit takes a fool to not praise giving.\nThe attentive celebrate giving,\nand so find happiness in the hereafter."}]},{"n":178,"vg":13,"pali":"Pathabyā ekarajjena,\nsaggassa gamanena vā;\nSabbalokādhipaccena,\nsotāpattiphalaṁ varaṁ.\nLokavaggo terasamo.","v":[{"k":"muller","t":"Better than sovereignty over the earth, better than going to heaven, better than lordship over all worlds, is the reward of the first step in holiness."},{"k":"wagiswara","t":"Rule on earth and joy in heaven,\nSovreignty of all the worlds--\nThese are all by him transcended\nWho hath entered on the stream."},{"k":"kaviratna","t":"The fruit of entering the stream (the path) is superior to that of the sole sovereignty of the world, or going to heaven, or the supreme lordship over the whole universe."},{"k":"buddharakkhita","t":"Better than sole sovereignty over the earth, better than going to heaven, better even than lordship over all the worlds is the supramundane Fruition of Stream Entrance. [15]"},{"k":"thanissaro","t":"Sole dominion over the earth,\ngoing to heaven,\nlordship over all worlds:\nthe fruit of stream-entry\nexcels them."},{"k":"suddhaso","t":"Compared to being the sole ruler of the earth,\nor going to heaven,\nor dominating the entire world,\nattaining stream-entry is better."},{"k":"sujato","t":"The fruit of stream-entry is better\nthan being the one king of the earth,\nthan going to heaven,\nthan lordship over all the world."}]},{"n":179,"vg":14,"pali":"Yassa jitaṁ nāvajīyati,\nJitaṁ yassa noyāti koci loke;\nTaṁ buddhamanantagocaraṁ,\nApadaṁ kena padena nessatha.","v":[{"k":"muller","t":"He whose conquest is not conquered again, into whose conquest no one in this world enters, by what track can you lead him, the Awakened, the Omniscient, the trackless?"},{"k":"wagiswara","t":"The Awakened One, unconquered Conqueror,\nWhose conquest naught in this world can undo.\nWho ranges o'er His boundless sphere untraced.\nBy what tracks can ye lead Him to rebirth?"},{"k":"kaviratna","t":"By what path will you lead the Buddha of infinite range of perception, the Pathless One, whose conquest of passions cannot be undone, into whose conquest no one in this world enters?"},{"k":"buddharakkhita","t":"By what track can you trace that trackless Buddha of limitless range, whose victory nothing can undo, whom none of the vanquished defilements can ever pursue?"},{"k":"thanissaro","t":"Whose conquest can't be undone,\nwhose conquest no one in the world\ncan reach;\nawakened, his pasture endless,\npathless:\nby what path will you lead him astray?"},{"k":"suddhaso","t":"One whose victory does not diminish,\nwhose victory cannot be removed by anyone in the world,\nthe domain of that Awakened One is infinite -\nNo one can lead that one astray."},{"k":"sujato","t":"He whose victory may not be undone,\na victory unrivaled in all the world;\nby what track would you trace that Buddha,\nwho leaves no track in his infinite range?"}]},{"n":180,"vg":14,"pali":"Yassa jālinī visattikā,\nTaṇhā natthi kuhiñci netave;\nTaṁ buddhamanantagocaraṁ,\nApadaṁ kena padena nessatha.","v":[{"k":"muller","t":"He whom no desire with its snares and poisons can lead astray, by what track can you lead him, the Awakened, the Omniscient, the trackless?"},{"k":"wagiswara","t":"Free from the snares of passion's outspread net,\nThe Awakened One, whom longing cannot draw,\nWho ranges o'er His boundless sphere untraced.\nBy what tracks can ye lead Him to rebirth?"},{"k":"kaviratna","t":"By what path will you lead the Buddha of infinite range of perception, the Pathless One, in whom there is not that entangling and poisonous craving which leads one astray (to another state of birth)?"},{"k":"buddharakkhita","t":"By what track can you trace that trackless Buddha of limitless range, in whom exists no longer, the entangling and embroiling craving that perpetuates becoming?"},{"k":"thanissaro","t":"In whom there's no craving\n— the sticky ensnarer —\nto lead him anywherever at all;\nawakened, his pasture endless,\npathless:\nby what path will you lead him astray?"},{"k":"suddhaso","t":"One who is not entangled or stuck,\nin whom no craving can be found,\nthe domain of that Awakened One is infinite -\nNo one can lead that one astray."},{"k":"sujato","t":"Of craving, the weaver, the clinger, he has none:\nso where can he be traced?\nBy what track would you trace that Buddha,\nwho leaves no track in his infinite range?"}]},{"n":181,"vg":14,"pali":"Ye jhānapasutā dhīrā,\nnekkhammūpasame ratā;\nDevāpi tesaṁ pihayanti,\nsambuddhānaṁ satīmataṁ.","v":[{"k":"muller","t":"Even the gods envy those who are awakened and not forgetful, who are given to meditation, who are wise, and who delight in the repose of retirement (from the world)."},{"k":"wagiswara","t":"Those sages who, to meditation given,\nDelight in freedom's bliss, with mind controlled,\nGods envy Them, Those All-Awakened Ones."},{"k":"kaviratna","t":"Those wise ones who are absorbed in meditation, who take delight in the inner calm of renunciation, such mindful and perfectly awakened ones even the devas (gods) hold dear."},{"k":"buddharakkhita","t":"Those wise ones who are devoted to meditation and who delight in the calm of renunciation — such mindful ones, Supreme Buddhas, even the gods hold dear."},{"k":"thanissaro","t":"They, the enlightened, intent on jhana,\ndelighting in stilling\n& renunciation,\nself-awakened & mindful:\neven the devas\nview them with envy."},{"k":"suddhaso","t":"They are steadfast, committed to Jhāna,\nappreciate the peacefulness of renunciation,\nand are envied even by the angels -\nthose who are mindful and fully Awakened."},{"k":"sujato","t":"The attentive intent on absorption,\nwho love the peace of renunciation,\nthe Buddhas, ever mindful,\nare envied by even the gods."}]},{"n":182,"vg":14,"pali":"Kiccho manussapaṭilābho,\nkicchaṁ maccāna jīvitaṁ;\nKicchaṁ saddhammassavanaṁ,\nkiccho buddhānamuppādo.","v":[{"k":"muller","t":"Difficult (to obtain) is the conception of men, difficult is the life of mortals, difficult is the hearing of the True Law, difficult is the birth of the Awakened (the attainment of Buddhahood)."},{"k":"wagiswara","t":"To gain a birth as man is hard indeed;\n'Tis hard to get one's living in the world;\nHard is the hearing of the doctrine true;\nHardest to be an All-Awakened One."},{"k":"kaviratna","t":"Difficult is it to be born as a human being; difficult is the existence of mortals; difficult is the hearing of the Sublime Truth; rare is the appearance of the Enlightened Ones (Buddhas)."},{"k":"buddharakkhita","t":"Hard is it to be born a man; hard is the life of mortals. Hard is it to gain the opportunity of hearing the Sublime Truth, and hard to encounter is the arising of the Buddhas."},{"k":"thanissaro","t":"Hard the winning of a human birth.\nHard the life of mortals.\nHard the chance to hear the true Dhamma.\nHard the arising of Awakened Ones."},{"k":"suddhaso","t":"It is hard to become a human,\nit is hard to live a mortal life,\nit is hard to hear the true Dhamma,\nit is hard to encounter an Awakened One."},{"k":"sujato","t":"It's hard to gain a human birth;\nthe life of mortals is hard;\nit's hard to hear the true teaching;\nthe arising of Buddhas is hard."}]},{"n":183,"vg":14,"pali":"Sabbapāpassa akaraṇaṁ,\nkusalassa upasampadā;\nSacittapariyodapanaṁ,\netaṁ buddhāna sāsanaṁ.","v":[{"k":"muller","t":"Not to commit any sin, to do good, and to purify one's mind, that is the teaching of (all) the Awakened."},{"k":"wagiswara","t":"\"Refrain thyself from every evil deed;\nStablish thyself in good; cleanse thine own thoughts\"--\nThis is the message of the Awakened Ones."},{"k":"kaviratna","t":"Abstention from all evil, the doing of good deeds, and the purification of the mind, is the admonition of the Enlightened Ones."},{"k":"buddharakkhita","t":"To avoid all evil, to cultivate good, and to cleanse one's mind — this is the teaching of the Buddhas."},{"k":"thanissaro","t":"The non-doing of any evil,\nthe performance of what's skillful,\nthe cleansing of one's own mind:\nthis is the teaching\nof the Awakened."},{"k":"suddhaso","t":"Not doing anything evil,\ncommitment to the wholesome,\nand cleansing one's own mind -\nthis is the teaching of the Awakened Ones."},{"k":"sujato","t":"Not to do any evil;\nto embrace the good;\nto purify one's mind:\nthis is the instruction of the Buddhas."}]},{"n":184,"vg":14,"pali":"Khantī paramaṁ tapo titikkhā,\nNibbānaṁ paramaṁ vadanti buddhā;\nNa hi pabbajito parūpaghātī,\nNa samaṇo hoti paraṁ viheṭhayanto.","v":[{"k":"muller","t":"The Awakened call patience the highest penance, long-suffering the highest Nirvana; for he is not an anchorite (pravragita) who strikes others, he is not an ascetic (sramana) who insults others."},{"k":"wagiswara","t":"Long-sufferance is the best austerity;\nNibbāna, say the Awakened Ones, is best."},{"k":"kaviratna","t":"Forbearance which is long-suffering is the highest austerity. The Buddhas declare nirvana to be the supreme state. Verily he is not an anchorite who harms another; nor is he an ascetic who causes grief to another."},{"k":"buddharakkhita","t":"Enduring patience is the highest austerity. \"Nibbana is supreme,\" say the Buddhas. He is not a true monk who harms another, nor a true renunciate who oppresses others."},{"k":"thanissaro","t":"Patient endurance:\nthe foremost austerity.\nUnbinding:\nthe foremost,\nso say the Awakened.\nHe who injures another\nis no contemplative.\nHe who mistreats another,\nno monk."},{"k":"suddhaso","t":"Endurance is the highest austerity,\nNibbāna is the highest, according to those who are Awakened.\nA renunciant does not harm others,\na contemplative does not oppress others."},{"k":"sujato","t":"Patient acceptance is the ultimate fervor.\nExtinguishment is the ultimate, say the Buddhas.\nNo true renunciate injures another,\nnor does an ascetic hurt another."}]},{"n":185,"vg":14,"pali":"Anūpavādo anūpaghāto,\nPātimokkhe ca saṁvaro;\nMattaññutā ca bhattasmiṁ,\nPantañca sayanāsanaṁ;\nAdhicitte ca āyogo,\nEtaṁ buddhāna sāsanaṁ.","v":[{"k":"muller","t":"Not to blame, not to strike, to live restrained under the law, to be moderate in eating, to sleep and sit alone, and to dwell on the highest thoughts,--this is the teaching of the Awakened."},{"k":"wagiswara","t":"\"Revile not, harm not, live by rule restrained;\nOf food take little; sleep and sit alone;\nIn meditation keep thy thoughts controlled\"--\nThis is the message of the Awakened Ones."},{"k":"kaviratna","t":"Not reviling, not injuring, practicing restraint according to the moral code (patimokkha) leading to freedom, moderation in eating, living in solitude, dwelling with diligence on the highest thoughts — this is the teaching of the Buddhas."},{"k":"buddharakkhita","t":"Not despising, not harming, restraint according to the code of monastic discipline, moderation in food, dwelling in solitude, devotion to meditation — this is the teaching of the Buddhas."},{"k":"thanissaro","t":"Not disparaging, not injuring,\nrestraint in line with the Patimokkha,\nmoderation in food,\ndwelling in seclusion,\ncommitment to the heightened mind:\nthis is the teaching\nof the Awakened."},{"k":"suddhaso","t":"Not insulting, not harming,\nself-restraint in accordance with the Pātimokkha,\nKnowing the right amount when eating,\nsitting and sleeping in a secluded place,\nand commitment to improving the mind -\nthis is the teaching of the Awakened Ones."},{"k":"sujato","t":"Not speaking ill nor doing harm;\nrestraint in the monastic code;\nmoderation in eating;\nstaying in remote lodgings;\ncommitment to the higher mind—\nthis is the instruction of the Buddhas."}]},{"n":186,"vg":14,"pali":"Na kahāpaṇavassena,\ntitti kāmesu vijjati;\nAppassādā dukhā kāmā,\niti viññāya paṇḍito.","v":[{"k":"muller","t":"There is no satisfying lusts, even by a shower of gold pieces; he who knows that lusts have a short taste and cause pain, he is wise;"},{"k":"wagiswara","t":"\"Lust is not sated, tho' it rain gold coins;\nBrief is the pleasure, great the pains of lust\"--\nWhoso saith this and knows it, he is wise."},{"k":"kaviratna","t":"There is no satisfying the passions even by a shower of gold coins; the wise man, knowing that sense delights are of fleeting pleasure and productive of pain, finds no joy even in celestial pleasures. The true disciple of the Fully Enlightened One delights only in the destruction of all worldly desires."},{"k":"buddharakkhita","t":"There is no satisfying sensual desires, even with the rain of gold coins. For sensual pleasures give little satisfaction and much pain. Having understood this, the wise man finds no delight even in heavenly pleasures. The disciple of the Supreme Buddha delights in the destruction of craving."},{"k":"thanissaro","t":"Not even if it rained gold coins\nwould we have our fill\nof sensual pleasures.\n'Stressful,\nthey give little enjoyment' —\nknowing this, the wise one\nfinds no delight\neven in heavenly sensual pleasures.\nHe is one who delights\nin the ending of craving,\na disciple of the Rightly\nSelf-Awakened One."},{"k":"suddhaso","t":"Not even with a rain of money\ncan one be sated when it comes to sensuality.\nThere is little gratification in sensuality, it is unsatisfying;\nthis is what the wise understand."},{"k":"sujato","t":"Even if it were raining money,\nyou'd not be sated in sensual pleasures.\nAn astute person understands that sensual pleasures\noffer little gratification and much suffering."}]},{"n":187,"vg":14,"pali":"Api dibbesu kāmesu,\nratiṁ so nādhigacchati;\nTaṇhakkhayarato hoti,\nsammāsambuddhasāvako.","v":[{"k":"muller","t":"Even in heavenly pleasures he finds no satisfaction, the disciple who is fully awakened delights only in the destruction of all desires."},{"k":"wagiswara","t":"He finds no pleasure e'en in heaven's delights;\nHe finds his joy in slaying all desire,\nThat follower of the All-Awakened Ones."},{"k":"kaviratna","t":"There is no satisfying the passions even by a shower of gold coins; the wise man, knowing that sense delights are of fleeting pleasure and productive of pain, finds no joy even in celestial pleasures. The true disciple of the Fully Enlightened One delights only in the destruction of all worldly desires."},{"k":"buddharakkhita","t":"There is no satisfying sensual desires, even with the rain of gold coins. For sensual pleasures give little satisfaction and much pain. Having understood this, the wise man finds no delight even in heavenly pleasures. The disciple of the Supreme Buddha delights in the destruction of craving."},{"k":"thanissaro","t":"Not even if it rained gold coins\nwould we have our fill\nof sensual pleasures.\n'Stressful,\nthey give little enjoyment' —\nknowing this, the wise one\nfinds no delight\neven in heavenly sensual pleasures.\nHe is one who delights\nin the ending of craving,\na disciple of the Rightly\nSelf-Awakened One."},{"k":"suddhaso","t":"Even in heavenly sensuality\none cannot find satisfaction.\nBut there is satisfaction in the elimination of craving\nfor a disciple of the Fully Awakened One."},{"k":"sujato","t":"Thus they find no delight\neven in celestial pleasures.\nA disciple of the fully awakened Buddha\ndelights in the ending of craving."}]},{"n":188,"vg":14,"pali":"Bahuṁ ve saraṇaṁ yanti,\npabbatāni vanāni ca;\nĀrāmarukkhacetyāni,\nmanussā bhayatajjitā.","v":[{"k":"muller","t":"Men, driven by fear, go to many a refuge, to mountains and forests, to groves and sacred trees."},{"k":"wagiswara","t":"To many a refuge frightened mortals flee,\nMountains and forests, groves and sacred trees;"},{"k":"kaviratna","t":"Men driven by fear betake themselves to numerous refuges, such as mountains, forests, groves, sacred trees and shrines."},{"k":"buddharakkhita","t":"Driven only by fear, do men go for refuge to many places — to hills, woods, groves, trees and shrines."},{"k":"thanissaro","t":"They go to many a refuge,\nto mountains and forests,\nto park and tree shrines:\npeople threatened with danger.\nThat's not the secure refuge,\nnot the supreme refuge,\nthat's not the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress."},{"k":"suddhaso","t":"They go to many places for refuge -\nmountains, groves,\nforest shrines -\npeople who are struck by fear."},{"k":"sujato","t":"So many go for refuge\nto mountains and forest groves,\nto shrines in tended parks;\nthose people are driven by fear."}]},{"n":189,"vg":14,"pali":"Netaṁ kho saraṇaṁ khemaṁ,\nnetaṁ saraṇamuttamaṁ;\nNetaṁ saraṇamāgamma,\nsabbadukkhā pamuccati.","v":[{"k":"muller","t":"But that is not a safe refuge, that is not the best refuge; a man is not delivered from all pains after having gone to that refuge."},{"k":"wagiswara","t":"These are no refuge safe, no sure retreat,\nBy these we are not from all woe released."},{"k":"kaviratna","t":"Verily, none of these is a safe refuge, nor is it the supreme refuge. For even after arriving at a refuge, one is not emancipated from all suffering."},{"k":"buddharakkhita","t":"Such, indeed, is no safe refuge; such is not the refuge supreme. Not by resorting to such a refuge is one released from all suffering."},{"k":"thanissaro","t":"They go to many a refuge,\nto mountains and forests,\nto park and tree shrines:\npeople threatened with danger.\nThat's not the secure refuge,\nnot the supreme refuge,\nthat's not the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress.\n\nBut when, having gone\nto the Buddha, Dhamma,\n& Sangha for refuge,\nyou see with right discernment\nthe four noble truths —\nstress,\nthe cause of stress,\nthe transcending of stress,\n& the noble eightfold path,\nthe way to the stilling of stress:\nthat's the secure refuge,\nthat, the supreme refuge,\nthat is the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress."},{"k":"suddhaso","t":"But that is not a secure refuge,\nthat is not the ultimate refuge;\nthat is not a refuge\nwhich brings freedom from all suffering."},{"k":"sujato","t":"But such refuge is no sanctuary,\nit is no supreme refuge.\nBy going to that refuge,\nyou're not released from all suffering."}]},{"n":190,"vg":14,"pali":"Yo ca buddhañca dhammañca,\nsaṅghañca saraṇaṁ gato;\nCattāri ariyasaccāni,\nsammappaññāya passati.","v":[{"k":"muller","t":"He who takes refuge with Buddha, the Law, and the Church; he who, with clear understanding, sees the four holy truths:--"},{"k":"wagiswara","t":"He who takes refuge in the Awakened One,\nThe Doctrine and the Brotherhood, beholds\nBy right insight the Fourfold Noble Truths,"},{"k":"kaviratna","t":"He who takes refuge in the Enlightened One (buddha), in his Doctrine (dhamma), and in his Community of Monks (sangha), perceives with clarity of wisdom the Four Noble Truths, namely:"},{"k":"buddharakkhita","t":"He who has gone for refuge to the Buddha, the Teaching and his Order, penetrates with transcendental wisdom the Four Noble Truths — suffering, the cause of suffering, the cessation of suffering, and the Noble Eightfold Path leading to the cessation of suffering. [16]"},{"k":"thanissaro","t":"They go to many a refuge,\nto mountains and forests,\nto park and tree shrines:\npeople threatened with danger.\nThat's not the secure refuge,\nnot the supreme refuge,\nthat's not the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress.\n\nBut when, having gone\nto the Buddha, Dhamma,\n& Sangha for refuge,\nyou see with right discernment\nthe four noble truths —\nstress,\nthe cause of stress,\nthe transcending of stress,\n& the noble eightfold path,\nthe way to the stilling of stress:\nthat's the secure refuge,\nthat, the supreme refuge,\nthat is the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress."},{"k":"suddhaso","t":"But one who has gone for refuge\nto the Buddha, Dhamma, and Sangha,\nand who sees the Four Noble Truths\nwith correct wisdom -"},{"k":"sujato","t":"One gone for refuge to the Buddha,\nto his teaching and to the Saṅgha,\nsees the four noble truths\nwith right understanding:"}]},{"n":191,"vg":14,"pali":"Dukkhaṁ dukkhasamuppādaṁ,\ndukkhassa ca atikkamaṁ;\nAriyaṁ caṭṭhaṅgikaṁ maggaṁ,\ndukkhūpasamagāminaṁ.","v":[{"k":"muller","t":"Viz. pain, the origin of pain, the destruction of pain, and the eightfold holy way that leads to the quieting of pain;--"},{"k":"wagiswara","t":"Sorrow and sorrow's cause and sorrow's ceasing,\nThe Noble Eightfold Path that leads thereto--"},{"k":"kaviratna","t":"Suffering, the Origin of Suffering, the Cessation of Suffering, the Noble Eightfold Path (1) that leads to the cessation of suffering."},{"k":"buddharakkhita","t":"He who has gone for refuge to the Buddha, the Teaching and his Order, penetrates with transcendental wisdom the Four Noble Truths — suffering, the cause of suffering, the cessation of suffering, and the Noble Eightfold Path leading to the cessation of suffering. [16]"},{"k":"thanissaro","t":"They go to many a refuge,\nto mountains and forests,\nto park and tree shrines:\npeople threatened with danger.\nThat's not the secure refuge,\nnot the supreme refuge,\nthat's not the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress.\n\nBut when, having gone\nto the Buddha, Dhamma,\n& Sangha for refuge,\nyou see with right discernment\nthe four noble truths —\nstress,\nthe cause of stress,\nthe transcending of stress,\n& the noble eightfold path,\nthe way to the stilling of stress:\nthat's the secure refuge,\nthat, the supreme refuge,\nthat is the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress."},{"k":"suddhaso","t":"suffering, the origin of suffering,\nthe transcending of suffering,\nand the Noble Eightfold Path\nwhich leads to the pacification of suffering -"},{"k":"sujato","t":"suffering, suffering's origin,\nsuffering's transcendence,\nand the noble eightfold path\nthat leads to the stilling of suffering."}]},{"n":192,"vg":14,"pali":"Etaṁ kho saraṇaṁ khemaṁ,\netaṁ saraṇamuttamaṁ;\nEtaṁ saraṇamāgamma,\nsabbadukkhā pamuccati.","v":[{"k":"muller","t":"That is the safe refuge, that is the best refuge; having gone to that refuge, a man is delivered from all pain."},{"k":"wagiswara","t":"This is the refuge safe, the sure retreat;\nThis only from our woes can us release."},{"k":"kaviratna","t":"Suffering, the Origin of Suffering, the Cessation of Suffering, the Noble Eightfold Path (1) that leads to the cessation of suffering."},{"k":"buddharakkhita","t":"This indeed is the safe refuge, this the refuge supreme. Having gone to such a refuge, one is released from all suffering."},{"k":"thanissaro","t":"But when, having gone\nto the Buddha, Dhamma,\n& Sangha for refuge,\nyou see with right discernment\nthe four noble truths —\nstress,\nthe cause of stress,\nthe transcending of stress,\n& the noble eightfold path,\nthe way to the stilling of stress:\nthat's the secure refuge,\nthat, the supreme refuge,\nthat is the refuge,\nhaving gone to which,\nyou gain release\nfrom all suffering & stress."},{"k":"suddhaso","t":"this is a secure refuge,\nthis is the ultimate refuge.\nThis is the refuge\nwhich brings freedom from all suffering."},{"k":"sujato","t":"Such refuge is a sanctuary,\nit is the supreme refuge.\nBy going to that refuge,\nyou're released from all suffering."}]},{"n":193,"vg":14,"pali":"Dullabho purisājañño,\nna so sabbattha jāyati;\nYattha so jāyati dhīro,\ntaṁ kulaṁ sukhamedhati.","v":[{"k":"muller","t":"A supernatural person (a Buddha) is not easily found, he is not born everywhere. Wherever such a sage is born, that race prospers."},{"k":"wagiswara","t":"Hard is that one of noble birth to find;\nNot born in every land is He; the race\nWherein that Sage is born is prosperous."},{"k":"kaviratna","t":"An illumined person (a Buddha) is indeed very rare. He is not born everywhere. Wherever such a one takes birth, that family prospers."},{"k":"buddharakkhita","t":"Hard to find is the thoroughbred man (the Buddha); he is not born everywhere. Where such a wise man is born, that clan thrives happily."},{"k":"thanissaro","t":"It's hard to come by\na thoroughbred of a man.\nIt's simply not true\nthat he's born everywhere.\nWherever he's born, an enlightened one,\nthe family prospers,\nis happy."},{"k":"suddhaso","t":"It is hard to find a high-quality person;\nthey are not born everywhere.\nWherever a steadfast person is born,\ntheir family grows in happiness."},{"k":"sujato","t":"It's hard to find a thoroughbred man:\nthey're not born just anywhere.\nA family where that attentive one is born\nprospers in happiness."}]},{"n":194,"vg":14,"pali":"Sukho buddhānamuppādo,\nsukhā saddhammadesanā;\nSukhā saṅghassa sāmaggī,\nsamaggānaṁ tapo sukho.","v":[{"k":"muller","t":"Happy is the arising of the awakened, happy is the teaching of the True Law, happy is peace in the church, happy is the devotion of those who are at peace."},{"k":"wagiswara","t":"Blest is the rising of the Awakened Ones;\nBlest is Their teaching of the Doctrine True;\nBlest is the union of the Brotherhood;\nAnd blest to dwell together in unity."},{"k":"kaviratna","t":"Blessed is the birth of the Buddhas; blessed is the discourse on the Noble Law; blessed is the harmony of the Community of Monks; blessed is the devotion of those living in brotherhood."},{"k":"buddharakkhita","t":"Blessed is the birth of the Buddhas; blessed is the enunciation of the sacred Teaching; blessed is the harmony in the Order, and blessed is the spiritual pursuit of the united truth-seeker."},{"k":"thanissaro","t":"A blessing: the arising of Awakened Ones.\nA blessing: the teaching of true Dhamma.\nA blessing: the concord of the Sangha.\nThe austerity of those in concord\nis a blessing."},{"k":"suddhaso","t":"Happy is the arising of Awakened Ones,\nhappy is the teaching of the true Dhamma,\nhappy is the harmony of the Sangha,\nhappy is the austerity of those on the same Path."},{"k":"sujato","t":"Happy, the arising of Buddhas!\nHappy, the teaching of Dhamma!\nHappy is the harmony of the Saṅgha,\nand the striving of the harmonious is happy."}]},{"n":195,"vg":14,"pali":"Pūjārahe pūjayato,\nbuddhe yadi va sāvake;\nPapañcasamatikkante,\ntiṇṇasokapariddave.","v":[{"k":"muller","t":"He who pays homage to those who deserve homage, whether the awakened (Buddha) or their disciples, those who have overcome the host (of evils), and crossed the flood of sorrow, he who pays homage to such as have found deliverance and know no fear, his merit can never be measured by anybody."},{"k":"wagiswara","t":"The Awakened Ones and they that follow Them,\nWorthy to be adored, have conquered all\nThe hosts of evil, crossed the flood of sorrow."},{"k":"kaviratna","t":"He who pays homage to those who deserve homage, whether the Enlightened Ones or their disciples; he who has overcome the host of passions, and crossed the stream of grief and lamentations; he who pays homage to such as are emancipated and fearless — his merit cannot be measured."},{"k":"buddharakkhita","t":"He who reveres those worthy of reverence, the Buddhas and their disciples, who have transcended all obstacles and passed beyond the reach of sorrow and lamentation — he who reveres such peaceful and fearless ones, his merit none can compute by any measure."},{"k":"thanissaro","t":"If you worship those worthy of worship,\n— Awakened Ones or their disciples —\nwho've transcended\nobjectifications,\nlamentation,\n& grief,\nwho are unendangered,\nfearless,\nunbound:\nthere's no measure for reckoning\nthat your merit's 'this much.'"},{"k":"suddhaso","t":"One who honors those worthy of honor -\nAwakened Ones or their disciples,\nthose who have transcended complication\nand gone beyond sorrow and grief,"},{"k":"sujato","t":"When a person venerates the worthy—\nthe Buddha or his disciple,\nwho have transcended proliferation,\nand have left behind grief and lamentation,"}]},{"n":196,"vg":14,"pali":"Te tādise pūjayato,\nnibbute akutobhaye;\nNa sakkā puññaṁ saṅkhātuṁ,\nimettamapi kenaci.\nBuddhavaggo cuddasamo.\nPaṭhamabhāṇavāraṁ.","v":[{"k":"muller","t":"He who pays homage to those who deserve homage, whether the awakened (Buddha) or their disciples, those who have overcome the host (of evils), and crossed the flood of sorrow, he who pays homage to such as have found deliverance and know no fear, his merit can never be measured by anybody."},{"k":"wagiswara","t":"Whoso shall worship Them, the worthy Ones,\nIn whom desires are quenched and fear allayed,\nNone can declare the merits of that man."},{"k":"kaviratna","t":"He who pays homage to those who deserve homage, whether the Enlightened Ones or their disciples; he who has overcome the host of passions, and crossed the stream of grief and lamentations; he who pays homage to such as are emancipated and fearless — his merit cannot be measured."},{"k":"buddharakkhita","t":"He who reveres those worthy of reverence, the Buddhas and their disciples, who have transcended all obstacles and passed beyond the reach of sorrow and lamentation — he who reveres such peaceful and fearless ones, his merit none can compute by any measure."},{"k":"thanissaro","t":"If you worship those worthy of worship,\n— Awakened Ones or their disciples —\nwho've transcended\nobjectifications,\nlamentation,\n& grief,\nwho are unendangered,\nfearless,\nunbound:\nthere's no measure for reckoning\nthat your merit's 'this much.'"},{"k":"suddhaso","t":"who have reached Nibbāna,\nand are fearless -\nit is not possible to calculate the merit\nof one who honors such beings."},{"k":"sujato","t":"quenched, fearing nothing from any quarter—\nthe merit of one venerating such as these,\ncannot be calculated by anyone,\nsaying it is just this much."}]},{"n":197,"vg":15,"pali":"Susukhaṁ vata jīvāma,\nverinesu averino;\nVerinesu manussesu,\nviharāma averino.","v":[{"k":"muller","t":"Let us live happily then, not hating those who hate us! among men who hate us let us dwell free from hatred!"},{"k":"wagiswara","t":"O happily we live\nAngerless amid the angry!\nO happily we spend our days\nAmid the angry angerless!"},{"k":"kaviratna","t":"Blessed indeed are we who live among those who hate, hating no one; amidst those who hate, let us dwell without hatred."},{"k":"buddharakkhita","t":"Happy indeed we live, friendly amidst the hostile. Amidst hostile men we dwell free from hatred."},{"k":"thanissaro","t":"How very happily we live,\nfree from hostility\namong those who are hostile.\nAmong hostile people,\nfree from hostility we dwell."},{"k":"suddhaso","t":"Oh so happily we live,\nnon-hostile amidst the hostile.\nAmidst hostile people\nwe live without hostility."},{"k":"sujato","t":"Let us live so very happily,\nloving among the hostile.\nAmong hostile humans,\nlet us live with love."}]},{"n":198,"vg":15,"pali":"Susukhaṁ vata jīvāma,\nāturesu anāturā;\nĀturesu manussesu,\nviharāma anāturā.","v":[{"k":"muller","t":"Let us live happily then, free from ailments among the ailing! among men who are ailing let us dwell free from ailments!"},{"k":"wagiswara","t":"O happily we live\nIn health amid the sickly ones!\nO happily we spend our days\nAmid the sickly ones in health!"},{"k":"kaviratna","t":"Blessed indeed are we who live among those who are ailing, without ailments; amidst those who are so afflicted, let us live in good health."},{"k":"buddharakkhita","t":"Happy indeed we live, friendly amidst the afflicted (by craving). Amidst afflicted men we dwell free from affliction."},{"k":"thanissaro","t":"How very happily we live,\nfree from misery\namong those who are miserable.\nAmong miserable people,\nfree from misery we dwell."},{"k":"suddhaso","t":"Oh so happily we live,\nunafflicted amidst the afflicted.\nAmidst afflicted people\nwe live without affliction."},{"k":"sujato","t":"Let us live so very happily,\nhealthy among the ailing.\nAmong ailing humans\nlet us live healthily."}]},{"n":199,"vg":15,"pali":"Susukhaṁ vata jīvāma,\nussukesu anussukā;\nUssukesu manussesu,\nviharāma anussukā.","v":[{"k":"muller","t":"Let us live happily then, free from greed among the greedy! among men who are greedy let us dwell free from greed!"},{"k":"wagiswara","t":"O happily we live\nFree from greed amid the greedy!\nO happily we spend our days\nAmid the greedy free from greed!"},{"k":"kaviratna","t":"Blessed indeed are we who live among those who are yearning for sense delights, without yearning for such things; amidst those who are yearning for sense delights, let us dwell without yearning."},{"k":"buddharakkhita","t":"Happy indeed we live, free from avarice amidst the avaricious. Amidst the avaricious men we dwell free from avarice."},{"k":"thanissaro","t":"How very happily we live,\nfree from busyness\namong those who are busy.\nAmong busy people,\nfree from busyness we dwell."},{"k":"suddhaso","t":"Oh so happily we live,\nunpreoccupied amidst the preoccupied.\nAmidst preoccupied people\nwe live without preoccupation."},{"k":"sujato","t":"Let us live so very happily,\ncontent among the greedy.\nAmong greedy humans,\nlet us live content."}]},{"n":200,"vg":15,"pali":"Susukhaṁ vata jīvāma,\nyesaṁ no natthi kiñcanaṁ;\nPītibhakkhā bhavissāma,\ndevā ābhassarā yathā.","v":[{"k":"muller","t":"Let us live happily then, though we call nothing our own! We shall be like the bright gods, feeding on happiness!"},{"k":"wagiswara","t":"O happily we live\nWho have not anything at all!\nLike ever-radiant gods above,\nOur food immortal joys shall be."},{"k":"kaviratna","t":"Happy indeed are we who live without possessions. Let us feed on happiness, like the radiant gods (who feed on spiritual bliss)."},{"k":"buddharakkhita","t":"Happy indeed we live, we who possess nothing. Feeders on joy we shall be, like the Radiant Gods."},{"k":"thanissaro","t":"How very happily we live,\nwe who have nothing.\nWe will feed on rapture\nlike the Radiant gods."},{"k":"suddhaso","t":"Oh so happily we live,\nwe who have nothing.\nWe will feed on bliss,\nlike the radiant angels."},{"k":"sujato","t":"Let us live so very happily,\nwe who have nothing.\nWe shall feed on rapture,\nlike the gods of streaming radiance."}]},{"n":201,"vg":15,"pali":"Jayaṁ veraṁ pasavati,\ndukkhaṁ seti parājito;\nUpasanto sukhaṁ seti,\nhitvā jayaparājayaṁ.","v":[{"k":"muller","t":"Victory breeds hatred, for the conquered is unhappy. He who has given up both victory and defeat, he, the contented, is happy."},{"k":"wagiswara","t":"Hate follows victory;\nConquered ones sit sorrowing.\nBut the calm live blissfully,\nRenouncing conquest and defeat."},{"k":"kaviratna","t":"Victory breeds enmity; the vanquished one dwells in sorrow; the composed person lives happily, disregarding both victory and defeat."},{"k":"buddharakkhita","t":"Victory begets enmity; the defeated dwell in pain. Happily the peaceful live, discarding both victory and defeat."},{"k":"thanissaro","t":"Winning gives birth to hostility.\nLosing, one lies down in pain.\nThe calmed lie down with ease,\nhaving set\nwinning & losing\naside."},{"k":"suddhaso","t":"Victory produces hostility;\nthe defeated sleep uncomfortably.\nThe peaceful sleep happily,\nhaving relinquished both victory and defeat."},{"k":"sujato","t":"Victory breeds enmity;\nthe defeated sleep badly.\nThe peaceful sleep at ease,\nhaving left victory and defeat behind."}]},{"n":202,"vg":15,"pali":"Natthi rāgasamo aggi,\nNatthi dosasamo kali;\nNatthi khandhasamā dukkhā,\nNatthi santiparaṁ sukhaṁ.","v":[{"k":"muller","t":"There is no fire like passion; there is no losing throw like hatred; there is no pain like this body; there is no happiness higher than rest."},{"k":"wagiswara","t":"There is no fire like lust;\nNo sin brings such ill-luck as hate;\nNo pains so great as body's pains;\nNo bliss is like the perfect Calm."},{"k":"kaviratna","t":"There is no fire like passion; there is no blemish like hatred; there is no suffering like physical existence (the five aggregates or skandhas) and there is no bliss equal to the calm (of nirvana)."},{"k":"buddharakkhita","t":"There is no fire like lust and no crime like hatred. There is no ill like the aggregates (of existence) and no bliss higher than the peace (of Nibbana). [17]"},{"k":"thanissaro","t":"There's no fire like passion,\nno loss like anger,\nno pain like the aggregates,\nno ease other than peace."},{"k":"suddhaso","t":"There is no fire as strong as passion,\nno distress as strong as aversion,\nno suffering as strong as the components of being,\nno happiness greater than peace"},{"k":"sujato","t":"There is no fire like greed,\nno crime like hate,\nno suffering like the aggregates,\nno bliss beyond peace."}]},{"n":203,"vg":15,"pali":"Jighacchāparamā rogā,\nsaṅkhāraparamā dukhā;\nEtaṁ ñatvā yathābhūtaṁ,\nnibbānaṁ paramaṁ sukhaṁ.","v":[{"k":"muller","t":"Hunger is the worst of diseases, the body the greatest of pains; if one knows this truly, that is Nirvana, the highest happiness."},{"k":"wagiswara","t":"Hunger's the greatest plague,\nEmbodied life the greatest woe;\nWhoso knows this in truth, can say:\n\"Nibbāna is the Bliss Supreme.\""},{"k":"kaviratna","t":"Greed is the worst of afflictions; mental and emotional tendencies are the greatest of sorrows. Having perceived this fact truly, one realizes nirvana, the highest bliss."},{"k":"buddharakkhita","t":"Hunger is the worst disease, conditioned things the worst suffering. Knowing this as it really is, the wise realize Nibbana, the highest bliss."},{"k":"thanissaro","t":"Hunger: the foremost illness.\nFabrications: the foremost pain.\nFor one knowing this truth\nas it actually is,\nUnbinding\nis the foremost ease."},{"k":"suddhaso","t":"Hunger is the highest affliction,\nconditions are the highest suffering;\nfor one who truly knows this,\nNibbāna is the highest happiness."},{"k":"sujato","t":"Hunger is the worst illness,\nconditions are the worst suffering.\nWhen one has known this as it is.\nextinguishment is the ultimate happiness."}]},{"n":204,"vg":15,"pali":"Ārogyaparamā lābhā,\nSantuṭṭhiparamaṁ dhanaṁ;\nVissāsaparamā ñāti,\nNibbānaṁ paramaṁ sukhaṁ.","v":[{"k":"muller","t":"Health is the greatest of gifts, contentedness the best riches; trust is the best of relationships, Nirvana the highest happiness."},{"k":"wagiswara","t":"Health is the greatest gain;\nContentment is the greatest wealth;\nBest kinsman is the trusty friend;\nNibbāna is the Bliss Supreme."},{"k":"kaviratna","t":"Health is the greatest of gifts, contentment the greatest of riches; trust is the finest of relationships and nirvana the highest bliss."},{"k":"buddharakkhita","t":"Health is the most precious gain and contentment the greatest wealth. A trustworthy person is the best kinsman, Nibbana the highest bliss."},{"k":"thanissaro","t":"Freedom from illness: the foremost good fortune.\nContentment: the foremost wealth.\nTrust: the foremost kinship.\nUnbinding: the foremost ease."},{"k":"suddhaso","t":"Freedom from illness is the highest acquisition,\ncontentment is the highest wealth,\ntrust is the highest kin,\nNibbāna is the highest happiness."},{"k":"sujato","t":"Health is the ultimate blessing;\ncontentment, the ultimate wealth;\ntrust is the ultimate family;\nextinguishment, the ultimate happiness."}]},{"n":205,"vg":15,"pali":"Pavivekarasaṁ pitvā,\nrasaṁ upasamassa ca;\nNiddaro hoti nippāpo,\ndhammapītirasaṁ pivaṁ.","v":[{"k":"muller","t":"He who has tasted the sweetness of solitude and tranquillity, is free from fear and free from sin, while he tastes the sweetness of drinking in the law."},{"k":"wagiswara","t":"Who tastes the savour sweet\nOf solitude, who drinks of calm,\nIs free from terror, free from sin,\nDraining the nectar of the Norm."},{"k":"kaviratna","t":"Having tasted the sweetness of solitude and of inner tranquillity, he becomes free of woe and sin, enjoying the sweetness of the bliss of the Dhamma."},{"k":"buddharakkhita","t":"Having savored the taste of solitude and peace (of Nibbana), pain-free and stainless he becomes, drinking deep the taste of the bliss of the Truth."},{"k":"thanissaro","t":"Drinking the nourishment,\nthe flavor,\nof seclusion & calm,\none is freed from evil, devoid\nof distress,\nrefreshed with the nourishment\nof rapture in the Dhamma."},{"k":"suddhaso","t":"Having tasted the flavor of seclusion\nand the flavor of peace,\nfree from anguish, flawless,\none tastes the bliss of the Dhamma."},{"k":"sujato","t":"Having drunk the nectar of seclusion\nand the nectar of peace—\nfree of stress, free of evil,\ndrink the joyous nectar of truth."}]},{"n":206,"vg":15,"pali":"Sāhu dassanamariyānaṁ,\nsannivāso sadā sukho;\nAdassanena bālānaṁ,\nniccameva sukhī siyā.","v":[{"k":"muller","t":"The sight of the elect (Arya) is good, to live with them is always happiness; if a man does not see fools, he will be truly happy."},{"k":"wagiswara","t":"'Tis good to see the saints;\nTo dwell with them is blessedness;\nIf he should never fools behold,\nA man could dwell in happiness."},{"k":"kaviratna","t":"Glorious is it to see the Noble Ones; their company at all times brings happiness; by not seeing the spiritually ignorant, one will always be happy."},{"k":"buddharakkhita","t":"Good is it to see the Noble Ones; to live with them is ever blissful. One will always be happy by not encountering fools."},{"k":"thanissaro","t":"It's good to see Noble Ones.\nHappy their company — always.\nThrough not seeing fools\nconstantly, constantly\none would be happy."},{"k":"suddhaso","t":"It is good to see the Noble Ones,\nliving with them is always pleasant.\nOne who does not see fools\nwill always be happy."},{"k":"sujato","t":"It's good to see the noble ones,\nstaying with them is always good.\nWere you not to see fools,\nyou'd always be happy."}]},{"n":207,"vg":15,"pali":"Bālasaṅgatacārī hi,\ndīghamaddhāna socati;\nDukkho bālehi saṁvāso,\namitteneva sabbadā;\nDhīro ca sukhasaṁvāso,\nñātīnaṁva samāgamo.","v":[{"k":"muller","t":"He who walks in the company of fools suffers a long way; company with fools, as with an enemy, is always painful; company with the wise is pleasure, like meeting with kinsfolk."},{"k":"wagiswara","t":"The company of fools\nNe'er fails to bring distress.\nTo live with fools brings suffering,\nAs living with an enemy,\nBut wise men's company brings bliss,\nAs being with dear relatives."},{"k":"kaviratna","t":"He who leads a life in the company of fools suffers long; it is as painful to live with fools as it is with a foe; association with the wise brings happiness as does the company of one's kinsfolk."},{"k":"buddharakkhita","t":"Indeed, he who moves in the company of fools grieves for longing. Association with fools is ever painful, like partnership with an enemy. But association with the wise is happy, like meeting one's own kinsmen."},{"k":"thanissaro","t":"For, living with a fool,\none grieves a long time.\nPainful is communion with fools,\nas with an enemy —\nalways.\nHappy is communion\nwith the enlightened,\nas with a gathering of kin."},{"k":"suddhaso","t":"Those who go with fools\nwill sorrow for a long time.\nLiving with fools is painful,\nlike being with an enemy all the time.\nBut living with the wise is pleasant,\nlike being together with one's relatives."},{"k":"sujato","t":"For one who consorts with fools\ngrieves long.\nPainful is living with fools,\nlike being stuck with your enemy.\nHappy is living with an attentive one,\nlike meeting with your kin."}]},{"n":208,"vg":15,"pali":"Tasmā hi—\nDhīrañca paññañca bahussutañca,\nDhorayhasīlaṁ vatavantamariyaṁ;\nTaṁ tādisaṁ sappurisaṁ sumedhaṁ,\nBhajetha nakkhattapathaṁva candimā.\nSukhavaggo pannarasamo.","v":[{"k":"muller","t":"Therefore, one ought to follow the wise, the intelligent, the learned, the much enduring, the dutiful, the elect; one ought to follow a good and wise man, as the moon follows the path of the stars."},{"k":"wagiswara","t":"If one be good and wise,\nWell-versed in lore profound,\nLong-suffering, dutiful, a saint,\nRighteous and wise; if such there be,\nFollow his footsteps, as the moon\nFollows the path of the stars."},{"k":"kaviratna","t":"Therefore, one should follow the steadfast, the wise, the educated, the self-reliant, the dutiful and the noble. Even as the moon follows the path of the stars, so ought one to follow such a virtuous and highly intelligent man."},{"k":"buddharakkhita","t":"Therefore, follow the Noble One, who is steadfast, wise, learned, dutiful and devout. One should follow only such a man, who is truly good and discerning, even as the moon follows the path of the stars."},{"k":"thanissaro","t":"So:\nthe enlightened man —\ndiscerning, learned,\nenduring, dutiful, noble,\nintelligent, a man of integrity:\nfollow him\n— one of this sort —\nas the moon, the path\nof the zodiac stars."},{"k":"suddhaso","t":"Therefore,\nfollow one who is steadfast, wise, and educated,\na good person who is patient, religious, noble, and astute,\nfollow that person,\nas the moon follows the path of the stars."},{"k":"sujato","t":"Therefore:\nAn attentive one, wise and learned,\na behemoth of virtue, true to their vows, noble:\nfollow a true and intelligent person such as this,\nas the moon tracks the path of the stars."}]},{"n":209,"vg":16,"pali":"Ayoge yuñjamattānaṁ,\nyogasmiñca ayojayaṁ;\nAtthaṁ hitvā piyaggāhī,\npihetattānuyoginaṁ.","v":[{"k":"muller","t":"He who gives himself to vanity, and does not give himself to meditation, forgetting the real aim (of life) and grasping at pleasure, will in time envy him who has exerted himself in meditation."},{"k":"wagiswara","t":"He who applies his mind unworthily,\nNeglecting discipline,\nForsakes the goal and clings to things beloved,\nThen envies those to meditation given."},{"k":"kaviratna","t":"He who gives himself to what is not befitting and thus forgets his own quest; he who indulges in sense pleasures envies the person who exerts himself in meditation."},{"k":"buddharakkhita","t":"Giving himself to things to be shunned and not exerting where exertion is needed, a seeker after pleasures, having given up his true welfare, envies those intent upon theirs."},{"k":"thanissaro","t":"Having applied himself\nto what was not his own task,\nand not having applied himself\nto what was,\nhaving disregarded the goal\nto grasp at what he held dear,\nhe now envies those\nwho kept after themselves,\ntook themselves\nto task."},{"k":"suddhaso","t":"One who is dedicated to that which is not worthy of dedication,\nand who is not dedicated to that which is worthy of dedication,\nhas dropped the goal and grabbed their preferences -\nyet envies those who are intent upon self-development."},{"k":"sujato","t":"Applying yourself where you ought not,\nneglecting what you should be doing,\nforgetting your goal, you cling to what you hold dear,\njealous of those devoted to their heart's goal."}]},{"n":210,"vg":16,"pali":"Mā piyehi samāgañchi,\nappiyehi kudācanaṁ;\nPiyānaṁ adassanaṁ dukkhaṁ,\nappiyānañca dassanaṁ.","v":[{"k":"muller","t":"Let no man ever look for what is pleasant, or what is unpleasant. Not to see what is pleasant is pain, and it is pain to see what is unpleasant."},{"k":"wagiswara","t":"Join not thyself to things beloved or loathed.\nTo lack dear company,\nTo be with those we loathe, brings misery."},{"k":"kaviratna","t":"Do not become attached to what is pleasing nor to what is displeasing; not to see what is dear to one is painful, as also is the sight of the unpleasant."},{"k":"buddharakkhita","t":"Seek no intimacy with the beloved and also not with the unloved, for not to see the beloved and to see the unloved, both are painful."},{"k":"thanissaro","t":"Don't ever — regardless —\nbe conjoined with what's dear\nor undear.\nIt's painful\nnot to see what's dear\nor to see what's not."},{"k":"suddhaso","t":"Don't get caught up in what you prefer\nor in what you do not prefer.\nNot seeing what you prefer is hard to bear\nand so is seeing what you do not prefer."},{"k":"sujato","t":"Don't ever get too close\nto those you like or dislike.\nFor not seeing the liked is suffering,\nand so is seeing the disliked."}]},{"n":211,"vg":16,"pali":"Tasmā piyaṁ na kayirātha,\npiyāpāyo hi pāpako;\nGanthā tesaṁ na vijjanti,\nyesaṁ natthi piyāppiyaṁ.","v":[{"k":"muller","t":"Let, therefore, no man love anything; loss of the beloved is evil. Those who love nothing and hate nothing, have no fetters."},{"k":"wagiswara","t":"Seek not for love; things loved when lost bring woe;\nBoth are impermanent.\nThey have no bonds who dwell indifferent."},{"k":"kaviratna","t":"Therefore, let no one cherish anything, inasmuch as the loss of what is beloved is hard. There are no fetters for him who knows neither pleasure nor pain."},{"k":"buddharakkhita","t":"Therefore hold nothing dear, for separation from the dear is painful. There are no bonds for those who have nothing beloved or unloved."},{"k":"thanissaro","t":"So don't make anything dear,\nfor it's dreadful to be far\nfrom what's dear.\nNo bonds are found\nfor those for whom\nthere's neither dear\nnor undear."},{"k":"suddhaso","t":"Therefore don't form any preference;\nloss of what one prefers is painful.\nOne who has no attachments\nhas no preferences."},{"k":"sujato","t":"Therefore don't hold anything dear,\nfor it's bad to lose those you love.\nNo ties are found in they who\nhold nothing loved or loathed."}]},{"n":212,"vg":16,"pali":"Piyato jāyatī soko,\npiyato jāyatī bhayaṁ;\nPiyato vippamuttassa,\nnatthi soko kuto bhayaṁ.","v":[{"k":"muller","t":"From pleasure comes grief, from pleasure comes fear; he who is free from pleasure knows neither grief nor fear."},{"k":"wagiswara","t":"Sorrow and fear are born of things beloved.\nFrom things beloved set free,\nHow canst thou sorrow? fearful how canst be?"},{"k":"kaviratna","t":"From pleasure arises sorrow; from pleasure arises fear. To him who is free from pleasure there is no sorrow. Whence, then, comes fear?"},{"k":"buddharakkhita","t":"From endearment springs grief, from endearment springs fear. For one who is wholly free from endearment there is no grief, whence then fear?"},{"k":"thanissaro","t":"From what's dear is born grief,\nfrom what's dear is born fear.\nFor one freed from what's dear\nthere's no grief\n— so how fear?"},{"k":"suddhaso","t":"Sorrow is born from preference,\nfear is born from preference;\none who is free from preference\nhas no sorrow and no fear."},{"k":"sujato","t":"Sorrow springs from what we hold dear,\nfear springs from what we hold dear;\none free from holding anything dear\nhas no sorrow, let alone fear."}]},{"n":213,"vg":16,"pali":"Pemato jāyatī soko,\npemato jāyatī bhayaṁ;\nPemato vippamuttassa,\nnatthi soko kuto bhayaṁ.","v":[{"k":"muller","t":"From affection comes grief, from affection comes fear; he who is free from affection knows neither grief nor fear."},{"k":"wagiswara","t":"From things held dear, sorrow and fear are born.\nSet free from things held dear,\nHow canst thou sorrow have? how canst have fear?"},{"k":"kaviratna","t":"From affection arises sorrow; from affection arises fear. To him who is free from affection there is no sorrow. Whence fear?"},{"k":"buddharakkhita","t":"From affection springs grief, from affection springs fear. For one who is wholly free from affection there is no grief, whence then fear?"},{"k":"thanissaro","t":"From what's loved is born grief,\nfrom what's loved is born fear.\nFor one freed from what's loved\nthere's no grief\n— so how fear?"},{"k":"suddhaso","t":"Sorrow is born from affection,\nfear is born from affection;\none who is free from affection\nhas no sorrow and no fear."},{"k":"sujato","t":"Sorrow springs from attachment,\nfear springs from attachment;\none free from attachment\nhas no sorrow, let alone fear."}]},{"n":214,"vg":16,"pali":"Ratiyā jāyatī soko,\nratiyā jāyatī bhayaṁ;\nRatiyā vippamuttassa,\nnatthi soko kuto bhayaṁ.","v":[{"k":"muller","t":"From lust comes grief, from lust comes fear; he who is free from lust knows neither grief nor fear."},{"k":"wagiswara","t":"Sorrow and fear are children born of pleasure.\nNo longer pleasure's slave,\nHow canst thou sorrow, fear how canst thou have?"},{"k":"kaviratna","t":"From attachment arises sorrow; from attachment arises fear. To him who is free from attachment there is no sorrow. Whence fear?"},{"k":"buddharakkhita","t":"From attachment springs grief, from attachment springs fear. For one who is wholly free from attachment there is no grief, whence then fear?"},{"k":"thanissaro","t":"From delight is born grief,\nfrom delight is born fear.\nFor one freed from delight\nthere's no grief\n— so how fear?"},{"k":"suddhaso","t":"Sorrow is born from partiality,\nfear is born from partiality;\none who is free from partiality\nhas no sorrow and no fear."},{"k":"sujato","t":"Sorrow springs from relishing,\nfear springs from relishing;\none free from relishing\nhas no sorrow, let alone fear."}]},{"n":215,"vg":16,"pali":"Kāmato jāyatī soko,\nkāmato jāyatī bhayaṁ;\nKāmato vippamuttassa,\nnatthi soko kuto bhayaṁ.","v":[{"k":"muller","t":"From love comes grief, from love comes fear; he who is free from love knows neither grief nor fear."},{"k":"wagiswara","t":"Sorrow and fear are children of desire.\nFrom all desire set free,\nHow canst thou sorrow? fearful how canst be?"},{"k":"kaviratna","t":"From desire arises sorrow, from desire arises fear. To him who is free from desire there is no sorrow. Whence fear?"},{"k":"buddharakkhita","t":"From lust springs grief, from lust springs fear. For one who is wholly free from craving there is no grief; whence then fear?"},{"k":"thanissaro","t":"From sensuality is born grief,\nfrom sensuality is born fear.\nFor one freed from sensuality\nthere's no grief\n— so how fear?"},{"k":"suddhaso","t":"Sorrow is born from sensuality,\nfear is born from sensuality;\none who is free from sensuality\nhas no sorrow and no fear."},{"k":"sujato","t":"Sorrow springs from desire,\nfear springs from desire;\none free from desire\nhas no sorrow, let alone fear."}]},{"n":216,"vg":16,"pali":"Taṇhāya jāyatī soko,\ntaṇhāya jāyatī bhayaṁ;\nTaṇhāya vippamuttassa,\nnatthi soko kuto bhayaṁ.","v":[{"k":"muller","t":"From greed comes grief, from greed comes fear; he who is free from greed knows neither grief nor fear."},{"k":"wagiswara","t":"Sorrow and fear are things of longing born.\nFrom longing if thou part,\nThou hast no fear nor sorrow in thine heart."},{"k":"kaviratna","t":"From craving arises sorrow; from craving arises fear. To him who is free from craving there is no sorrow. Whence fear?"},{"k":"buddharakkhita","t":"From craving springs grief, from craving springs fear. For one who is wholly free from craving there is no grief; whence then fear?"},{"k":"thanissaro","t":"From craving is born grief,\nfrom craving is born fear.\nFor one freed from craving\nthere's no grief\n— so how fear?"},{"k":"suddhaso","t":"Sorrow is born from craving,\nfear is born from craving;\none who is free from craving\nhas no sorrow and no fear."},{"k":"sujato","t":"Sorrow springs from craving,\nfear springs from craving;\none free from craving\nhas no sorrow, let alone fear."}]},{"n":217,"vg":16,"pali":"Sīladassanasampannaṁ,\ndhammaṭṭhaṁ saccavedinaṁ;\nAttano kamma kubbānaṁ,\ntaṁ jano kurute piyaṁ.","v":[{"k":"muller","t":"He who possesses virtue and intelligence, who is just, speaks the truth, and does what is his own business, him the world will hold dear."},{"k":"wagiswara","t":"Upright and Norm-abiding, speaking truth,\nWho minds his own affair,\nThat is the man whom every one holds dear."},{"k":"kaviratna","t":"He who possesses virtue and spiritual insight, who is well established in the Dhamma, who is truthful, who performs his duties, him the people hold dear."},{"k":"buddharakkhita","t":"People hold dear him who embodies virtue and insight, who is principled, has realized the truth, and who himself does what he ought to be doing."},{"k":"thanissaro","t":"One consummate in virtue & vision,\njudicious,\nspeaking the truth,\ndoing his own task:\nthe world holds him dear."},{"k":"suddhaso","t":"One who has perfect morality and wisdom,\nwho is established in the Dhamma and understands truth,\nand who works on themself -\nthis is the kind of person that the populace prefers."},{"k":"sujato","t":"One accomplished in virtue and vision,\nfirmly principled, and truthful,\ndoing oneself what ought be done:\nthat's who the people love."}]},{"n":218,"vg":16,"pali":"Chandajāto anakkhāte,\nManasā ca phuṭo siyā;\nKāmesu ca appaṭibaddhacitto,\nUddhaṁsototi vuccati.","v":[{"k":"muller","t":"He in whom a desire for the Ineffable (Nirvana) has sprung up, who is satisfied in his mind, and whose thoughts are not bewildered by love, he is called urdhvamsrotas (carried upwards by the stream)."},{"k":"wagiswara","t":"In whom is longing for the Nameless born,\nWhose mind It hath enthralled,\nWhose thoughts no longer are by passion torn,\nThat man \"a Climber of the Stream\" is called."},{"k":"kaviratna","t":"He in whom is born a sublime longing for the Ineffable, whose mind is permeated by this longing, whose thoughts are not bewildered by attachment — such a person is called \"one bound upstream.\""},{"k":"buddharakkhita","t":"One who is intent upon the Ineffable (Nibbana), dwells with mind inspired (by supramundane wisdom), and is no more bound by sense pleasures — such a man is called \"One Bound Upstream.\" [18]"},{"k":"thanissaro","t":"If\nyou've given birth to a wish\nfor what can't be expressed,\nare suffused with heart,\nyour mind not enmeshed\nin sensual passions:\nyou're said to be\nin the up-flowing stream."},{"k":"suddhaso","t":"Interested in the inexpressible,\nwith an expanded mind,\nand not bound by sensuality -\nsuch a one is said be going upstream."},{"k":"sujato","t":"One eager to realize the ineffable\nwould be filled with awareness.\nTheir mind not bound to pleasures of sense,\nthey're said to be heading upstream."}]},{"n":219,"vg":16,"pali":"Cirappavāsiṁ purisaṁ,\ndūrato sotthimāgataṁ;\nÑātimittā suhajjā ca,\nabhinandanti āgataṁ.","v":[{"k":"muller","t":"Kinsmen, friends, and lovers salute a man who has been long away, and returns safe from afar."},{"k":"wagiswara","t":"As when a dweller in some far-off land\nSafe home returns at last,\nKin, friends and lovers waiting to greet him stand;"},{"k":"kaviratna","t":"When a man who has been away for a long time returns home safely, his kinsmen, friends and well-wishers welcome him gladly."},{"k":"buddharakkhita","t":"When, after a long absence, a man safely returns from afar, his relatives, friends and well-wishers welcome him home on arrival."},{"k":"thanissaro","t":"A man long absent\ncomes home safe from afar.\nHis kin, his friends, his companions,\ndelight in his return."},{"k":"suddhaso","t":"When a person who has been away for a long time\narrives safely from afar,\ntheir relatives, friends, and loved ones\ndelight in that arrival."},{"k":"sujato","t":"When a man returns safely\nafter a long time spent abroad,\nfamily, friends, and loved ones\ncelebrate his return."}]},{"n":220,"vg":16,"pali":"Tatheva katapuññampi,\nasmā lokā paraṁ gataṁ;\nPuññāni paṭigaṇhanti,\npiyaṁ ñātīva āgataṁ.\nPiyavaggo soḷasamo.","v":[{"k":"muller","t":"In like manner his good works receive him who has done good, and has gone from this world to the other;--as kinsmen receive a friend on his return."},{"k":"wagiswara","t":"So, when a man on earth good deeds hath done,\nWhen he hath passed beyond,\nAll his good deeds like kin, await that one."},{"k":"kaviratna","t":"When a man has departed from this world to the next, the effects of his good deeds receive him gladly, even as kinsmen welcome a friend on his return home."},{"k":"buddharakkhita","t":"As kinsmen welcome a dear one on arrival, even so his own good deeds will welcome the doer of good who has gone from this world to the next."},{"k":"thanissaro","t":"In just the same way,\nwhen you've done good\n& gone from this world\nto the world beyond,\nyour good deeds receive you —\nas kin, someone dear\ncome home."},{"k":"suddhaso","t":"In the same way, when one who has made merit\ngoes from this world to the next,\nthey are received by their merit\nlike the arrival of a beloved relative."},{"k":"sujato","t":"Just so, when one who has done good\ngoes from this world to the next,\ntheir good deeds receive them there,\nas family welcomes home one they love."}]},{"n":221,"vg":17,"pali":"Kodhaṁ jahe vippajaheyya mānaṁ,\nSaṁyojanaṁ sabbamatikkameyya;\nTaṁ nāmarūpasmimasajjamānaṁ,\nAkiñcanaṁ nānupatanti dukkhā.","v":[{"k":"muller","t":"Let a man leave anger, let him forsake pride, let him overcome all bondage! No sufferings befall the man who is not attached to name and form, and who calls nothing his own."},{"k":"wagiswara","t":"Conquer anger, banish pride;\nEvery fetter cast aside;\nClinging not to Name and Form,\nHim who calleth nought his own\nSorrow never shall betide."},{"k":"kaviratna","t":"Let a man abandon anger, let him renounce pride and let him get beyond all worldly fetters. No suffering befalls him who is passionless and clings neither to mind nor to form (nama-rupa)."},{"k":"buddharakkhita","t":"One should give up anger, renounce pride, and overcome all fetters. Suffering never befalls him who clings not to mind and body and is detached."},{"k":"thanissaro","t":"Abandon anger,\nbe done with conceit,\nget beyond every fetter.\nWhen for name & form\nyou have no attachment\n— have nothing at all —\nno sufferings, no stresses, invade."},{"k":"suddhaso","t":"Abandon anger, discard conceit,\ncompletely transcend the fetter;\nNot adhering to mind and body,\npossessing nothing, one does not fall into suffering."},{"k":"sujato","t":"Give up anger, get rid of conceit,\nand escape every fetter.\nSufferings don't befall one who has nothing,\nnot clinging to name and form."}]},{"n":222,"vg":17,"pali":"Yo ve uppatitaṁ kodhaṁ,\nrathaṁ bhantaṁva vāraye;\nTamahaṁ sārathiṁ brūmi,\nrasmiggāho itaro jano.","v":[{"k":"muller","t":"He who holds back rising anger like a rolling chariot, him I call a real driver; other people are but holding the reins."},{"k":"wagiswara","t":"He who rising wrath restrains,\nAs one checks a whirling team,\nHim a driver true I deem;\nOthers only hold the reins."},{"k":"kaviratna","t":"He who controls his rising anger as a skilled driver curbs a rolling chariot, him I call a true charioteer. Others merely hold the reins."},{"k":"buddharakkhita","t":"He who checks rising anger as a charioteer checks a rolling chariot, him I call a true charioteer. Others only hold the reins."},{"k":"thanissaro","t":"When anger arises,\nwhoever keeps firm control\nas if with a racing chariot:\nhim\nI call a master charioteer.\nAnyone else,\na rein-holder —\nthat's all."},{"k":"suddhaso","t":"When anger arises,\none who stops it like a runaway cart -\nThat is the one I call a charioteer;\nother people just hold the reins."},{"k":"sujato","t":"When anger surges like a lurching chariot,\nkeep it in check.\nThat's what I call a charioteer;\nothers just hold the reins."}]},{"n":223,"vg":17,"pali":"Akkodhena jine kodhaṁ,\nasādhuṁ sādhunā jine;\nJine kadariyaṁ dānena,\nsaccenālikavādinaṁ.","v":[{"k":"muller","t":"Let a man overcome anger by love, let him overcome evil by good; let him overcome the greedy by liberality, the liar by truth!"},{"k":"wagiswara","t":"Wrath with kindliness allay,\nTo the stingy freely give;\nConquer lying words with truth;\nEvil deeds with good repay."},{"k":"kaviratna","t":"Let a man conquer anger by love, let him subdue evil by good; let him overcome the greedy by liberality and the liar by truth."},{"k":"buddharakkhita","t":"Overcome the angry by non-anger; overcome the wicked by goodness; overcome the miser by generosity; overcome the liar by truth."},{"k":"thanissaro","t":"Conquer anger\nwith lack of anger;\nbad, with good;\nstinginess, with a gift;\na liar, with truth."},{"k":"suddhaso","t":"By means of non-anger one defeats anger,\nby means of excellence one defeats non-excellence,\nby means of generosity one defeats stinginess,\nby means of truth one defeats lies."},{"k":"sujato","t":"Defeat anger with kindness,\nvillainy with virtue,\nstinginess with giving,\nand lies with truth."}]},{"n":224,"vg":17,"pali":"Saccaṁ bhaṇe na kujjheyya,\ndajjā appampi yācito;\nEtehi tīhi ṭhānehi,\ngacche devāna santike.","v":[{"k":"muller","t":"Speak the truth, do not yield to anger; give, if thou art asked for little; by these three steps thou wilt go near the gods."},{"k":"wagiswara","t":"Speak the truth nor vexed be;\nGive, however scantily.\nFollowing these maxims three,\nThou the blessed gods shalt see."},{"k":"kaviratna","t":"One should always speak the truth, not yield to anger, and give, even though it be little, to the person who begs. By these three virtues, a man is able to come into the presence of the devas."},{"k":"buddharakkhita","t":"Speak the truth; yield not to anger; when asked, give even if you only have a little. By these three means can one reach the presence of the gods."},{"k":"thanissaro","t":"By telling the truth;\nby not growing angry;\nby giving, when asked,\nno matter how little you have:\nby these three things\nyou enter the presence of devas."},{"k":"suddhaso","t":"Speak the truth, do not get angry,\nand give - even just a little bit - when asked;\nby means of these three things\nyou will enter the presence of the angels."},{"k":"sujato","t":"Speak the truth, do not be angry,\nand give when asked, if only a little.\nBy these three means,\nyou may enter the presence of the gods."}]},{"n":225,"vg":17,"pali":"Ahiṁsakā ye munayo,\nniccaṁ kāyena saṁvutā;\nTe yanti accutaṁ ṭhānaṁ,\nyattha gantvā na socare.","v":[{"k":"muller","t":"The sages who injure nobody, and who always control their body, they will go to the unchangeable place (Nirvana), where, if they have gone, they will suffer no more."},{"k":"wagiswara","t":"Sages harm no living thing;\nSelf-restraint accomplishing\nSuch men reach the Deathless Lot,\nWhere all sorrow is forgot."},{"k":"kaviratna","t":"Those sages who observe nonviolence, who are ever controlled in body, attain the changeless state (nirvana) where, having gone, they suffer no more."},{"k":"buddharakkhita","t":"Those sages who are inoffensive and ever restrained in body, go to the Deathless State, where, having gone, they grieve no more."},{"k":"thanissaro","t":"Gentle sages,\nconstantly restrained in body,\ngo to the unwavering state\nwhere, having gone,\nthere's no grief."},{"k":"suddhaso","t":"Those sages who are harmless,\nwho are always physically restrained,\ngo to the undying state\nwhere they do not sorrow."},{"k":"sujato","t":"Those harmless sages,\nalways restrained in body,\ngo to the state that does not pass,\nwhere there is no sorrow."}]},{"n":226,"vg":17,"pali":"Sadā jāgaramānānaṁ,\nahorattānusikkhinaṁ;\nNibbānaṁ adhimuttānaṁ,\natthaṁ gacchanti āsavā.","v":[{"k":"muller","t":"Those who are ever watchful, who study day and night, and who strive after Nirvana, their passions will come to an end."},{"k":"wagiswara","t":"Ever watchful, night and day\nLearning wisdom never cease;\nIn the one who strives for Peace\nAll the cravings die away."},{"k":"kaviratna","t":"The influxes of passion disappear in those who are ever vigilant, who are absorbed day and night in spiritual studies, and who are bent on realization of nirvana."},{"k":"buddharakkhita","t":"Those who are ever vigilant, who discipline themselves day and night, and are ever intent upon Nibbana — their defilements fade away."},{"k":"thanissaro","t":"Those who always stay wakeful,\ntraining by day & by night,\nkeen on Unbinding:\ntheir effluents come to an end."},{"k":"suddhaso","t":"When one is always wakeful,\ntraining day and night,\nand intent upon Nibbāna,\ntheir defilements disappear."},{"k":"sujato","t":"Always wakeful,\npracticing night and day,\nfocused only on extinguishment,\ntheir defilements come to an end."}]},{"n":227,"vg":17,"pali":"Porāṇametaṁ atula,\nnetaṁ ajjatanāmiva;\nNindanti tuṇhimāsīnaṁ,\nnindanti bahubhāṇinaṁ;\nMitabhāṇimpi nindanti,\nnatthi loke anindito.","v":[{"k":"muller","t":"This is an old saying, O Atula, this is not only of to-day: `They blame him who sits silent, they blame him who speaks much, they also blame him who says little; there is no one on earth who is not blamed.'"},{"k":"wagiswara","t":"There is a saying, Atula,\nOf old, not of to-day:\n\"They blame the man who silent sits,\nOr whose tongue wags alway;\nAnd blame the man who keeps the mean;\nNone in the world is blameless seen.\""},{"k":"kaviratna","t":"This is an old saying, O Atula, not one merely of today: \"They blame him who remains silent, they blame him who speaks much, they even blame him who speaks in moderation.\" There is none in this world who is not blamed."},{"k":"buddharakkhita","t":"O Atula! Indeed, this is an ancient practice, not one only of today: they blame those who remain silent, they blame those who speak much, they blame those who speak in moderation. There is none in the world who is not blamed."},{"k":"thanissaro","t":"This has come down from old, Atula,\n& not just from today:\nthey find fault with one\nwho sits silent,\nthey find fault with one\nwho speaks a great deal,\nthey find fault with one\nwho measures his words.\nThere's no one unfaulted in the world."},{"k":"suddhaso","t":"This is an incomparably ancient truth,\nnot just the way it is today:\nthey criticize those who are silent,\nthey criticize those who speak a lot,\nthey criticize those who speak moderately;\nthere is no one in the world who is not criticized."},{"k":"sujato","t":"It's always been this way, Atula,\nit's not just today.\nThey blame you when you're silent,\nthey blame you when you speak a lot,\nand even when you speak just right:\nno-one in the world escapes blame."}]},{"n":228,"vg":17,"pali":"Na cāhu na ca bhavissati,\nna cetarahi vijjati;\nEkantaṁ nindito poso,\nekantaṁ vā pasaṁsito.","v":[{"k":"muller","t":"There never was, there never will be, nor is there now, a man who is always blamed, or a man who is always praised."},{"k":"wagiswara","t":"There never was, nor will be, sure,\nNor lives now among men,\nA being blamed exclusively,\nNor one entirely praised."},{"k":"kaviratna","t":"There never existed, nor will there ever exist, nor does there exist today anyone who is always scorned or always praised."},{"k":"buddharakkhita","t":"There never was, there never will be, nor is there now, a person who is wholly blamed or wholly praised."},{"k":"thanissaro","t":"There never was,\nwill be,\nnor at present is found\nanyone entirely faulted\nor entirely praised."},{"k":"suddhaso","t":"It has not been, it will not be,\nand it is not now the case\nthat anyone is exclusively criticized\nor exclusively praised."},{"k":"sujato","t":"There never was, nor will be,\nnor is there today,\nsomeone who is wholly praised\nor wholly blamed."}]},{"n":229,"vg":17,"pali":"Yañce viññū pasaṁsanti,\nanuvicca suve suve;\nAcchiddavuttiṁ medhāviṁ,\npaññāsīlasamāhitaṁ.","v":[{"k":"muller","t":"But he whom those who discriminate praise continually day after day, as without blemish, wise, rich in knowledge and virtue, who would dare to blame him, like a coin made of gold from the Gambu river? Even the gods praise him, he is praised even by Brahman."},{"k":"wagiswara","t":"But one whom men of wisdom praise,\nWatching him day by day,\nOf faultless life, of holy ways,\nThoughtful and wise, like Jambu gold,\nWho to blame such a saint is bold?\nNeither the gods, nor e'en Brahmā,\nFrom him their praise withhold."},{"k":"kaviratna","t":"If wise men, after due observation day after day, praise one who is flawless in character, highly intelligent and endowed with religious insight and virtue, who is like unto a coin made of the purest gold from the jambu river — who would dare censure such a man? Even the devas praise him; he is praised even by Brahma."},{"k":"buddharakkhita","t":"But the man whom the wise praise, after observing him day after day, is one of flawless character, wise, and endowed with knowledge and virtue."},{"k":"thanissaro","t":"If knowledgeable people praise him,\nhaving observed him\nday after day\nto be blameless in conduct, intelligent,\nendowed with discernment & virtue:\nlike an ingot of gold —\nwho's fit to find fault with him?\nEven devas praise him.\nEven by Brahmas he's praised."},{"k":"suddhaso","t":"The discerning praise one who,\nwhen observed day after day,\nis known to have impeccable conduct, intelligence,\nwisdom, morality, and concentration."},{"k":"sujato","t":"If, after watching them day in day out,\ndiscerning people praise\nthat sage of impeccable conduct,\nendowed with ethics and wisdom;"}]},{"n":230,"vg":17,"pali":"Nikkhaṁ jambonadasseva,\nko taṁ ninditumarahati;\nDevāpi naṁ pasaṁsanti,\nbrahmunāpi pasaṁsito.","v":[{"k":"muller","t":"But he whom those who discriminate praise continually day after day, as without blemish, wise, rich in knowledge and virtue, who would dare to blame him, like a coin made of gold from the Gambu river? Even the gods praise him, he is praised even by Brahman."},{"k":"wagiswara","t":"But one whom men of wisdom praise,\nWatching him day by day,\nOf faultless life, of holy ways,\nThoughtful and wise, like Jambu gold,\nWho to blame such a saint is bold?\nNeither the gods, nor e'en Brahmā,\nFrom him their praise withhold."},{"k":"kaviratna","t":"If wise men, after due observation day after day, praise one who is flawless in character, highly intelligent and endowed with religious insight and virtue, who is like unto a coin made of the purest gold from the jambu river — who would dare censure such a man? Even the devas praise him; he is praised even by Brahma."},{"k":"buddharakkhita","t":"Who can blame such a one, as worthy as a coin of refined gold? Even the gods praise him; by Brahma, too, is he praised."},{"k":"thanissaro","t":"If knowledgeable people praise him,\nhaving observed him\nday after day\nto be blameless in conduct, intelligent,\nendowed with discernment & virtue:\nlike an ingot of gold —\nwho's fit to find fault with him?\nEven devas praise him.\nEven by Brahmas he's praised."},{"k":"suddhaso","t":"Such a person is like a gold coin -\nwho would be worthy to criticize them?\nEven the angels praise such a person;\neven Brahmā praises such a person."},{"k":"sujato","t":"like a pendant of Black Plum River gold,\nwho is worthy to criticize them?\nEven the gods praise them,\nand by the Divinity, too, they're praised."}]},{"n":231,"vg":17,"pali":"Kāyappakopaṁ rakkheyya,\nkāyena saṁvuto siyā;\nKāyaduccaritaṁ hitvā,\nkāyena sucaritaṁ care.","v":[{"k":"muller","t":"Beware of bodily anger, and control thy body! Leave the sins of the body, and with thy body practise virtue!"},{"k":"wagiswara","t":"'Gainst angry deeds be on thy guard;\nIn body be composed;\nAll bodily misdeeds discard;\nWith body tread the Way."},{"k":"kaviratna","t":"One should guard against the agitations of the body; he should be restrained in body. Having abandoned the bodily sins (1 ), he should cultivate good conduct in body."},{"k":"buddharakkhita","t":"Let a man guard himself against irritability in bodily action; let him be controlled in deed. Abandoning bodily misconduct, let him practice good conduct in deed."},{"k":"thanissaro","t":"Guard against anger\nerupting in body;\nin body, be restrained.\nHaving abandoned bodily misconduct,\nlive conducting yourself well\nin body."},{"k":"suddhaso","t":"Protect yourself from manifesting anger physically;\npractice physical self-restraint.\nHaving relinquished physical misconduct,\npractice good conduct with the body."},{"k":"sujato","t":"Guard against ill-tempered deeds,\nbe restrained in body.\nGiving up bad bodily conduct,\nconduct yourself well in body."}]},{"n":232,"vg":17,"pali":"Vacīpakopaṁ rakkheyya,\nvācāya saṁvuto siyā;\nVacīduccaritaṁ hitvā,\nvācāya sucaritaṁ care.","v":[{"k":"muller","t":"Beware of the anger of the tongue, and control thy tongue! Leave the sins of the tongue, and practise virtue with thy tongue!"},{"k":"wagiswara","t":"'Gainst angry words be on thy guard;\nIn speech be thou composed;\nAll wrongful ways of speech discard;\nIn speech follow the Way."},{"k":"kaviratna","t":"One should guard against the agitations of speech; he should be restrained in speech. Having abandoned the verbal sins (2), he should cultivate good conduct in speech."},{"k":"buddharakkhita","t":"Let a man guard himself against irritability in speech; let him be controlled in speech. Abandoning verbal misconduct, let him practice good conduct in speech."},{"k":"thanissaro","t":"Guard against anger\nerupting in speech;\nin speech, be restrained.\nHaving abandoned verbal misconduct,\nlive conducting yourself well\nin speech."},{"k":"suddhaso","t":"Protect yourself from manifesting anger verbally;\npractice verbal self-restraint.\nHaving relinquished verbal misconduct,\npractice good conduct with speech."},{"k":"sujato","t":"Guard against ill-tempered words,\nbe restrained in speech.\nGiving up bad verbal conduct,\nconduct yourself well in speech."}]},{"n":233,"vg":17,"pali":"Manopakopaṁ rakkheyya,\nmanasā saṁvuto siyā;\nManoduccaritaṁ hitvā,\nmanasā sucaritaṁ care.","v":[{"k":"muller","t":"Beware of the anger of the mind, and control thy mind! Leave the sins of the mind, and practise virtue with thy mind!"},{"k":"wagiswara","t":"'Gainst angry thoughts be on thy guard;\nIn thought be thou composed;\nAll wrongful ways of thought discard;\nIn thoughts follow the Way."},{"k":"kaviratna","t":"One should guard against the agitations of mind; he should be restrained of mind. Having abandoned the mental sins (3), he should cultivate good conduct in mind."},{"k":"buddharakkhita","t":"Let a man guard himself against irritability in thought; let him be controlled in mind. Abandoning mental misconduct, let him practice good conduct in thought."},{"k":"thanissaro","t":"Guard against anger\nerupting in mind;\nin mind, be restrained.\nHaving abandoned mental misconduct,\nlive conducting yourself well\nin mind."},{"k":"suddhaso","t":"Protect yourself from manifesting anger mentally;\npractice mental self-restraint.\nHaving relinquished mental misconduct,\npractice good conduct with the mind."},{"k":"sujato","t":"Guard against ill-tempered thoughts,\nbe restrained in mind.\nGiving up bad mental conduct,\nconduct yourself well in mind."}]},{"n":234,"vg":17,"pali":"Kāyena saṁvutā dhīrā,\natho vācāya saṁvutā;\nManasā saṁvutā dhīrā,\nte ve suparisaṁvutā.\nKodhavaggo sattarasamo.","v":[{"k":"muller","t":"The wise who control their body, who control their tongue, the wise who control their mind, are indeed well controlled."},{"k":"wagiswara","t":"In body sages are controlled;\nIn thoughts as well as speech;\nAnd they are Sages truly called\nWho are controlled in each."},{"k":"kaviratna","t":"The wise who are controlled in body, who likewise are controlled in speech, those wise men who are controlled in mind, are indeed well controlled."},{"k":"buddharakkhita","t":"The wise are controlled in bodily action, controlled in speech and controlled in thought. They are truly well-controlled."},{"k":"thanissaro","t":"Those restrained in body\n— the enlightened —\nrestrained in speech & in mind\n— enlightened —\nare the ones whose restraint is secure."},{"k":"suddhaso","t":"The steadfast are self-restrained physically,\nverbally,\nand mentally;\nthey are well-restrained in every way."},{"k":"sujato","t":"An attentive one is restrained in body\nrestrained also in speech,\nin thought, too, they are restrained:\nthey are restrained in every way."}]},{"n":235,"vg":18,"pali":"Paṇḍupalāsova dānisi,\nYamapurisāpi ca te upaṭṭhitā;\nUyyogamukhe ca tiṭṭhasi,\nPātheyyampi ca te na vijjati.","v":[{"k":"muller","t":"Thou art now like a sear leaf, the messengers of death (Yama) have come near to thee; thou standest at the door of thy departure, and thou hast no provision for thy journey."},{"k":"wagiswara","t":"Lo! Thou art now a pale and withered leaf;\nDeath's messengers are close at hand;\nThou in the very gate of Death dost stand,\nAnd yet hast no provision for the way."},{"k":"kaviratna","t":"You are now like a withered leaf; even the messengers of Yama (death) have drawn near you. You stand at the threshold of departure, with no provision for your journey."},{"k":"buddharakkhita","t":"Like a withered leaf are you now; death's messengers await you. You stand on the eve of your departure, yet you have made no provision for your journey!"},{"k":"thanissaro","t":"You are now\nlike a yellowed leaf.\nAlready\nYama's minions stand near.\nYou stand at the door to departure\nbut have yet to provide\nfor the journey."},{"k":"suddhaso","t":"Now you are like a fallen leaf,\nand Death's minions are near.\nYou stand at the starting point of a struggle,\nand no provisions can be found for you."},{"k":"sujato","t":"Today you're like a withered leaf,\nYama's men await you.\nYou stand at the departure gates,\nyet you have no supplies for the road."}]},{"n":236,"vg":18,"pali":"So karohi dīpamattano,\nKhippaṁ vāyama paṇḍito bhava;\nNiddhantamalo anaṅgaṇo,\nDibbaṁ ariyabhūmiṁ upehisi.","v":[{"k":"muller","t":"Make thyself an island, work hard, be wise! When thy impurities are blown away, and thou art free from guilt, thou wilt enter into the heavenly world of the elect (Ariya)."},{"k":"wagiswara","t":"Then make thyself an island of defence;\nStrive quick; be wise; when all the taints\nOf dirt and dust are blown away, the saints\nShall greet thee entering the Happy Land."},{"k":"kaviratna","t":"Make of yourself a light; strive hard, without delay, and be wise; purged of moral impurities and being thus stainless, you will then enter the celestial realm of the Noble Ones."},{"k":"buddharakkhita","t":"Make an island for yourself! Strive hard and become wise! Rid of impurities and cleansed of stain, you shall enter the celestial abode of the Noble Ones."},{"k":"thanissaro","t":"Make an island for yourself!\nWork quickly! Be wise!\nWith impurities all blown away,\nunblemished,\nyou'll reach the divine realm\nof the noble ones."},{"k":"suddhaso","t":"Make an island for yourself,\nquickly try to become wise;\none who has no contaminants and no flaws\nwill reach the divine state of the noble ones."},{"k":"sujato","t":"Make an island of yourself!\nSwiftly strive, learn to be wise!\nPurged of stains, flawless,\nyou'll go to the heavenly realm of the noble ones."}]},{"n":237,"vg":18,"pali":"Upanītavayo ca dānisi,\nSampayātosi yamassa santikaṁ;\nVāso te natthi antarā,\nPātheyyampi ca te na vijjati.","v":[{"k":"muller","t":"Thy life has come to an end, thou art come near to death (Yama), there is no resting-place for thee on the road, and thou hast no provision for thy journey."},{"k":"wagiswara","t":"Thy life has run its course; thou art come nigh\nThe King of Death; for thine abode\nThou hast no resting-place upon the road,\nAnd yet hast no provision for the way."},{"k":"kaviratna","t":"Your life has now come to a close; you have come into the presence of death. There is no halting-place for you on the way, and no provision have you made for your journey."},{"k":"buddharakkhita","t":"Your life has come to an end now; You are setting forth into the presence of Yama, the king of death. No resting place is there for you on the way, yet you have made no provision for the journey!"},{"k":"thanissaro","t":"You are now\nright at the end of your time.\nYou are headed\nto Yama's presence,\nwith no place to rest along the way,\nbut have yet to provide\nfor the journey."},{"k":"suddhaso","t":"Now you are close to departing;\nyou are in the presence of Death.\nYou have nowhere to dwell here,\nand no provisions can be found for you."},{"k":"sujato","t":"You've journeyed the stages of life,\nand now you set out to meet Yama.\nAlong the way there's nowhere to stay,\nyet you have no supplies for the road."}]},{"n":238,"vg":18,"pali":"So karohi dīpamattano,\nKhippaṁ vāyama paṇḍito bhava;\nNiddhantamalo anaṅgaṇo,\nNa punaṁ jātijaraṁ upehisi.","v":[{"k":"muller","t":"Make thyself an island, work hard, be wise! When thy impurities are blown away, and thou art free from guilt, thou wilt not enter again into birth and decay."},{"k":"wagiswara","t":"Then make thyself an island of defence;\nStrive quick; be wise; blow off the dust\nAnd stains of travel; wipe away the rust;\nSo shalt thou see no more birth and decay."},{"k":"kaviratna","t":"Make of yourself a light; strive hard, without delay, and be wise; purged of moral impurities and being thus stainless, you will not then come again into birth and old age."},{"k":"buddharakkhita","t":"Make an island unto yourself! Strive hard and become wise! Rid of impurities and cleansed of stain, you shall not come again to birth and decay."},{"k":"thanissaro","t":"Make an island for yourself!\nWork quickly! Be wise!\nWith impurities all blown away,\nunblemished,\nyou won't again undergo birth\n& aging."},{"k":"suddhaso","t":"Make an island for yourself,\nquickly try to become wise;\none who has no contaminants and no flaws\ndoes not come again to birth and decrepitude."},{"k":"sujato","t":"Make an island of yourself!\nSwiftly strive, learn to be wise!\nPurged of stains, flawless,\nyou'll not come again to rebirth and old age."}]},{"n":239,"vg":18,"pali":"Anupubbena medhāvī,\nthokaṁ thokaṁ khaṇe khaṇe;\nKammāro rajatasseva,\nniddhame malamattano.","v":[{"k":"muller","t":"Let a wise man blow off the impurities of his self, as a smith blows off the impurities of silver one by one, little by little, and from time to time."},{"k":"wagiswara","t":"The wise and thoughtful man attacks his faults\nOne after other, momently,\nIn order due, and rubs them all away,\nE'en as a smith blows off the silver's dross,"},{"k":"kaviratna","t":"Little by little, ever and anon, the wise man should remove his moral impurities as a smith blows away the dross of silver."},{"k":"buddharakkhita","t":"One by one, little by little, moment by moment, a wise man should remove his own impurities, as a smith removes his dross from silver."},{"k":"thanissaro","t":"Just as a silver smith\nstep by\nstep,\nbit by\nbit,\nmoment to\nmoment,\nblows away the impurities\nof molten silver —\nso the wise man, his own."},{"k":"suddhaso","t":"Progressively,\nbit by bit, moment after moment,\nlike a smith purifying silver,\nthe wise remove their contaminants."},{"k":"sujato","t":"A smart person would purge\ntheir own stains gradually,\nbit by bit, moment by moment,\nlike a smith smelting silver."}]},{"n":240,"vg":18,"pali":"Ayasāva malaṁ samuṭṭhitaṁ,\nTatuṭṭhāya tameva khādati;\nEvaṁ atidhonacārinaṁ,\nSāni kammāni nayanti duggatiṁ.","v":[{"k":"muller","t":"As the impurity which springs from the iron, when it springs from it, destroys it; thus do a transgressor's own works lead him to the evil path."},{"k":"wagiswara","t":"Just as the iron rust accumulates\nSelf born; and eats itself away;\nSo with the man who sinneth; day by day\nHis own deeds to destruction lead him on,"},{"k":"kaviratna","t":"As rust arising from iron straightway corrodes the very iron from which it arose, even so the evil deeds of the transgressor lead him to the state of woe."},{"k":"buddharakkhita","t":"Just as rust arising from iron eats away the base from which it arises, even so, their own deeds lead transgressors to states of woe."},{"k":"thanissaro","t":"Just as rust\n— iron's impurity —\neats the very iron\nfrom which it is born,\nso the deeds\nof one who lives slovenly\nlead him on\nto a bad destination."},{"k":"suddhaso","t":"When rust appears\nit eats away the metal that produced it;\nin the same way, a sanctimonious person\nis led to a bad destination by their own actions."},{"k":"sujato","t":"It is the rust born on the iron\nthat eats away the place it arose.\nAnd so it is their own deeds\nthat lead the overly-ascetic to a bad place."}]},{"n":241,"vg":18,"pali":"Asajjhāyamalā mantā,\nanuṭṭhānamalā gharā;\nMalaṁ vaṇṇassa kosajjaṁ,\npamādo rakkhato malaṁ.","v":[{"k":"muller","t":"The taint of prayers is non-repetition; the taint of houses, non-repair; the taint of the body is sloth; the taint of a watchman, thoughtlessness."},{"k":"wagiswara","t":"Texts not repeated oft are soon forgot;\nThe house neglected soon decays;\nSloth is the bane of beauty; heedless ways\nBring ruin unto him that keepeth watch."},{"k":"kaviratna","t":"Non-recitation is the rust of the scriptures; non-exertion is the rust of households; sloth is the rust of beauty; negligence is the rust of a watchman."},{"k":"buddharakkhita","t":"Non-repetition is the bane of scriptures; neglect is the bane of a home; slovenliness is the bane of personal appearance, and heedlessness is the bane of a guard."},{"k":"thanissaro","t":"No recitation: the ruinous impurity\nof chants.\nNo initiative: of a household.\nIndolence: of beauty.\nHeedlessness: of a guard."},{"k":"suddhaso","t":"Non-repetition contaminates mantras,\nnon-upkeep contaminates a house,\nlaziness contaminates beauty,\nnegligence contaminates security."},{"k":"sujato","t":"Not rehearsing is the stain of hymns.\nThe stain of houses is neglect.\nLaziness is the stain of beauty.\nA guard's stain is negligence."}]},{"n":242,"vg":18,"pali":"Malitthiyā duccaritaṁ,\nmaccheraṁ dadato malaṁ;\nMalā ve pāpakā dhammā,\nasmiṁ loke paramhi ca.","v":[{"k":"muller","t":"Bad conduct is the taint of woman, greediness the taint of a benefactor; tainted are all evil ways in this world and in the next."},{"k":"wagiswara","t":"The taint of woman is impurity,\nAnd gifts by stinginess are spoiled,\nAnd mortal man by oft transgression soiled\nFinds ruin here, loss in the life to come."},{"k":"kaviratna","t":"An unchaste life is the blemish of woman; niggardliness is the taint of a benefactor; impurities are indeed evils in this world and in the next."},{"k":"buddharakkhita","t":"Unchastity is the taint in a woman; niggardliness is the taint in a giver. Taints, indeed, are all evil things, both in this world and the next."},{"k":"thanissaro","t":"In a woman, misconduct is an impurity.\nIn a donor, stinginess.\nEvil deeds are the real impurities\nin this world & the next."},{"k":"suddhaso","t":"Misconduct contaminates a woman,\nstinginess contaminates a donor,\nevil choices contaminate\nboth this life and the next."},{"k":"sujato","t":"Misconduct is a woman's stain.\nA giver's stain is stinginess.\nBad qualities are a stain\nin this world and the next."}]},{"n":243,"vg":18,"pali":"Tato malā malataraṁ,\navijjā paramaṁ malaṁ;\nEtaṁ malaṁ pahantvāna,\nnimmalā hotha bhikkhavo.","v":[{"k":"muller","t":"But there is a taint worse than all taints,--ignorance is the greatest taint. O mendicants! throw off that taint, and become taintless!"},{"k":"wagiswara","t":"Yet there's a taint far worse than any other.\nWhat is that taint? 'tis ignorance.\nMake yourselves free from this, O mendicants!\nWipe off this stain and be ye undefiled."},{"k":"kaviratna","t":"But there is an impurity greater than all impurities — this is ignorance. Rid yourselves of this greatest impurity, O monks, be you free from all impurities."},{"k":"buddharakkhita","t":"A worse taint than these is ignorance, the worst of all taints. Destroy this one taint and become taintless, O monks!"},{"k":"thanissaro","t":"More impure than these impurities\nis the ultimate impurity:\nignorance.\nHaving abandoned this impurity,\nmonks, you're impurity-free."},{"k":"suddhaso","t":"There is a contaminant that is even worse than that:\nignorance, the paramount contaminant.\nAbandon this contaminant\nand be free of contaminants, monks!"},{"k":"sujato","t":"But a worse stain than these\nis ignorance, the worst stain of all.\nHaving given up that stain,\nbe without stains, mendicants!"}]},{"n":244,"vg":18,"pali":"Sujīvaṁ ahirikena,\nkākasūrena dhaṁsinā;\nPakkhandinā pagabbhena,\nsaṅkiliṭṭhena jīvitaṁ.","v":[{"k":"muller","t":"Life is easy to live for a man who is without shame, a crow hero, a mischief-maker, an insulting, bold, and wretched fellow."},{"k":"wagiswara","t":"Life seems an easy thing to him that lives\nWanton and shameless as a crow,\nA fault-finder, who through this life doth go\nImmodest, insolent, and full of sins."},{"k":"kaviratna","t":"Life is easy for him who is shameless, impudent as a crow-hero (rascal) and a slanderer, a braggart, arrogant and impure in living."},{"k":"buddharakkhita","t":"Easy is life for the shameless one who is impudent as a crow, is backbiting and forward, arrogant and corrupt."},{"k":"thanissaro","t":"Life's easy to live\nfor someone unscrupulous,\ncunning as a crow,\ncorrupt, back-biting,\nforward, & brash;\nbut for someone who's constantly\nscrupulous, cautious,\nobservant, sincere,\npure in his livelihood,\nclean in his pursuits,\nit's hard."},{"k":"suddhaso","t":"It is easy to lose one's conscience,\nto act like an impudent and offensive crow,\nobtrusive and inconsiderate,\nliving a defiled life."},{"k":"sujato","t":"Life is easy for the shameless.\nWith all the rude courage of a crow,\nthey live pushy,\nrude, and corrupt."}]},{"n":245,"vg":18,"pali":"Hirīmatā ca dujjīvaṁ,\nniccaṁ sucigavesinā;\nAlīnenāppagabbhena,\nsuddhājīvena passatā.","v":[{"k":"muller","t":"But life is hard to live for a modest man, who always looks for what is pure, who is disinterested, quiet, spotless, and intelligent."},{"k":"wagiswara","t":"But life's no easy thing for one restrained\nBy shame, who seeks to walk aright,\nAll unattached, withdrawn from vulgar sight;\nWho liveth purely and hath eyes to see."},{"k":"kaviratna","t":"But life is difficult for him who is unassuming, constantly seeking that which is pure, disinterested in worldly things, not boastful, who lives in purity and is endowed with insight."},{"k":"buddharakkhita","t":"Difficult is life for the modest one who always seeks purity, is detached and unassuming, clean in life, and discerning."},{"k":"thanissaro","t":"Life's easy to live\nfor someone unscrupulous,\ncunning as a crow,\ncorrupt, back-biting,\nforward, & brash;\nbut for someone who's constantly\nscrupulous, cautious,\nobservant, sincere,\npure in his livelihood,\nclean in his pursuits,\nit's hard."},{"k":"suddhaso","t":"It is not easy to maintain one's conscience,\nalways seeking to be impeccable,\none who is diligent and considerate,\ninsightful and living a life of purity."},{"k":"sujato","t":"Life is hard for the conscientious,\nalways seeking purity,\nneither clinging nor rude,\npure of livelihood and discerning."}]},{"n":246,"vg":18,"pali":"Yo pāṇamatipāteti,\nmusāvādañca bhāsati;\nLoke adinnamādiyati,\nparadārañca gacchati.","v":[{"k":"muller","t":"He who destroys life, who speaks untruth, who in this world takes what is not given him, who goes to another man's wife;"},{"k":"wagiswara","t":"He who takes life; whose mouth is full of lies;\nWho steals, and fouls another's wife;\nA slave to drink, he even in this life\nThe root of his own fortunes undermines."},{"k":"kaviratna","t":"He who destroys life here, who utters untruth, who takes what is not given to him, who goes to the wife of another, who indulges in intoxicating liquors, such a man, while in this world, destroys the root of his being."},{"k":"buddharakkhita","t":"One who destroys life, utters lies, takes what is not given, goes to another man's wife, and is addicted to intoxicating drinks — such a man digs up his own root even in this world."},{"k":"thanissaro","t":"Whoever kills, lies, steals,\ngoes to someone else's wife,\n& is addicted to intoxicants,\ndigs himself up\nby the root\nright here in this world."},{"k":"suddhaso","t":"One who kills,\nlies,\nsteals,\ncommits adultery,"},{"k":"sujato","t":"Take anyone in this world\nwho kills living creatures,\nspeaks falsely, steals,\ncommits adultery,"}]},{"n":247,"vg":18,"pali":"Surāmerayapānañca,\nyo naro anuyuñjati;\nIdheva meso lokasmiṁ,\nmūlaṁ khaṇati attano.","v":[{"k":"muller","t":"And the man who gives himself to drinking intoxicating liquors, he, even in this world, digs up his own root."},{"k":"wagiswara","t":"He who takes life; whose mouth is full of lies;\nWho steals, and fouls another's wife;\nA slave to drink, he even in this life\nThe root of his own fortunes undermines."},{"k":"kaviratna","t":"He who destroys life here, who utters untruth, who takes what is not given to him, who goes to the wife of another, who indulges in intoxicating liquors, such a man, while in this world, destroys the root of his being."},{"k":"buddharakkhita","t":"One who destroys life, utters lies, takes what is not given, goes to another man's wife, and is addicted to intoxicating drinks — such a man digs up his own root even in this world."},{"k":"thanissaro","t":"Whoever kills, lies, steals,\ngoes to someone else's wife,\n& is addicted to intoxicants,\ndigs himself up\nby the root\nright here in this world.\n\nSo know, my good man,\nthat bad deeds are reckless.\nDon't let greed & unrighteousness\noppress you with long-term pain."},{"k":"suddhaso","t":"and drinks alcohol -\na person who engages in such activities\nright here in this world\ndestroys their own foundation."},{"k":"sujato","t":"and indulges in drinking\nbeer and wine.\nRight here they dig up\nthe root of their own self."}]},{"n":248,"vg":18,"pali":"Evaṁ bho purisa jānāhi,\npāpadhammā asaññatā;\nMā taṁ lobho adhammo ca,\nciraṁ dukkhāya randhayuṁ.","v":[{"k":"muller","t":"O man, know this, that the unrestrained are in a bad state; take care that greediness and vice do not bring thee to grief for a long time!"},{"k":"wagiswara","t":"O man I know this: \"Not easy of control\nAre evil ways.\" Let not thy greed\nAnd wickedness (of misery the seed)\nBecome thy masters, lest thou suffer long."},{"k":"kaviratna","t":"Know this, O man, evil-natured ones are unrestrained; let not greed and wrongdoing lead you to untold misery for a long time."},{"k":"buddharakkhita","t":"Know this, O good man: evil things are difficult to control. Let not greed and wickedness drag you to protracted misery."},{"k":"thanissaro","t":"So know, my good man,\nthat bad deeds are reckless.\nDon't let greed & unrighteousness\noppress you with long-term pain."},{"k":"suddhaso","t":"Therefore, you should know\nthat lack of restraint is evil;\ndo not let greed contrary to Dhamma\nafflict you with long-lasting suffering."},{"k":"sujato","t":"Know this, my man:\nthey are unrestrained and wicked.\nDon't let that greed and unrighteousness\ninflict pain on you for long."}]},{"n":249,"vg":18,"pali":"Dadāti ve yathāsaddhaṁ,\nyathāpasādanaṁ jano;\nTattha yo ca maṅku bhavati,\nparesaṁ pānabhojane;\nNa so divā vā rattiṁ vā,\nsamādhimadhigacchati.","v":[{"k":"muller","t":"The world gives according to their faith or according to their pleasure: if a man frets about the food and the drink given to others, he will find no rest either by day or by night."},{"k":"wagiswara","t":"According to their trust and faith men give.\nWhoso regards with discontent\nAnd jealousy the food for others meant\nCannot get peace of mind by night or day."},{"k":"kaviratna","t":"People give alms according to their faith and inclination. But he who frets about the drink and food given to others does not attain peace of mind by day or by night."},{"k":"buddharakkhita","t":"People give according to their faith or regard. If one becomes discontented with the food and drink given by others, one does not attain meditative absorption, either by day or by night."},{"k":"thanissaro","t":"People give\nin line with their faith,\nin line with conviction.\nWhoever gets flustered\nat food & drink given to others,\nattains no concentration\nby day or by night."},{"k":"suddhaso","t":"People give because it brings\nfaith and joy.\nOne who is disturbed\nwhen food and drink are given to others\ndoes not gain concentration\nby day and by night."},{"k":"sujato","t":"The people give according to their faith,\naccording to their confidence.\nIf you get upset over that,\nover others' food and drink,\nyou'll not, by day or by night,\nbecome immersed in samādhi."}]},{"n":250,"vg":18,"pali":"Yassa cetaṁ samucchinnaṁ,\nmūlaghaccaṁ samūhataṁ;\nSa ve divā vā rattiṁ vā,\nsamādhimadhigacchati.","v":[{"k":"muller","t":"He in whom that feeling is destroyed, and taken out with the very root, finds rest by day and by night."},{"k":"wagiswara","t":"But whoso disregards what others get,\nWhose heart of jealousy is void,\nIn whom the root of envy is destroyed,\nHe gaineth peace of mind by night and day."},{"k":"kaviratna","t":"He in whom that feeling is totally uprooted and destroyed, that person attains peace of mind by day and by night."},{"k":"buddharakkhita","t":"But he in who this (discontent) is fully destroyed, uprooted and extinct, he attains absorption, both by day and by night."},{"k":"thanissaro","t":"But one in whom this is\ncut through\nup- rooted\nwiped out —\nattains concentration\nby day or by night."},{"k":"suddhaso","t":"One who has shredded,\nuprooted, and destroyed that attitude\ngains concentration\nby day and by night."},{"k":"sujato","t":"Those who have cut that out,\ndug it up at the root, eradicated it,\nthey will, by day or by night,\nbecome immersed in samādhi."}]},{"n":251,"vg":18,"pali":"Natthi rāgasamo aggi,\nnatthi dosasamo gaho;\nNatthi mohasamaṁ jālaṁ,\nnatthi taṇhāsamā nadī.","v":[{"k":"muller","t":"There is no fire like passion, there is no shark like hatred, there is no snare like folly, there is no torrent like greed."},{"k":"wagiswara","t":"There is no fire that burneth like desire;\nNo beast like hatred can devour;\nNo snare like folly to entrap hath power;\nNo river-flood can carry off like greed."},{"k":"kaviratna","t":"There is no fire like passion; there is no stranglehold like hatred; there is no snare like delusion; there is no torrent like craving."},{"k":"buddharakkhita","t":"There is no fire like lust; there is no grip like hatred; there is no net like delusion; there is no river like craving."},{"k":"thanissaro","t":"There's no fire like passion,\nno seizure like anger,\nno snare like delusion,\nno river like craving."},{"k":"suddhaso","t":"There is no fire as strong as passion,\nno grasp as strong as aversion,\nno trap as strong as delusion,\nno river as strong as craving."},{"k":"sujato","t":"There is no fire like greed,\nno crime like hate,\nno net like delusion,\nno river like craving."}]},{"n":252,"vg":18,"pali":"Sudassaṁ vajjamaññesaṁ,\nattano pana duddasaṁ;\nParesaṁ hi so vajjāni,\nopunāti yathā bhusaṁ;\nAttano pana chādeti,\nkaliṁva kitavā saṭho.","v":[{"k":"muller","t":"The fault of others is easily perceived, but that of oneself is difficult to perceive; a man winnows his neighbour's faults like chaff, but his own fault he hides, as a cheat hides the bad die from the gambler."},{"k":"wagiswara","t":"'Tis easy to perceive another's faults;\nHard are one's own faults to descry;\nA man will winnow others' faults like chaff;\nBut as the cheating gambler hides the die,\nHis own faults he conceals right carefully."},{"k":"kaviratna","t":"The faults of others are easily seen, but one's own faults are perceived with difficulty. One winnows the faults of others like chaff, but conceals his own faults as a fowler covers his body with twigs and leaves."},{"k":"buddharakkhita","t":"Easily seen is the fault of others, but one's own fault is difficult to see. Like chaff one winnows another's faults, but hides one's own, even as a crafty fowler hides behind sham branches."},{"k":"thanissaro","t":"It's easy to see\nthe errors of others,\nbut hard to see\nyour own.\nYou winnow like chaff\nthe errors of others,\nbut conceal your own —\nlike a cheat, an unlucky throw."},{"k":"suddhaso","t":"It is easy to see the faults of others,\nand hard to see our own.\nWhen we frequently expose\nthe faults of others\nbut conceal our own,\nwe are like a fraud cheating at dice."},{"k":"sujato","t":"It's easy to see the faults of others,\nhard to see one's own.\nFor the faults of others\nare tossed high like hay,\nwhile one's own are hidden,\nas a cheat hides a bad hand."}]},{"n":253,"vg":18,"pali":"Paravajjānupassissa,\nniccaṁ ujjhānasaññino;\nĀsavā tassa vaḍḍhanti,\nārā so āsavakkhayā.","v":[{"k":"muller","t":"If a man looks after the faults of others, and is always inclined to be offended, his own passions will grow, and he is far from the destruction of passions."},{"k":"wagiswara","t":"Whoso is watchful for another's faults,\nTesty and quick to take offence,\nIn him his passions will increase, and thence\nFurther is he from cleansing of his sins."},{"k":"kaviratna","t":"If a man sees only the faults of others, and is ever taking offense, his appetite for sense pleasures increases and he is far from the eradication of his desires."},{"k":"buddharakkhita","t":"He who seeks another's faults, who is ever censorious — his cankers grow. He is far from destruction of the cankers."},{"k":"thanissaro","t":"If you focus on the errors of others,\nconstantly finding fault,\nyour effluents flourish.\nYou're far from their ending."},{"k":"suddhaso","t":"When one looks at the faults of others\nand is always looking to criticize,\none's defilements grow\nand one is far the elimination of defilements."},{"k":"sujato","t":"When you look for the flaws of others,\nalways finding fault,\nyour defilements only grow,\nyou're far from ending defilements."}]},{"n":254,"vg":18,"pali":"Ākāseva padaṁ natthi,\nsamaṇo natthi bāhire;\nPapañcābhiratā pajā,\nnippapañcā tathāgatā.","v":[{"k":"muller","t":"There is no path through the air, a man is not a Samana by outward acts. The world delights in vanity, the Tathagatas (the Buddhas) are free from vanity."},{"k":"wagiswara","t":"The sky-path shows no tracks; no outward signs\nThe treader of the Path betray;\nThe multitude in outward shows delay;\nThey who have won the Goal are free from all."},{"k":"kaviratna","t":"There is no footprint in the sky (akasa); there is no ascetic outwardly. Mankind delights in the illusory world; the Tathagatas (Buddhas) find no delight therein."},{"k":"buddharakkhita","t":"There is no track in the sky, and no recluse outside (the Buddha's dispensation). Mankind delights in worldliness, but the Buddhas are free from worldliness. [19]"},{"k":"thanissaro","t":"There's no trail in space,\nno outside contemplative.\nPeople are smitten\nwith objectifications,\nbut devoid of objectification are\nthe Tathagatas."},{"k":"suddhaso","t":"There is no path in the sky,\nthere is no contemplative elsewhere.\nPeople delight in complication,\nwhereas a Truth-Finder is free of complication."},{"k":"sujato","t":"In the atmosphere there is no track,\nthere's no true ascetic outside here.\nPeople enjoy proliferation,\nthe Realized Ones are free of proliferation."}]},{"n":255,"vg":18,"pali":"Ākāseva padaṁ natthi,\nsamaṇo natthi bāhire;\nSaṅkhārā sassatā natthi,\nnatthi buddhānamiñjitaṁ.\nMalavaggo aṭṭhārasamo.","v":[{"k":"muller","t":"There is no path through the air, a man is not a Samana by outward acts. No creatures are eternal; but the awakened (Buddha) are never shaken."},{"k":"wagiswara","t":"The sky-path shows no tracks; no outward signs\nThe treader of the Path betray;\nNought lasts; all things embodied pass away;\nBut nought can shake the All-Awakened Ones."},{"k":"kaviratna","t":"There is no footprint in the sky; there is no ascetic outwardly; no composite things are eternal; there is no instability in the Buddhas."},{"k":"buddharakkhita","t":"There is no track in the sky, and no recluse outside (the Buddha's dispensation). There are no conditioned things that are eternal, and no instability in the Buddhas."},{"k":"thanissaro","t":"There's no trail in space,\nno outside contemplative,\nno eternal fabrications,\nno wavering in the Awakened."},{"k":"suddhaso","t":"There is no path in the sky,\nthere is no contemplative elsewhere.\nThere is nothing that is eternal,\nand no agitation in Buddhas."},{"k":"sujato","t":"In the atmosphere there is no track,\nthere's no true ascetic outside here.\nNo conditions last forever,\nthe Awakened Ones are not shaken."}]},{"n":256,"vg":19,"pali":"Na tena hoti dhammaṭṭho,\nyenatthaṁ sāhasā naye;\nYo ca atthaṁ anatthañca,\nubho niccheyya paṇḍito.","v":[{"k":"muller","t":"A man is not just if he carries a matter by violence; no, he who distinguishes both right and wrong, who is learned and leads others, not by violence, but by law and equity, and who is guarded by the law and intelligent, he is called just."},{"k":"wagiswara","t":"He is not just who arbitrates by will.\nHe who by weighing right and wrong decides.\nHe is a just man called."},{"k":"kaviratna","t":"He who arbitrates a case by force does not thereby become just (established in Dhamma). But the wise man is he who carefully discriminates between right and wrong."},{"k":"buddharakkhita","t":"Not by passing arbitrary judgments does a man become just; a wise man is he who investigates both right and wrong."},{"k":"thanissaro","t":"To pass judgment hurriedly\ndoesn't mean you're a judge.\nThe wise one, weighing both\nthe right judgment & wrong,\njudges others impartially —\nunhurriedly, in line with the Dhamma,\nguarding the Dhamma,\nguarded by Dhamma,\nintelligent:\nhe's called a judge."},{"k":"suddhaso","t":"One is not established in Dhamma\nif one seeks benefit using violence;\na wise person does not wish to have\nboth benefit and detriment."},{"k":"sujato","t":"You don't become just\nby passing hasty judgment.\nAn astute person evaluates both\nwhat is pertinent and what is irrelevant."}]},{"n":257,"vg":19,"pali":"Asāhasena dhammena,\nsamena nayatī pare;\nDhammassa gutto medhāvī,\n\"dhammaṭṭho\"ti pavuccati.","v":[{"k":"muller","t":"A man is not just if he carries a matter by violence; no, he who distinguishes both right and wrong, who is learned and leads others, not by violence, but by law and equity, and who is guarded by the law and intelligent, he is called just."},{"k":"wagiswara","t":"Not by his will, but with impartial mind\nKeeping the Norm, thoughtful, who others guides,\nHe is a just man called."},{"k":"kaviratna","t":"He who leads others by nonviolence, righteously and equitably, is indeed a guardian of justice, wise and righteous."},{"k":"buddharakkhita","t":"He who does not judge others arbitrarily, but passes judgment impartially according to the truth, that sagacious man is a guardian of law and is called just."},{"k":"thanissaro","t":"To pass judgment hurriedly\ndoesn't mean you're a judge.\nThe wise one, weighing both\nthe right judgment & wrong,\njudges others impartially —\nunhurriedly, in line with the Dhamma,\nguarding the Dhamma,\nguarded by Dhamma,\nintelligent:\nhe's called a judge."},{"k":"suddhaso","t":"One who guides others nonviolently,\npeacefully, in accordance with Dhamma,\nsuch a wise person is a guardian of the Dhamma\nand is said to be established in Dhamma."},{"k":"sujato","t":"A wise one judges others without haste,\njustly and impartially;\nthat guardian of the law\nis said to be just."}]},{"n":258,"vg":19,"pali":"Na tena paṇḍito hoti,\nyāvatā bahu bhāsati;\nKhemī averī abhayo,\n\"paṇḍito\"ti pavuccati.","v":[{"k":"muller","t":"A man is not learned because he talks much; he who is patient, free from hatred and fear, he is called learned."},{"k":"wagiswara","t":"One is not wise because his speech is long.\nLong-suffering and harmless, free from fear,\nHe is a wise man called."},{"k":"kaviratna","t":"One is not wise merely because he talks much. But he who is calm, free from hatred and fear, is verily called a wise man."},{"k":"buddharakkhita","t":"One is not wise because one speaks much. He who is peaceable, friendly and fearless is called wise."},{"k":"thanissaro","t":"Simply talking a lot\ndoesn't mean one is wise.\nWhoever's secure —\nno hostility,\nfear —\nis said to be wise."},{"k":"suddhaso","t":"One is not wise\njust because one talks a lot.\nOne who is safe, non-hostile, harmless and fearless\nis said to be wise."},{"k":"sujato","t":"You're not an astute scholar\njust because you speak a lot.\nOne who is secure, free of enmity and fear,\nis said to be astute."}]},{"n":259,"vg":19,"pali":"Na tāvatā dhammadharo,\nyāvatā bahu bhāsati;\nYo ca appampi sutvāna,\ndhammaṁ kāyena passati;\nSa ve dhammadharo hoti,\nyo dhammaṁ nappamajjati.","v":[{"k":"muller","t":"A man is not a supporter of the law because he talks much; even if a man has learnt little, but sees the law bodily, he is a supporter of the law, a man who never neglects the law."},{"k":"wagiswara","t":"Not by much talk doth one uphold the Norm.\nWho sees the Norm in action, tho' he be\nOf little learning, strenuous in the Norm,\n'Tis he upholds the Norm."},{"k":"kaviratna","t":"One is not a supporter of Dhamma merely because he talks much. But he who hears only a little of the Law, yet perceives its essence by diligent exertion, and does not neglect it, is indeed a true supporter of Dhamma."},{"k":"buddharakkhita","t":"A man is not versed in Dhamma because he speaks much. He who, after hearing a little Dhamma, realizes its truth directly and is not heedless of it, is truly versed in the Dhamma."},{"k":"thanissaro","t":"Simply talking a lot\ndoesn't maintain the Dhamma.\nWhoever\n— although he's heard next to nothing —\nsees Dhamma through his body,\nis not heedless of Dhamma:\nhe's one who maintains the Dhamma."},{"k":"suddhaso","t":"One is not an upholder of the Dhamma\njust because one talks a lot.\nEven if one has learned little\nbut personally sees the Dhamma,\nthen one is an upholder of the Dhamma,\none who does not neglect the Dhamma."},{"k":"sujato","t":"You're not one who has memorized the teaching\njust because you recite a lot.\nSomeone who directly sees the teaching\nafter hearing only a little\nis truly one who has memorized the teaching,\nfor they can never forget it."}]},{"n":260,"vg":19,"pali":"Na tena thero so hoti,\nyenassa palitaṁ siro;\nParipakko vayo tassa,\n\"moghajiṇṇo\"ti vuccati.","v":[{"k":"muller","t":"A man is not an elder because his head is grey; his age may be ripe, but he is called `Old-in-vain.'"},{"k":"wagiswara","t":"Grey hairs do not a man an elder make.\nTho' ripe in years, if all his age be vain,\nHe may be dotard called."},{"k":"kaviratna","t":"One does not become an elder by reason of his hair being grey. Of course, he may be ripe in age, but he is a person \"grown old in vain.\""},{"k":"buddharakkhita","t":"A monk is not an elder because his head is gray. He is but ripe in age, and he is called one grown old in vain."},{"k":"thanissaro","t":"A head of gray hairs\ndoesn't mean one's an elder.\nAdvanced in years,\none's called an old fool.\n\nBut one in whom there is\ntruth, restraint,\nrectitude, gentleness,\nself-control —\nhe's called an elder,\nhis impurities disgorged,\nenlightened."},{"k":"suddhaso","t":"One is not an elder\njust because one has grey hairs on one's head.\nOne is who is decrepit and feeble\nis said to be an old fool."},{"k":"sujato","t":"You don't become a senior\nby getting some grey hairs;\nfor one ripe only in age,\nis said to have aged in vain."}]},{"n":261,"vg":19,"pali":"Yamhi saccañca dhammo ca,\nahiṁsā saṁyamo damo;\nSa ve vantamalo dhīro,\n\"thero\" iti pavuccati.","v":[{"k":"muller","t":"He in whom there is truth, virtue, love, restraint, moderation, he who is free from impurity and is wise, he is called an elder."},{"k":"wagiswara","t":"True, virtuous, harmless, moderate, restrained,\nWise and washed clean of all impurities,\nHe is an elder called."},{"k":"kaviratna","t":"He in whom there dwell truth, virtue, nonviolence, self-restraint and moderation, such a wise monk who has cast away all impurities is indeed called an elder (thera)."},{"k":"buddharakkhita","t":"One in whom there is truthfulness, virtue, inoffensiveness, restraint and self-mastery, who is free from defilements and is wise — he is truly called an Elder."},{"k":"thanissaro","t":"A head of gray hairs\ndoesn't mean one's an elder.\nAdvanced in years,\none's called an old fool.\n\nBut one in whom there is\ntruth, restraint,\nrectitude, gentleness,\nself-control —\nhe's called an elder,\nhis impurities disgorged,\nenlightened."},{"k":"suddhaso","t":"But one who is truthful, in accordance with the Dhamma,\nharmless, self-restrained, trained,\nsteadfast, and free of all contaminants\nis said to be an elder."},{"k":"sujato","t":"One who is truthful and principled,\nharmless, restrained, and self-controlled,\nattentive, purged of stains,\nis said to be a senior."}]},{"n":262,"vg":19,"pali":"Na vākkaraṇamattena,\nvaṇṇapokkharatāya vā;\nSādhurūpo naro hoti,\nissukī maccharī saṭho.","v":[{"k":"muller","t":"An envious greedy, dishonest man does not become respectable by means of much talking only, or by the beauty of his complexion."},{"k":"wagiswara","t":"Not by mere talk nor beauty of his form,\nIf he be grudging, greedy, fraudulent,\nIs any reverend called."},{"k":"kaviratna","t":"Not by mere ornate speech, nor by a beautiful complexion, does a man who is jealous, selfish and crafty become worthy of respect."},{"k":"buddharakkhita","t":"Not by mere eloquence nor by beauty of form does a man become accomplished, if he is jealous, selfish and deceitful."},{"k":"thanissaro","t":"Not by suave conversation\nor lotus-like coloring\ndoes an envious, miserly cheat\nbecome an exemplary man.\n\nBut one in whom this is\ncut through\nup- rooted\nwiped out —\nhe's called exemplary,\nhis aversion disgorged,\nintelligent."},{"k":"suddhaso","t":"Not by the quality of their conversation\nor the beauty of their appearance\nis a person considered excellent,\nif they are envious, stingy, and deceitful."},{"k":"sujato","t":"Not by mere enunciation,\nor a beautiful complexion\ndoes a person become holy,\nif they're jealous, stingy, and devious."}]},{"n":263,"vg":19,"pali":"Yassa cetaṁ samucchinnaṁ,\nmūlaghaccaṁ samūhataṁ;\nSa vantadoso medhāvī,\n\"sādhurūpo\"ti vuccati.","v":[{"k":"muller","t":"He in whom all this is destroyed, and taken out with the very root, he, when freed from hatred and wise, is called respectable."},{"k":"wagiswara","t":"In whom these faults are cut down, rooted out,\nWho hath cast off his sins, who meditates,\nThat man is reverend called."},{"k":"kaviratna","t":"But he in whom these evils are completely uprooted and extinguished, who has given up hatred and is wise — indeed he is called worthy of respect."},{"k":"buddharakkhita","t":"But he in whom these are wholly destroyed, uprooted and extinct, and who has cast out hatred — that wise man is truly accomplished."},{"k":"thanissaro","t":"Not by suave conversation\nor lotus-like coloring\ndoes an envious, miserly cheat\nbecome an exemplary man.\n\nBut one in whom this is\ncut through\nup- rooted\nwiped out —\nhe's called exemplary,\nhis aversion disgorged,\nintelligent."},{"k":"suddhaso","t":"One who has shredded,\nuprooted, and destroyed those qualities,\na wise person who has expelled their defects,\nis said to be excellent."},{"k":"sujato","t":"But if they've cut that out,\ndug it up at the root, eradicated it,\nthat wise one, purged of vice,\nis said to be holy."}]},{"n":264,"vg":19,"pali":"Na muṇḍakena samaṇo,\nabbato alikaṁ bhaṇaṁ;\nIcchālobhasamāpanno,\nsamaṇo kiṁ bhavissati.","v":[{"k":"muller","t":"Not by tonsure does an undisciplined man who speaks falsehood become a Samana; can a man be a Samana who is still held captive by desire and greediness?"},{"k":"wagiswara","t":"A shaven crown makes not the Samana.\nIf such a one, lying and unrestrained,\nBe full of lust and craving, how can he\nA Samana be called?"},{"k":"kaviratna","t":"Not by tonsure does one who is undisciplined and utters lies become a monk. How can he who is overcome by desire and greed become a monk?"},{"k":"buddharakkhita","t":"Not by shaven head does a man who is indisciplined and untruthful become a monk. How can he who is full of desire and greed be a monk?"},{"k":"thanissaro","t":"A shaven head\ndoesn't mean a contemplative.\nThe liar observing no duties,\nfilled with greed & desire:\nwhat kind of contemplative's he?"},{"k":"suddhaso","t":"One is not a contemplative just because one has a shaven head.\nIf one has no religious practices, tells lies,\nand is full of desire and greed,\nhow can they be a contemplative?"},{"k":"sujato","t":"A liar and breaker of vows is no ascetic\njust because they shave their head.\nHow on earth can one be an ascetic\nwho's full of desire and greed?"}]},{"n":265,"vg":19,"pali":"Yo ca sameti pāpāni,\naṇuṁthūlāni sabbaso;\nSamitattā hi pāpānaṁ,\n\"samaṇo\"ti pavuccati.","v":[{"k":"muller","t":"He who always quiets the evil, whether small or large, he is called a Samana (a quiet man), because he has quieted all evil."},{"k":"wagiswara","t":"But if he calm his faults, both great and small,\nSince he all evil ways hath quieted,\nHe is a Samana."},{"k":"kaviratna","t":"But he who constantly stills his evil tendencies, small or great, is called a true monk (samana), because he has quieted all these evils."},{"k":"buddharakkhita","t":"He who wholly subdues evil both small and great is called a monk, because he has overcome all evil."},{"k":"thanissaro","t":"But whoever tunes out\nthe dissonance\nof his evil qualities\n— large or small —\nin every way\nby bringing evil to consonance:\nhe's called a contemplative."},{"k":"suddhaso","t":"One who tranquilizes all that is evil,\nwhether minor or major,\none who has tranquilized all that is evil\nis said to be a contemplative."},{"k":"sujato","t":"One who stops all wicked deeds,\ngreat and small,\nbecause of stopping wicked deeds\nis said to be an ascetic."}]},{"n":266,"vg":19,"pali":"Na tena bhikkhu so hoti,\nyāvatā bhikkhate pare;\nVissaṁ dhammaṁ samādāya,\nbhikkhu hoti na tāvatā.","v":[{"k":"muller","t":"A man is not a mendicant (Bhikshu) simply because he asks others for alms; he who adopts the whole law is a Bhikshu, not he who only begs."},{"k":"wagiswara","t":"He is no mendicant who begs his food.\nNot he who begs but he who keeps the Norm,\nHe is a mendicant."},{"k":"kaviratna","t":"He is not a religious mendicant because he begs alms from others. He does not become a bhikkhu merely by outward observances of the Law."},{"k":"buddharakkhita","t":"He is not a monk just because he lives on others' alms. Not by adopting outward form does one become a true monk."},{"k":"thanissaro","t":"Begging from others\ndoesn't mean one's a monk.\nAs long as one follows\nhouseholders' ways,\none is no monk at all."},{"k":"suddhaso","t":"One is not a monk\njust because one receives almsfood from others.\nOne who takes up a flawed doctrine\nis not a monk."},{"k":"sujato","t":"You don't become a mendicant\njust by begging from others.\nOne who has undertaken domestic duties\nhas not yet become a mendicant."}]},{"n":267,"vg":19,"pali":"Yodha puññañca pāpañca,\nbāhetvā brahmacariyavā;\nSaṅkhāya loke carati,\nsa ve \"bhikkhū\"ti vuccati.","v":[{"k":"muller","t":"He who is above good and evil, who is chaste, who with knowledge passes through the world, he indeed is called a Bhikshu."},{"k":"wagiswara","t":"He who hath good and evil laid aside,\nWho wisely in this world walks righteously,\nHe is a mendicant."},{"k":"kaviratna","t":"But he who has transcended both merit and demerit, who leads a life of purity and lives in this world in full realization of the Truth, he indeed is called a bhikkhu."},{"k":"buddharakkhita","t":"Whoever here (in the Dispensation) lives a holy life, transcending both merit and demerit, and walks with understanding in this world — he is truly called a monk."},{"k":"thanissaro","t":"But whoever puts aside\nboth merit & evil and,\nliving the chaste life,\njudiciously\ngoes through the world:\nhe's called a monk."},{"k":"suddhaso","t":"One who has discarded both merit and evil,\nlives a spiritual life,\nand wanders in the world with careful consideration\nis said to be a monk."},{"k":"sujato","t":"But one living a spiritual life,\nwho has banished both merit and evil,\nwho wanders having appraised the world,\nis said to be a mendicant."}]},{"n":268,"vg":19,"pali":"Na monena munī hoti,\nmūḷharūpo aviddasu;\nYo ca tulaṁva paggayha,\nvaramādāya paṇḍito.","v":[{"k":"muller","t":"A man is not a Muni because he observes silence (mona, i.e. mauna), if he is foolish and ignorant; but the wise who, taking the balance, chooses the good and avoids evil, he is a Muni, and is a Muni thereby; he who in this world weighs both sides is called a Muni."},{"k":"wagiswara","t":"He is no Muni who refrains from speech,\nIf he be foolish and have wandering wits.\nBut he who holds the balance, grasps the real,\nWho's wise to choose the good and leave the bad,\nWho in this world sees both sides, is thereby\nA Muni truly called."},{"k":"kaviratna","t":"By quietude alone one does not become a sage (muni) if he is foolish and ignorant. But he who, as if holding a pair of scales, takes the good and shuns the evil, is a wise man; he is indeed a muni by that very reason. He who understands both good and evil as they really are, is called a true sage."},{"k":"buddharakkhita","t":"Not by observing silence does one become a sage, if he be foolish and ignorant. But that man is wise who, as if holding a balance-scale accepts only the good."},{"k":"thanissaro","t":"Not by silence\ndoes someone confused\n& unknowing\nturn into a sage.\nBut whoever — wise,\nas if holding the scales,\ntaking the excellent —\nrejects evil deeds:\nhe is a sage,\nthat's how he's a sage.\nWhoever can weigh\nboth sides of the world:\nthat's how he's called\na sage."},{"k":"suddhaso","t":"One is not a sage if they act like one\nyet are confused and ignorant.\nA wise person who carefully weighs their options,\nchooses the best,"},{"k":"sujato","t":"You don't become a sage by being sagelike,\nwhile still confused and ignorant.\nThe astute one who holds the scales,\ntaking only the best,"}]},{"n":269,"vg":19,"pali":"Pāpāni parivajjeti,\nsa munī tena so muni;\nYo munāti ubho loke,\n\"muni\" tena pavuccati.","v":[{"k":"muller","t":"A man is not a Muni because he observes silence (mona, i.e. mauna), if he is foolish and ignorant; but the wise who, taking the balance, chooses the good and avoids evil, he is a Muni, and is a Muni thereby; he who in this world weighs both sides is called a Muni."},{"k":"kaviratna","t":"By quietude alone one does not become a sage (muni) if he is foolish and ignorant. But he who, as if holding a pair of scales, takes the good and shuns the evil, is a wise man; he is indeed a muni by that very reason. He who understands both good and evil as they really are, is called a true sage."},{"k":"buddharakkhita","t":"The sage (thus) rejecting the evil, is truly a sage. Since he comprehends both (present and future) worlds, he is called a sage."},{"k":"thanissaro","t":"Not by silence\ndoes someone confused\n& unknowing\nturn into a sage.\nBut whoever — wise,\nas if holding the scales,\ntaking the excellent —\nrejects evil deeds:\nhe is a sage,\nthat's how he's a sage.\nWhoever can weigh\nboth sides of the world:\nthat's how he's called\na sage."},{"k":"suddhaso","t":"and completely avoids evil\nis a sage; because of this one is a sage.\nOne who evaluates both of these in the world\nis said to be a sage."},{"k":"sujato","t":"and shunning the bad—\nthat is a sage,\nand that is how one becomes a sage.\nOne who sagely weighs both in the world,\nis thereby said to be a sage."}]},{"n":270,"vg":19,"pali":"Na tena ariyo hoti,\nyena pāṇāni hiṁsati;\nAhiṁsā sabbapāṇānaṁ,\n\"ariyo\"ti pavuccati.","v":[{"k":"muller","t":"A man is not an elect (Ariya) because he injures living creatures; because he has pity on all living creatures, therefore is a man called Ariya."},{"k":"wagiswara","t":"He is no Worthy One who creatures harms.\nBy harmlessness to every living thing\nA man is Worthy called."},{"k":"kaviratna","t":"He who injures living beings is not an Ariya (noble). By nonviolence towards all living beings one becomes an Ariya."},{"k":"buddharakkhita","t":"He is not noble who injures living beings. He is called noble because he is harmless towards all living beings."},{"k":"thanissaro","t":"Not by harming life\ndoes one become noble.\nOne is termed noble\nfor being gentle\nto all living things."},{"k":"suddhaso","t":"One is not noble\nif one harms living beings.\nOne who does not harm any living being\nis said to be noble."},{"k":"sujato","t":"You don't become a noble one\nby harming living beings.\nOne harmless towards all living beings\nis said to be a noble one."}]},{"n":271,"vg":19,"pali":"Na sīlabbatamattena,\nbāhusaccena vā pana;\nAtha vā samādhilābhena,\nvivittasayanena vā.","v":[{"k":"muller","t":"Not only by discipline and vows, not only by much learning, not by entering into a trance, not by sleeping alone, do I earn the happiness of release which no worldling can know. Bhikshu, be not confident as long as thou hast not attained the extinction of desires."},{"k":"wagiswara","t":"Not by mere goodness nor by ceremonies,\nNot by vast knowledge nor by ecstasy,\nNor by a life retired,\nNor sleeping lonely, do I touch the Bliss\nOf freedom which no worldly one can know.\nBy killing all desire, the mendicant\nAttaineth confidence."},{"k":"kaviratna","t":"Not merely by the practice of morality and self-discipline nor by great learning, not even by samadhi (profound spiritual contemplation) or by a life of seclusion, do I reach the bliss of freedom which is not attainable by the ordinary mortal. O bhikkhu, rest not content until you have attained the extinction of all desires."},{"k":"buddharakkhita","t":"Not by rules and observances, not even by much learning, nor by gain of absorption, nor by a life of seclusion, nor by thinking, \"I enjoy the bliss of renunciation, which is not experienced by the worldling\" should you, O monks, rest content, until the utter destruction of cankers (Arahantship) is reached."},{"k":"thanissaro","t":"Monk,\ndon't\non account of\nyour precepts & practices,\ngreat erudition,\nconcentration attainments,\nsecluded dwelling,\nor the thought, 'I touch\nthe renunciate ease\nthat run-of-the-mill people\ndon't know':\never let yourself get complacent\nwhen the ending of effluents\nis still unattained."},{"k":"suddhaso","t":"Not just by morality or by spiritual practices\nor by learning a lot\nor by gaining concentration\nor by sleeping in seclusion"},{"k":"sujato","t":"Not by precepts and observances,\nnor by much learning,\nnor by meditative immersion,\nnor by living in seclusion,"}]},{"n":272,"vg":19,"pali":"Phusāmi nekkhammasukhaṁ,\naputhujjanasevitaṁ;\nBhikkhu vissāsamāpādi,\nappatto āsavakkhayaṁ.\nDhammaṭṭhavaggo ekūnavīsatimo.","v":[{"k":"muller","t":"Not only by discipline and vows, not only by much learning, not by entering into a trance, not by sleeping alone, do I earn the happiness of release which no worldling can know. Bhikshu, be not confident as long as thou hast not attained the extinction of desires."},{"k":"wagiswara","t":"Not by mere goodness nor by ceremonies,\nNot by vast knowledge nor by ecstasy,\nNor by a life retired,\nNor sleeping lonely, do I touch the Bliss\nOf freedom which no worldly one can know.\nBy killing all desire, the mendicant\nAttaineth confidence."},{"k":"kaviratna","t":"Not merely by the practice of morality and self-discipline nor by great learning, not even by samadhi (profound spiritual contemplation) or by a life of seclusion, do I reach the bliss of freedom which is not attainable by the ordinary mortal. O bhikkhu, rest not content until you have attained the extinction of all desires."},{"k":"buddharakkhita","t":"Not by rules and observances, not even by much learning, nor by gain of absorption, nor by a life of seclusion, nor by thinking, \"I enjoy the bliss of renunciation, which is not experienced by the worldling\" should you, O monks, rest content, until the utter destruction of cankers (Arahantship) is reached."},{"k":"thanissaro","t":"Monk,\ndon't\non account of\nyour precepts & practices,\ngreat erudition,\nconcentration attainments,\nsecluded dwelling,\nor the thought, 'I touch\nthe renunciate ease\nthat run-of-the-mill people\ndon't know':\never let yourself get complacent\nwhen the ending of effluents\nis still unattained."},{"k":"suddhaso","t":"or by experiencing the happiness of renunciation\nor by associating with uncommon people\nshould a monk be satisfied\nas long as one's defilements have not been eliminated."},{"k":"sujato","t":"do I experience the bliss of renunciation\nnot frequented by ordinary people.\nA mendicant cannot rest confident\nwithout attaining the end of defilements."}]},{"n":273,"vg":20,"pali":"Maggānaṭṭhaṅgiko seṭṭho,\nsaccānaṁ caturo padā;\nVirāgo seṭṭho dhammānaṁ,\ndvipadānañca cakkhumā.","v":[{"k":"muller","t":"The best of ways is the eightfold; the best of truths the four words; the best of virtues passionlessness; the best of men he who has eyes to see."},{"k":"wagiswara","t":"Best is the Eightfold Path: of truths, the four;\nDispassion in the best of states sublime.\nBlest is he of human beings, who hath eyes to see."},{"k":"kaviratna","t":"Of paths the Eightfold is the best; of truths the Four Noble Truths are the best; of all states Detachment is the best; of men (1) the Seeing One (Buddha) is the foremost."},{"k":"buddharakkhita","t":"Of all the paths the Eightfold Path is the best; of all the truths the Four Noble Truths are the best; of all things passionlessness is the best: of men the Seeing One (the Buddha) is the best."},{"k":"thanissaro","t":"Of paths, the eightfold is best.\nOf truths, the four sayings.\nOf qualities, dispassion.\nOf two-footed beings,\nthe one with the eyes\nto see."},{"k":"suddhaso","t":"The best of paths is the Eightfold;\nof truths, the one in four steps.\nThe best of qualities is dispassion;\nof bipeds, the one who sees."},{"k":"sujato","t":"Of paths, the eightfold is the best;\nof truths, the four statements;\ndispassion is the best of things,\nand the Clear-eyed One is the best of humans."}]},{"n":274,"vg":20,"pali":"Eseva maggo natthañño,\nDassanassa visuddhiyā;\nEtañhi tumhe paṭipajjatha,\nMārassetaṁ pamohanaṁ.","v":[{"k":"muller","t":"This is the way, there is no other that leads to the purifying of intelligence. Go on this way! Everything else is the deceit of Mara (the tempter)."},{"k":"wagiswara","t":"This is the way; no other way can lead ye\nTo purify the mind and see the truth.\nWalk this Way and free yourselves from Māra's host of ills."},{"k":"kaviratna","t":"This is the path; there is no other path that leads to purity of insight. Follow this path, for this path bewilders the Evil One (Mara)."},{"k":"buddharakkhita","t":"This is the only path; there is none other for the purification of insight. Tread this path, and you will bewilder Mara."},{"k":"thanissaro","t":"Just this\nis the path\n— there is no other —\nto purify vision.\nFollow it,\nand that will be Mara's\nbewilderment."},{"k":"suddhaso","t":"This is the path - there is no other -\nfor obtaining vision and purity.\nTherefore, follow this path\nwhich confuses Māra."},{"k":"sujato","t":"This is the path, there is no other\nfor the purification of vision.\nYou all must practice this,\nit is the way to baffle Māra."}]},{"n":275,"vg":20,"pali":"Etañhi tumhe paṭipannā,\ndukkhassantaṁ karissatha;\nAkkhāto vo mayā maggo,\naññāya sallakantanaṁ.","v":[{"k":"muller","t":"If you go on this way, you will make an end of pain! The way was preached by me, when I had understood the removal of the thorns (in the flesh)."},{"k":"wagiswara","t":"Tread ye this Path, and make an end of sorrow.\nTread ye this Path for I myself have shown it.\nShown it after learning how to pluck away the thorns."},{"k":"kaviratna","t":"Having entered upon the path you will come to an end of your suffering. Having myself recognized this, I proclaimed this path which removes all thorns."},{"k":"buddharakkhita","t":"Walking upon this path you will make an end of suffering. Having discovered how to pull out the thorn of lust, I make known the path."},{"k":"thanissaro","t":"Following it,\nyou put an end\nto suffering & stress.\nI have taught you this path\nhaving known\n— for your knowing —\nthe extraction of arrows."},{"k":"suddhaso","t":"When you have followed this path\nyou will end suffering.\nI have explained the path for you;\nby means of knowledge the sting is eased."},{"k":"sujato","t":"When you all are practicing this,\nyou'll make an end of suffering.\nI have explained the path to you\nfor extracting the thorn with wisdom."}]},{"n":276,"vg":20,"pali":"Tumhehi kiccamātappaṁ,\nakkhātāro tathāgatā;\nPaṭipannā pamokkhanti,\njhāyino mārabandhanā.","v":[{"k":"muller","t":"You yourself must make an effort. The Tathagatas (Buddhas) are only preachers. The thoughtful who enter the way are freed from the bondage of Mara."},{"k":"wagiswara","t":"Strive ye yourselves; Buddha's but preach the way\nTo them that strive. To meditation given\nThey who walk this Way are free from Māra's every bond."},{"k":"kaviratna","t":"You yourself must make the effort. The Tathagatas (Buddhas) can only point the way. Those who have entered the path and become meditative are freed from the fetters of Mara."},{"k":"buddharakkhita","t":"You yourselves must strive; the Buddhas only point the way. Those meditative ones who tread the path are released from the bonds of Mara."},{"k":"thanissaro","t":"It's for you to strive\nardently.\nTathagatas simply\npoint out the way.\nThose who practice,\nabsorbed in jhana:\nfrom Mara's bonds\nthey'll be freed."},{"k":"suddhaso","t":"It is by you that the effort must be made;\nthe Truth-Finders just explain.\nThose who have followed the path become free\nfrom the bonds of Māra."},{"k":"sujato","t":"You yourselves must do the work,\nthe Realized Ones just show the way.\nMeditators practicing absorption\nare released from Māra's bonds."}]},{"n":277,"vg":20,"pali":"\"Sabbe saṅkhārā aniccā\"ti,\nyadā paññāya passati;\nAtha nibbindati dukkhe,\nesa maggo visuddhiyā.","v":[{"k":"muller","t":"`All created things perish,' he who knows and sees this becomes passive in pain; this is the way to purity."},{"k":"wagiswara","t":"_\"All things compounded are impermanent\"_;\nWhoso sees this with opened inner eye\nWearies soon of sorrow. 'Tis the Path of Purity."},{"k":"kaviratna","t":"\"Transient are all composite things\"; he who perceives the truth of this gets disgusted with this world of suffering. This is the path to purity."},{"k":"buddharakkhita","t":"\"All conditioned things are impermanent\" — when one sees this with wisdom, one turns away from suffering. This is the path to purification."},{"k":"thanissaro","t":"When you see with discernment,\n'All fabrications are inconstant' —\nyou grow disenchanted with stress.\nThis is the path\nto purity."},{"k":"suddhaso","t":"Everything is impermanent -\nwhen one sees this with wisdom,\none becomes disenchanted with suffering;\nthis is the path to purity."},{"k":"sujato","t":"All conditions are impermanent—\nwhen this is seen with wisdom,\none grows disillusioned with suffering:\nthis is the path to purity."}]},{"n":278,"vg":20,"pali":"\"Sabbe saṅkhārā dukkhā\"ti,\nyadā paññāya passati;\nAtha nibbindati dukkhe,\nesa maggo visuddhiyā.","v":[{"k":"muller","t":"`All created things are grief and pain,' he who knows and sees this becomes passive in pain; this is the way that leads to purity."},{"k":"wagiswara","t":"_\"All things compounded are of sorrow made\"_;\nWhoso sees this with opened inner eye,\nWearies soon of sorrow. 'Tis the Path of Purity."},{"k":"kaviratna","t":"\"Sorrowful are all composite things\"; he who perceives the truth of this gets disgusted with this world of suffering. This is the path to purity."},{"k":"buddharakkhita","t":"\"All conditioned things are unsatisfactory\" — when one sees this with wisdom, one turns away from suffering. This is the path to purification."},{"k":"thanissaro","t":"When you see with discernment,\n'All fabrications are stressful' —\nyou grow disenchanted with stress.\nThis is the path\nto purity."},{"k":"suddhaso","t":"Everything is unsatisfying -\nwhen one sees this with wisdom\none becomes disenchanted with suffering;\nthis is the path to purity."},{"k":"sujato","t":"All conditions are suffering—\nwhen this is seen with wisdom,\none grows disillusioned with suffering:\nthis is the path to purity."}]},{"n":279,"vg":20,"pali":"\"Sabbe dhammā anattā\"ti,\nyadā paññāya passati;\nAtha nibbindati dukkhe,\nesa maggo visuddhiyā.","v":[{"k":"muller","t":"`All forms are unreal,' he who knows and sees this becomes passive in pain; this is the way that leads to purity."},{"k":"wagiswara","t":"_\"All states compounded are without a self\"_;\nWhoso sees this with opened inner eye,\nWearies soon of sorrow. 'Tis the Path of Purity."},{"k":"kaviratna","t":"\"All forms of existence are unreal\" (an-atta); he who perceives the truth of this gets disgusted with this world of suffering. This is the path to purity."},{"k":"buddharakkhita","t":"\"All things are not-self\" — when one sees this with wisdom, one turns away from suffering. This is the path to purification."},{"k":"thanissaro","t":"When you see with discernment,\n'All phenomena are not-self' —\nyou grow disenchanted with stress.\nThis is the path\nto purity."},{"k":"suddhaso","t":"Everything is impersonal -\nwhen one sees this with wisdom,\none becomes disenchanted with suffering;\nthis is the path to purity."},{"k":"sujato","t":"All things are not-self—\nwhen this is seen with wisdom,\none grows disillusioned with suffering:\nthis is the path to purity."}]},{"n":280,"vg":20,"pali":"Uṭṭhānakālamhi anuṭṭhahāno,\nYuvā balī ālasiyaṁ upeto;\nSaṁsannasaṅkappamano kusīto,\nPaññāya maggaṁ alaso na vindati.","v":[{"k":"muller","t":"He who does not rouse himself when it is time to rise, who, though young and strong, is full of sloth, whose will and thought are weak, that lazy and idle man will never find the way to knowledge."},{"k":"wagiswara","t":"Whoso strives not when it is time to strive,\nTho' young and strong, to sloth and folly prone,\nWeak in will and thought, to knowledge never finds the way."},{"k":"kaviratna","t":"He who does not get up when it is time to do so; who, although youthful and strong, is yet given to indolence, is weak in resolution and thought — such an idle and lazy person does not find the path to wisdom."},{"k":"buddharakkhita","t":"The idler who does not exert himself when he should, who though young and strong is full of sloth, with a mind full of vain thoughts — such an indolent man does not find the path to wisdom."},{"k":"thanissaro","t":"At the time for initiative\nhe takes no initiative.\nYoung, strong, but lethargic,\nthe resolves of his heart\nexhausted,\nthe lazy, lethargic one\nloses the path\nto discernment."},{"k":"suddhaso","t":"Not rising to the occasion when it is time to do so,\nyoung and strong, but indolent,\naimless, and lazy,\nthe indolent one does not find the path of wisdom."},{"k":"sujato","t":"They don't get going when it's time to start;\nthey're young and strong, but given to sloth.\nTheir mind depressed in sunken thought,\nlazy and slothful, they can't discern the path."}]},{"n":281,"vg":20,"pali":"Vācānurakkhī manasā susaṁvuto,\nKāyena ca nākusalaṁ kayirā;\nEte tayo kammapathe visodhaye,\nĀrādhaye maggamisippaveditaṁ.","v":[{"k":"muller","t":"Watching his speech, well restrained in mind, let a man never commit any wrong with his body! Let a man but keep these three roads of action clear, and he will achieve the way which is taught by the wise."},{"k":"wagiswara","t":"Who guardeth speech and mind, who doth no wrong\nWith body, making pure the triple way,\nHe shall tread the Path of Wisdom by the sages shown."},{"k":"kaviratna","t":"One should be watchful over his speech, well-restrained in mind, and commit no unwholesome deed with his body. Let him purify this threefold avenue of action (karma), and he will tread the path made known by the sages."},{"k":"buddharakkhita","t":"Let a man be watchful of speech, well controlled in mind, and not commit evil in bodily action. Let him purify these three courses of action, and win the path made known by the Great Sage."},{"k":"thanissaro","t":"Guarded in speech,\nwell-restrained in mind,\nyou should do nothing unskillful\nin body.\nPurify\nthese three courses of action.\nBring to fruition\nthe path that seers have proclaimed."},{"k":"suddhaso","t":"With speech controlled and mind well-restrained,\nand doing nothing harmful with the body,\npurify these three paths of karma\nand accomplish the path demonstrated by the seer."},{"k":"sujato","t":"Guarded in speech, restrained in mind,\ndoing no unskillful bodily deed.\nPurify these three ways of performing deeds,\nand win the path known to seers."}]},{"n":282,"vg":20,"pali":"Yogā ve jāyatī bhūri,\nayogā bhūrisaṅkhayo;\nEtaṁ dvedhāpathaṁ ñatvā,\nbhavāya vibhavāya ca;\nTathāttānaṁ niveseyya,\nyathā bhūri pavaḍḍhati.","v":[{"k":"muller","t":"Through zeal knowledge is gotten, through lack of zeal knowledge is lost; let a man who knows this double path of gain and loss thus place himself that knowledge may grow."},{"k":"wagiswara","t":"Wisdom is born of meditation deep,\nBut lost by mind's distraction; knowing these\nTwo paths of loss and gain, so let him live,\nLet him so direct his life that wisdom may increase."},{"k":"kaviratna","t":"Verily, from devotion (yoga) arises wisdom, from nondevotion springs the loss of wisdom. Having become aware of this twofold path that leads to progress and decline, let him place himself in such a way that his wisdom increases."},{"k":"buddharakkhita","t":"Wisdom springs from meditation; without meditation wisdom wanes. Having known these two paths of progress and decline, let a man so conduct himself that his wisdom may increase."},{"k":"thanissaro","t":"From striving comes wisdom;\nfrom not, wisdom's end.\nKnowing these two courses\n— to development,\ndecline —\nconduct yourself\nso that wisdom will grow."},{"k":"suddhaso","t":"Commitment produces abundance,\na lack of commitment completely eliminates it.\nKnowing these two paths\nwhich lead to existence and non-existence,\none should settle oneself accordingly\nand cultivate abundance."},{"k":"sujato","t":"From meditation springs wisdom,\nwithout meditation, wisdom ends.\nKnowing these two paths—\nof progress and decline—\nyou should conduct yourself\nso that wisdom grows."}]},{"n":283,"vg":20,"pali":"Vanaṁ chindatha mā rukkhaṁ,\nvanato jāyate bhayaṁ;\nChetvā vanañca vanathañca,\nnibbanā hotha bhikkhavo.","v":[{"k":"muller","t":"Cut down the whole forest (of lust), not a tree only! Danger comes out of the forest (of lust). When you have cut down both the forest (of lust) and its undergrowth, then, Bhikshus, you will be rid of the forest and free!"},{"k":"wagiswara","t":"Cut down trees and undergrowth, and from desire be free!\nFor from this jungle fear of danger's born;\nCut it down, O mendicants, and from desire be free!"},{"k":"kaviratna","t":"Cut down the whole forest (of desires), not just a tree. From the forest arises fear. Cut down the forest and its brushwood, O monks, and be emancipated."},{"k":"buddharakkhita","t":"Cut down the forest (lust), but not the tree; from the forest springs fear. Having cut down the forest and the underbrush (desire), be passionless, O monks! [20]"},{"k":"thanissaro","t":"Cut down\nthe forest of desire,\nnot the forest of trees.\nFrom the forest of desire\ncome danger & fear.\nHaving cut down this forest\n& its underbrush, monks,\nbe deforested."},{"k":"suddhaso","t":"Cut down the forest, not the tree;\nthe forest produces danger.\nWhen you have cut down the forest and its undergrowth,\nyou will have no forest, monks."},{"k":"sujato","t":"Cut down the jungle, not just a tree;\nfrom the jungle springs fear.\nHaving cut down jungle and snarl,\nbe free of jungles, mendicants!"}]},{"n":284,"vg":20,"pali":"Yāva hi vanatho na chijjati,\nAṇumattopi narassa nārisu;\nPaṭibaddhamanova tāva so,\nVaccho khīrapakova mātari.","v":[{"k":"muller","t":"So long as the love of man towards women, even the smallest, is not destroyed, so long is his mind in bondage, as the calf that drinks milk is to its mother."},{"k":"wagiswara","t":"If but a trace there be, however small,\nOf lust of man for woman, as a calf\nClingeth to its dam, the mind in bondage will be held."},{"k":"kaviratna","t":"As long as the brushwood of a man's lust towards women is not completely destroyed, even to the last seedling, so long is his mind fettered as a suckling calf is bound to its mother."},{"k":"buddharakkhita","t":"For so long as the underbrush of desire, even the most subtle, of a man towards a woman is not cut down, his mind is in bondage, like the sucking calf to its mother."},{"k":"thanissaro","t":"For as long as the least\nbit of underbrush\nof a man for women\nis not cleared away,\nthe heart is fixated\nlike a suckling calf\non its mother."},{"k":"suddhaso","t":"As long as the undergrowth has not been cut down,\neven if only a tiny amount is left, then whether one is a man or a woman\none will be bound to it,\nlike a calf sucking milk from its mother."},{"k":"sujato","t":"So long as the vine, no matter how small,\nthat ties a man to women is not cut,\nhis mind remains trapped,\nlike a calf suckling its mother."}]},{"n":285,"vg":20,"pali":"Ucchinda sinehamattano,\nKumudaṁ sāradikaṁva pāṇinā;\nSantimaggameva brūhaya,\nNibbānaṁ sugatena desitaṁ.","v":[{"k":"muller","t":"Cut out the love of self, like an autumn lotus, with thy hand! Cherish the road of peace. Nirvana has been shown by Sugata (Buddha)."},{"k":"wagiswara","t":"Pluck out the love of self with thine own hand,\nJust as the hand an autumn lily plucks;\nTread the Way of Peace declared by Him who hath it trod."},{"k":"kaviratna","t":"Cut off the love of self as one would pluck an autumnal white lotus. Proceed then upon that (Eightfold) path of peace — the nirvana as expounded by Sugata (Buddha)."},{"k":"buddharakkhita","t":"Cut off your affection in the manner of a man who plucks with his hand an autumn lotus. Cultivate only the path to peace, Nibbana, as made known by the Exalted One."},{"k":"thanissaro","t":"Crush\nyour sense of self-allure\nlike an autumn lily\nin the hand.\nNurture only the path to peace\n— Unbinding —\nas taught by the One Well Gone."},{"k":"suddhaso","t":"Cut off self-cherishing,\nlike plucking a lotus in autumn.\nPractice the peaceful path to Nibbāna\nas taught by the Heavenly One."},{"k":"sujato","t":"Cut out affection for oneself,\nlike plucking an autumn lotus.\nFoster only the path to peace,\nthe extinguishment the Holy One taught."}]},{"n":286,"vg":20,"pali":"Idha vassaṁ vasissāmi,\nidha hemantagimhisu;\nIti bālo vicinteti,\nantarāyaṁ na bujjhati.","v":[{"k":"muller","t":"`Here I shall dwell in the rain, here in winter and summer,' thus the fool meditates, and does not think of his death."},{"k":"wagiswara","t":"\"Here in the rainy season will I dwell;\nAnd here in heat and cold.\" So thinks the fool,\nLittle recking of the dangers that may him befall."},{"k":"kaviratna","t":"\"Here shall I dwell in the rainy season; here shall I dwell in winter and summer.\" Thus the fool muses, but never reflects on the dangers that might befall him."},{"k":"buddharakkhita","t":"\"Here shall I live during the rains, here in winter and summer\" — thus thinks the fool. He does not realize the danger (that death might intervene)."},{"k":"thanissaro","t":"'Here I'll stay for the rains.\nHere, for the summer & winter.'\nSo imagines the fool,\nunaware of obstructions.\n\nThat drunk-on-his-sons-&-cattle man,\nall tangled up in the mind:\ndeath sweeps him away —\nas a great flood,\na village asleep."},{"k":"suddhaso","t":"\"Here I will spend the rainy season,\nhere the winter, here the summer.\"\nThis is how a fool thinks,\nnot aware of the obstacle."},{"k":"sujato","t":"\"Here I will stay for the rains;\nhere for winter, here the summer\";\nthus the fool thinks,\nnot realizing the danger."}]},{"n":287,"vg":20,"pali":"Taṁ puttapasusammattaṁ,\nbyāsattamanasaṁ naraṁ;\nSuttaṁ gāmaṁ mahoghova,\nmaccu ādāya gacchati.","v":[{"k":"muller","t":"Death comes and carries off that man, praised for his children and flocks, his mind distracted, as a flood carries off a sleeping village."},{"k":"wagiswara","t":"Care-stricken, with his thoughts of sons and flocks,\nAttached to life, Death comes and seizes him,\nAs a sleeping village by a flood is swept away."},{"k":"kaviratna","t":"As a great flood carries off a sleeping village, so death seizes and carries off a man who is distracted and overly attached to his children and cattle."},{"k":"buddharakkhita","t":"As a great flood carries away a sleeping village, so death seizes and carries away the man with a clinging mind, doting on his children and cattle."},{"k":"thanissaro","t":"'Here I'll stay for the rains.\nHere, for the summer & winter.'\nSo imagines the fool,\nunaware of obstructions.\n\nThat drunk-on-his-sons-&-cattle man,\nall tangled up in the mind:\ndeath sweeps him away —\nas a great flood,\na village asleep."},{"k":"suddhaso","t":"Intoxicated with children and cattle,\na person with mind attached;\nlike a great flood sweeping away a sleeping village,\nsuch a person is swept away by death."},{"k":"sujato","t":"As a mighty flood sweeps away a sleeping village,\ndeath steals away a man\nwho dotes on children and cattle,\nhis mind caught up in them."}]},{"n":288,"vg":20,"pali":"Na santi puttā tāṇāya,\nna pitā nāpi bandhavā;\nAntakenādhipannassa,\nnatthi ñātīsu tāṇatā.","v":[{"k":"muller","t":"Sons are no help, nor a father, nor relations; there is no help from kinsfolk for one whom death has seized."},{"k":"wagiswara","t":"Not all his sons have power to guard that man;\nNo sire, no kinsman can protect him now;\nHow can kinsmen aught avail him in the grasp of Death?"},{"k":"kaviratna","t":"Sons are no protection, neither father nor kinsfolk; when one is assailed by death, there is no protection among one's kin."},{"k":"buddharakkhita","t":"For him who is assailed by death there is no protection by kinsmen. None there are to save him — no sons, nor father, nor relatives."},{"k":"thanissaro","t":"There are no sons\nto give shelter,\nno father,\nno family\nfor one seized by the Ender,\nno shelter among kin."},{"k":"suddhaso","t":"There is no safety in children,\nparents, or kin;\nwhen one is seized by the Ender,\nthere is no safety in relatives."},{"k":"sujato","t":"Children provide you no shelter,\nnor does father, nor relatives.\nWhen you're seized by the terminator,\nthere's no shelter in family."}]},{"n":289,"vg":20,"pali":"Etamatthavasaṁ ñatvā,\npaṇḍito sīlasaṁvuto;\nNibbānagamanaṁ maggaṁ,\nkhippameva visodhaye.\nMaggavaggo vīsatimo.","v":[{"k":"muller","t":"A wise and good man who knows the meaning of this, should quickly clear the way that leads to Nirvana."},{"k":"wagiswara","t":"The wise man, when he sees the truth of this,\nRestrained by righteous living in the Norm,\nSoon will clear the path that leadeth unto Perfect Bliss."},{"k":"kaviratna","t":"Having perceived this significant fact, let the wise and self-restrained man quickly clear the path that leads to nirvana."},{"k":"buddharakkhita","t":"Realizing this fact, let the wise man, restrained by morality, hasten to clear the path leading to Nibbana."},{"k":"thanissaro","t":"Conscious\nof this compelling reason,\nthe wise man, restrained by virtue,\nshould make the path pure\n— right away —\nthat goes all the way to Unbinding."},{"k":"suddhaso","t":"Having understood this issue,\nthe wise person, moral and self-restrained,\nquickly purifies the path\nthat leads to Nibbāna."},{"k":"sujato","t":"Knowing the reason for this,\nastute, and ethically restrained,\none would quickly clear the path\nthat leads to extinguishment."}]},{"n":290,"vg":21,"pali":"Mattāsukhapariccāgā,\npasse ce vipulaṁ sukhaṁ;\nCaje mattāsukhaṁ dhīro,\nsampassaṁ vipulaṁ sukhaṁ.","v":[{"k":"muller","t":"If by leaving a small pleasure one sees a great pleasure, let a wise man leave the small pleasure, and look to the great."},{"k":"wagiswara","t":"If in giving up slight pleasure\nThou a greater bliss discern,\nLeave the lesser gain and wisely\nTo the greater profit turn."},{"k":"kaviratna","t":"If by renouncing a small pleasure one derives great bliss, the wise man relinquishes that smaller pleasure in view of the greater one."},{"k":"buddharakkhita","t":"If by renouncing a lesser happiness one may realize a greater happiness, let the wise man renounce the lesser, having regard for the greater."},{"k":"thanissaro","t":"If, by forsaking\na limited ease,\nhe would see\nan abundance of ease,\nthe enlightened man\nwould forsake\nthe limited ease\nfor the sake\nof the abundant."},{"k":"suddhaso","t":"If by relinquishing limited happiness\none can see abundant happiness,\nthen one who is wise relinquishes limited happiness\nand sees abundant happiness."},{"k":"sujato","t":"If by giving up material happiness\none sees abundant happiness,\nthe attentive would give up material happiness,\nseeing the abundant happiness."}]},{"n":291,"vg":21,"pali":"Paradukkhūpadhānena,\nattano sukhamicchati;\nVerasaṁsaggasaṁsaṭṭho,\nverā so na parimuccati.","v":[{"k":"muller","t":"He who, by causing pain to others, wishes to obtain pleasure for himself, he, entangled in the bonds of hatred, will never be free from hatred."},{"k":"wagiswara","t":"He who causeth pain to others,\nSeeking his own selfish bliss,\nBy the bonds of hate encumbered\nHatred never can dismiss."},{"k":"kaviratna","t":"He who desires happiness for himself by inflicting injury on others, is not freed from hatred, being entangled himself in the bonds of hatred."},{"k":"buddharakkhita","t":"Entangled by the bonds of hate, he who seeks his own happiness by inflicting pain on others, is never delivered from hatred."},{"k":"thanissaro","t":"He wants his own ease\nby giving others dis-ease.\nIntertwined in the inter-\naction of hostility,\nfrom hostility\nhe's not set free."},{"k":"suddhaso","t":"By profiting from the suffering of others,\none seeks happiness for oneself;\none who is intimately involved in hostility\nis not free from hostility."},{"k":"sujato","t":"Seeking their own happiness\nby imposing suffering on others,\nintimate with enmity,\nthey're not freed from enmity."}]},{"n":292,"vg":21,"pali":"Yañhi kiccaṁ apaviddhaṁ,\nakiccaṁ pana karīyati;\nUnnaḷānaṁ pamattānaṁ,\ntesaṁ vaḍḍhanti āsavā.","v":[{"k":"muller","t":"What ought to be done is neglected, what ought not to be done is done; the desires of unruly, thoughtless people are always increasing."},{"k":"wagiswara","t":"Those who disregard their duty,\nDoing what should not be done,\nInsolent and negligent in evil-doing\nMore and more corrupt become."},{"k":"kaviratna","t":"If what ought to be done is neglected, and what ought not to be done is done, then the sensuous influxes of the arrogant and the heedless increase."},{"k":"buddharakkhita","t":"The cankers only increase for those who are arrogant and heedless, who leave undone what should be done and do what should not be done."},{"k":"thanissaro","t":"In those who\nreject what should,\n& do what shouldn't be done\n— heedless, insolent —\neffluents grow."},{"k":"suddhaso","t":"They reject what should be done\nand do what should not be done;\narrogant and negligent,\ntheir defilements increase."},{"k":"sujato","t":"They dump what should be done,\nand do what should not be done.\nFor the insolent and the negligent,\ntheir defilements only grow."}]},{"n":293,"vg":21,"pali":"Yesañca susamāraddhā,\nniccaṁ kāyagatā sati;\nAkiccaṁ te na sevanti,\nkicce sātaccakārino;\nSatānaṁ sampajānānaṁ,\natthaṁ gacchanti āsavā.","v":[{"k":"muller","t":"But they whose whole watchfulness is always directed to their body, who do not follow what ought not to be done, and who steadfastly do what ought to be done, the desires of such watchful and wise people will come to an end."},{"k":"wagiswara","t":"They who mounting guard on body,\nCeaseless watch and ward preserve;\nThey who others' things neglecting,\nFrom their duty never swerve;\nThey who, self-controlled, aspire,\nConcentrate in every nerve,\nReach destruction of desire."},{"k":"kaviratna","t":"Those who are constantly watchful as to the nature of the body, who abstain from doing what ought not to be done, who strive to perform the deeds that ought to be done, who are mindful and self-restrained — in such men the sensuous influxes are extinguished."},{"k":"buddharakkhita","t":"The cankers cease for those mindful and clearly comprehending ones who always earnestly practice mindfulness of the body, who do not resort to what should not be done, and steadfastly pursue what should be done."},{"k":"thanissaro","t":"But for those who\nare well-applied, constantly,\nto mindfulness immersed in the body;\ndon't indulge\nin what shouldn't be done\n& persist\nin what should\n— mindful, alert —\neffluents come to an end."},{"k":"suddhaso","t":"They have undertaken\ncontinuous mindfulness of the body,\nthey do not do what should not be done,\nand they always do what should be done;\nmindful and aware,\ntheir defilements disappear."},{"k":"sujato","t":"Those that have properly undertaken\nconstant mindfulness of the body,\ndon't cultivate what should not be done,\nbut always do what should be done.\nMindful and aware,\ntheir defilements come to an end."}]},{"n":294,"vg":21,"pali":"Mātaraṁ pitaraṁ hantvā,\nrājāno dve ca khattiye;\nRaṭṭhaṁ sānucaraṁ hantvā,\nanīgho yāti brāhmaṇo.","v":[{"k":"muller","t":"A true Brahmana goes scatheless, though he have killed father and mother, and two valiant kings, though he has destroyed a kingdom with all its subjects."},{"k":"wagiswara","t":"Slaying father, slaying mother,\nWith two kings of warrior fame,\nAnd a realm with all its subjects,\nBrāhmana's go free from blame."},{"k":"kaviratna","t":"Having slain mother (craving), father (egotism), and the two kings of the Kshatriya caste (the two false doctrines of eternalism and annihilation of the soul), and having destroyed the kingdom with its inhabitants (the twelve bases of sense perception and objects of attachment), the true Brahman goes his way unperturbed."},{"k":"buddharakkhita","t":"Having slain mother (craving), father (self-conceit), two warrior-kings (eternalism and nihilism), and destroyed a country (sense organs and sense objects) together with its treasurer (attachment and lust), ungrieving goes the holy man."},{"k":"thanissaro","t":"Having killed mother & father,\ntwo warrior kings,\nthe kingdom & its dependency —\nthe brahman, untroubled, travels on."},{"k":"suddhaso","t":"Having slain mother and father,\ntwo royal kings,\nand a kingdom with its followers,\nthe brahmin proceeds untroubled."},{"k":"sujato","t":"Having slain mother and father,\nand two aristocratic kings,\nand having wiped out\nthe kingdom with its tax collector,\nthe brahmin walks on untroubled."}]},{"n":295,"vg":21,"pali":"Mātaraṁ pitaraṁ hantvā,\nrājāno dve ca sotthiye;\nVeyagghapañcamaṁ hantvā,\nanīgho yāti brāhmaṇo.","v":[{"k":"muller","t":"A true Brahmana goes scatheless, though he have killed father and mother, and two holy kings, and an eminent man besides."},{"k":"wagiswara","t":"Slaying father, slaying mother,\nWith two kings of saintly name,\nAnd a fifth pre-eminent,\nBrāhmana's go free from blame."},{"k":"kaviratna","t":"Having slain mother, father and two kings of the Brahman caste, and having destroyed as the fifth, the tiger (the perilous path of the five hindrances, namely, lust, ill will, torpor, restlessness and doubt), the true Brahman goes his way unperturbed."},{"k":"buddharakkhita","t":"Having slain mother, father, two brahman kings (two extreme views), and a tiger as the fifth (the five mental hindrances), ungrieving goes the holy man."},{"k":"thanissaro","t":"Having killed mother & father,\ntwo learned kings,\n&, fifth, a tiger —\nthe brahman, untroubled, travels on."},{"k":"suddhaso","t":"Having slain mother and father,\ntwo scholar kings,\nand a tiger as well,\nthe brahmin proceeds untroubled."},{"k":"sujato","t":"Having slain mother and father,\nand two prosperous kings,\nand a tiger as the fifth,\nthe brahmin walks on untroubled."}]},{"n":296,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nniccaṁ buddhagatā sati.","v":[{"k":"muller","t":"The disciples of Gotama (Buddha) are always well awake, and their thoughts day and night are always set on Buddha."},{"k":"wagiswara","t":"They who, watchful night and day,\nOn the Buddha meditate,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama (Gautama) always awake well-enlightened. Their consciousness is constantly centered, day and night, on the Buddha."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily who day and night constantly practice the Recollection of the Qualities of the Buddha."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose mindfulness, both day & night,\nis constantly immersed\nin the Buddha."},{"k":"suddhaso","t":"They always wake up well,\nthe disciples of Gotama\nwho continuously recollect the Buddha\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwho day and night\nconstantly recollect the Buddha."}]},{"n":297,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nniccaṁ dhammagatā sati.","v":[{"k":"muller","t":"The disciples of Gotama are always well awake, and their thoughts day and night are always set on the law."},{"k":"wagiswara","t":"They who watchful night and day,\nOn the Dhamma meditate,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama always awake well-enlightened. Their consciousness is constantly centered, day and night, on the Dhamma."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily who day and night constantly practice the Recollection of the Qualities of the Dhamma."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose mindfulness, both day & night,\nis constantly immersed\nin the Dhamma."},{"k":"suddhaso","t":"They always wake up well,\ndisciples of the Buddha\nwho continuously recollect the Dhamma\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwho day and night\nconstantly recollect the teaching."}]},{"n":298,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nniccaṁ saṅghagatā sati.","v":[{"k":"muller","t":"The disciples of Gotama are always well awake, and their thoughts day and night are always set on the church."},{"k":"wagiswara","t":"They who, watchful night and day,\nOn the Sangha meditate,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama always awake well-enlightened. Their consciousness is constantly centered, day and night, on the Order (sangha)."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily who day and night constantly practice the Recollection of the Qualities of the Sangha."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose mindfulness, both day & night,\nis constantly immersed\nin the Sangha."},{"k":"suddhaso","t":"They always wake up well,\nthe disciples of Gotama\nwho continuously recollect the Saṅgha\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwho day and night\nconstantly recollect the Saṅgha."}]},{"n":299,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nniccaṁ kāyagatā sati.","v":[{"k":"muller","t":"The disciples of Gotama are always well awake, and their thoughts day and night are always set on their body."},{"k":"wagiswara","t":"They who, watchful night and day,\nOn the body meditate,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama always awake well-enlightened. Their consciousness is constantly centered, day and night, upon (the transitory nature of) the body."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily who day and night constantly practice Mindfulness of the Body."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose mindfulness, both day & night,\nis constantly immersed\nin the body."},{"k":"suddhaso","t":"They always wake up well,\nthe disciples of Gotama\nwho continuously practice mindfulness of the body\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwho day and night\nare constantly mindful of the body."}]},{"n":300,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nahiṁsāya rato mano.","v":[{"k":"muller","t":"The disciples of Gotama are always well awake, and their mind day and night always delights in compassion."},{"k":"wagiswara","t":"They who, watchful night and day,\nTake delight in harmlessness,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama always awake well-enlightened. Their consciousness, by day and night, delights in the virtue of nonviolence (ahimsa)."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily whose minds by day and night delight in the practice of non-violence."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose hearts delight, both day & night,\nin harmlessness."},{"k":"suddhaso","t":"They always wake up well,\nthe disciples of Gotama\nwho approve of harmlessness\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwhose minds day and night\ndelight in harmlessness."}]},{"n":301,"vg":21,"pali":"Suppabuddhaṁ pabujjhanti,\nsadā gotamasāvakā;\nYesaṁ divā ca ratto ca,\nbhāvanāya rato mano.","v":[{"k":"muller","t":"The disciples of Gotama are always well awake, and their mind day and night always delights in meditation."},{"k":"wagiswara","t":"They who, watchful night and day,\nTake delight in ecstasy,\nAre followers of Gotama."},{"k":"kaviratna","t":"The disciples of Gotama always awake well-enlightened. Their consciousness, by day and night, delights in contemplation."},{"k":"buddharakkhita","t":"Those disciples of Gotama ever awaken happily whose minds by day and night delight in the practice of meditation."},{"k":"thanissaro","t":"They awaken, always wide awake:\nGotama's disciples\nwhose hearts delight, both day & night,\nin developing the mind."},{"k":"suddhaso","t":"They always wake up well,\nthe disciples of Gotama\nwho approve of self-development\nby day and by night."},{"k":"sujato","t":"The disciples of Gotama\nalways wake up refreshed,\nwhose minds day and night\ndelight in meditation."}]},{"n":302,"vg":21,"pali":"Duppabbajjaṁ durabhiramaṁ,\nDurāvāsā gharā dukhā;\nDukkhosamānasaṁvāso,\nDukkhānupatitaddhagū;\nTasmā na caddhagū siyā,\nNa ca dukkhānupatito siyā.","v":[{"k":"muller","t":"It is hard to leave the world (to become a friar), it is hard to enjoy the world; hard is the monastery, painful are the houses; painful it is to dwell with equals (to share everything in common) and the itinerant mendicant is beset with pain. Therefore let no man be an itinerant mendicant and he will not be beset with pain."},{"k":"wagiswara","t":"O 'tis hard to give the world up,\nYet the lonely life is hard;\nPainful 'tis to dwell in houses\nWith the uncongenial;\nPainful travelling to and fro;\nCease to be a traveller.\nCease to be beset with pain!"},{"k":"kaviratna","t":"Renunciation of the worldly life is difficult; difficult is it to be happy in the monastic life; equally difficult and painful is it to lead a householder's life. Association with the unsympathetic is also painful. Woe befalls the wayfarer (who enters the cycle of births and deaths). Therefore be not a traveler (in samsara); fall not a victim of sorrow!"},{"k":"buddharakkhita","t":"Difficult is life as a monk; difficult is it to delight therein. Also difficult and sorrowful is the household life. Suffering comes from association with unequals; suffering comes from wandering in samsara. Therefore, be not an aimless wanderer, be not a pursuer of suffering."},{"k":"thanissaro","t":"Hard is the life gone forth,\nhard to delight in.\nHard is the miserable\nhouseholder's life.\nIt's painful to stay with dissonant people,\npainful to travel the road.\nSo be neither traveler\nnor pained."},{"k":"suddhaso","t":"The renunciant life is difficult and hard to enjoy;\nthe household life is difficult and hard to endure.\nLiving with others is suffering,\nand travelers also undergo suffering.\nTherefore, just as one can choose to not travel,\none can choose to not suffer."},{"k":"sujato","t":"Going forth is hard, it's hard to be happy;\nlife at home is hard too, and painful,\nit's painful to stay when you've nothing in common.\nA traveler is a prey to pain,\nso don't be a traveler,\ndon't be prey to pain."}]},{"n":303,"vg":21,"pali":"Saddho sīlena sampanno,\nyasobhogasamappito;\nYaṁ yaṁ padesaṁ bhajati,\ntattha tattheva pūjito.","v":[{"k":"muller","t":"Whatever place a faithful, virtuous, celebrated, and wealthy man chooses, there he is respected."},{"k":"wagiswara","t":"Faithful and of good repute,\nFull of honour and renown,\nHe is reverenced and honoured,\nWhereso'er he choose to dwell."},{"k":"kaviratna","t":"He who is endowed with devotion and virtue and is blessed with fame and wealth, is revered wherever he goes."},{"k":"buddharakkhita","t":"He who is full of faith and virtue, and possesses good repute and wealth — he is respected everywhere, in whatever land he travels."},{"k":"thanissaro","t":"The man of conviction\nendowed with virtue,\nglory, & wealth:\nwherever he goes\nhe is honored."},{"k":"suddhaso","t":"One who has faith and morality,\ninfluence and wealth,\nis honored\nwherever they are."},{"k":"sujato","t":"One who is faithful, accomplished in ethics,\nblessed with fame and wealth,\nis honored in whatever place\nthey frequent."}]},{"n":304,"vg":21,"pali":"Dūre santo pakāsenti,\nhimavantova pabbato;\nAsantettha na dissanti,\nrattiṁ khittā yathā sarā.","v":[{"k":"muller","t":"Good people shine from afar, like the snowy mountains; bad people are not seen, like arrows shot by night."},{"k":"wagiswara","t":"Holy saints are far-resplendent\nLike the peaks Himalayan;\nLike the shaft that flies in darkness,\nWicked men are never seen."},{"k":"kaviratna","t":"Good men shine from afar like the snowy peaks of the Himalayas. But the wicked, like arrows shot in the night, are not seen."},{"k":"buddharakkhita","t":"The good shine from afar, like the Himalaya mountains. But the wicked are unseen, like arrows shot in the night."},{"k":"thanissaro","t":"The good shine from afar\nlike the snowy Himalayas.\nThe bad don't appear\neven when near,\nlike arrows shot into the night."},{"k":"suddhaso","t":"Those who are good are visible from afar,\nlike a Himalayan mountain;\nbut those who are not good cannot be seen,\nlike arrows loosed at night."},{"k":"sujato","t":"The good shine from afar,\nlike the Himalayan peaks,\nbut the wicked are not seen,\nlike arrows scattered in the night."}]},{"n":305,"vg":21,"pali":"Ekāsanaṁ ekaseyyaṁ,\neko caramatandito;\nEko damayamattānaṁ,\nvanante ramito siyā.\nPakiṇṇakavaggo ekavīsatimo.","v":[{"k":"muller","t":"He alone who, without ceasing, practises the duty of sitting alone and sleeping alone, he, subduing himself, will rejoice in the destruction of all desires alone, as if living in a forest."},{"k":"wagiswara","t":"Lonely sitting, lying lonely,\nAct alone and strenuous;\nTaming self alone, rejoice thee\nIn the ending of desire."},{"k":"kaviratna","t":"Sitting alone, sleeping alone, living alone, and being diligent, subduing the self by means of the Self, let a man find delight in the ending of the forest (of desires)."},{"k":"buddharakkhita","t":"He who sits alone, sleeps alone, and walks alone, who is strenuous and subdues himself alone, will find delight in the solitude of the forest."},{"k":"thanissaro","t":"Sitting alone,\nresting alone,\nwalking alone,\nuntiring.\nTaming himself,\nhe'd delight alone —\nalone in the forest."},{"k":"suddhaso","t":"Sitting alone, sleeping alone,\ngoing alone, never lazy;\ntraining oneself alone,\none can enjoy the forest."},{"k":"sujato","t":"Sitting alone, sleeping alone,\ntirelessly wandering alone;\none who tames themselves alone\nwould delight within a forest."}]},{"n":306,"vg":22,"pali":"Abhūtavādī nirayaṁ upeti,\nYo vāpi katvā na karomi cāha;\nUbhopi te pecca samā bhavanti,\nNihīnakammā manujā parattha.","v":[{"k":"muller","t":"He who says what is not, goes to hell; he also who, having done a thing, says I have not done it. After death both are equal, they are men with evil deeds in the next world."},{"k":"wagiswara","t":"The liar reaches hell, and he who says\nHe did not what he did;\nBoth are the same hereafter, men of crooked ways."},{"k":"kaviratna","t":"The man who utters a falsehood goes to the woeful state (hell), as does he who having committed an act says, \"I did not commit it.\" After death both these men of contemptible deeds become equal in the next world."},{"k":"buddharakkhita","t":"The liar goes to the state of woe; also he who, having done (wrong), says, \"I did not do it.\" Men of base actions both, on departing they share the same destiny in the other world."},{"k":"thanissaro","t":"He goes to hell,\nthe one who asserts\nwhat didn't take place,\nas does the one\nwho, having done,\nsays, 'I didn't.'\nBoth — low-acting people —\nthere become equal:\nafter death, in the world beyond."},{"k":"suddhaso","t":"Those who proclaim what never happened go to hell,\nas well as those who do something then say they did not.\nAfter death, both are the same;\npeople whose afterlife was determined by lowly actions."},{"k":"sujato","t":"A liar goes to hell,\nas does one who denies what they did.\nBoth are equal in the hereafter,\nthose men of base deeds."}]},{"n":307,"vg":22,"pali":"Kāsāvakaṇṭhā bahavo,\npāpadhammā asaññatā;\nPāpā pāpehi kammehi,\nnirayaṁ te upapajjare.","v":[{"k":"muller","t":"Many men whose shoulders are covered with the yellow gown are ill-conditioned and unrestrained; such evil-doers by their evil deeds go to hell."},{"k":"wagiswara","t":"And many a one the yellow gown who wears,\nWicked and uncontrolled,\nBy reason of his evil deeds in hell appears."},{"k":"kaviratna","t":"Many of those who wear the saffron robe are of evil character and unrestrained. These evildoers are born in hell by reason of their sinful deeds."},{"k":"buddharakkhita","t":"There are many evil characters and uncontrolled men wearing the saffron robe. These wicked men will be born in states of woe because of their evil deeds."},{"k":"thanissaro","t":"An ochre robe tied 'round their necks,\nmany with evil qualities\n— unrestrained, evil —\nrearise, because of their evil acts,\nin hell."},{"k":"suddhaso","t":"Many who wear ochre on their neck\nare evil and unrestrained.\nBecause of their evil actions\nthey are reborn in hell."},{"k":"sujato","t":"Many who wear a scrap of ocher cloth\nare unrestrained and wicked.\nBeing wicked, they are reborn in hell\ndue to their bad deeds."}]},{"n":308,"vg":22,"pali":"Seyyo ayoguḷo bhutto,\ntatto aggisikhūpamo;\nYañce bhuñjeyya dussīlo,\nraṭṭhapiṇḍamasaññato.","v":[{"k":"muller","t":"Better it would be to swallow a heated iron ball, like flaring fire, than that a bad unrestrained fellow should live on the charity of the land."},{"k":"wagiswara","t":"Better for him who lives unworthily\nA red-hot ball to swallow,\nThan eat the food the country gives in charity."},{"k":"kaviratna","t":"It is far better for an irreligious and unrestrained monk to swallow a flaming ball of red-hot iron than to feed on the alms of the people."},{"k":"buddharakkhita","t":"It would be better to swallow a red-hot iron ball, blazing like fire, than as an immoral and uncontrolled monk to eat the alms of the people."},{"k":"thanissaro","t":"Better to eat an iron ball\n— glowing, aflame —\nthan that, unprincipled &\nunrestrained,\nyou should eat the alms of the country."},{"k":"suddhaso","t":"It is better to eat a red-hot iron ball,\nglowing like fire,\nthan for an immoral, unrestrained person\nto eat the nation's almsfood."},{"k":"sujato","t":"It'd be better for the immoral and unrestrained\nto eat an iron ball,\nscorching, like a burning flame,\nthan to eat the nation's alms."}]},{"n":309,"vg":22,"pali":"Cattāri ṭhānāni naro pamatto,\nĀpajjati paradārūpasevī;\nApuññalābhaṁ na nikāmaseyyaṁ,\nNindaṁ tatīyaṁ nirayaṁ catutthaṁ.","v":[{"k":"muller","t":"Four things does a wreckless man gain who covets his neighbour's wife,--a bad reputation, an uncomfortable bed, thirdly, punishment, and lastly, hell."},{"k":"wagiswara","t":"Four states of ill to reckless men I tell\nWho seek the wives of others--\nIll-luck, a restless bed, an evil name and hell."},{"k":"kaviratna","t":"Four wretched conditions befall the heedless man who commits adultery: demerit, broken sleep, scorn as third, and birth in hell as fourth."},{"k":"buddharakkhita","t":"Four misfortunes befall the reckless man who consorts with another's wife: acquisition of demerit, disturbed sleep, ill-repute, and (rebirth in) states of woe."},{"k":"thanissaro","t":"Four things befall the heedless man\nwho lies down with the wife of another:\na wealth of demerit;\na lack of good sleep;\nthird, censure;\nfourth, hell."},{"k":"suddhaso","t":"Four things happen to a negligent person\nwho commits adultery:\nbad karma, insomnia,\ncriticism, and rebirth in hell."},{"k":"sujato","t":"Four things befall a heedless man\nwho sleeps with another's wife:\nwickedness, poor sleep,\nill-repute, and rebirth in hell."}]},{"n":310,"vg":22,"pali":"Apuññalābho ca gatī ca pāpikā,\nBhītassa bhītāya ratī ca thokikā;\nRājā ca daṇḍaṁ garukaṁ paṇeti,\nTasmā naro paradāraṁ na seve.","v":[{"k":"muller","t":"There is bad reputation, and the evil way (to hell), there is the short pleasure of the frightened in the arms of the frightened, and the king imposes heavy punishment; therefore let no man think of his neighbour's wife."},{"k":"wagiswara","t":"Ill-luck, the Evil Way, short-lived delight\nOf fearful man with timid woman spent,\nAnd from the king a grievous punishment--\nLet these four evils all adulterers affright."},{"k":"kaviratna","t":"There is the acquirement of demerit as well as of rebirth in an evil state; even the fleeting pleasure of the man in the arms of the woman is accompanied by fear; and, moreover, the penalty inflicted by the Raja is heavy. Therefore, a man should not commit adultery."},{"k":"buddharakkhita","t":"Such a man acquires demerit and an unhappy birth in the future. Brief is the pleasure of the frightened man and woman, and the king imposes heavy punishment. Hence, let no man consort with another's wife."},{"k":"thanissaro","t":"A wealth of demerit, an evil destination,\n& the brief delight of a\nfearful man with a\nfearful woman,\n& the king inflicts a harsh punishment.\nSo\nno man should lie down\nwith the wife of another."},{"k":"suddhaso","t":"One acquires bad karma and the destiny of evil people,\nand only the minute pleasure of a frightened man with a frightened woman;\nand then the king enacts a severe punishment.\nTherefore, one should not commit adultery."},{"k":"sujato","t":"He accrues wickedness and is reborn in a bad place,\nall so a frightened couple\nmay snatch a moment's pleasure,\nfor which rulers impose a heavy punishment.\nThat's why a man should not\nsleep with another's wife."}]},{"n":311,"vg":22,"pali":"Kuso yathā duggahito,\nhatthamevānukantati;\nSāmaññaṁ dupparāmaṭṭhaṁ,\nnirayāyupakaḍḍhati.","v":[{"k":"muller","t":"As a grass-blade, if badly grasped, cuts the arm, badly-practised asceticism leads to hell."},{"k":"wagiswara","t":"Just as a blade of grass not handled well\nWill cut the hand that grasps,\nSo doth the ascetic's life ill-handled lead to hell."},{"k":"kaviratna","t":"Just as a blade of kusa grass when wrongly handled cuts the hand, so does asceticism when wrongly practiced drag one to the woeful state."},{"k":"buddharakkhita","t":"Just as kusa grass wrongly handled cuts the hand, even so, a recluse's life wrongly lived drags one to states of woe."},{"k":"thanissaro","t":"Just as sharp-bladed grass,\nif wrongly held,\nwounds the very hand that holds it —\nthe contemplative life, if wrongly grasped,\ndrags you down to hell."},{"k":"suddhaso","t":"Just as a blade, when poorly held,\ncuts the hand that holds it,\na contemplative life that is held incorrectly\ndraws one closer to hell."},{"k":"sujato","t":"When kusa grass is wrongly grasped\nit only cuts the hand.\nSo too, the ascetic life, when wrongly taken,\ndrags you to hell."}]},{"n":312,"vg":22,"pali":"Yaṁ kiñci sithilaṁ kammaṁ,\nsaṅkiliṭṭhañca yaṁ vataṁ;\nSaṅkassaraṁ brahmacariyaṁ,\nna taṁ hoti mahapphalaṁ.","v":[{"k":"muller","t":"An act carelessly performed, a broken vow, and hesitating obedience to discipline, all this brings no great reward."},{"k":"wagiswara","t":"Deeds done with sluggishness, the broken vow,\nThe saintly life befouled--\nSuch evil deeds as these small recompense bestow."},{"k":"kaviratna","t":"Any act performed halfheartedly, any religious rite observed improperly, or continence reluctantly practiced none of these produces great fruit."},{"k":"buddharakkhita","t":"Any loose act, any corrupt observance, any life of questionable celibacy — none of these bear much fruit."},{"k":"thanissaro","t":"Any slack act,\nor defiled observance,\nor fraudulent life of chastity\nbears no great fruit."},{"k":"suddhaso","t":"Lax behavior,\ndefiled practice,\na suspicious spiritual life -\nthis does not bring great benefit."},{"k":"sujato","t":"Any lax act,\nany corrupt observance,\nor suspicious spiritual life,\nis not very fruitful."}]},{"n":313,"vg":22,"pali":"Kayirā ce kayirāthenaṁ,\ndaḷhamenaṁ parakkame;\nSithilo hi paribbājo,\nbhiyyo ākirate rajaṁ.","v":[{"k":"muller","t":"If anything is to be done, let a man do it, let him attack it vigorously! A careless pilgrim only scatters the dust of his passions more widely."},{"k":"wagiswara","t":"Act thou with energy, if act thou must:\nThe careless mendicant\nDoth but stir up a denser cloud of passion's dust."},{"k":"kaviratna","t":"If anything ought to be done, let a man perform that deed with all his might; an ascetic who is lax scatters more and more dust (of passion)."},{"k":"buddharakkhita","t":"If anything is to be done, let one do it with sustained vigor. A lax monastic life stirs up the dust of passions all the more."},{"k":"thanissaro","t":"If something's to be done,\nthen work at it firmly,\nfor a slack going-forth\nkicks up all the more dust."},{"k":"suddhaso","t":"If one will do what one should do,\nthen one should make a solid effort,\nbecause a lax renunciant\nscatters more dust."},{"k":"sujato","t":"If one is to do what should be done,\none should staunchly strive.\nFor the life gone forth when laxly led\njust stirs up dust all the more."}]},{"n":314,"vg":22,"pali":"Akataṁ dukkaṭaṁ seyyo,\npacchā tappati dukkaṭaṁ;\nKatañca sukataṁ seyyo,\nyaṁ katvā nānutappati.","v":[{"k":"muller","t":"An evil deed is better left undone, for a man repents of it afterwards; a good deed is better done, for having done it, one does not repent."},{"k":"wagiswara","t":"Leave evil deeds which afterwards bring pain;\nBetter to do the good;\nFor when 'tis done that deed no sorrow brings again."},{"k":"kaviratna","t":"An evil act is better left undone, for that evil deed causes torment afterwards. It is better to perform a good deed; by performing it one does not repent later."},{"k":"buddharakkhita","t":"An evil deed is better left undone, for such a deed torments one afterwards. But a good deed is better done, doing which one repents not later."},{"k":"thanissaro","t":"It's better to leave a misdeed\nundone.\nA misdeed burns you afterward.\nBetter that a good deed be done\nthat, after you've done it,\nwon't make you burn."},{"k":"suddhaso","t":"It is better when misconduct is not done;\nmisconduct torments afterwards.\nIt is better when good conduct is done;\nafter doing so, one is not tormented."},{"k":"sujato","t":"A bad deed is better left undone,\nfor it will plague you later on.\nA good deed is better done,\none that does not plague you."}]},{"n":315,"vg":22,"pali":"Nagaraṁ yathā paccantaṁ,\nguttaṁ santarabāhiraṁ;\nEvaṁ gopetha attānaṁ,\nkhaṇo vo mā upaccagā;\nKhaṇātītā hi socanti,\nnirayamhi samappitā.","v":[{"k":"muller","t":"Like a well-guarded frontier fort, with defences within and without, so let a man guard himself. Not a moment should escape, for they who allow the right moment to pass, suffer pain when they are in hell."},{"k":"wagiswara","t":"Just as a frontier town that's guarded well,\nWhich ramparts well defend on every side,\nSo guard thyself, let not a moment slide;\nTime-wasters suffer sorrow when consigned to hell."},{"k":"kaviratna","t":"As a frontier city, well-guarded within and without, so guard yourself. Do not lose a single moment, for those who let opportunity slip away do indeed grieve when they are born in the woeful state (hell)."},{"k":"buddharakkhita","t":"Just as a border city is closely guarded both within and without, even so, guard yourself. Do not let slip this opportunity (for spiritual growth). For those who let slip this opportunity grieve indeed when consigned to hell."},{"k":"thanissaro","t":"Like a frontier fortress,\nguarded inside & out,\nguard yourself.\nDon't let the moment pass by.\nThose for whom the moment is past\ngrieve, consigned to hell."},{"k":"suddhaso","t":"As a border city\nis guarded inside and out,\nin the same way guard yourself;\nlet not a moment slip past you.\nWhen the moment is past they sorrow,\nthose who arrived in hell."},{"k":"sujato","t":"As a frontier city\nis guarded inside and out,\nso you should ward yourselves—\ndon't let the moment pass you by.\nFor if you miss your moment\nyou'll grieve when sent to hell."}]},{"n":316,"vg":22,"pali":"Alajjitāye lajjanti,\nlajjitāye na lajjare;\nMicchādiṭṭhisamādānā,\nsattā gacchanti duggatiṁ.","v":[{"k":"muller","t":"They who are ashamed of what they ought not to be ashamed of, and are not ashamed of what they ought to be ashamed of, such men, embracing false doctrines enter the evil path."},{"k":"wagiswara","t":"They who feel shame, where shame there should be none,\nShameless, where shame should be,\nEmbracing doctrines false, down the Ill Path have gone."},{"k":"kaviratna","t":"Those who are ashamed of what they ought not to be ashamed of, and are not ashamed of what they ought to be, such men, embracing erroneous views, enter the woeful path."},{"k":"buddharakkhita","t":"Those who are ashamed of what they should not be ashamed of, and are not ashamed of what they should be ashamed of — upholding false views, they go to states of woe."},{"k":"thanissaro","t":"Ashamed of what's not shameful,\nnot ashamed of what is,\nbeings adopting wrong views\ngo to a bad destination."},{"k":"suddhaso","t":"They are ashamed when they should not be ashamed,\nthey are not ashamed when they should be ashamed;\ntaking up wrong view,\nbeings go to a bad destination."},{"k":"sujato","t":"Unashamed of what is shameful,\nashamed of what is not shameful;\nbeings who uphold wrong view\ngo to a bad place."}]},{"n":317,"vg":22,"pali":"Abhaye bhayadassino,\nbhaye cābhayadassino;\nMicchādiṭṭhisamādānā,\nsattā gacchanti duggatiṁ.","v":[{"k":"muller","t":"They who fear when they ought not to fear, and fear not when they ought to fear, such men, embracing false doctrines, enter the evil path."},{"k":"wagiswara","t":"They who feel fear, where fear there should be none,\nFearless, when they should fear,\nEmbracing doctrines false, down the Ill Path have gone."},{"k":"kaviratna","t":"Those who are fearful when there is no cause for fear, and feel no fear when they should, such men, embracing erroneous views, enter the woeful path."},{"k":"buddharakkhita","t":"Those who see something to fear where there is nothing to fear, and see nothing to fear where there is something to fear — upholding false views, they go to states of woe."},{"k":"thanissaro","t":"Seeing danger where there is none,\n& no danger where there is,\nbeings adopting wrong views\ngo to a bad destination."},{"k":"suddhaso","t":"They see danger where there is no danger,\nthey see no danger where there is danger;\ntaking up wrong view,\nbeings go to a bad destination."},{"k":"sujato","t":"Seeing danger where there is none,\nand blind to the actual danger,\nbeings who uphold wrong view\ngo to a bad place."}]},{"n":318,"vg":22,"pali":"Avajje vajjamatino,\nvajje cāvajjadassino;\nMicchādiṭṭhisamādānā,\nsattā gacchanti duggatiṁ.","v":[{"k":"muller","t":"They who forbid when there is nothing to be forbidden, and forbid not when there is something to be forbidden, such men, embracing false doctrines, enter the evil path."},{"k":"wagiswara","t":"They who see sin, where sin there can be none,\nWho see no harm in sin,\nEmbracing doctrines false, down the Ill Path have gone."},{"k":"kaviratna","t":"Those who imagine error where there is none, and do not see it where it does exist, such men, embracing false views, enter the woeful path."},{"k":"buddharakkhita","t":"Those who imagine evil where there is none, and do not see evil where it is — upholding false views, they go to states of woe."},{"k":"thanissaro","t":"Imagining error where there is none,\nand seeing no error where there is,\nbeings adopting wrong views\ngo to a bad destination."},{"k":"suddhaso","t":"They think the blameless is blameworthy,\nand see the blameworthy as blameless;\ntaking up wrong view,\nbeings go to a bad destination."},{"k":"sujato","t":"Seeing fault where there is none,\nand blind to the actual fault,\nbeings who uphold wrong view\ngo to a bad place."}]},{"n":319,"vg":22,"pali":"Vajjañca vajjato ñatvā,\navajjañca avajjato;\nSammādiṭṭhisamādānā,\nsattā gacchanti suggatiṁ.\nNirayavaggo dvāvīsatimo.","v":[{"k":"muller","t":"They who know what is forbidden as forbidden, and what is not forbidden as not forbidden, such men, embracing the true doctrine, enter the good path."},{"k":"wagiswara","t":"They who know sin as sin, and right as right,\nEmbracing doctrines true,\nThose beings enter on the Path of True Delight."},{"k":"kaviratna","t":"Those who discern error as error and truth as truth, such men, embracing right views, enter the path of bliss."},{"k":"buddharakkhita","t":"Those who discern the wrong as wrong and the right as right — upholding right views, they go to realms of bliss."},{"k":"thanissaro","t":"But knowing error as error,\nand non-error as non-,\nbeings adopting right views\ngo to a good\ndestination."},{"k":"suddhaso","t":"Knowing the blameworthy as blameworthy\nand the blameless as blameless,\ntaking up right view,\nbeings go to a good destination."},{"k":"sujato","t":"Knowing a fault as a fault\nand the faultless as faultless,\nbeings who uphold right view\ngo to a good place."}]},{"n":320,"vg":23,"pali":"Ahaṁ nāgova saṅgāme,\ncāpato patitaṁ saraṁ;\nAtivākyaṁ titikkhissaṁ,\ndussīlo hi bahujjano.","v":[{"k":"muller","t":"Silently shall I endure abuse as the elephant in battle endures the arrow sent from the bow: for the world is ill-natured."},{"k":"wagiswara","t":"As an elephant in battle bears the arrows at him hurled,\nI must bear men's bitter tongues, for very evil is the world."},{"k":"kaviratna","t":"Even as an elephant on the battlefield endures the arrow shot from the bow, so shall I bear with abusive language. Verily, most people are ill-tempered."},{"k":"buddharakkhita","t":"As an elephant in the battlefield withstands arrows shot from bows all around, even so shall I endure abuse. There are many, indeed, who lack virtue."},{"k":"thanissaro","t":"I — like an elephant in battle,\nenduring an arrow shot from a bow —\nwill endure a false accusation,\nfor the mass of people\nhave no principles."},{"k":"suddhaso","t":"Like an elephant in battle\nstruck by an arrow from a bow,\nI will endure criticism\nfrom the immoral multitude."},{"k":"sujato","t":"Like an elephant struck\nwith arrows in battle,\nI shall endure abuse,\nfor so many folk are badly behaved."}]},{"n":321,"vg":23,"pali":"Dantaṁ nayanti samitiṁ,\ndantaṁ rājābhirūhati;\nDanto seṭṭho manussesu,\nyotivākyaṁ titikkhati.","v":[{"k":"muller","t":"They lead a tamed elephant to battle, the king mounts a tamed elephant; the tamed is the best among men, he who silently endures abuse."},{"k":"wagiswara","t":"Tamed, they lead him into battle; tamed, the king his back ascends;\nTamed is he the best of beings, whom no bitter speech offends."},{"k":"kaviratna","t":"They lead a well-trained elephant to the assembly; the king mounts a well-tamed elephant. The self-controlled man who can bear with abusive language is the best among men."},{"k":"buddharakkhita","t":"A tamed elephant is led into a crowd, and the king mounts a tamed elephant. Best among men is the subdued one who endures abuse."},{"k":"thanissaro","t":"The tamed is the one\nthey take into assemblies.\nThe tamed is the one\nthe king mounts.\nThe tamed who endures\na false accusation\nis, among human beings,\nthe best."},{"k":"suddhaso","t":"One who is trained can be led through a crowd,\none who is trained can be mounted by a king;\na trained person is the best among humans,\none who endures criticism."},{"k":"sujato","t":"The well-tamed beast is the one led to the crowd;\nthe tamed elephant's the one the king mounts;\nthe tamed person who endures abuse\nis the best of human beings."}]},{"n":322,"vg":23,"pali":"Varamassatarā dantā,\nājānīyā ca sindhavā;\nKuñjarā ca mahānāgā,\nattadanto tato varaṁ.","v":[{"k":"muller","t":"Mules are good, if tamed, and noble Sindhu horses, and elephants with large tusks; but he who tames himself is better still."},{"k":"wagiswara","t":"Good are well-tamed mules, and good are Scindian steeds of lineage famed;\nGood indeed the mighty tusker; best of all the man self-tamed."},{"k":"kaviratna","t":"When trained, mules are good, so also are the horses of Sindhu breed and the great tuskers of noble lineage. But better than all these is the man who has controlled the senses."},{"k":"buddharakkhita","t":"Excellent are well-trained mules, thoroughbred Sindhu horses and noble tusker elephants. But better still is the man who has subdued himself."},{"k":"thanissaro","t":"Excellent are tamed mules,\ntamed thoroughbreds,\ntamed horses from Sindh.\nExcellent, tamed tuskers,\ngreat elephants.\nBut even more excellent\nare those self-tamed."},{"k":"suddhaso","t":"Excellent are trained mules,\nwell-bred Sindhi horses,\nand enormous elephants;\nbut more excellent that those is one who is self-trained."},{"k":"sujato","t":"Those who have tamed themselves are better\nthan fine tamed mules,\nthoroughbreds from Sindh,\nor giant tuskers."}]},{"n":323,"vg":23,"pali":"Na hi etehi yānehi,\ngaccheyya agataṁ disaṁ;\nYathāttanā sudantena,\ndanto dantena gacchati.","v":[{"k":"muller","t":"For with these animals does no man reach the untrodden country (Nirvana), where a tamed man goes on a tamed animal, viz. on his own well-tamed self."},{"k":"wagiswara","t":"Yet such mounts can nought avail us, cannot be Nibbāna's guide;\nWe can only reach The Pathless on the self-tamed self astride."},{"k":"kaviratna","t":"Not astride any of these (animals) can one reach the untrodden realm (nirvana), where a well-disciplined man goes only on his well-tamed (nature), his well-controlled self."},{"k":"buddharakkhita","t":"Not by these mounts, however, would one go to the Untrodden Land (Nibbana), as one who is self-tamed goes by his own tamed and well-controlled mind."},{"k":"thanissaro","t":"For not by these mounts could you go\nto the land unreached,\nas the tamed one goes\nby taming, well-taming, himself."},{"k":"suddhaso","t":"For it is not by means of those vehicles\nthat one goes in the direction one has never gone;\nwhere one who is self-trained, well-trained,\ncan go by means of that training."},{"k":"sujato","t":"For not on those mounts\nwould you go to the untrodden place,\nwhereas, with the help of one\nwhose self is well tamed,\nyou go there, tamed by the tamed."}]},{"n":324,"vg":23,"pali":"Dhanapālo nāma kuñjaro,\nKaṭukabhedano dunnivārayo;\nBaddho kabaḷaṁ na bhuñjati,\nSumarati nāgavanassa kuñjaro.","v":[{"k":"muller","t":"The elephant called Dhanapalaka, his temples running with sap, and difficult to hold, does not eat a morsel when bound; the elephant longs for the elephant grove."},{"k":"wagiswara","t":"With the must from temples streaming, mighty Dhanapālako\nCaptive, tastes no food, but longeth to the Nāga-grove to go."},{"k":"kaviratna","t":"The royal tusker named Dhanapalaka, with sap-flowing temples in its rut period, is difficult to control. It does not eat a morsel when bound. It eagerly longs for the elephant forest."},{"k":"buddharakkhita","t":"Musty during rut, the tusker named Dhanapalaka is uncontrollable. Held in captivity, the tusker does not touch a morsel, but only longingly calls to mind the elephant forest."},{"k":"thanissaro","t":"The tusker, Dhanapalaka,\ndeep in rut, is hard to control.\nBound, he won't eat a morsel:\nthe tusker misses\nthe elephant wood."},{"k":"suddhaso","t":"The elephant named Dhanapāla\nis bitter about being separated, and is hard to restrain;\ncaptive, he does not eat,\nas he misses the elephant forest."},{"k":"sujato","t":"The tusker named Dhanapāla\nis musky in rut, hard to control.\nBound, he eats not a morsel,\nfor he misses the elephant forest."}]},{"n":325,"vg":23,"pali":"Middhī yadā hoti mahagghaso ca,\nNiddāyitā samparivattasāyī;\nMahāvarāhova nivāpapuṭṭho,\nPunappunaṁ gabbhamupeti mando.","v":[{"k":"muller","t":"If a man becomes fat and a great eater, if he is sleepy and rolls himself about, that fool, like a hog fed on wash, is born again and again."},{"k":"wagiswara","t":"Sluggish, gluttonous and sleepy, wallowing idly to and fro,\nLike a huge and grain-fed hog, a fool again to birth must go."},{"k":"kaviratna","t":"If a man is torpid, gluttonous, slumberous and rolling to and fro like a huge hog which has been fattened by pig wash and podder, that indolent and stupid fool is born again and again."},{"k":"buddharakkhita","t":"When a man is sluggish and gluttonous, sleeping and rolling around in bed like a fat domestic pig, that sluggard undergoes rebirth again and again."},{"k":"thanissaro","t":"When torpid & over-fed,\na sleepy-head lolling about\nlike a stout hog, fattened on fodder:\na dullard enters the womb\nover &\nover again."},{"k":"suddhaso","t":"Lethargic and gluttonous,\nlanguid, lazing about,\nlike an oversized pig that has taken the bait,\nthe fool arrives again and again in the womb."},{"k":"sujato","t":"One who gets drowsy from overeating,\nfond of sleep, rolling round the bed\nlike a great hog stuffed with grain:\nthat dullard returns to the womb again and again."}]},{"n":326,"vg":23,"pali":"Idaṁ pure cittamacāri cārikaṁ,\nYenicchakaṁ yatthakāmaṁ yathāsukhaṁ;\nTadajjahaṁ niggahessāmi yoniso,\nHatthippabhinnaṁ viya aṅkusaggaho.","v":[{"k":"muller","t":"This mind of mine went formerly wandering about as it liked, as it listed, as it pleased; but I shall now hold it in thoroughly, as the rider who holds the hook holds in the furious elephant."},{"k":"wagiswara","t":"Once this mind roamed as it listed, as it pleaded a-wandering went.\nAs the holder of the _ankus_ checks the furious elephant,\nNow with wisdom I'll restrain it, guide it wholly to my bent."},{"k":"kaviratna","t":"During the past, this mind of mine roamed freely as it liked, as it desired, at its own pleasure. But today, I shall fully keep it in check, even as the elephant driver with the point of a goad controls an unruly elephant in rut."},{"k":"buddharakkhita","t":"Formerly this mind wandered about as it liked, where it wished and according to its pleasure, but now I shall thoroughly master it with wisdom as a mahout controls with his ankus an elephant in rut."},{"k":"thanissaro","t":"Before, this mind went wandering\nhowever it pleased,\nwherever it wanted,\nby whatever way that it liked.\nToday I will hold it aptly in check —\nas one wielding a goad, an elephant in rut."},{"k":"suddhaso","t":"In the past this mind would wander,\ngoing wherever it wished, wherever it desired, wherever it found pleasure.\nToday I will subdue it with a wise understanding of causality,\nlike an elephant-trainer subduing a rampaging elephant."},{"k":"sujato","t":"In the past my mind wandered\nhow it wished, where it liked, as it pleased.\nNow I'll carefully guide it,\nas a trainer with a hook guides a rutting elephant."}]},{"n":327,"vg":23,"pali":"Appamādaratā hotha,\nsacittamanurakkhatha;\nDuggā uddharathattānaṁ,\npaṅke sannova kuñjaro.","v":[{"k":"muller","t":"Be not thoughtless, watch your thoughts! Draw yourself out of the evil way, like an elephant sunk in mud."},{"k":"wagiswara","t":"Take delight in earnestness; watch thy thoughts and never tire;\nLift thee from the Path of Evil, like the tusker sunk in mire."},{"k":"kaviratna","t":"Be ever vigilant; keep close watch over your thoughts; extricate yourself from the mire of evil, as does an elephant sunk in the mud."},{"k":"buddharakkhita","t":"Delight in heedfulness! Guard well your thoughts! Draw yourself out of this bog of evil, even as an elephant draws himself out of the mud."},{"k":"thanissaro","t":"Delight in heedfulness.\nWatch over your own mind.\nLift yourself up\nfrom the hard-going way,\nlike a tusker sunk in the mud."},{"k":"suddhaso","t":"Approve of non-negligence,\nand guard your own mind.\nLift yourself up from the harmful path,\nlike an elephant lifting itself up from the mud."},{"k":"sujato","t":"Delight in diligence!\nTake good care of your mind!\nPull yourself out of this pit,\nlike an elephant sunk in a bog."}]},{"n":328,"vg":23,"pali":"Sace labhetha nipakaṁ sahāyaṁ,\nSaddhiṁ caraṁ sādhuvihāridhīraṁ;\nAbhibhuyya sabbāni parissayāni,\nCareyya tenattamano satīmā.","v":[{"k":"muller","t":"If a man find a prudent companion who walks with him, is wise, and lives soberly, he may walk with him, overcoming all dangers, happy, but considerate."},{"k":"wagiswara","t":"Hast thou found a fellow-traveller, upright, firm, intelligent?\nLeaving all thy cares behind thee, gladly walk with him intent."},{"k":"kaviratna","t":"If you find a wise companion to associate with you, one who leads a virtuous life and is diligent, you should lead a life with him joyfully and mindfully, conquering all obstacles."},{"k":"buddharakkhita","t":"If for company you find a wise and prudent friend who leads a good life, you should, overcoming all impediments, keep his company joyously and mindfully."},{"k":"thanissaro","t":"If you gain a mature companion —\na fellow traveler, right-living, enlightened —\novercoming all dangers\ngo with him, gratified,\nmindful."},{"k":"suddhaso","t":"If you can get a prudent companion\nto travel with, a steadfast person who lives an excellent life,\nthen leave behind all your problems\nand go with them, satisfied and mindful."},{"k":"sujato","t":"If you find an alert companion,\nan attentive friend to live happily together,\nthen, overcoming all adversities,\nwander with them, joyful and mindful."}]},{"n":329,"vg":23,"pali":"No ce labhetha nipakaṁ sahāyaṁ,\nSaddhiṁ caraṁ sādhuvihāridhīraṁ;\nRājāva raṭṭhaṁ vijitaṁ pahāya,\nEko care mātaṅgaraññeva nāgo.","v":[{"k":"muller","t":"If a man find no prudent companion who walks with him, is wise, and lives soberly, let him walk alone, like a king who has left his conquered country behind,--like an elephant in the forest."},{"k":"wagiswara","t":"Hast thou found no fellow-traveller, upright, firm, intelligent?\nAs a king deserts his borders, by the enemy pursued,\nLike the tusker in the forest, go thy way in solitude."},{"k":"kaviratna","t":"If you do not find a wise companion to associate with you, one who leads a virtuous life and is diligent, then like the monarch who has renounced his conquered kingdom, and like Matanga the elephant in the forest, you should live alone."},{"k":"buddharakkhita","t":"If for company you cannot find a wise and prudent friend who leads a good life, then, like a king who leaves behind a conquered kingdom, or like a lone elephant in the elephant forest, you should go your way alone."},{"k":"thanissaro","t":"If you don't gain a mature companion —\na fellow traveler, right-living, enlightened —\ngo alone\nlike a king renouncing his kingdom,\nlike the elephant in the Matanga wilds,\nhis herd."},{"k":"suddhaso","t":"If you can not get a prudent companion\nto travel with, a steadfast person who lives an excellent life,\nthen like a king leaving behind a conquered realm,\ngo alone, like an elephant in its wilderness habitat."},{"k":"sujato","t":"If you find no alert companion,\nno attentive friend to live happily together,\nthen, like a king who flees his conquered realm,\nwander alone like a tusker in the wilds."}]},{"n":330,"vg":23,"pali":"Ekassa caritaṁ seyyo,\nNatthi bāle sahāyatā;\nEko care na ca pāpāni kayirā,\nAppossukko mātaṅgaraññeva nāgo.","v":[{"k":"muller","t":"It is better to live alone, there is no companionship with a fool; let a man walk alone, let him commit no sin, with few wishes, like an elephant in the forest."},{"k":"wagiswara","t":"Better is the lonely life, for fools companions cannot be;\nLive alone and do no evil, live alone with scanty needs,\nLonely, as the mighty tusker in the forest lonely feeds."},{"k":"kaviratna","t":"It is better to lead a solitary life; there is no companionship with a childish person! Let one live alone committing no sin, having few wishes, like Matanga the elephant in the elephant grove."},{"k":"buddharakkhita","t":"Better it is to live alone; there is no fellowship with a fool. Live alone and do no evil; be carefree like an elephant in the elephant forest."},{"k":"thanissaro","t":"Going alone is better,\nthere's no companionship with a fool.\nGo alone,\ndoing no evil, at peace,\nlike the elephant in the Matanga wilds."},{"k":"suddhaso","t":"It is best to go alone;\nthere is no companionship with a fool.\nOne who lives alone and does nothing harmful\nwill be at ease, like an elephant in its wilderness habitat."},{"k":"sujato","t":"It's better to wander alone,\nthere's no fellowship with fools.\nWander alone and do no wrong,\nat ease like a tusker in the wilds."}]},{"n":331,"vg":23,"pali":"Atthamhi jātamhi sukhā sahāyā,\nTuṭṭhī sukhā yā itarītarena;\nPuññaṁ sukhaṁ jīvitasaṅkhayamhi,\nSabbassa dukkhassa sukhaṁ pahānaṁ.","v":[{"k":"muller","t":"If an occasion arises, friends are pleasant; enjoyment is pleasant, whatever be the cause; a good work is pleasant in the hour of death; the giving up of all grief is pleasant."},{"k":"wagiswara","t":"Sweet are friends when need ariseth, sweet is joy whate'er it be;\nSweet the blessing of life's ending, sweet to be from sorrow free."},{"k":"kaviratna","t":"Companions are pleasant to have when a need arises; contentment is pleasant when it is mutual; merit is pleasant at the last hour; pleasant is the extinction of all suffering."},{"k":"buddharakkhita","t":"Good are friends when need arises; good is contentment with just what one has; good is merit when life is at an end, and good is the abandoning of all suffering (through Arahantship)."},{"k":"thanissaro","t":"A blessing: friends when the need arises.\nA blessing: contentment with whatever there is.\nMerit at the ending of life is a blessing.\nA blessing: the abandoning of all suffering\n& stress.\n\nA blessing in the world: reverence to your mother.\nA blessing: reverence to your father as well.\nA blessing in the world: reverence to a contemplative.\nA blessing: reverence for a brahman, too.\n\nA blessing into old age is virtue.\nA blessing: conviction established.\nA blessing: discernment attained.\nThe non-doing of evil things is\na blessing."},{"k":"suddhaso","t":"It is pleasant to have companions when the need arises,\nit is pleasant to be content with whatever comes,\nit is pleasant to have merit when life comes to an end,\nit is pleasant to leave behind all suffering."},{"k":"sujato","t":"A friend in need is a blessing;\nit's a blessing to be content with whatever;\ngood deeds are a blessing at the end of life,\nand giving up all suffering is a blessing."}]},{"n":332,"vg":23,"pali":"Sukhā matteyyatā loke,\natho petteyyatā sukhā;\nSukhā sāmaññatā loke,\natho brahmaññatā sukhā.","v":[{"k":"muller","t":"Pleasant in the world is the state of a mother, pleasant the state of a father, pleasant the state of a Samana, pleasant the state of a Brahmana."},{"k":"wagiswara","t":"Sweet it is to be a mother, sweet the lot of fatherhood,\nSweet the life of holy hermits, sweet the life of Brāhmans good."},{"k":"kaviratna","t":"To be a mother in this world is bliss; to be a father in this world is bliss; to be a homeless recluse in this world is bliss, and to be a Brahman in this world is bliss (sukha)."},{"k":"buddharakkhita","t":"In this world, good it is to serve one's mother, good it is to serve one's father, good it is to serve the monks, and good it is to serve the holy men."},{"k":"thanissaro","t":"A blessing: friends when the need arises.\nA blessing: contentment with whatever there is.\nMerit at the ending of life is a blessing.\nA blessing: the abandoning of all suffering\n& stress.\n\nA blessing in the world: reverence to your mother.\nA blessing: reverence to your father as well.\nA blessing in the world: reverence to a contemplative.\nA blessing: reverence for a brahman, too.\n\nA blessing into old age is virtue.\nA blessing: conviction established.\nA blessing: discernment attained.\nThe non-doing of evil things is\na blessing."},{"k":"suddhaso","t":"It is pleasant to be a mother in this world,\nit is pleasant to be a father;\nit is pleasant to be a contemplative in this world,\nit is pleasant to be spiritual."},{"k":"sujato","t":"In this world it's a blessing to serve\none's mother and one's father.\nAnd it's a blessing also to serve\nascetics and brahmins."}]},{"n":333,"vg":23,"pali":"Sukhaṁ yāva jarā sīlaṁ,\nsukhā saddhā patiṭṭhitā;\nSukho paññāya paṭilābho,\npāpānaṁ akaraṇaṁ sukhaṁ.\nNāgavaggo tevīsatimo.","v":[{"k":"muller","t":"Pleasant is virtue lasting to old age, pleasant is a faith firmly rooted; pleasant is attainment of intelligence, pleasant is avoiding of sins."},{"k":"wagiswara","t":"Sweet is growing old in goodness, sweet is faith established,\nSweet to gain the prize of wisdom when desire for sin is dead."},{"k":"kaviratna","t":"The virtue that lasts to the end of life is bliss; steadfast faith is also bliss; the attainment of wisdom is bliss, and not to commit sin is bliss."},{"k":"buddharakkhita","t":"Good is virtue until life's end, good is faith that is steadfast, good is the acquisition of wisdom, and good is the avoidance of evil."},{"k":"thanissaro","t":"A blessing: friends when the need arises.\nA blessing: contentment with whatever there is.\nMerit at the ending of life is a blessing.\nA blessing: the abandoning of all suffering\n& stress.\n\nA blessing in the world: reverence to your mother.\nA blessing: reverence to your father as well.\nA blessing in the world: reverence to a contemplative.\nA blessing: reverence for a brahman, too.\n\nA blessing into old age is virtue.\nA blessing: conviction established.\nA blessing: discernment attained.\nThe non-doing of evil things is\na blessing."},{"k":"suddhaso","t":"It is pleasant to have virtue that lasts into old age,\nit is pleasant to have established faith,\nit is pleasant to have attained wisdom,\nit is pleasant to do no evil."},{"k":"sujato","t":"It's a blessing to keep precepts until you grow old;\na blessing to be grounded in faith;\nthe getting of wisdom's a blessing;\nand it's a blessing to avoid doing wrong."}]},{"n":334,"vg":24,"pali":"Manujassa pamattacārino,\nTaṇhā vaḍḍhati māluvā viya;\nSo plavatī hurā huraṁ,\nPhalamicchaṁva vanasmi vānaro.","v":[{"k":"muller","t":"The thirst of a thoughtless man grows like a creeper; he runs from life to life, like a monkey seeking fruit in the forest."},{"k":"wagiswara","t":"Even as a creeper groweth,\nCreatures that are indolent\nFind their craving ever grow;\nLike a monkey in the forest\nSeeking fruit from bough to bough,\nSo they wander to and fro."},{"k":"kaviratna","t":"The craving (tanha) of a heedless man grows like the maluva creeper. He jumps (from life to life) like a monkey eagerly seeking fruit in the forest."},{"k":"buddharakkhita","t":"The craving of one given to heedless living grows like a creeper. Like the monkey seeking fruits in the forest, he leaps from life to life (tasting the fruit of his kamma)."},{"k":"thanissaro","t":"When a person lives heedlessly,\nhis craving grows like a creeping vine.\nHe runs now here\n& now there,\nas if looking for fruit:\na monkey in the forest."},{"k":"suddhaso","t":"For a person who lives negligently,\ncraving grows like vines;\nthey drift from life to life,\nlike a monkey in the forest wishing for fruit."},{"k":"sujato","t":"When a man lives heedlessly,\ncraving grows in them like a camel's foot creeper.\nThey jump from one thing to the next, like a langur\ngreedy for fruit in a forest grove."}]},{"n":335,"vg":24,"pali":"Yaṁ esā sahate jammī,\ntaṇhā loke visattikā;\nSokā tassa pavaḍḍhanti,\nabhivaṭṭhaṁva bīraṇaṁ.","v":[{"k":"muller","t":"Whomsoever this fierce thirst overcomes, full of poison, in this world, his sufferings increase like the abounding Birana grass."},{"k":"wagiswara","t":"He who yields to sordid craving\nThat thro' all the world doth go,\nLike the gadding vine that spreadeth,\nThat man's sorrows ever grow."},{"k":"kaviratna","t":"Whosoever is overcome by this shameful craving which creates entanglements in this world, his sorrows increase like the luxuriant birana grass (in the rainy season)."},{"k":"buddharakkhita","t":"Whoever is overcome by this wretched and sticky craving, his sorrows grow like grass after the rains."},{"k":"thanissaro","t":"If this sticky, uncouth craving\novercomes you in the world,\nyour sorrows grow like wild grass\nafter rain."},{"k":"suddhaso","t":"When one is overcome by that which is despicable -\ncraving, which keeps us stuck in the world -\nthen sorrow grows in them,\nlike weeds after rain."},{"k":"sujato","t":"Whoever is beaten by this wretched craving,\nthis attachment to the world,\ntheir sorrow grows,\nlike grass in the rain."}]},{"n":336,"vg":24,"pali":"Yo cetaṁ sahate jammiṁ,\ntaṇhaṁ loke duraccayaṁ;\nSokā tamhā papatanti,\nudabinduva pokkharā.","v":[{"k":"muller","t":"He who overcomes this fierce thirst, difficult to be conquered in this world, sufferings fall off from him, like water-drops from a lotus leaf."},{"k":"wagiswara","t":"He who quiets sordid craving,\nHard in this world to allay,\nLike the dewdrop from the lotus,\nAll his sorrows fall away."},{"k":"kaviratna","t":"But whosoever overcomes in this world this shameful craving, which is difficult to suppress, finds his sorrows fall from him, as drops of water from a lotus leaf."},{"k":"buddharakkhita","t":"But whoever overcomes this wretched craving, so difficult to overcome, from him sorrows fall away like water from a lotus leaf."},{"k":"thanissaro","t":"If, in the world, you overcome\nthis uncouth craving, hard to escape,\nsorrows roll off you,\nlike water beads off\na lotus."},{"k":"suddhaso","t":"When one overcomes that which is despicable -\ncraving, which is so hard to transcend in this world -\nthen sorrow falls away from them,\nlike drops of water from a lotus."},{"k":"sujato","t":"But whoever prevails over this wretched craving,\nso hard to get over in the world,\ntheir sorrows fall from them,\nlike a drop from a lotus-leaf."}]},{"n":337,"vg":24,"pali":"Taṁ vo vadāmi bhaddaṁ vo,\nyāvantettha samāgatā;\nTaṇhāya mūlaṁ khaṇatha,\nusīratthova bīraṇaṁ;\nMā vo naḷaṁva sotova,\nmāro bhañji punappunaṁ.","v":[{"k":"muller","t":"This salutary word I tell you, `Do ye, as many as are here assembled, dig up the root of thirst, as he who wants the sweet-scented Usira root must dig up the Birana grass, that Mara (the tempter) may not crush you again and again, as the stream crushes the reeds.'"},{"k":"wagiswara","t":"Lo! to all of ye assembled\nThis the good advice I tell:\n\"Dig ye up the root of craving,\nAs men dig the scented grass.\nLet not Death so oft assail ye,\nEven as the rushing torrent\nO'er the river reeds doth pass.\""},{"k":"kaviratna","t":"This I say unto you! May all of you, who are gathered here, be blessed! May you dig up the root of craving as one who digs up the birana grass for the fragrant usira root. (1) Let not Mara destroy you again and again, even as the current of the river destroys the reeds."},{"k":"buddharakkhita","t":"This I say to you: Good luck to all assembled here! Dig up the root of craving, like one in search of the fragrant root of the birana grass. Let not Mara crush you again and again, as a flood crushes a reed."},{"k":"thanissaro","t":"To all of you gathered here\nI say: Good fortune.\nDig up craving\n— as when seeking medicinal roots, wild grass —\nby the root.\nDon't let Mara cut you down\n— as a raging river, a reed —\nover & over again."},{"k":"suddhaso","t":"I wish the best to all of you\nthat are gathered here -\ndig up the root of craving,\nas one seeks the root of a weed;\ndo not let Māra subdue you again and again,\nlike a stream does to reeds."},{"k":"sujato","t":"I say this to you, good people,\nall those who have gathered here:\ndig up the root of craving,\nas you'd dig up grass in search of roots.\nDon't let Māra break you again and again,\nlike a stream breaking a reed."}]},{"n":338,"vg":24,"pali":"Yathāpi mūle anupaddave daḷhe,\nChinnopi rukkho punareva rūhati;\nEvampi taṇhānusaye anūhate,\nNibbattatī dukkhamidaṁ punappunaṁ.","v":[{"k":"muller","t":"As a tree, even though it has been cut down, is firm so long as its root is safe, and grows again, thus, unless the feeders of thirst are destroyed, the pain (of life) will return again and again."},{"k":"wagiswara","t":"If the root be still uninjured,\nTrees cut down will spring again;\nIf the root of craving liveth,\nStill there is rebirth of pain."},{"k":"kaviratna","t":"Just as a tree when cut down sprouts up again if the roots remain firm and uninjured, even so this suffering (of life) returns again and again if the root of craving is not completely destroyed."},{"k":"buddharakkhita","t":"Just as a tree, though cut down, sprouts up again if its roots remain uncut and firm, even so, until the craving that lies dormant is rooted out, suffering springs up again and again."},{"k":"thanissaro","t":"If its root remains\nundamaged & strong,\na tree, even if cut,\nwill grow back.\nSo too if latent craving\nis not rooted out,\nthis suffering returns\nagain\n&\nagain."},{"k":"suddhaso","t":"As long as its root is undisturbed and strong,\na felled tree grows again.\nIn the same way, as long as the tendency towards craving is not destroyed,\nit produces suffering again and again."},{"k":"sujato","t":"A tree grows back even when cut down,\nso long as its roots are strong and undamaged;\nsuffering springs up again and again,\nso long as the tendency to craving is not pulled out."}]},{"n":339,"vg":24,"pali":"Yassa chattiṁsati sotā,\nmanāpasavanā bhusā;\nMahāvahanti duddiṭṭhiṁ,\nsaṅkappā rāganissitā.","v":[{"k":"muller","t":"He whose thirst running towards pleasure is exceeding strong in the thirty-six channels, the waves will carry away that misguided man, viz. his desires which are set on passion."},{"k":"wagiswara","t":"When the six and thirty currents\nBring one under pleasure's sway,\nThoughts, like waves, with passion surging.\nSweep him all confused away."},{"k":"kaviratna","t":"The man in whom the thirty-six streams of craving flow strongly towards pleasurable objects, the waves of passions carry off. He is of confused vision and erroneous thoughts."},{"k":"buddharakkhita","t":"The misguided man in whom the thirty-six currents of craving strongly rush toward pleasurable objects, is swept away by the flood of his passionate thoughts. [21]"},{"k":"thanissaro","t":"He whose 36 streams,\nflowing to what is appealing, are strong:\nthe currents — resolves based on passion —\ncarry him, of base views, away."},{"k":"suddhaso","t":"If the 36 streams\nare flowing strongly towards what one likes,\nthen one is swept along by harmful views\nand attitudes based on passion."},{"k":"sujato","t":"A person of low views\nin whom the thirty-six streams\nthat flow to pleasure are mighty,\nis swept away by lustful thoughts."}]},{"n":340,"vg":24,"pali":"Savanti sabbadhi sotā,\nlatā uppajja tiṭṭhati;\nTañca disvā lataṁ jātaṁ,\nmūlaṁ paññāya chindatha.","v":[{"k":"muller","t":"The channels run everywhere, the creeper (of passion) stands sprouting; if you see the creeper springing up, cut its root by means of knowledge."},{"k":"wagiswara","t":"Everywhere those streams are flowing;\nNow the creeper of desire\nPlants its roots and standeth fast;\nCut it ere it riseth higher,\nCut it with the axe of wisdom,\nRoot the creeper up at last."},{"k":"kaviratna","t":"Streams flow everywhere; the creeper (of passion) sprouts and remains fixed. If you see that creeper springing up, cut its root by means of wisdom."},{"k":"buddharakkhita","t":"Everywhere these currents flow, and the creeper (of craving) sprouts and grows. Seeing that the creeper has sprung up, cut off its root with wisdom."},{"k":"thanissaro","t":"They flow every which way, the streams,\nbut the sprouted creeper stays\nin place.\nNow, seeing that the creeper's arisen,\ncut through its root\nwith discernment."},{"k":"suddhaso","t":"Streams flow everywhere,\ncreepers appear and remain;\nhaving seen the birth of the creeper,\ncut its root with wisdom."},{"k":"sujato","t":"The streams flow everywhere;\na weed springs up and remains.\nSeeing this weed that has been born,\ncut the root with wisdom."}]},{"n":341,"vg":24,"pali":"Saritāni sinehitāni ca,\nSomanassāni bhavanti jantuno;\nTe sātasitā sukhesino,\nTe ve jātijarūpagā narā.","v":[{"k":"muller","t":"A creature's pleasures are extravagant and luxurious; sunk in lust and looking for pleasure, men undergo (again and again) birth and decay."},{"k":"wagiswara","t":"Restless, wanton is men's craving;\nThey who wander to and fro\nIn the restless search for pleasure\nBirth and death must undergo."},{"k":"kaviratna","t":"In creatures there arise pleasures extending towards sense objects. Immersed in various enjoyments they hanker after them. Verily, these people are subject to birth and old age."},{"k":"buddharakkhita","t":"Flowing in (from all objects) and watered by craving, feelings of pleasure arise in beings. Bent on pleasures and seeking enjoyment, these men fall prey to birth and decay."},{"k":"thanissaro","t":"Loosened & oiled\nare the joys of a person.\nPeople, bound by enticement,\nlooking for ease:\nto birth & aging they go."},{"k":"suddhaso","t":"Currents of infatuation\nand elation exist in people;\nthose who are addicted to comfort, seeking pleasure,\narrive at rebirth and decrepitude."},{"k":"sujato","t":"A personage's joys\nflow from senses and cravings.\nSeekers of happiness, bent on pleasure,\ncontinue to be reborn and grow old."}]},{"n":342,"vg":24,"pali":"Tasiṇāya purakkhatā pajā,\nParisappanti sasova bandhito;\nSaṁyojanasaṅgasattakā,\nDukkhamupenti punappunaṁ cirāya.","v":[{"k":"muller","t":"Men, driven on by thirst, run about like a snared hare; held in fetters and bonds, they undergo pain for a long time, again and again."},{"k":"wagiswara","t":"They who in the trap of craving,\nLike a hare run to and fro,\nBy the fetters' bonds entangled,\nLong must sorrow undergo."},{"k":"kaviratna","t":"People beset by craving circle round and round, like a hare ensnared in a net; held fast by the (ten) fetters and shackles (that bind man to the wheel of life), they undergo suffering for a long time, again and again."},{"k":"buddharakkhita","t":"Beset by craving, people run about like an entrapped hare. Held fast by mental fetters, they come to suffering again and again for a long time."},{"k":"thanissaro","t":"Encircled with craving,\npeople hop round & around\nlike a rabbit caught in a snare.\nTied with fetters & bonds\nthey go on to suffering,\nagain & again, for long."},{"k":"suddhaso","t":"Pursued by craving,\npeople thrash about like a trapped rabbit;\nbound by attachment and adherence,\nthey come to suffering again and again for a long time."},{"k":"sujato","t":"People governed by thirst,\ncrawl about like a trapped rabbit.\nBound and fettered, for a long time\nthey return to pain time and again."}]},{"n":343,"vg":24,"pali":"Tasiṇāya purakkhatā pajā,\nParisappanti sasova bandhito;\nTasmā tasiṇaṁ vinodaye,\nĀkaṅkhanta virāgamattano.","v":[{"k":"muller","t":"Men, driven on by thirst, run about like a snared hare; let therefore the mendicant drive out thirst, by striving after passionlessness for himself."},{"k":"wagiswara","t":"Beings, in the trap of craving\nLike a hare run to and fro:\nMendicants who hope for freedom\nMust their passions all forego."},{"k":"kaviratna","t":"People beset by craving circle round and round, like a hare ensnared in a net; therefore, let the monk who desires freedom from passion abandon craving."},{"k":"buddharakkhita","t":"Beset by craving, people run about like an entrapped hare. Therefore, one who yearns to be passion-free should destroy his own craving."},{"k":"thanissaro","t":"Encircled with craving,\npeople hop round & around\nlike a rabbit caught in a snare.\nSo a monk\nshould dispel craving,\nshould aspire to dispassion\nfor himself."},{"k":"suddhaso","t":"Pursued by craving,\npeople thrash about like a trapped rabbit;\ntherefore, one should remove craving,\nwishing to be dispassionate."},{"k":"sujato","t":"People governed by thirst,\ncrawl about like a trapped rabbit.\nThat's why one who longs for dispassion\nshould dispel thirst."}]},{"n":344,"vg":24,"pali":"Yo nibbanatho vanādhimutto,\nVanamutto vanameva dhāvati;\nTaṁ puggalametha passatha,\nMutto bandhanameva dhāvati.","v":[{"k":"muller","t":"He who having got rid of the forest (of lust) (i.e. after having reached Nirvana) gives himself over to forest-life (i.e. to lust), and who, when removed from the forest (i.e. from lust), runs to the forest (i.e. to lust), look at that man! though free, he runs into bondage."},{"k":"wagiswara","t":"Whoso, free from human passions,\nJunglewards to run is fain;\nWho, from lust emancipated,\nTo his lust runs back again;\nLo! the man infatuated\nPlunges into bonds of pain."},{"k":"kaviratna","t":"He who has renounced the forest (of craving), and having liberated himself from that forest, yet runs back into it — behold this man! Although once freed, he runs into bondage."},{"k":"buddharakkhita","t":"There is one who, turning away from desire (for household life) takes to the life of the forest (i.e., of a monk). But after being freed from the household, he runs back to it. Behold that man! Though freed, he runs back to that very bondage! [22]"},{"k":"thanissaro","t":"Cleared of the underbrush\nbut obsessed with the forest,\nset free from the forest,\nright back to the forest he runs.\nCome, see the person set free\nwho runs right back to the same old chains!"},{"k":"suddhaso","t":"One who has left the forest yet is intent upon the forest,\nthough free from the forest, runs back to the forest.\nLook at that person;\nalthough free, they run back to imprisonment."},{"k":"sujato","t":"Unsnarled, they set out for the jungle,\nthen they run right back to the jungle they left behind.\nJust look at this individual!\nFreed, they run to bondage."}]},{"n":345,"vg":24,"pali":"Na taṁ daḷhaṁ bandhanamāhu dhīrā,\nYadāyasaṁ dārujapabbajañca;\nSārattarattā maṇikuṇḍalesu,\nPuttesu dāresu ca yā apekkhā.","v":[{"k":"muller","t":"Wise people do not call that a strong fetter which is made of iron, wood, or hemp; far stronger is the care for precious stones and rings, for sons and a wife."},{"k":"wagiswara","t":"Not by ties of wood or iron\nNor of rope (the wise men say)\nAre men held in bondage strong;\nBut for jewels, wives and children,\nThey who passionately crave,\nThey are held in bondage long."},{"k":"kaviratna","t":"The wise do not call strong that fetter which is made of iron, wood or hemp. Rather do they call attachment to jewels, ornaments, children and wives a far stronger fetter."},{"k":"buddharakkhita","t":"That is not a strong fetter, the wise say, which is made of iron, wood or hemp. But the infatuation and longing for jewels and ornaments, children and wives — that, they say, is a far stronger fetter, which pulls one downward and, though seemingly loose, is hard to remove. This, too, the wise cut off. Giving up sensual pleasure, and without any longing, they renounce the world."},{"k":"thanissaro","t":"That's not a strong bond\n— so say the enlightened —\nthe one made of iron, of wood, or of grass.\nTo be smitten, enthralled,\nwith jewels & ornaments,\nlonging for children & wives:\nthat's the strong bond,\n— so say the enlightened —\none that's constraining,\nelastic,\nhard to untie.\nBut having cut it, they\n— the enlightened — go forth,\nfree of longing, abandoning\nsensual ease."},{"k":"suddhaso","t":"The wise say that prisons\nmade of iron, wood, and thatch\nare not as strong as\nobsession with jewelry, children, and spouses."},{"k":"sujato","t":"The attentive say that shackle is not strong\nthat's made of iron, wood, or knots.\nBut obsession with jeweled earrings,\nconcern for your partners and children:"}]},{"n":346,"vg":24,"pali":"Etaṁ daḷhaṁ bandhanamāhu dhīrā,\nOhārinaṁ sithilaṁ duppamuñcaṁ;\nEtampi chetvāna paribbajanti,\nAnapekkhino kāmasukhaṁ pahāya.","v":[{"k":"muller","t":"That fetter wise people call strong which drags down, yields, but is difficult to undo; after having cut this at last, people leave the world, free from cares, and leaving desires and pleasures behind."},{"k":"wagiswara","t":"But the downward-dragging chain,\nYielding, hard to loose again--\nThis is bondage real (they say):\nWho this chain of craving breaks,\nFree from lust, the world forsakes."},{"k":"kaviratna","t":"That fetter is strong, say the wise, which drags a man down; which, although slack, is difficult to escape from. Severing even this, they set forth, desiring nothing and abandoning all sensuous pleasures."},{"k":"buddharakkhita","t":"That is not a strong fetter, the wise say, which is made of iron, wood or hemp. But the infatuation and longing for jewels and ornaments, children and wives — that, they say, is a far stronger fetter, which pulls one downward and, though seemingly loose, is hard to remove. This, too, the wise cut off. Giving up sensual pleasure, and without any longing, they renounce the world."},{"k":"thanissaro","t":"That's not a strong bond\n— so say the enlightened —\nthe one made of iron, of wood, or of grass.\nTo be smitten, enthralled,\nwith jewels & ornaments,\nlonging for children & wives:\nthat's the strong bond,\n— so say the enlightened —\none that's constraining,\nelastic,\nhard to untie.\nBut having cut it, they\n— the enlightened — go forth,\nfree of longing, abandoning\nsensual ease.\n\nThose smitten with passion\nfall back\ninto a self-made stream,\nlike a spider snared in its web.\nBut, having cut it, the enlightened set forth,\nfree of longing, abandoning\nall suffering & stress."},{"k":"suddhaso","t":"The wise say that this is a strong prison\nwhich oppresses the lax and is hard to escape from.\nThey break free and become renunciants,\nleaving behind sensual pleasure without looking back."},{"k":"sujato","t":"this, say the attentive, is a strong shackle\ndragging the indulgent down, hard to escape.\nHaving cut this one too they go forth,\nunconcerned, having given up sensual pleasures."}]},{"n":347,"vg":24,"pali":"Ye rāgarattānupatanti sotaṁ,\nSayaṅkataṁ makkaṭakova jālaṁ;\nEtampi chetvāna vajanti dhīrā,\nAnapekkhino sabbadukkhaṁ pahāya.","v":[{"k":"muller","t":"Those who are slaves to passions, run down with the stream (of desires), as a spider runs down the web which he has made himself; when they have cut this, at last, wise people leave the world free from cares, leaving all affection behind."},{"k":"wagiswara","t":"They who yield to their desires\nDown the stream of craving swim;\nAs we see the spider run\nIn the net himself hath spun.\nWise men cut the net and go\nFree from craving, free from woe."},{"k":"kaviratna","t":"Those beings who are infatuated with the fire of lust fall into the current (of thirst for life), as the spider into its self-spun web. The wise, having curtailed the current, go off, leaving all sorrow behind."},{"k":"buddharakkhita","t":"Those who are lust-infatuated fall back into the swirling current (of samsara) like a spider on its self-spun web. This, too, the wise cut off. Without any longing, they abandon all suffering and renounce the world."},{"k":"thanissaro","t":"Those smitten with passion\nfall back\ninto a self-made stream,\nlike a spider snared in its web.\nBut, having cut it, the enlightened set forth,\nfree of longing, abandoning\nall suffering & stress."},{"k":"suddhaso","t":"Those who fall into the stream of passion\nare like a spider stuck in its own web.\nThe wise break free and move on,\nleaving behind all suffering without looking back."},{"k":"sujato","t":"Besotted by lust they fall into the stream,\nlike a spider caught in the web she wove.\nThe attentive proceed, having cut this one too,\nunconcerned, having given up all suffering."}]},{"n":348,"vg":24,"pali":"Muñca pure muñca pacchato,\nMajjhe muñca bhavassa pāragū;\nSabbattha vimuttamānaso,\nNa punaṁ jātijaraṁ upehisi.","v":[{"k":"muller","t":"Give up what is before, give up what is behind, give up what is in the middle, when thou goest to the other shore of existence; if thy mind is altogether free, thou wilt not again enter into birth and decay."},{"k":"wagiswara","t":"Loose all behind, between, before;\nCross thou unto the other shore;\nWith thy mind on all sides free\nBirth and death no more shalt see."},{"k":"kaviratna","t":"Renounce the craving for the past, renounce the craving for the future, renounce the craving for what is between, and cross to the opposite shore. With the mind fully emancipated you will not return to birth and old age."},{"k":"buddharakkhita","t":"Let go of the past, let go of the future, let go of the present, and cross over to the farther shore of existence. With mind wholly liberated, you shall come no more to birth and death."},{"k":"thanissaro","t":"Gone to the beyond of becoming,\nyou let go of in front,\nlet go of behind,\nlet go of between.\nWith a heart everywhere let-go,\nyou don't come again to birth\n& aging."},{"k":"suddhaso","t":"Be free before, be free after,\nbe free in the middle; transcend existence.\nWith a mind liberated everywhere,\ndo not return again to birth and decrepitude."},{"k":"sujato","t":"Let go of the past, let go of the future,\nlet go of the present, having gone beyond rebirth.\nWith your heart freed in every respect,\nyou'll not come again to rebirth and old age."}]},{"n":349,"vg":24,"pali":"Vitakkamathitassa jantuno,\nTibbarāgassa subhānupassino;\nBhiyyo taṇhā pavaḍḍhati,\nEsa kho daḷhaṁ karoti bandhanaṁ.","v":[{"k":"muller","t":"If a man is tossed about by doubts, full of strong passions, and yearning only for what is delightful, his thirst will grow more and more, and he will indeed make his fetters strong."},{"k":"wagiswara","t":"He whose mind is tossed with doubt,\nSeeing bliss in passion's surge,\nMakes his craving grow the longer,\nRivets all his bonds the stronger."},{"k":"kaviratna","t":"Craving (tanha) steadily grows in the mortal whose mind is agitated by (evil) thoughts, who is full of strong passions and ever yearning for what is pleasant. Such a one makes his fetters strong."},{"k":"buddharakkhita","t":"For a person tormented by evil thoughts, who is passion-dominated and given to the pursuit of pleasure, his craving steadily grows. He makes the fetter strong, indeed."},{"k":"thanissaro","t":"For a person\nforced on by his thinking,\nfierce in his passion,\nfocused on beauty,\ncraving grows all the more.\nHe's the one\nwho tightens the bond.\n\nBut one who delights\nin the stilling of thinking,\nalways mindful\ncultivating\na focus on the foul:\nHe's the one\nwho will make an end,\nthe one who will cut Mara's bond."},{"k":"suddhaso","t":"When one has disturbed thoughts,\nstrong passion, and fixation on beauty,\nthen craving grows ever greater\nand makes a strong prison."},{"k":"sujato","t":"For a personage churned by thoughts,\nvery lustful, focusing on beauty,\ntheir craving grows and grows,\ntying them with a stout bond."}]},{"n":350,"vg":24,"pali":"Vitakkūpasame ca yo rato,\nAsubhaṁ bhāvayate sadā sato;\nEsa kho byanti kāhiti,\nEsa checchati mārabandhanaṁ.","v":[{"k":"muller","t":"If a man delights in quieting doubts, and, always reflecting, dwells on what is not delightful (the impurity of the body, &c.), he certainly will remove, nay, he will cut the fetter of Mara."},{"k":"wagiswara","t":"He who joys in calming doubt,\nAnd the loathsome contemplates,\nSoon will Māra's bondage leave,\nEvery fetter soon will cleave."},{"k":"kaviratna","t":"He who delights in controlling his thoughts, who ever absorbs himself in contemplation on what is not pleasant (the impurity of the body), such a one will put an end (to craving) and cut the bonds of Mara."},{"k":"buddharakkhita","t":"He who delights in subduing evil thoughts, who meditates on the impurities and is ever mindful — it is he who will make an end of craving and rend asunder Mara's fetter."},{"k":"thanissaro","t":"For a person\nforced on by his thinking,\nfierce in his passion,\nfocused on beauty,\ncraving grows all the more.\nHe's the one\nwho tightens the bond.\n\nBut one who delights\nin the stilling of thinking,\nalways mindful\ncultivating\na focus on the foul:\nHe's the one\nwho will make an end,\nthe one who will cut Mara's bond."},{"k":"suddhaso","t":"One who approves of tranquil thought,\nwho has cultivated awareness of non-beauty and is always mindful,\nwill put an end to that craving\nand break free of Māra's prison."},{"k":"sujato","t":"But one who loves to calm their thoughts,\ndeveloping perception of ugliness, ever mindful,\nwill surely eliminate that craving,\ncutting off the bonds of Māra."}]},{"n":351,"vg":24,"pali":"Niṭṭhaṅgato asantāsī,\nvītataṇho anaṅgaṇo;\nAcchindi bhavasallāni,\nantimoyaṁ samussayo.","v":[{"k":"muller","t":"He who has reached the consummation, who does not tremble, who is without thirst and without sin, he has broken all the thorns of life: this will be his last body."},{"k":"wagiswara","t":"He who hath attained the goal,\nFearless, free from lust and sin,\nWho hath plucked out every thorn,\nNevermore will be reborn."},{"k":"kaviratna","t":"He who has arrived at the goal, who is fearless, devoid of craving, passionless, has destroyed the arrows of existence. For such a person this is his last physical form."},{"k":"buddharakkhita","t":"He who has reached the goal, is fearless, free from craving, passionless, and has plucked out the thorns of existence — for him this is the last body."},{"k":"thanissaro","t":"Arrived at the finish,\nunfrightened, unblemished, free\nof craving, he has cut away\nthe arrows of becoming.\nThis physical heap is his last.\n\nFree from craving,\nungrasping,\nastute in expression,\nknowing the combination of sounds —\nwhich comes first & which after.\nHe's called a\nlast-body\ngreatly discerning\ngreat man."},{"k":"suddhaso","t":"When one has reached the final destination, is fearless,\nfree of craving, flawless,\nand has broken the thorn of existence,\nthen they bear their last body."},{"k":"sujato","t":"One who is confident, unafraid,\nrid of craving, free of blemish,\nhaving struck down the arrows flying to future lives,\nthis bag of bones is their last."}]},{"n":352,"vg":24,"pali":"Vītataṇho anādāno,\nNiruttipadakovido;\nAkkharānaṁ sannipātaṁ,\nJaññā pubbāparāni ca;\nSa ve \"antimasārīro,\nMahāpañño mahāpuriso\"ti vuccati.","v":[{"k":"muller","t":"He who is without thirst and without affection, who understands the words and their interpretation, who knows the order of letters (those which are before and which are after), he has received his last body, he is called the great sage, the great man."},{"k":"wagiswara","t":"Free from lust, to nothing clinging,\nWho is skilful to interpret\nAll the wealth of sacred lore;\nAll the mass of letters knowing\n(Whether after or before),\nThis indeed is his last body,\nHe's a Master of The Wisdom,\nMighty Being,\nHe indeed is born no more."},{"k":"kaviratna","t":"He who is devoid of craving and attachment, who is an expert in etymology and terminology, who knows the systematic arrangement of letters (in their prior and posterior relations), is called a foremost sage, a great man. He bears a physical body for the last time."},{"k":"buddharakkhita","t":"He who is free from craving and attachment, is perfect in uncovering the true meaning of the Teaching, and knows the arrangement of the sacred texts in correct sequence — he, indeed, is the bearer of his final body. He is truly called the profoundly wise one, the great man."},{"k":"thanissaro","t":"Arrived at the finish,\nunfrightened, unblemished, free\nof craving, he has cut away\nthe arrows of becoming.\nThis physical heap is his last.\n\nFree from craving,\nungrasping,\nastute in expression,\nknowing the combination of sounds —\nwhich comes first & which after.\nHe's called a\nlast-body\ngreatly discerning\ngreat man."},{"k":"suddhaso","t":"When one is free of craving, not acquisitive,\nand is a master of words and phrases\nwho knows the proper grouping\nand sequencing of sentences,\nthen they are called a bearer of their last body,\na great person of great wisdom."},{"k":"sujato","t":"Rid of craving, free of grasping,\nexpert in the definition of terms,\nknowing the correct\nstructure and sequence of syllables,\nthey are said to be one who bears their final body,\none of great wisdom, a great person."}]},{"n":353,"vg":24,"pali":"Sabbābhibhū sabbavidūhamasmi,\nSabbesu dhammesu anūpalitto;\nSabbañjaho taṇhakkhaye vimutto,\nSayaṁ abhiññāya kamuddiseyyaṁ.","v":[{"k":"muller","t":"`I have conquered all, I know all, in all conditions of life I am free from taint; I have left all, and through the destruction of thirst I am free; having learnt myself, whom shall I teach?'"},{"k":"wagiswara","t":"Conqueror of all am I!\nKnowing all, from all conditions\nOf existence I am free;\nBy the slaying of desire\nI have ended craving's fire.\nWho could then my teacher be?\nI have now forsaken all,\nI myself, by mine own knowledge.\nWhom should I my teacher call?"},{"k":"kaviratna","t":"I am the conqueror of all, I am the knower of all, in all the states of life. I am unattached, I have relinquished all, and with the destruction of craving I am liberated. Having comprehended everything by myself, whom shall I call my teacher?\""},{"k":"buddharakkhita","t":"A victor am I over all, all have I known. Yet unattached am I to all that is conquered and known. Abandoning all, I am freed through the destruction of craving. Having thus directly comprehended all by myself, whom shall I call my teacher? [23]"},{"k":"thanissaro","t":"All-conquering,\nall-knowing am I,\nwith regard to all things,\nunadhering.\nAll-abandoning,\nreleased in the ending of craving:\nhaving fully known on my own,\nto whom should I point as my teacher?"},{"k":"suddhaso","t":"I have overcome all, I know all;\namidst all things I am unsullied;\nI have relinquished everything and I am liberated through the elimination of craving -\nknowing this directly and personally, who could I indicate as my teacher?"},{"k":"sujato","t":"I am the vanquisher of all, the knower of all,\nunsullied in the midst of all things.\nI've given up all, freed in the ending of craving.\nSince I know for myself, whose follower should I be?"}]},{"n":354,"vg":24,"pali":"Sabbadānaṁ dhammadānaṁ jināti,\nSabbarasaṁ dhammaraso jināti;\nSabbaratiṁ dhammarati jināti,\nTaṇhakkhayo sabbadukkhaṁ jināti.","v":[{"k":"muller","t":"The gift of the law exceeds all gifts; the sweetness of the law exceeds all sweetness; the delight in the law exceeds all delights; the extinction of thirst overcomes all pain."},{"k":"wagiswara","t":"To give The Norm all gifts transcends;\nTo taste The Norm is sweetest far;\nNo joy can with its joy compare;\nWho raving slays all sorrow ends."},{"k":"kaviratna","t":"The gift of Truth (dhamma) excels all other gifts; the flavor of Truth excels all other flavors; the delight in Truth surpasses all delights. The destruction of craving overcomes all suffering."},{"k":"buddharakkhita","t":"The gift of Dhamma excels all gifts; the taste of the Dhamma excels all tastes; the delight in Dhamma excels all delights. The Craving-Freed vanquishes all suffering."},{"k":"thanissaro","t":"A gift of Dhamma conquers all gifts;\nthe taste of Dhamma, all tastes;\na delight in Dhamma, all delights;\nthe ending of craving, all suffering\n& stress."},{"k":"suddhaso","t":"The gift of Dhamma trumps all gifts,\nthe taste of Dhamma trumps all tastes,\nthe appreciation of Dhamma trumps all appreciation,\nthe elimination of craving trumps all suffering."},{"k":"sujato","t":"The gift of the teaching surmounts all other gifts;\nthe taste of the teaching surmounts all other tastes;\nthe joy of the teaching surmounts all other joys;\nthe ending of craving surmounts all suffering."}]},{"n":355,"vg":24,"pali":"Hananti bhogā dummedhaṁ,\nno ca pāragavesino;\nBhogataṇhāya dummedho,\nhanti aññeva attanaṁ.","v":[{"k":"muller","t":"Pleasures destroy the foolish, if they look not for the other shore; the foolish by his thirst for pleasures destroys himself, as if he were his own enemy."},{"k":"wagiswara","t":"Wealth harms the fool; not him who runs\nTo win the goal intent;\nBy lust of wealth the fool harms self\nWith harm for others meant."},{"k":"kaviratna","t":"Riches destroy the ignorant, yet not those who seek the further shore. Through his craving for material wealth, he destroys himself as if (destroying) others."},{"k":"buddharakkhita","t":"Riches ruin only the foolish, not those in quest of the Beyond. By craving for riches the witless man ruins himself as well as others."},{"k":"thanissaro","t":"Riches ruin the man\nweak in discernment,\nbut not those who seek\nthe beyond.\nThrough craving for riches\nthe man weak in discernment\nruins himself\nas he would others."},{"k":"suddhaso","t":"Wealth destroys a fool\nwho does not seek transcendence;\na fool who craves wealth\nharms both self and others."},{"k":"sujato","t":"Riches ruin a simpleton,\nbut not a seeker of the far shore.\nFrom craving for wealth, a simpleton\nruins themselves and others."}]},{"n":356,"vg":24,"pali":"Tiṇadosāni khettāni,\nrāgadosā ayaṁ pajā;\nTasmā hi vītarāgesu,\ndinnaṁ hoti mahapphalaṁ.","v":[{"k":"muller","t":"The fields are damaged by weeds, mankind is damaged by passion: therefore a gift bestowed on the passionless brings great reward."},{"k":"wagiswara","t":"Weeds are the ruin of the fields;\nThis world by lust is spoiled;\nThen great the fruit of gifts to those\nBy lust who are not soiled."},{"k":"kaviratna","t":"Fields have the blight of weeds; mankind has the blight of passion; therefore, offerings given to those devoid of passion bring forth abundant fruit."},{"k":"buddharakkhita","t":"Weeds are the bane of fields, lust is the bane of mankind. Therefore, what is offered to those free of lust yields abundant fruit."},{"k":"thanissaro","t":"Fields are spoiled by weeds;\npeople, by passion.\nSo what's given to those\nfree of passion\nbears great fruit."},{"k":"suddhaso","t":"Grass is the defect of fields,\npassion is the defect of this generation;\ntherefore a gift given to those free of passion\nis of great benefit."},{"k":"sujato","t":"Weeds are the bane of crops,\nbut greed is these folk's bane.\nThat's why a gift to one rid of greed\nis so very fruitful."}]},{"n":357,"vg":24,"pali":"Tiṇadosāni khettāni,\ndosadosā ayaṁ pajā;\nTasmā hi vītadosesu,\ndinnaṁ hoti mahapphalaṁ.","v":[{"k":"muller","t":"The fields are damaged by weeds, mankind is damaged by hatred: therefore a gift bestowed on those who do not hate brings great reward."},{"k":"wagiswara","t":"Weeds are the ruin of the fields;\nThis world is spoiled by hate;\nTo those by hatred undefiled\nThe fruit of gifts is great."},{"k":"kaviratna","t":"Fields have the blight of weeds; mankind has the blight of hatred; therefore, offerings given to those devoid of hatred bring forth abundant fruit."},{"k":"buddharakkhita","t":"Weeds are the bane of fields, hatred is the bane of mankind. Therefore, what is offered to those free of hatred yields abundant fruit."},{"k":"thanissaro","t":"Fields are spoiled by weeds;\npeople, by aversion.\nSo what's given to those\nfree of aversion\nbears great fruit."},{"k":"suddhaso","t":"Grass is the defect of fields,\nhatred is the defect of this generation;\ntherefore a gift given to those free of hate\nis of great benefit."},{"k":"sujato","t":"Weeds are the bane of crops,\nbut hate is these folk's bane.\nThat's why a gift to one rid of hate\nis so very fruitful."}]},{"n":358,"vg":24,"pali":"Tiṇadosāni khettāni,\nmohadosā ayaṁ pajā;\nTasmā hi vītamohesu,\ndinnaṁ hoti mahapphalaṁ.","v":[{"k":"muller","t":"The fields are damaged by weeds, mankind is damaged by vanity: therefore a gift bestowed on those who are free from vanity brings great reward."},{"k":"wagiswara","t":"Weeds are the ruin of the fields;\nDeluded are mankind;\nThen great the fruit of gifts to those\nWhom folly doth not blind."},{"k":"kaviratna","t":"Fields have the blight of weeds; mankind has the blight of delusion; therefore, offerings given to those devoid of delusion bring forth abundant fruit."},{"k":"buddharakkhita","t":"Weeds are the bane of fields, delusion is the bane of mankind. Therefore, what is offered to those free of delusion yields abundant fruit."},{"k":"thanissaro","t":"Fields are spoiled by weeds;\npeople, by delusion.\nSo what's given to those\nfree of delusion\nbears great fruit."},{"k":"suddhaso","t":"Grass is the defect of fields,\ndelusion is the defect of this generation;\ntherefore a gift given to those free of delusion\nis of great benefit."},{"k":"sujato","t":"Weeds are the bane of crops,\nbut delusion is these folk's bane.\nThat's why a gift to one rid of delusion\nis so very fruitful."}]},{"n":359,"vg":24,"pali":"Tiṇadosāni khettāni,\nicchādosā ayaṁ pajā;\nTasmā hi vigaticchesu,\ndinnaṁ hoti mahapphalaṁ.\nTaṇhāvaggo catuvīsatimo.","v":[{"k":"muller","t":"The fields are damaged by weeds, mankind is damaged by lust: therefore a gift bestowed on those who are free from lust brings great reward."},{"k":"wagiswara","t":"Weeds are the ruin of the fields;\nCraving pollutes the world;\nThen great the fruit of gifts to those\nBy craving not enthralled."},{"k":"kaviratna","t":"Fields have the blight of weeds; mankind has the blight of desire; therefore, offerings given to those devoid of desire bring forth abundant fruit."},{"k":"buddharakkhita","t":"Weeds are the bane of fields, desire is the bane of mankind. Therefore, what is offered to those free of desire yields abundant fruit."},{"k":"thanissaro","t":"Fields are spoiled by weeds;\npeople, by longing.\nSo what's given to those\nfree of longing\nbears great fruit."},{"k":"suddhaso","t":"Grass is the defect of fields,\ncraving is the defect of this generation;\ntherefore a gift given to those free of craving\nis of great benefit."},{"k":"sujato","t":"Weeds are the bane of crops,\nbut desire is these folk's bane.\nThat's why a gift to one rid of desire\nis so very fruitful."}]},{"n":360,"vg":25,"pali":"Cakkhunā saṁvaro sādhu,\nsādhu sotena saṁvaro;\nGhānena saṁvaro sādhu,\nsādhu jivhāya saṁvaro.","v":[{"k":"muller","t":"Restraint in the eye is good, good is restraint in the ear, in the nose restraint is good, good is restraint in the tongue."},{"k":"wagiswara","t":"Good is restraint of eye and ear, of nose and tongue,\nOf body, speech and mind; restraint is good\nIn every way; the mendicant restrained\nAll sorrow casts away."},{"k":"kaviratna","t":"Restraint through the eye is good; good is restraint through the ear; restraint through the nose is good and good is restraint through the tongue."},{"k":"buddharakkhita","t":"Good is restraint over the eye; good is restraint over the ear; good is restraint over the nose; good is restraint over the tongue."},{"k":"thanissaro","t":"Restraint with the eye is good,\ngood is restraint with the ear.\nRestraint with the nose is good,\ngood is restraint with the tongue.\nRestraint with the body is good,\ngood is restraint with speech.\nRestraint with the heart is good,\ngood is restraint everywhere.\nA monk everywhere restrained\nis released from all suffering & stress."},{"k":"suddhaso","t":"Excellent is restraint of the eye,\nexcellent is restraint of the ear,\nexcellent is restraint of the nose,\nexcellent is restraint of the tongue,"},{"k":"sujato","t":"Restraint of the eye is good;\ngood is restraint of the ear;\nrestraint of the nose is good;\ngood is restraint of the tongue."}]},{"n":361,"vg":25,"pali":"Kāyena saṁvaro sādhu,\nsādhu vācāya saṁvaro;\nManasā saṁvaro sādhu,\nsādhu sabbattha saṁvaro;\nSabbattha saṁvuto bhikkhu,\nsabbadukkhā pamuccati.","v":[{"k":"muller","t":"In the body restraint is good, good is restraint in speech, in thought restraint is good, good is restraint in all things. A Bhikshu, restrained in all things, is freed from all pain."},{"k":"wagiswara","t":"Good is restraint of eye and ear, of nose and tongue,\nOf body, speech and mind; restraint is good\nIn every way; the mendicant restrained\nAll sorrow casts away."},{"k":"kaviratna","t":"Restraint in body is good and good is restraint in speech; restraint by the mind is good and good is restraint in all things. The mendicant who is restrained in every respect is liberated from all suffering."},{"k":"buddharakkhita","t":"Good is restraint in the body; good is restraint in speech; good is restraint in thought. Restraint everywhere is good. The monk restrained in every way is freed from all suffering."},{"k":"thanissaro","t":"Restraint with the eye is good,\ngood is restraint with the ear.\nRestraint with the nose is good,\ngood is restraint with the tongue.\nRestraint with the body is good,\ngood is restraint with speech.\nRestraint with the heart is good,\ngood is restraint everywhere.\nA monk everywhere restrained\nis released from all suffering & stress."},{"k":"suddhaso","t":"excellent is restraint of the body,\nexcellent is restraint of speech,\nexcellent is restraint of the mind,\nexcellent is restraint in every situation.\nA monk who is restrained in every situation\nis freed from all suffering."},{"k":"sujato","t":"Restraint of the body is good;\ngood is restraint of speech;\nrestraint of mind is good;\neverywhere, restraint is good.\nThe mendicant restrained everywhere\nis released from all suffering."}]},{"n":362,"vg":25,"pali":"Hatthasaṁyato pādasaṁyato,\nVācāsaṁyato saṁyatuttamo;\nAjjhattarato samāhito,\nEko santusito tamāhu bhikkhuṁ.","v":[{"k":"muller","t":"He who controls his hand, he who controls his feet, he who controls his speech, he who is well controlled, he who delights inwardly, who is collected, who is solitary and content, him they call Bhikshu."},{"k":"wagiswara","t":"In hand and foot and speech whoso is self restrained;\nWhoso to ponder inwardly delights,\nWho liveth lonely and is well-content,\nHim men call mendicant."},{"k":"kaviratna","t":"He who is controlled in hand, foot, and in speech, who is well disciplined and practices the utmost restraint; he who delights inwardly, in concentration, who leads a solitary life and is content — him they call a bhikkhu (mendicant)."},{"k":"buddharakkhita","t":"He who has control over his hands, feet and tongue; who is fully controlled, delights in inward development, is absorbed in meditation, keeps to himself and is contented — him do people call a monk."},{"k":"thanissaro","t":"Hands restrained,\nfeet restrained\nspeech restrained,\nsupremely restrained —\ndelighting in what is inward,\ncontent, centered, alone:\nhe's what they call\na monk."},{"k":"suddhaso","t":"Hand restrained, foot restrained,\nspeech restrained, restrained to the utmost,\nappreciating introspection, concentrated,\none who is content like this is called a monk."},{"k":"sujato","t":"One restrained in hand and foot,\nand in speech, the supreme restraint;\nhappy inside, serene,\nsolitary, content, I call a mendicant."}]},{"n":363,"vg":25,"pali":"Yo mukhasaṁyato bhikkhu,\nmantabhāṇī anuddhato;\nAtthaṁ dhammañca dīpeti,\nmadhuraṁ tassa bhāsitaṁ.","v":[{"k":"muller","t":"The Bhikshu who controls his mouth, who speaks wisely and calmly, who teaches the meaning and the law, his word is sweet."},{"k":"wagiswara","t":"Whoso controls his lips, and words of wisdom speaks,\nIs not puffed up, who can elucidate\nThe meaning and the essence of The Norm--\nPleasant is he to hear."},{"k":"kaviratna","t":"The mendicant who restrains his tongue, who speaks with wisdom, who is not conceited, who illuminates the inner meaning (and letter) of the Law (dhamma), sweet indeed is his utterance."},{"k":"buddharakkhita","t":"That monk who has control over his tongue, is moderate in speech, unassuming and who explains the Teaching in both letter and spirit — whatever he says is pleasing."},{"k":"thanissaro","t":"A monk restrained in his speaking,\ngiving counsel unruffled,\ndeclaring the message & meaning:\nsweet is his speech."},{"k":"suddhaso","t":"A monk who has a restrained mouth,\nwho gives advice without arrogance,\nilluminates the meaning and the Dhamma,\nand their speech is like honey."},{"k":"sujato","t":"When a mendicant of restrained mouth,\nthoughtful in counsel, not restless,\nexplains the text and its meaning,\ntheir words are sweet."}]},{"n":364,"vg":25,"pali":"Dhammārāmo dhammarato,\ndhammaṁ anuvicintayaṁ;\nDhammaṁ anussaraṁ bhikkhu,\nsaddhammā na parihāyati.","v":[{"k":"muller","t":"He who dwells in the law, delights in the law, meditates on the law, follows the law, that Bhikshu will never fall away from the true law."},{"k":"wagiswara","t":"Who dwelleth in the Norm and in the Norm delights,\nWho searcheth out and well remembers it--\nFrom the True Norm that steadfast mendicant\nWill never fall away."},{"k":"kaviratna","t":"The mendicant who dwells in the Law, who glories in the Law, who meditates on the Law, who ever follows the Law, does not fall away from the true Dhamma."},{"k":"buddharakkhita","t":"The monk who abides in the Dhamma, delights in the Dhamma, meditates on the Dhamma, and bears the Dhamma well in mind — he does not fall away from the sublime Dhamma."},{"k":"thanissaro","t":"Dhamma his dwelling,\nDhamma his delight,\na monk pondering Dhamma,\ncalling Dhamma to mind,\ndoes not fall away\nfrom true Dhamma."},{"k":"suddhaso","t":"Appreciating the Dhamma, approving of the Dhamma,\ninvestigating the Dhamma,\nremembering the Dhamma,\na monk does not fall away from the true Dhamma."},{"k":"sujato","t":"Delighting in the teaching, enjoying the teaching,\ncontemplating the teaching,\na mendicant who recollects the teaching\ndoesn't fall away from the true teaching."}]},{"n":365,"vg":25,"pali":"Salābhaṁ nātimaññeyya,\nnāññesaṁ pihayaṁ care;\nAññesaṁ pihayaṁ bhikkhu,\nsamādhiṁ nādhigacchati.","v":[{"k":"muller","t":"Let him not despise what he has received, nor ever envy others: a mendicant who envies others does not obtain peace of mind."},{"k":"wagiswara","t":"Let him not think of little worth the alms he gains.\nNor jealous be of alms to others given;\nFor whoso envies other mendicants\nWins not tranquillity."},{"k":"kaviratna","t":"Let the mendicant not underestimate the gift he has received; let him not feel envy for others. The mendicant who envies others does not attain tranquillity of mind."},{"k":"buddharakkhita","t":"One should not despise what one has received, nor envy the gains of others. The monk who envies the gains of others does not attain to meditative absorption."},{"k":"thanissaro","t":"Gains:\ndon't treat your own with scorn,\ndon't go coveting those of others.\nA monk who covets those of others\nattains\nno concentration."},{"k":"suddhaso","t":"One should not disdain what one has,\nnor envy what belongs to others;\na monk who envies the belongings of others\ndoes not attain concentration."},{"k":"sujato","t":"A well-off mendicant ought not look down\non others, nor should they be envious.\nA mendicant who envies others\ndoes not achieve immersion."}]},{"n":366,"vg":25,"pali":"Appalābhopi ce bhikkhu,\nsalābhaṁ nātimaññati;\nTaṁ ve devā pasaṁsanti,\nsuddhājīviṁ atanditaṁ.","v":[{"k":"muller","t":"A Bhikshu who, though he receives little, does not despise what he has received, even the gods will praise him, if his life is pure, and if he is not slothful."},{"k":"wagiswara","t":"Though small the part of charity that falls to him,\nWhoso despiseth not the alms he gains,\nIf he live clean, not given to slothfulness,\nE'en by the gods is praised."},{"k":"kaviratna","t":"Even the gods praise that mendicant who does not underestimate what he has received, however little, if he is pure and energetic in his life."},{"k":"buddharakkhita","t":"A monk who does not despise what he has received, even though it be little, who is pure in livelihood and unremitting in effort — him even the gods praise."},{"k":"thanissaro","t":"Even if he gets next to nothing,\nhe doesn't treat his gains with scorn.\nLiving purely, untiring:\nhe's the one\nthat the devas praise."},{"k":"suddhaso","t":"Even if a monk has little,\nbut does not disdain what he has,\nthe angels praise him,\nthe one who lives with purity and diligence."},{"k":"sujato","t":"If a mendicant is poor in offerings,\nthe well-to-do ought not look down on them.\nFor the gods indeed praise them,\nwho are tireless and pure of livelihood."}]},{"n":367,"vg":25,"pali":"Sabbaso nāmarūpasmiṁ,\nyassa natthi mamāyitaṁ;\nAsatā ca na socati,\nsa ve \"bhikkhū\"ti vuccati.","v":[{"k":"muller","t":"He who never identifies himself with name and form, and does not grieve over what is no more, he indeed is called a Bhikshu."},{"k":"wagiswara","t":"Whoso hath neither part nor lot in Name and Form\n(Who saith not \"this is I\" or \"this is mine\")\nAnd grieveth not for what existeth not,\nA mendicant is called."},{"k":"kaviratna","t":"He who has not any attachment to name and form (mind and body), and does not grieve for what does not really exist — he, indeed, is called a real bhikkhu."},{"k":"buddharakkhita","t":"He who has no attachment whatsoever for the mind and body, who does not grieve for what he has not — he is truly called a monk."},{"k":"thanissaro","t":"For whom, in name & form\nin every way,\nthere's no sense of mine,\n& who doesn't grieve\nfor what's not:\nhe's deservedly called\na monk."},{"k":"suddhaso","t":"When there is nothing whatsoever in mind and body\nthat one thinks of as \"mine,\"\nand one does not sorrow on account of the unpleasant,\nthen one can be called a monk."},{"k":"sujato","t":"One who has no sense of ownership\nin the whole realm of name and form,\nwho does not grieve for that which is not,\nis said to be a mendicant."}]},{"n":368,"vg":25,"pali":"Mettāvihārī yo bhikkhu,\npasanno buddhasāsane;\nAdhigacche padaṁ santaṁ,\nsaṅkhārūpasamaṁ sukhaṁ.","v":[{"k":"muller","t":"The Bhikshu who acts with kindness, who is calm in the doctrine of Buddha, will reach the quiet place (Nirvana), cessation of natural desires, and happiness."},{"k":"wagiswara","t":"Whoso in friendly wise with all mankind abides,\nFirm in the teaching of the Awakened One;\nReaches the bliss where all conditions cease,\nReaches the State of Peace."},{"k":"kaviratna","t":"The mendicant who lives compassionately, who takes delight in the doctrine of the Enlightened One, will attain that exalted state of peace and happiness, which is the cessation of conditioned existence."},{"k":"buddharakkhita","t":"The monk who abides in universal love and is deeply devoted to the Teaching of the Buddha attains the peace of Nibbana, the bliss of the cessation of all conditioned things."},{"k":"thanissaro","t":"Dwelling in kindness, a monk\nwith faith in the Awakened One's teaching,\nwould attain the good state,\nthe peaceful state:\nstilling-of-fabrications ease."},{"k":"suddhaso","t":"A monk who maintains benevolence,\nand who has serene faith in the teaching of the Buddha,\narrives at the peaceful path\nand the happiness of complete tranquility."},{"k":"sujato","t":"A mendicant who meditates on love,\ndevoted to the Buddha's teaching,\nwould realize the peaceful state,\nthe blissful stilling of conditions."}]},{"n":369,"vg":25,"pali":"Siñca bhikkhu imaṁ nāvaṁ,\nsittā te lahumessati;\nChetvā rāgañca dosañca,\ntato nibbānamehisi.","v":[{"k":"muller","t":"O Bhikshu, empty this boat! if emptied, it will go quickly; having cut off passion and hatred thou wilt go to Nirvana."},{"k":"wagiswara","t":"O mendicants! bail out the water from this boat!\nSwift will it go when from this burden freed.\nOf passion and of hatred cut the root;\nThen shalt thou reach The Peace."},{"k":"kaviratna","t":"Empty this boat, O monk! When emptied, it will go lightly. Cutting off lust and hatred, you will reach nirvana."},{"k":"buddharakkhita","t":"Empty this boat, O monk! Emptied, it will sail lightly. Rid of lust and hatred, you shall reach Nibbana."},{"k":"thanissaro","t":"Monk, bail out this boat.\nIt will take you lightly when bailed.\nHaving cut through passion, aversion,\nyou go from there to Unbinding."},{"k":"suddhaso","t":"Bale out this boat, monk;\nwhen emptied, it moves easily.\nHaving cut off passion and hatred,\ngo from here to Nibbāna."},{"k":"sujato","t":"Bail out this boat, mendicant!\nWhen bailed out it will float lightly.\nHaving cut off desire and hate,\nyou shall reach extinguishment."}]},{"n":370,"vg":25,"pali":"Pañca chinde pañca jahe,\npañca cuttari bhāvaye;\nPañca saṅgātigo bhikkhu,\n\"oghatiṇṇo\"ti vuccati.","v":[{"k":"muller","t":"Cut off the five (senses), leave the five, rise above the five. A Bhikshu, who has escaped from the five fetters, he is called Oghatinna, `saved from the flood.'"},{"k":"wagiswara","t":"Cut off the five; desert the five; the five subdue!\nThat mendicant, who from the fetters five\nHath freed himself at last, by men is called\n\"A crosser of the Stream\"."},{"k":"kaviratna","t":"(Of the fetters) cut off the five, renounce the five, and (of the virtues) cultivate the five. He who has gone beyond the five attachments is called a bhikkhu who has crossed the stream."},{"k":"buddharakkhita","t":"Cut off the five, abandon the five, and cultivate the five. The monk who has overcome the five bonds is called one who has crossed the flood. [24]"},{"k":"thanissaro","t":"Cut through five,\nlet go of five,\n& develop five above all.\nA monk gone past five attachments\nis said to have crossed the flood."},{"k":"suddhaso","t":"When five are cut off and five are discarded,\nand another five are developed,\nthen a monk who has gone beyond five attachments\nis said to have crossed the flood."},{"k":"sujato","t":"Five to cut, five to drop,\nand five more to develop.\nWhen a mendicant slips five chains\nthey're said to have crossed the flood."}]},{"n":371,"vg":25,"pali":"Jhāya bhikkhu mā pamādo,\nMā te kāmaguṇe ramessu cittaṁ;\nMā lohaguḷaṁ gilī pamatto,\nMā kandi \"dukkhamidan\"ti dayhamāno.","v":[{"k":"muller","t":"Meditate, O Bhikshu, and be not heedless! Do not direct thy thought to what gives pleasure that thou mayest not for thy heedlessness have to swallow the iron ball (in hell), and that thou mayest not cry out when burning, `This is pain.'"},{"k":"wagiswara","t":"O mendicant! be meditative; let not sloth,\nLet not thy passions toss thee to and fro;\nLest, swallowing the ball, thou burning cry,\n\"Ah! this is suffering!\""},{"k":"kaviratna","t":"Meditate, O monk! Be not heedless! Let not your mind wander among the pleasures of the senses, lest through your heedlessness you swallow the red-hot iron ball (in hell) and cry out, as you thus burn — \"This is suffering.\""},{"k":"buddharakkhita","t":"Meditate, O monk! Do not be heedless. Let not your mind whirl on sensual pleasures. Heedless, do not swallow a red-hot iron ball, lest you cry when burning, \"O this is painful!\""},{"k":"thanissaro","t":"Practice jhana, monk,\nand don't be heedless.\nDon't take your mind roaming\nin sensual strands.\nDon't swallow — heedless —\nthe ball of iron aflame.\nDon't burn & complain: 'This is pain.'"},{"k":"suddhaso","t":"Meditate, monk, do not be negligent;\ndo not let your mind swirl in sensuality.\nDo not negligently swallow a metal ball,\ncomplaining about suffering as you burn."},{"k":"sujato","t":"Practice absorption, don't be negligent!\nDon't let the mind delight in the senses!\nDon't heedlessly swallow a hot iron ball!\nAnd when it burns, don't cry, \"Oh, the pain!\""}]},{"n":372,"vg":25,"pali":"Natthi jhānaṁ apaññassa,\npaññā natthi ajhāyato;\nYamhi jhānañca paññā ca,\nsa ve nibbānasantike.","v":[{"k":"muller","t":"Without knowledge there is no meditation, without meditation there is no knowledge: he who has knowledge and meditation is near unto Nirvana."},{"k":"wagiswara","t":"Who hath no wisdom cannot ecstasy attain;\nWho knows not ecstasy, no wisdom gains;\nWhoso both ecstasy and wisdom hath,\nUnto The Peace is nigh."},{"k":"kaviratna","t":"There is no perfect contemplation for him who is not wise, and no wisdom for him who does not concentrate. He in whom there is both perfect contemplation and wisdom is, indeed, close to nirvana."},{"k":"buddharakkhita","t":"There is no meditative concentration for him who lacks insight, and no insight for him who lacks meditative concentration. He in whom are found both meditative concentration and insight, indeed, is close to Nibbana."},{"k":"thanissaro","t":"There's no jhana\nfor one with no discernment,\nno\ndiscernment\nfor one with no jhana.\nBut one with both jhana\n&\ndiscernment:\nhe's on the verge\nof Unbinding."},{"k":"suddhaso","t":"There is no Jhāna for one who has no wisdom;\nthere is no wisdom for one who does not reach Jhāna.\nOne who has both Jhāna and wisdom\nis close to Nibbāna."},{"k":"sujato","t":"No absorption for one without wisdom,\nno wisdom for one without absorption.\nBut one with absorption and wisdom—\nthey have truly drawn near to extinguishment."}]},{"n":373,"vg":25,"pali":"Suññāgāraṁ paviṭṭhassa,\nsantacittassa bhikkhuno;\nAmānusī rati hoti,\nsammā dhammaṁ vipassato.","v":[{"k":"muller","t":"A Bhikshu who has entered his empty house, and whose mind is tranquil, feels a more than human delight when he sees the law clearly."},{"k":"wagiswara","t":"The mendicant, whose mind hath gained tranquillity,\nWhen he hath entered on his empty cell,\nHath joy beyond man's power to tell, for he\nThe Truth discerneth well."},{"k":"kaviratna","t":"The mendicant who has withdrawn to a lonely spot, whose heart and mind are tranquil, who clearly perceives the Dhamma, his bliss (of contemplation) is more than human."},{"k":"buddharakkhita","t":"The monk who has retired to a solitary abode and calmed his mind, who comprehends the Dhamma with insight, in him there arises a delight that transcends all human delights."},{"k":"thanissaro","t":"A monk with his mind at peace,\ngoing into an empty dwelling,\nclearly seeing the Dhamma aright:\nhis delight is more\nthan human."},{"k":"suddhaso","t":"In an empty hut,\na monk with a peaceful mind\nappreciates the absence of humans\nand sees the Dhamma clearly and correctly."},{"k":"sujato","t":"A mendicant who enters an empty hut\nwith mind at peace\nfinds a superhuman delight\nas they rightly discern the Dhamma."}]},{"n":374,"vg":25,"pali":"Yato yato sammasati,\nkhandhānaṁ udayabbayaṁ;\nLabhatī pītipāmojjaṁ,\namataṁ taṁ vijānataṁ.","v":[{"k":"muller","t":"As soon as he has considered the origin and destruction of the elements (khandha) of the body, he finds happiness and joy which belong to those who know the immortal (Nirvana)."},{"k":"wagiswara","t":"Soon as he grasps the rise and fall of elements,\nSuch pleasure and delight thereby he wins\nAs falls to them that rightly know the state\nOf immortality."},{"k":"kaviratna","t":"Whenever one clearly comprehends the origin and destruction of the five aggregates (khandha), he experiences bliss and happiness. (1) This is as the nectar (of immortality) to those who truly comprehend it."},{"k":"buddharakkhita","t":"Whenever he sees with insight the rise and fall of the aggregates, he is full of joy and happiness. To the discerning one this reflects the Deathless. [25]"},{"k":"thanissaro","t":"However it is,\nhowever it is he touches\nthe arising-&-passing of aggregates:\nhe gains rapture & joy:\nthat, for those who know it,\nis deathless,\nthe Deathless."},{"k":"suddhaso","t":"When one directly experiences\nthe appearance and disappearance of the components of being,\none acquires euphoria and joy,\naware of the deathless."},{"k":"sujato","t":"Whenever they are mindful\nof the rise and fall of the aggregates,\nthey feel rapture and joy:\nthat is freedom from death for one who knows."}]},{"n":375,"vg":25,"pali":"Tatrāyamādi bhavati,\nidha paññassa bhikkhuno;\nIndriyagutti santuṭṭhi,\npātimokkhe ca saṁvaro.","v":[{"k":"muller","t":"And this is the beginning here for a wise Bhikshu: watchfulness over the senses, contentedness, restraint under the law; keep noble friends whose life is pure, and who are not slothful."},{"k":"wagiswara","t":"Let the wise mendicant in this world thus begin;\nGuard thou thy senses; next, with mind content,\nBy discipline restrained, seek noble friends\nWho zealous live and pure;"},{"k":"kaviratna","t":"In this world this becomes the first requisite for a wise monk: control of the senses, contentment, restraint according to the fundamental code of monastic law; cultivation of noble friends whose lives are pure and who are not indolent."},{"k":"buddharakkhita","t":"Control of the senses, contentment, restraint according to the code of monastic discipline — these form the basis of holy life here for the wise monk."},{"k":"thanissaro","t":"Here the first things\nfor a discerning monk\nare guarding the senses,\ncontentment,\nrestraint in line with the Patimokkha.\nHe should associate with admirable friends.\nLiving purely, untiring,\nhospitable by habit,\nskilled in his conduct,\ngaining a manifold joy,\nhe will put an end\nto suffering & stress."},{"k":"suddhaso","t":"This is the starting point\nfor a monk:\nguarding the sense-faculties, contentment,\nand restraint according to the code of conduct."},{"k":"sujato","t":"This is the very start of the path\nfor a wise mendicant here:\nguarding the senses, contentment,\nand restraint in the monastic code."}]},{"n":376,"vg":25,"pali":"Mitte bhajassu kalyāṇe,\nsuddhājīve atandite;\nPaṭisanthāravutyassa,\nācārakusalo siyā;\nTato pāmojjabahulo,\ndukkhassantaṁ karissati.","v":[{"k":"muller","t":"Let him live in charity, let him be perfect in his duties; then in the fulness of delight he will make an end of suffering."},{"k":"wagiswara","t":"And by the laws of friendship act, live perfectly,\nAnd upright walk according to the Norm;\nThen in the fullness of thy joy thou shalt\nAn end of suffering make."},{"k":"kaviratna","t":"The mendicant who is hospitable and friendly, who really lives his ethics and is full of spiritual joy, thereby makes an end of his suffering."},{"k":"buddharakkhita","t":"Let him associate with friends who are noble, energetic, and pure in life, let him be cordial and refined in conduct. Thus, full of joy, he will make an end of suffering."},{"k":"thanissaro","t":"Here the first things\nfor a discerning monk\nare guarding the senses,\ncontentment,\nrestraint in line with the Patimokkha.\nHe should associate with admirable friends.\nLiving purely, untiring,\nhospitable by habit,\nskilled in his conduct,\ngaining a manifold joy,\nhe will put an end\nto suffering & stress."},{"k":"suddhaso","t":"If one associates with good spiritual friends\nwho live a pure and diligent life,\nif one is polite in speech\nand wholesome in conduct,\nthen one will have abundant joy\nand will put an end to suffering."},{"k":"sujato","t":"Mix with spiritual friends,\nwho are tireless and pure of livelihood.\nShare what you have with others,\nbeing skillful in your conduct.\nAnd when you're full of joy,\nyou'll make an end to suffering."}]},{"n":377,"vg":25,"pali":"Vassikā viya pupphāni,\nmaddavāni pamuñcati;\nEvaṁ rāgañca dosañca,\nvippamuñcetha bhikkhavo.","v":[{"k":"muller","t":"As the Vassika plant sheds its withered flowers, men should shed passion and hatred, O ye Bhikshus!"},{"k":"wagiswara","t":"O mendicants! just as the snow-white _vassikâ_,\nThe jasmine, putting forth fresh blooms to-day,\nSheds down the withered blooms of yesterday,\nSo shed ye lust and hate."},{"k":"kaviratna","t":"Just as the jasmine sheds its withered flowers, even so, O mendicants, you should cast off passion and hatred."},{"k":"buddharakkhita","t":"Just as the jasmine creeper sheds its withered flowers, even so, O monks, should you totally shed lust and hatred!"},{"k":"thanissaro","t":"Shed passion\n& aversion, monks —\nas a jasmine would,\nits withered flowers."},{"k":"suddhaso","t":"Just as a jasmine plant\nreleases its wilted flowers,\nin the same way, monks,\nlet go of your passion and aversion."},{"k":"sujato","t":"As a jasmine sheds\nits withered flowers,\nO mendicants,\nshed greed and hate."}]},{"n":378,"vg":25,"pali":"Santakāyo santavāco,\nsantavā susamāhito;\nVantalokāmiso bhikkhu,\n\"upasanto\"ti vuccati.","v":[{"k":"muller","t":"The Bhikshu whose body and tongue and mind are quieted, who is collected, and has rejected the baits of the world, he is called quiet."},{"k":"wagiswara","t":"Tranquil in body, speech and mind, O mendicants,\nWhoso in every way is well-restrained,\nWho all this world's desires hath thrown aside\nHe is \"the tranquil\" called."},{"k":"kaviratna","t":"That mendicant is called truly tranquil, who is calm in body, calm in speech, calm in mind, who is well-regulated in thoughts and has renounced all worldly allurements."},{"k":"buddharakkhita","t":"The monk who is calm in body, calm in speech, calm in thought, well-composed and who has spewn out worldliness — he, truly, is called serene."},{"k":"thanissaro","t":"Calmed in body,\ncalmed in speech,\nwell-centered & calm,\nhaving disgorged the baits of the world,\na monk is called\nthoroughly\ncalmed."},{"k":"suddhaso","t":"Peaceful in body, peaceful in speech,\npeaceful in mind, and well-concentrated,\na monk who has expelled the world's bait\nis said to be at peace."},{"k":"sujato","t":"Calm in body, calm in speech,\npeaceful and serene;\na mendicant who's spat out the world's bait\nis said to be one at peace."}]},{"n":379,"vg":25,"pali":"Attanā codayattānaṁ,\npaṭimaṁsetha attanā;\nSo attagutto satimā,\nsukhaṁ bhikkhu vihāhisi.","v":[{"k":"muller","t":"Rouse thyself by thyself, examine thyself by thyself, thus self-protected and attentive wilt thou live happily, O Bhikshu!"},{"k":"wagiswara","t":"Rouse thou the self by self, by self examine self;\nThus guarded by the self, and with thy mind\nIntent and watchful, thus, O mendicant,\nThou shall live happily."},{"k":"kaviratna","t":"Rouse the self by the Self, restrain the self by the Self, self-guarded and mindful, O monk, you shall live happily."},{"k":"buddharakkhita","t":"By oneself one must censure oneself and scrutinize oneself. The self-guarded and mindful monk will always live in happiness."},{"k":"thanissaro","t":"You yourself should reprove yourself,\nshould examine\nyourself.\nAs a self-guarded monk\nwith guarded self,\nmindful, you dwell at ease."},{"k":"suddhaso","t":"Admonish yourself,\ninvestigate yourself;\na monk who is self-protected and mindful\nlives happily."},{"k":"sujato","t":"Urge yourself on,\nreflect on yourself.\nA mendicant self-controlled and mindful\nwill always dwell in happiness."}]},{"n":380,"vg":25,"pali":"Attā hi attano nātho,\nko hi nātho paro siyā;\nAttā hi attano gati,\ntasmā saṁyamamattānaṁ;\nAssaṁ bhadraṁva vāṇijo.","v":[{"k":"muller","t":"For self is the lord of self, self is the refuge of self; therefore curb thyself as the merchant curbs a good horse."},{"k":"wagiswara","t":"Yea! Self is guard of self and refuge takes in self;\nJust as a dealer trains a thoroughbred,\nA noble steed, and breaks him to the rein,\nSo do thou self restrain."},{"k":"kaviratna","t":"For Self is indeed the protector of oneself; Self is indeed one's destiny. Therefore, curb yourself even as a wise merchant curbs a noble steed."},{"k":"buddharakkhita","t":"One is one's own protector, one is one's own refuge. Therefore, one should control oneself, even as a trader controls a noble steed."},{"k":"thanissaro","t":"Your own self is\nyour own mainstay.\nYour own self is\nyour own guide.\nTherefore you should\nwatch over yourself —\nas a trader, a fine steed."},{"k":"suddhaso","t":"You are your own protector,\nfor who could protect another?\nYou are your own destiny;\ntherefore, restrain yourself,\nas a merchant restrains an excellent horse."},{"k":"sujato","t":"Self is indeed the lord of self,\nfor who else would be one's lord?\nSelf is indeed the home of self,\nso restrain yourself,\nas a merchant his thoroughbred steed."}]},{"n":381,"vg":25,"pali":"Pāmojjabahulo bhikkhu,\npasanno buddhasāsane;\nAdhigacche padaṁ santaṁ,\nsaṅkhārūpasamaṁ sukhaṁ.","v":[{"k":"muller","t":"The Bhikshu, full of delight, who is calm in the doctrine of Buddha will reach the quiet place (Nirvana), cessation of natural desires, and happiness."},{"k":"wagiswara","t":"That mendicant, with utter joy and gladness filled,\nFirm in the teaching of the Awakened One,\nReaches the bliss where all conditions cease,\nReaches the State of Peace."},{"k":"kaviratna","t":"The mendicant who is full of spiritual delight and faith in the doctrine of the Enlightened One will attain the peaceful state (nirvana), the cessation of conditioned existence."},{"k":"buddharakkhita","t":"Full of joy, full of faith in the Teaching of the Buddha, the monk attains the Peaceful State, the bliss of cessation of conditioned things."},{"k":"thanissaro","t":"A monk with a manifold joy,\nwith faith in the Awakened One's teaching,\nwould attain the good state,\nthe peaceful state:\nstilling-of-fabrications ease."},{"k":"suddhaso","t":"A monk with abundant joy\nand serene faith in the Buddha's instructions\narrives at the peaceful path\nand the happiness of complete tranquility."},{"k":"sujato","t":"A monk full of joy\ntrusting in the Buddha's teaching,\nwould realize the peaceful state,\nthe blissful stilling of conditions."}]},{"n":382,"vg":25,"pali":"Yo have daharo bhikkhu,\nyuñjati buddhasāsane;\nSomaṁ lokaṁ pabhāseti,\nabbhā muttova candimā.\nBhikkhuvaggo pañcavīsatimo.","v":[{"k":"muller","t":"He who, even as a young Bhikshu, applies himself to the doctrine of Buddha, brightens up this world, like the moon when free from clouds."},{"k":"wagiswara","t":"Lo ye! a mendicant, though young he be, that strives\nTo grasp the teaching of the Awakened One,\nLights up the world, as from a cloud released\nThe moon lights up the night."},{"k":"kaviratna","t":"The mendicant, though young in years, who applies himself to the teaching of the Awakened One (Gotama), illumines the world, even as the moon when freed from the cloud."},{"k":"buddharakkhita","t":"That monk who while young devotes himself to the Teaching of the Buddha illumines this world like the moon freed from clouds."},{"k":"thanissaro","t":"A young monk who strives\nin the Awakened One's teaching,\nbrightens the world\nlike the moon set free from a cloud."},{"k":"suddhaso","t":"A young monk\nwho makes a sincere effort in following the Buddha's instructions\nbrightens this world,\nlike the moon emerging from clouds."},{"k":"sujato","t":"A young mendicant\ndevoted to the Buddha's teaching,\nlights up the world,\nlike the moon freed from clouds."}]},{"n":383,"vg":26,"pali":"Chinda sotaṁ parakkamma,\nkāme panuda brāhmaṇa;\nSaṅkhārānaṁ khayaṁ ñatvā,\nakataññūsi brāhmaṇa.","v":[{"k":"muller","t":"Stop the stream valiantly, drive away the desires, O Brahmana! When you have understood the destruction of all that was made, you will understand that which was not made."},{"k":"wagiswara","t":"Cut off the stream, O Brāhmana, right manfully;\nRepel desires; when thou hast known the end\nOf things conditioned, thou shalt be\nA knower of the Uncreate."},{"k":"kaviratna","t":"Cut off the stream of craving. Strive hard and renounce the sense pleasures, O Brahman. When you comprehend the secret of the destruction of all composite things, O Brahman, you will know the Uncreated (nirvana)."},{"k":"buddharakkhita","t":"Exert yourself, O holy man! Cut off the stream (of craving), and discard sense desires. Knowing the destruction of all the conditioned things, become, O holy man, the knower of the Uncreated (Nibbana)! [26]"},{"k":"thanissaro","t":"Having striven, brahman,\ncut the stream.\nExpel sensual passions.\nKnowing the ending of fabrications,\nbrahman,\nyou know the Unmade."},{"k":"suddhaso","t":"Cut the stream,\ntry to dispel sensuality, brahmin.\nHaving known the elimination of all things,\nyou will know the Unmade, brahmin."},{"k":"sujato","t":"Cut the stream, striving!\nCast aside sensual pleasures, brahmin.\nKnowing the ending of conditions,\nknow the uncreated, brahmin."}]},{"n":384,"vg":26,"pali":"Yadā dvayesu dhammesu,\npāragū hoti brāhmaṇo;\nAthassa sabbe saṁyogā,\natthaṁ gacchanti jānato.","v":[{"k":"muller","t":"If the Brahmana has reached the other shore in both laws (in restraint and contemplation), all bonds vanish from him who has obtained knowledge."},{"k":"wagiswara","t":"When by the twofold law (restraint and ecstasy),\nBy virtue of the knowledge he hath gained,\nThe Brāhmana hath crossed the stream;\nThen every fetter falls away."},{"k":"kaviratna","t":"When the Brahman has reached the farther shore of the two states (of tranquillity and insight), then all the fetters of that knowing one disappear."},{"k":"buddharakkhita","t":"When a holy man has reached the summit of two paths (meditative concentration and insight), he knows the truth and all his fetters fall away."},{"k":"thanissaro","t":"When the brahman has gone\nto the beyond of two things,\nthen all his fetters\ngo to their end —\nhe who knows."},{"k":"suddhaso","t":"When a brahmin\ngoes beyond duality,\nthen all fetters come to an end\nfor the one who knows."},{"k":"sujato","t":"When a brahmin has gone beyond\ndualistic phenomena,\nthen they consciously\nmake an end of all fetters."}]},{"n":385,"vg":26,"pali":"Yassa pāraṁ apāraṁ vā,\npārāpāraṁ na vijjati;\nVītaddaraṁ visaṁyuttaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"He for whom there is neither this nor that shore, nor both, him, the fearless and unshackled, I call indeed a Brahmana."},{"k":"wagiswara","t":"Whoso the stream hath crossed and from this shore hath passed,\nFree from all cares, unfettered; one to whom\nThis shore and that alike are naught;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He for whom there exist neither the farther (the external six senses), nor the hither (the internal six senses), nor both of these, and who is devoid of fear and free from fetters him I call a Brahman."},{"k":"buddharakkhita","t":"He for whom there is neither this shore nor the other shore, nor yet both, he who is free of cares and is unfettered — him do I call a holy man. [27]"},{"k":"thanissaro","t":"One whose beyond or\nnot-beyond or\nbeyond-&-not-beyond\ncan't be found;\nunshackled, carefree:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One for whom the beyond, the not-beyond,\nand both beyond and not beyond cannot be found,\nwithout anxiety, unattached -\nthat is who I call a brahmin."},{"k":"sujato","t":"One for whom there is no crossing over\nor crossing back, or crossing over and back;\nstress-free, detached,\nthat's who I declare a brahmin."}]},{"n":386,"vg":26,"pali":"Jhāyiṁ virajamāsīnaṁ,\nkatakiccamanāsavaṁ;\nUttamatthamanuppattaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"He who is thoughtful, blameless, settled, dutiful, without passions, and who has attained the highest end, him I call indeed a Brahmana."},{"k":"wagiswara","t":"Whoso dwells meditiative, passionless,\nAnd free from all Taints, his course hath run,\nWhoso hath won the highest Goal--\nHim I deem a Brāmaṇa."},{"k":"kaviratna","t":"He who is contemplative, lives without passions, is steadfast and has performed his duties, who is free from sensuous influxes and has attained the highest goal — him I call a Brahman."},{"k":"buddharakkhita","t":"He who is meditative, stainless and settled, whose work is done and who is free from cankers, having reached the highest goal — him do I call a holy man."},{"k":"thanissaro","t":"Sitting silent, dustless,\nabsorbed in jhana,\nhis task done, effluents gone,\nultimate goal attained:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Sitting dispassionately in meditation,\nthe task complete, free of defilements,\nhaving reached the highest goal -\nthat is who I call a brahmin."},{"k":"sujato","t":"Absorbed, rid of hopes,\ntheir task completed, without defilements,\narrived at the highest goal:\nthat's who I declare a brahmin."}]},{"n":387,"vg":26,"pali":"Divā tapati ādicco,\nrattimābhāti candimā;\nSannaddho khattiyo tapati,\njhāyī tapati brāhmaṇo;\nAtha sabbamahorattiṁ,\nbuddho tapati tejasā.","v":[{"k":"muller","t":"The sun is bright by day, the moon shines by night, the warrior is bright in his armour, the Brahmana is bright in his meditation; but Buddha, the Awakened, is bright with splendour day and night."},{"k":"wagiswara","t":"\"One who is rid of evil\" is a Brāmaṇa;\n_Samaṇa_ is one who tranquil hath become;\n\"Gone forth from all impurity\";\nThe hermit is _pabbajjā_ called."},{"k":"kaviratna","t":"The sun shines by day, the moon by night; the warrior is resplendent in armor and the Brahman radiant in meditation. But Buddha, the Awakened One, illumines both day and night by the splendor of his wisdom."},{"k":"buddharakkhita","t":"The sun shines by day, the moon shines by night. The warrior shines in armor, the holy man shines in meditation. But the Buddha shines resplendent all day and all night."},{"k":"thanissaro","t":"By day shines the sun;\nby night, the moon;\nin armor, the warrior;\nin jhana, the brahman.\nBut all day & all night,\nevery day & every night,\nthe Awakened One shines\nin splendor."},{"k":"suddhaso","t":"The sun shines by day,\nthe moon illuminates the night,\na well-dressed aristocrat shines,\na meditating brahmin shines,\nand the one that shines both day and night\nis the Buddha, the Radiant One."},{"k":"sujato","t":"The sun blazes by day,\nthe moon radiates at night,\nthe aristocrat shines in armor,\nand the brahmin shines in absorption.\nBut all day and all night,\nthe Buddha blazes with glory."}]},{"n":388,"vg":26,"pali":"Bāhitapāpoti brāhmaṇo,\nSamacariyā samaṇoti vuccati;\nPabbājayamattano malaṁ,\nTasmā \"pabbajito\"ti vuccati.","v":[{"k":"muller","t":"Because a man is rid of evil, therefore he is called Brahmana; because he walks quietly, therefore he is called Samana; because he has sent away his own impurities, therefore he is called Pravragita (Pabbagita, a pilgrim)."},{"k":"wagiswara","t":"Let not a Brāhmaṇa assail a Brāhmaṇa;\nNor let him with the assailant angry be,\nWoe to the striker; greater woe\nTo him that, stricken, strikes again."},{"k":"kaviratna","t":"Because a man has discarded all evil, he is called a Brahman; because of his balanced conduct, he is called a monk (samana); because he has rid himself of all impurities, he is called a recluse (pabbajita)."},{"k":"buddharakkhita","t":"Because he has discarded evil, he is called a holy man. Because he is serene in conduct, he is called a recluse. And because he has renounced his impurities, he is called a renunciate."},{"k":"thanissaro","t":"He's called a brahman\nfor having banished his evil,\na contemplative\nfor living in consonance,\none gone forth\nfor having forsaken\nhis own impurities."},{"k":"suddhaso","t":"One who has expelled all evil is called a brahmin,\none who lives peacefully is called a contemplative,\none who has personally exiled all their contaminants\nis called a renunciant."},{"k":"sujato","t":"A brahmin's so-called\nsince they've banished evil,\nan ascetic's so-called\nsince they live a serene life.\nOne who has renounced all stains\nis said to be a \"renunciant\"."}]},{"n":389,"vg":26,"pali":"Na brāhmaṇassa pahareyya,\nnāssa muñcetha brāhmaṇo;\nDhī brāhmaṇassa hantāraṁ,\ntato dhī yassa muñcati.","v":[{"k":"muller","t":"No one should attack a Brahmana, but no Brahmana (if attacked) should let himself fly at his aggressor! Woe to him who strikes a Brahmana, more woe to him who flies at his aggressor!"},{"k":"kaviratna","t":"One should not strike a Brahman; neither should a Brahman give way to anger against him who strikes. Woe to him who slays a Brahman; but greater woe to the Brahman who vents his wrath (on the aggressor)."},{"k":"buddharakkhita","t":"One should not strike a holy man, nor should a holy man, when struck, give way to anger. Shame on him who strikes a holy man, and more shame on him who gives way to anger."},{"k":"thanissaro","t":"One should not strike a brahman,\nnor should the brahman\nlet loose with his anger.\nShame on a brahman's killer.\nMore shame on the brahman\nwhose anger's let loose."},{"k":"suddhaso","t":"A brahmin would not attack another person,\nnor would a brahmin abandon one.\nWoe comes to one who attacks a brahmin,\nwoe comes to one who abandons a brahmin."},{"k":"sujato","t":"One should never strike a brahmin,\nnor should a brahmin retaliate.\nWoe to the one who hurts a brahmin,\nand woe for the one who retaliates."}]},{"n":390,"vg":26,"pali":"Na brāhmaṇassetadakiñci seyyo,\nYadā nisedho manaso piyehi;\nYato yato hiṁsamano nivattati,\nTato tato sammatimeva dukkhaṁ.","v":[{"k":"muller","t":"It advantages a Brahmana not a little if he holds his mind back from the pleasures of life; when all wish to injure has vanished, pain will cease."},{"k":"wagiswara","t":"No little profit cometh to the Brāhmaṇa\nWho hath his mind from pleasant things restrained;\nSoon as the lust to harm is gone\nAll sorrowing is laid to rest."},{"k":"kaviratna","t":"It is no small advantage to a Brahman to restrain the mind from clinging to pleasurable things. In proportion to the degree that he abstains from wishing to injure others, to that degree will suffering cease."},{"k":"buddharakkhita","t":"Nothing is better for a holy man than when he holds his mind back from what is endearing. To the extent the intent to harm wears away, to that extent does suffering subside."},{"k":"thanissaro","t":"Nothing's better for the brahman\nthan when the mind is held back\nfrom what is endearing & not.\nHowever his harmful-heartedness\nwears away,\nthat's how stress\nsimply comes to rest."},{"k":"suddhaso","t":"There is nothing better than this for a brahmin:\nwhen the mind is kept away from its preferences.\nWhenever one turns away from causing harm,\nthen suffering is replaced by peace."},{"k":"sujato","t":"Nothing is better for a brahmin\nthan to hold their mind back from attachment.\nFrom wherever a cruel wish recoils,\nright there suffering subsides."}]},{"n":391,"vg":26,"pali":"Yassa kāyena vācāya,\nmanasā natthi dukkaṭaṁ;\nSaṁvutaṁ tīhi ṭhānehi,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who does not offend by body, word, or thought, and is controlled on these three points."},{"k":"wagiswara","t":"Whoso offendeth not in thought and word and deed,\nIn whom no evil from these three is seen;\nWhoso is in these three controlled;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has not committed unwholesome deeds through body, speech, or mind, and who is restrained in these three avenues — him I call a Brahman."},{"k":"buddharakkhita","t":"He who does no evil in deed, word and thought, who is restrained in these three ways — him do I call a holy man."},{"k":"thanissaro","t":"Whoever does no wrong\nin body,\nspeech,\nheart,\nis restrained in these three ways:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who does no misconduct\nwith body, speech, or mind,\none who is restrained in these three ways -\nthat is who I call a brahmin."},{"k":"sujato","t":"Who does nothing wrong\nby body, speech or mind,\nrestrained in these three respects,\nthat's who I declare a brahmin."}]},{"n":392,"vg":26,"pali":"Yamhā dhammaṁ vijāneyya,\nsammāsambuddhadesitaṁ;\nSakkaccaṁ taṁ namasseyya,\naggihuttaṁva brāhmaṇo.","v":[{"k":"muller","t":"After a man has once understood the law as taught by the Well-awakened (Buddha), let him worship it carefully, as the Brahmana worships the sacrificial fire."},{"k":"wagiswara","t":"If there be one from whom thou canst obtain the Norm\nWhich He, the All-Awakened One, declared,\nRevere him, as a Brāhmaṇa\nThe sacrificial fire reveres."},{"k":"kaviratna","t":"Even as the (orthodox) Brahman bows down to the sacrificial fire, so one should make obeisance to him who understands the Dhamma as proclaimed by the Fully Enlightened One."},{"k":"buddharakkhita","t":"Just as a brahman priest reveres his sacrificial fire, even so should one devoutly revere the person from whom one has learned the Dhamma taught by the Buddha."},{"k":"thanissaro","t":"The person from whom\nyou would learn the Dhamma\ntaught by the Rightly\nSelf-Awakened One:\nyou should honor him with respect —\nas a brahman, the flame for a sacrifice."},{"k":"suddhaso","t":"If someone has helped you understand the Dhamma\ntaught by the fully awakened one,\nthen you should respectfully venerate them,\nlike a brahmin at a fire-sacrifice."},{"k":"sujato","t":"You should graciously honor\nthe one from whom you learn the Dhamma\ntaught by the awakened Buddha,\nas a brahmin honors the sacred flame."}]},{"n":393,"vg":26,"pali":"Na jaṭāhi na gottena,\nna jaccā hoti brāhmaṇo;\nYamhi saccañca dhammo ca,\nso sucī so ca brāhmaṇo.","v":[{"k":"muller","t":"A man does not become a Brahmana by his platted hair, by his family, or by birth; in whom there is truth and righteousness, he is blessed, he is a Brahmana."},{"k":"wagiswara","t":"Not matted hair, nor caste, nor noble birth can make\nThe Brāhmaṇa; but he that knows the truth\nAnd knows the Norm, is blest indeed;\nAnd him I deem a Brāhmaṇa."},{"k":"kaviratna","t":"Not by matted hair, by lineage, nor by birth (caste) does one become a Brahman. But the one in whom there abide truth and righteousness, he is pure; he is a Brahman."},{"k":"buddharakkhita","t":"Not by matted hair, nor by lineage, nor by birth does one become a holy man. But he in whom truth and righteousness exist — he is pure, he is a holy man."},{"k":"thanissaro","t":"Not by matted hair,\nby clan, or by birth,\nis one a brahman.\nWhoever has truth\n& rectitude:\nhe is a pure one,\nhe, a brahman."},{"k":"suddhaso","t":"It is not because of tangled hair, lineage,\nor birth that one is a brahmin.\nOne in whom there is truth, Dhamma,\nand purity is a brahmin."},{"k":"sujato","t":"Not by matted hair or family,\nor birth is one a brahmin.\nThose who are  truthful and principled:\nthey are pure, they are brahmins."}]},{"n":394,"vg":26,"pali":"Kiṁ te jaṭāhi dummedha,\nkiṁ te ajinasāṭiyā;\nAbbhantaraṁ te gahanaṁ,\nbāhiraṁ parimajjasi.","v":[{"k":"muller","t":"What is the use of platted hair, O fool! what of the raiment of goat-skins? Within thee there is ravening, but the outside thou makest clean."},{"k":"wagiswara","t":"Of what avail to thee, O fool, is matted hair?\nAnd what avails thy garment made of skins?\nThe outer part thou makest clean,\nBut all is ravening within."},{"k":"kaviratna","t":"O fool, what is the use of matted hair, and to what avail is raiment made of antelope skin? (1) Outwardly you cleanse yourself, but within you is a jungle of passions."},{"k":"buddharakkhita","t":"What is the use of your matted hair, O witless man? What of your garment of antelope's hide? Within you is the tangle (of passion); only outwardly do you cleanse yourself. [28]"},{"k":"thanissaro","t":"What's the use of your matted hair,\nyou dullard?\nWhat's the use of your deerskin cloak?\nThe tangle's inside you.\nYou comb the outside."},{"k":"suddhaso","t":"Fool, what does tangled hair do for you?\nWhat does a goatskin robe do for you?\nInside you there is a jungle;\nyou only polish the outside."},{"k":"sujato","t":"Why the matted hair, you simpleton,\nand why the skin of deer?\nThe tangle is inside you,\nyet you polish up your outsides."}]},{"n":395,"vg":26,"pali":"Paṁsukūladharaṁ jantuṁ,\nkisaṁ dhamanisanthataṁ;\nEkaṁ vanasmiṁ jhāyantaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"The man who wears dirty raiments, who is emaciated and covered with veins, who lives alone in the forest, and meditates, him I call indeed a Brahmana."},{"k":"wagiswara","t":"Whoso wears rags from dustheaps picked, whoso is lean,\nWith veins o'erspread, who in the jungle dwells\nAnd meditates in loneliness;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who wears the cast-off garments (of a hermit), who is emaciated with the veins of his body standing out, who is solitary and contemplative in the forest — him I call a Brahman."},{"k":"buddharakkhita","t":"The person who wears a robe made of rags, who is lean, with veins showing all over the body, and who meditates alone in the forest — him do I call a holy man."},{"k":"thanissaro","t":"Wearing cast-off rags\n— his body lean & lined with veins —\nabsorbed in jhana,\nalone in the forest:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"A person wearing rag-robes,\nlean, with protruding veins,\nmeditating alone in the forest -\nthat is who I call a brahmin."},{"k":"sujato","t":"A personage who wears robes of rags,\nlean, their limbs showing veins,\nmeditating alone in the forest,\nthat's who I declare a brahmin."}]},{"n":396,"vg":26,"pali":"Na cāhaṁ brāhmaṇaṁ brūmi,\nyonijaṁ mattisambhavaṁ;\nBhovādi nāma so hoti,\nsace hoti sakiñcano;\nAkiñcanaṁ anādānaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"I do not call a man a Brahmana because of his origin or of his mother. He is indeed arrogant, and he is wealthy: but the poor, who is free from all attachments, him I call indeed a Brahmana."},{"k":"wagiswara","t":"One is not Brāhmaṇa because of race or birth;\n\"Hail-fellow\" is such called, and riches hath.\nPossessing naught, free from desire\nIs one I call a Brāhmaṇa."},{"k":"kaviratna","t":"I do not call him a Brahman merely because he is born in the caste of the noble ones, or of a Brahman mother. If he is a possessor (of passions), he becomes known by the appellation bhovadi. But one who is free from possessions (craving) and from worldly attachments — him I call a Brahman."},{"k":"buddharakkhita","t":"I do not call him a holy man because of his lineage or high-born mother. If he is full of impeding attachments, he is just a supercilious man. But who is free from impediments and clinging — him do I call a holy man."},{"k":"thanissaro","t":"I don't call one a brahman\nfor being born of a mother\nor sprung from a womb.\nHe's called a 'bho-sayer'\nif he has anything at all.\nBut someone with nothing,\nwho clings to no thing:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"I do not say that one is a brahmin\nbecause of the womb they were born from or the mother that produced them;\nif they are possessive;\nbut one who is not possessive and not acquisitive -\nthat is who I call a brahmin."},{"k":"sujato","t":"I don't call someone a brahmin\nafter the mother's womb they're born from.\nIf they still have attachments,\nthey're just someone who says \"worthy\".\nHaving nothing, taking nothing:\nthat's who I declare a brahmin."}]},{"n":397,"vg":26,"pali":"Sabbasaṁyojanaṁ chetvā,\nyo ve na paritassati;\nSaṅgātigaṁ visaṁyuttaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who has cut all fetters, who never trembles, is independent and unshackled."},{"k":"wagiswara","t":"Whoso hath cut all fetters off and hath no fear\nOf what may him befall; whoso from bonds\nAnd all attachments is released;\nIs one I call a Brāhmaṇa."},{"k":"kaviratna","t":"He who has cut off all impediments and does not tremble with fears, who has passed beyond attachments and is free from shackles — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, having cut off all fetters, trembles no more, who has overcome all attachments and is emancipated — him do I call a holy man."},{"k":"thanissaro","t":"Having cut every fetter,\nhe doesn't get ruffled.\nBeyond attachment,\nunshackled:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has cut all fetters\nand is not agitated,\nwho has transcended all bonds and is unattached -\nthat is who I call a brahmin."},{"k":"sujato","t":"Having cut off all fetters\nthey have no anxiety.\nThey've slipped their chains and are detached:\nthat's who I declare a brahmin."}]},{"n":398,"vg":26,"pali":"Chetvā naddhiṁ varattañca,\nsandānaṁ sahanukkamaṁ;\nUkkhittapalighaṁ buddhaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who has cut the strap and the thong, the chain with all that pertains to it, who has burst the bar, and is awakened."},{"k":"wagiswara","t":"Whoso hath cut the strap, the leathern thong, the ropes\nAnd all thereto pertaining, and the bar\nHath lifted; him, the Awakened one;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He is enlightened who has cut the strap (of ill will) and the thong (of craving), who has broken the chain (of heretical views) with its appurtenances (latent tendencies), and has removed the crossbar (of ignorance) — him I call a Brahman."},{"k":"buddharakkhita","t":"He who has cut off the thong (of hatred), the band (of craving), and the rope (of false views), together with the appurtenances (latent evil tendencies), he who has removed the crossbar (of ignorance) and is enlightened — him do I call a holy man."},{"k":"thanissaro","t":"Having cut the strap & thong,\ncord & bridle,\nhaving thrown off the bar,\nawakened:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Having cut the thong and strap,\nhaving broken every link of the chain,\none who has removed the barricade and is awakened -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've cut the strap and harness,\nthe halter and bridle too,\nwith cross-bar lifted, they're awakened:\nthat's who I declare a brahmin."}]},{"n":399,"vg":26,"pali":"Akkosaṁ vadhabandhañca,\naduṭṭho yo titikkhati;\nKhantībalaṁ balānīkaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who, though he has committed no offence, endures reproach, bonds, and stripes, who has endurance for his force, and strength for his army."},{"k":"wagiswara","t":"He who endures, tho' innocent of all offence,\nAbuse and blows and e'en imprisonment\nWith patience strong, a host in strength;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who with forgiveness bears up under reproach, abuse and punishment, and who looks upon patience as his army and strength as his force — him I call a Brahman."},{"k":"buddharakkhita","t":"He who without resentment endures abuse, beating and punishment; whose power, real might, is patience — him do I call a holy man."},{"k":"thanissaro","t":"He endures — unangered —\ninsult, assault, & imprisonment.\nHis army is strength;\nhis strength, forbearance:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Insult, attack, imprisonment -\none who endures these without getting upset,\nwith patience as strong as an army -\nthat is who I call a brahmin."},{"k":"sujato","t":"Abuse, killing, caging:\nthey endure these without anger.\nPatience is their powerful army:\nthat's who I declare a brahmin."}]},{"n":400,"vg":26,"pali":"Akkodhanaṁ vatavantaṁ,\nsīlavantaṁ anussadaṁ;\nDantaṁ antimasārīraṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who is free from anger, dutiful, virtuous, without appetite, who is subdued, and has received his last body."},{"k":"wagiswara","t":"Who hath no anger, who to all his vows is true,\nUpright in life, from passion free, subdued,\nNo more on earth to be reborn;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who is free from anger, who vigilantly performs his religious practices, who is virtuous, pure, self-restrained, and bears his physical body for the last time — him I call a Brahman."},{"k":"buddharakkhita","t":"He who is free from anger, is devout, virtuous, without craving, self-subdued and bears his final body — him do I call a holy man."},{"k":"thanissaro","t":"Free from anger,\nduties observed,\nprincipled, with no overbearing pride,\ntrained, a 'last-body':\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Free from anger, religious,\nvirtuous, humble,\ntrained, bearing their final body -\nthat is who I call a brahmin."},{"k":"sujato","t":"Not irritable or pretentious,\ndutiful in precepts and observances,\ntamed, bearing their final body:\nthat's who I declare a brahmin."}]},{"n":401,"vg":26,"pali":"Vāri pokkharapatteva,\nāraggeriva sāsapo;\nYo na limpati kāmesu,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who does not cling to pleasures, like water on a lotus leaf, like a mustard seed on the point of a needle."},{"k":"wagiswara","t":"Who like a dew-drop on a lotus-lily leaf,\nOr seed of mustard on a needle's point,\nClings not to any worldly bliss;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who, like water on a lotus leaf, or a mustard seed on the point of an awl, does not cling to sensuous pleasures him I call a Brahman."},{"k":"buddharakkhita","t":"Like water on a lotus leaf, or a mustard seed on the point of a needle, he who does not cling to sensual pleasures — him do I call a holy man."},{"k":"thanissaro","t":"Like water on a lotus leaf,\na mustard seed on the tip of an awl,\nhe doesn't adhere to sensual pleasures:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Like water on a lotus leaf,\nlike a mustard seed on a needle tip,\none to whom sensuality does not stick -\nthat is who I call a brahmin."},{"k":"sujato","t":"Like water from a lotus leaf,\nlike a mustard seed off a pin-point,\nsensual pleasures slip off them:\nthat's who I declare a brahmin."}]},{"n":402,"vg":26,"pali":"Yo dukkhassa pajānāti,\nidheva khayamattano;\nPannabhāraṁ visaṁyuttaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who, even here, knows the end of his suffering, has put down his burden, and is unshackled."},{"k":"wagiswara","t":"Who knoweth even in this world his sorrow's end,\nWho bath laid down the burden of desire,\nEmancipated from his bonds;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who while in this world realizes the end of his suffering, who has laid aside the burden (of his skandhas) and is free from attachments — him I call a Brahman."},{"k":"buddharakkhita","t":"He who in this very life realizes for himself the end of suffering, who has laid aside the burden and become emancipated — him do I call a holy man."},{"k":"thanissaro","t":"He discerns right here,\nfor himself,\non his own,\nhis own\nending of stress.\nUnshackled, his burden laid down:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who understands suffering\nand has personally eliminated it here and now,\nwho has set down the burden, unattached -\nthat is who I call a brahmin."},{"k":"sujato","t":"They understand for themselves\nthe end of suffering in this life;\nwith burden put down, detached:\nthat's who I declare a brahmin."}]},{"n":403,"vg":26,"pali":"Gambhīrapaññaṁ medhāviṁ,\nmaggāmaggassa kovidaṁ;\nUttamatthamanuppattaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana whose knowledge is deep, who possesses wisdom, who knows the right way and the wrong, and has attained the highest end."},{"k":"wagiswara","t":"Whoso is deep in wisdom and intelligence,\nWho can with skill discern the right and wrong,\nWho hath attained the highest goal;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He whose wisdom is deep, who is expert in knowledge and in discerning the right from the wrong path; he who has realized the supreme goal — him I call a Brahman."},{"k":"buddharakkhita","t":"He who has profound knowledge, who is wise, skilled in discerning the right or wrong path, and has reached the highest goal — him do I call a holy man."},{"k":"thanissaro","t":"Wise, profound\nin discernment, astute\nas to what is the path\n& what's not;\nhis ultimate goal attained:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has profound wisdom and intelligence,\nexpert in what is and is not the path,\nwho has attained the highest goal -\nthat is who I call a brahmin."},{"k":"sujato","t":"Deep in wisdom, intelligent,\nexpert in the path and what is not the path;\narrived at the highest goal:\nthat's who I declare a brahmin."}]},{"n":404,"vg":26,"pali":"Asaṁsaṭṭhaṁ gahaṭṭhehi,\nanāgārehi cūbhayaṁ;\nAnokasārimappicchaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who keeps aloof both from laymen and from mendicants, who frequents no houses, and has but few desires."},{"k":"wagiswara","t":"Whoso with householders and wanderers alike\nSmall dealings hath, who lives the homeless life,\nA mendicant of scanty needs;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who does not associate closely either with householders (laymen) or with the homeless (mendicants), who does not frequent houses and who is content with few wants — him I call a Brahman."},{"k":"buddharakkhita","t":"He who holds aloof from householders and ascetics alike, and wanders about with no fixed abode and but few wants — him do I call a holy man."},{"k":"thanissaro","t":"Uncontaminated\nby householders\n& houseless ones alike;\nliving with no home,\nwith next to no wants:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Not involved with laypeople\nor with monks,\na homeless wanderer with few wishes -\nthat is who I call a brahmin."},{"k":"sujato","t":"Mixing with neither\nhouseholders nor the homeless;\na migrant with no bastion, few in wishes:\nthat's who I declare a brahmin."}]},{"n":405,"vg":26,"pali":"Nidhāya daṇḍaṁ bhūtesu,\ntasesu thāvaresu ca;\nYo na hanti na ghāteti,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who finds no fault with other beings, whether feeble or strong, and does not kill nor cause slaughter."},{"k":"wagiswara","t":"Whoso withholds the rod of painful punishment\nFrom living creatures, be they weak or strong,\nWho neither strikes nor makes to strike,\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has laid aside the cudgel that injures any creature whether moving or still, who neither slays nor causes to be slain — him I call a Brahman."},{"k":"buddharakkhita","t":"He who has renounced violence towards all living beings, weak or strong, who neither kills nor causes others to kill — him do I call a holy man."},{"k":"thanissaro","t":"Having put aside violence\nagainst beings fearful or firm,\nhe neither kills nor\ngets others to kill:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has renounced violence towards living beings,\nwhether weak or strong,\nwho does not injure or kill -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've laid aside violence\nagainst creatures firm and frail;\nnot killing or making others kill:\nthat's who I declare a brahmin."}]},{"n":406,"vg":26,"pali":"Aviruddhaṁ viruddhesu,\nattadaṇḍesu nibbutaṁ;\nSādānesu anādānaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who is tolerant with the intolerant, mild with fault-finders, and free from passion among the passionate."},{"k":"wagiswara","t":"Whoso forbearance hath to those that hinder him,\nAnd to the angry showeth gentleness,\nAmong the greedy without greed;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who is tolerant amongst the intolerant, who is calm amongst the violent, and who is unattached amongst those who are attached — him I call a Brahman."},{"k":"buddharakkhita","t":"He who is friendly amidst the hostile, peaceful amidst the violent, and unattached amidst the attached — him do I call a holy man."},{"k":"thanissaro","t":"Unopposing among opposition,\nunbound among the armed,\nunclinging among those who cling:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who is unhindered amidst the hindered,\nself-disciplined, cooled,\nnot acquisitive amidst the acquisitive -\nthat is who I call a brahmin."},{"k":"sujato","t":"Not fighting among those who fight,\nquenched among those who have taken up arms,\nnot grasping among those who grasp:\nthat's who I declare a brahmin."}]},{"n":407,"vg":26,"pali":"Yassa rāgo ca doso ca,\nmāno makkho ca pātito;\nSāsaporiva āraggā,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana from whom anger and hatred, pride and envy have dropt like a mustard seed from the point of a needle."},{"k":"wagiswara","t":"From whom all anger, hate, hypocrisy and pride\nHave fall'n away, as from a needle's point\nA grain of mustard-seed falls off;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"The one from whom lust and hatred, pride and hypocrisy have fallen away, like a mustard seed from the point of an awl — him I call a Brahman."},{"k":"buddharakkhita","t":"He whose lust and hatred, pride and hypocrisy have fallen off like a mustard seed from the point of a needle — him do I call a holy man."},{"k":"thanissaro","t":"His passion, aversion,\nconceit, & contempt,\nhave fallen away —\nlike a mustard seed\nfrom the tip of an awl:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One from whom passion, hatred,\nconceit, and contempt have fallen away,\nlike mustard seeds from a needle tip -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've discarded greed and hate,\nalong with conceit and contempt,\nlike a mustard seed off the point of a pin:\nthat's who I declare a brahmin."}]},{"n":408,"vg":26,"pali":"Akakkasaṁ viññāpaniṁ,\ngiraṁ saccamudīraye;\nYāya nābhisaje kañci,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who utters true speech, instructive and free from harshness, so that he offend no one."},{"k":"wagiswara","t":"Gentle in ways and apt to teach his fellow-men,\nWhoso will utter truth and naught but truth,\nWhoso in speech offendeth not;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who speaks gentle, instructive and truthful words, whose utterances offend no one — him I call a Brahman."},{"k":"buddharakkhita","t":"He who utters gentle, instructive and truthful words, who imprecates none — him do I call a holy man."},{"k":"thanissaro","t":"He would say\nwhat's non-grating,\ninstructive,\ntrue —\nabusing no one:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who speaks words that are gentle, instructive,\nand true,\nand that do not create attachment to anything -\nthat is who I call a brahmin."},{"k":"sujato","t":"The words they utter\nare polished, informative, and true,\nand don't offend anyone:\nthat's who I declare a brahmin."}]},{"n":409,"vg":26,"pali":"Yodha dīghaṁ va rassaṁ vā,\naṇuṁ thūlaṁ subhāsubhaṁ;\nLoke adinnaṁ nādiyati,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who takes nothing in the world that is not given him, be it long or short, small or large, good or bad."},{"k":"wagiswara","t":"He that takes nothing in this world that is not given,\nWhatever it may be, or great or small,\nOr long or short or good or bad;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who takes no object in this world that is not given to him, be it short or long, small or great, fair or ugly — him I call a Brahman."},{"k":"buddharakkhita","t":"He who in this world takes nothing that is not given to him, be it long or short, small or big, good or bad — him do I call a holy man."},{"k":"thanissaro","t":"Here in the world\nhe takes nothing not-given\n— long, short,\nlarge, small,\nattractive, not:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who steals nothing in the world -\nwhether it is long or short, small or large,\nbeautiful or ugly -\nthat is who I call a brahmin."},{"k":"sujato","t":"They don't steal anything in the world,\nlong or short,\nfine or coarse, beautiful or ugly:\nthat's who I declare a brahmin."}]},{"n":410,"vg":26,"pali":"Āsā yassa na vijjanti,\nasmiṁ loke paramhi ca;\nNirāsāsaṁ visaṁyuttaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who fosters no desires for this world or for the next, has no inclinations, and is unshackled."},{"k":"wagiswara","t":"In whom is seen no more the longing of desire\nFor this world or beyond, who hath no lust,\nWho hath no fetters any more;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has no desires regarding this world or the next, who is free of longings and without fetters — him I call a Brahman."},{"k":"buddharakkhita","t":"He who wants nothing of either this world or the next, who is desire-free and emancipated — him do I call a holy man."},{"k":"thanissaro","t":"His longing for this\n& for the next world\ncan't be found;\nfree from longing, unshackled:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One in whom no longing can be found,\nfor this world or the next,\nfree of longing, unattached -\nthat is who I call a brahmin."},{"k":"sujato","t":"They have no hope\nin this world or the next;\nwith no need for hope, detached:\nthat's who I declare a brahmin."}]},{"n":411,"vg":26,"pali":"Yassālayā na vijjanti,\naññāya akathaṅkathī;\nAmatogadhamanuppattaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who has no interests, and when he has understood (the truth), does not say How, how? and who has reached the depth of the Immortal."},{"k":"wagiswara","t":"In whom is seen no craving, who, because he knows,\nAsks not in doubt the How or Why, for he\nHath reached Nibbāna's peace profound;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who is free from craving and free from doubt through the realization of truth, and who has reached the depth of the deathless state (nirvana) — him I call a Brahman."},{"k":"buddharakkhita","t":"He who has no attachment, who through perfect knowledge is free from doubts and has plunged into the Deathless — him do I call a holy man."},{"k":"thanissaro","t":"His attachments,\nhis homes,\ncan't be found.\nThrough knowing\nhe is unperplexed,\nhas come ashore\nin the Deathless:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One in whom no adherence can be found,\nwho has overcome confusion through direct knowledge,\nwho has reached immersion in the deathless -\nthat is who I call a brahmin."},{"k":"sujato","t":"They have no clinging,\nknowledge has freed them of indecision,\nthey've arrived at the objective, freedom from death:\nthat's who I declare a brahmin."}]},{"n":412,"vg":26,"pali":"Yodha puññañca pāpañca,\nubho saṅgamupaccagā;\nAsokaṁ virajaṁ suddhaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who in this world is above good and evil, above the bondage of both, free from grief from sin, and from impurity."},{"k":"wagiswara","t":"Whoso on earth hath passed beyond the opposites\nOf good and evil, and is free from grief,\nFrom passion and impurity;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has transcended the bonds of both merit and demerit, who is sorrowless, free from passions, and pure him I call a Brahman."},{"k":"buddharakkhita","t":"He who in this world has transcended the ties of both merit and demerit, who is sorrowless, stainless and pure — him do I call a holy man."},{"k":"thanissaro","t":"He has gone\nbeyond attachment here\nfor both merit & evil —\nsorrowless, dustless, & pure:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has transcended\nattachment to both merit and evil,\nsorrowless, immaculate, and pure -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've escaped clinging\nto both good and bad deeds;\nsorrowless, stainless, pure:\nthat's who I declare a brahmin."}]},{"n":413,"vg":26,"pali":"Candaṁva vimalaṁ suddhaṁ,\nvippasannamanāvilaṁ;\nNandībhavaparikkhīṇaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who is bright like the moon, pure, serene, undisturbed, and in whom all gaiety is extinct."},{"k":"wagiswara","t":"Who, like the moon on high, is stainless, pure and calm,\nTranslucent and serene, who hath restrained\nThe rise of all delightful states;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who like the moon, is stainless, pure, serene and unruffled, in whom desire for existence is extinguished — him I call a Brahman."},{"k":"buddharakkhita","t":"He, who, like the moon, is spotless and pure, serene and clear, who has destroyed the delight in existence — him do I call a holy man."},{"k":"thanissaro","t":"Spotless, pure, like the moon\n— limpid & calm —\nhis delights, his becomings,\ntotally gone:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who, like the moon, is stainless, pure,\nclear, and undisturbed;\none who has completely eliminated delight in existence -\nthat is who I call a brahmin."},{"k":"sujato","t":"Pure as the spotless moon,\nclear and undisturbed,\nthey've ended relish for rebirth:\nthat's who I declare a brahmin."}]},{"n":414,"vg":26,"pali":"Yomaṁ palipathaṁ duggaṁ,\nsaṁsāraṁ mohamaccagā;\nTiṇṇo pāraṅgato jhāyī,\nanejo akathaṅkathī;\nAnupādāya nibbuto,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who has traversed this miry road, the impassable world and its vanity, who has gone through, and reached the other shore, is thoughtful, guileless, free from doubts, free from attachment, and content."},{"k":"wagiswara","t":"Whoso hath trod the hard and muddy road of births,\nHath crossed delusion, reached the other shore,\nNor lusts, nor doubts, grasps not, is calm,\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has traversed this miry path of samsara, difficult to pass; who has rid himself of delusion, crossed over and reached the other shore; who is absorbed in contemplation, free from craving and doubts, not grasping, and inwardly calm — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, having traversed this miry, perilous and delusive round of existence, has crossed over and reached the other shore; who is meditative, calm, free from doubt, and, clinging to nothing, has attained to Nibbana — him do I call a holy man."},{"k":"thanissaro","t":"He has made his way past\nthis hard-going path\n— samsara, delusion —\nhas crossed over,\nhas gone beyond,\nis free from want,\nfrom perplexity,\nabsorbed in jhana,\nthrough no-clinging\nUnbound:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"This dangerous, difficult path,\nSaṁsāra, delusion -\na meditator who has transcended it, crossed over it, gone beyond it,\nwho is unmoved, unconfused,\nand enlightened through non-grasping -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've got past this grueling swamp\nof delusion, transmigration.\nMeditating in stillness, free of indecision,\nthey have crossed over to the far shore.\nThey're quenched by not grasping:\nthat's who I declare a brahmin."}]},{"n":415,"vg":26,"pali":"Yodha kāme pahantvāna,\nanāgāro paribbaje;\nKāmabhavaparikkhīṇaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who in this world, leaving all desires, travels about without a home, and in whom all concupiscence is extinct."},{"k":"wagiswara","t":"Who homeless wanders through this world, a mendicant,\nAbandoning desires, who hath restrained\nThe rise of sensual delight;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who in this world has relinquished all sensuous pleasures, wanders homeless (for the welfare of the many), and has destroyed all desire (kama) for existence — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, having abandoned sensual pleasures, has renounced the household life and become a homeless one; has destroyed both sensual desire and continued existence — him do I call a holy man."},{"k":"thanissaro","t":"Whoever, abandoning sensual passions here,\nwould go forth from home —\nhis sensual passions, becomings,\ntotally gone:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has abandoned sensuality,\nwho wanders without a home,\nwho has completely eliminated sensual existence -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've given up sensual stimulations,\nand have gone forth from lay life;\nthey've ended rebirth in the sensual realm:\nthat's who I declare a brahmin."}]},{"n":416,"vg":26,"pali":"Yodha taṇhaṁ pahantvāna,\nanāgāro paribbaje;\nTaṇhābhavaparikkhīṇaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.\nJotikattheravatthu\nYodha taṇhaṁ pahantvāna,\nanāgāro paribbaje;\nTaṇhābhavaparikkhīṇaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who, leaving all longings, travels about without a home, and in whom all covetousness is extinct."},{"k":"wagiswara","t":"Who homeless wanders through this world a mendicant,\nAbandoning his lust; who hath restrained\nThe rise of craving and desire;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who in this world has extinguished all craving, wanders homeless, and has destroyed all thirst (tanha) for existence — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, having abandoned craving, has renounced the household life and become a homeless one, has destroyed both craving and continued existence — him do I call a holy man."},{"k":"thanissaro","t":"Whoever, abandoning craving here,\nwould go forth from home —\nhis cravings, becomings,\ntotally gone:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has abandoned craving,\nwho wanders without a home,\nwho has completely eliminated craving for existence -\nthat is who I call a brahmin.\nOne who has abandoned craving,\nwho wanders without a home,\nwho has completely eliminated craving for existence -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've given up craving,\nand have gone forth from lay life;\nthey've ended craving to be reborn:\nthat's who I declare a brahmin.\nThey've given up craving,\nand have gone forth from lay life;\nthey've ended craving to be reborn:\nthat's who I declare a brahmin."}]},{"n":417,"vg":26,"pali":"Hitvā mānusakaṁ yogaṁ,\ndibbaṁ yogaṁ upaccagā;\nSabbayogavisaṁyuttaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who, after leaving all bondage to men, has risen above all bondage to the gods, and is free from all and every bondage."},{"k":"wagiswara","t":"Whoso hath left behind all ties that bind on earth,\nAnd e'en the heavenly world transcended hath;\nWhoso from every tie is free;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has abandoned all human ties and transcended even the celestial ties; who is truly free from all attachments — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, casting off human bonds and transcending heavenly ties, is wholly delivered of all bondages — him do I call a holy man."},{"k":"thanissaro","t":"Having left behind\nthe human bond,\nhaving made his way past\nthe divine,\nfrom all bonds unshackled:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who is no longer attached to human existence,\nand is not attached to celestial existence either;\none who is not attached to anything -\nthat is who I call a brahmin."},{"k":"sujato","t":"They've thrown off the human yoke,\nand slipped out of the heavenly yoke;\nunyoked from all yokes:\nthat's who I declare a brahmin."}]},{"n":418,"vg":26,"pali":"Hitvā ratiñca aratiñca,\nsītibhūtaṁ nirūpadhiṁ;\nSabbalokābhibhuṁ vīraṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who has left what gives pleasure and what gives pain, who is cold, and free from all germs (of renewed life), the hero who has conquered all the worlds."},{"k":"kaviratna","t":"He who has put aside what gives pleasure as well as what gives pain, who is passionless and free from the causal seeds of existence (nirupadhi), the hero who has conquered all the worlds — him I call a Brahman."},{"k":"buddharakkhita","t":"He who, having cast off likes and dislikes, has become tranquil, is rid of the substrata of existence and like a hero has conquered all the worlds — him do I call a holy man."},{"k":"thanissaro","t":"Having left behind\ndelight & displeasure,\ncooled, with no acquisitions —\na hero who has conquered\nall the world,\nevery world:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"Having relinquished liking and disliking,\nserene and non-possessive,\na hero who has overcome the entire world -\nthat is who I call a brahmin."},{"k":"sujato","t":"Giving up desire and discontent,\nthey're cooled and free of attachments;\na hero, master of the whole world:\nthat's who I declare a brahmin."}]},{"n":419,"vg":26,"pali":"Cutiṁ yo vedi sattānaṁ,\nupapattiñca sabbaso;\nAsattaṁ sugataṁ buddhaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who knows the destruction and the return of beings everywhere, who is free from bondage, welfaring (Sugata), and awakened (Buddha)."},{"k":"wagiswara","t":"Who knows the rise and fall of things in birth and death,\nWho is not of the world, who hath the path\nWell trod, who hath become awake;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has all knowledge concerning the death and rebirth of all beings, is unattached, who is content in himself (sugata), and enlightened (buddha) — him I call a Brahman."},{"k":"buddharakkhita","t":"He who in every way knows the death and rebirth of all beings, and is totally detached, blessed and enlightened — him do I call a holy man."},{"k":"thanissaro","t":"He knows in every way\nbeings' passing away,\nand their re-\narising;\nunattached, awakened,\nwell-gone:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who completely understands\nthe death and rebirth of sentient beings,\nunattached, heavenly, awake -\nthat is who I call a brahmin."},{"k":"sujato","t":"They know the passing away\nand rebirth of all beings;\nunattached, holy, awakened:\nthat's who I declare a brahmin."}]},{"n":420,"vg":26,"pali":"Yassa gatiṁ na jānanti,\ndevā gandhabbamānusā;\nKhīṇāsavaṁ arahantaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana whose path the gods do not know, nor spirits (Gandharvas), nor men, whose passions are extinct, and who is an Arhat (venerable)."},{"k":"wagiswara","t":"Whose passage hence the gods themselves cannot discern,\nNor demi-gods nor men; a worthy one\nIn whom the passions are subdued;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He whose path is unknown to devas, gandharvas and men, who has nullified all sensuous influxes and is a Holy One (arahant) — him I call a Brahman."},{"k":"buddharakkhita","t":"He whose track no gods, no angels, no humans trace, the arahant who has destroyed all cankers — him do I call a holy man."},{"k":"thanissaro","t":"He whose course they don't know\n— devas, gandhabbas, & human beings —\nhis effluents ended, an arahant:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One whose destiny is not known\nby any angel, spirit, or human,\nan Arahant whose corruptions have been eliminated -\nthat is who I call a brahmin."},{"k":"sujato","t":"Gods, centaurs, and humans\ndon't know their destiny;\nthe perfected ones with defilements ended:\nthat's who I declare a brahmin."}]},{"n":421,"vg":26,"pali":"Yassa pure ca pacchā ca,\nmajjhe ca natthi kiñcanaṁ;\nAkiñcanaṁ anādānaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who calls nothing his own, whether it be before, behind, or between, who is poor, and free from the love of the world."},{"k":"wagiswara","t":"To whom pertaineth naught of past or future things\nOr of the present; one who owneth naught,\nWho hath no wish for anything;\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who has no longing for what is ahead, behind, or in the middle, who possesses nothing and is attached to nothing — him I call a Brahman."},{"k":"buddharakkhita","t":"He who clings to nothing of the past, present and future, who has no attachment and holds on to nothing — him do I call a holy man."},{"k":"thanissaro","t":"He who has nothing\n— in front, behind, in between —\nthe one with nothing\nwho clings to no thing:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who has nothing before, after,\nor in the middle;\none who is not possessive and not acquisitive -\nthat is who I call a brahmin."},{"k":"sujato","t":"They have nothing before or after,\nor even in between.\nHaving nothing, taking nothing:\nthat's who I declare a brahmin."}]},{"n":422,"vg":26,"pali":"Usabhaṁ pavaraṁ vīraṁ,\nmahesiṁ vijitāvinaṁ;\nAnejaṁ nhātakaṁ buddhaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.","v":[{"k":"muller","t":"Him I call indeed a Brahmana, the manly, the noble, the hero, the great sage, the conqueror, the impassible, the accomplished, the awakened."},{"k":"wagiswara","t":"Dauntless, pre-eminent, heroic mighty seer,\nThe conqueror, desireless one, made clean,\nWhose eyes have opened to the light,\nHim I deem a Brāhmaṇa."},{"k":"kaviratna","t":"He who is fearless (as a bull), distinguished and heroic, a great sage, a conqueror; who is entirely free from craving and who has washed off all impurities, an Enlightened One — him I call a Brahman."},{"k":"buddharakkhita","t":"He, the Noble, the Excellent, the Heroic, the Great Sage, the Conqueror, the Passionless, the Pure, the Enlightened one — him do I call a holy man."},{"k":"thanissaro","t":"A splendid bull, conqueror,\nhero, great seer —\nfree from want,\nawakened, washed:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"A bull, an excellent hero,\na great sage, a victor,\nunmoved, cleansed, awake -\nthat is who I call a brahmin."},{"k":"sujato","t":"Captain of the herd, excellent hero,\ngreat seer and victor;\nunstirred, washed, awakened:\nthat's who I declare a brahmin."}]},{"n":423,"vg":26,"pali":"Pubbenivāsaṁ yo vedi,\nsaggāpāyañca passati;\nAtho jātikkhayaṁ patto,\nabhiññāvosito muni;\nSabbavositavosānaṁ,\ntamahaṁ brūmi brāhmaṇaṁ.\nBrāhmaṇavaggo chabbīsatimo.\nEttāvatā sabbapaṭhame yamakavagge cuddasa vatthūni, appamādavagge nava, cittavagge nava, pupphavagge dvādasa, bālavagge pannarasa, paṇḍitavagge ekādasa, arahantavagge dasa, sahassavagge cuddasa, pāpavagge dvādasa, daṇḍavagge ekādasa, jarāvagge nava, attavagge dasa, lokavagge ekādasa, buddhavagge nava, sukhavagge aṭṭha, piyavagge nava, kodhavagge aṭṭha, malavagge dvādasa, dhammaṭṭhavagge dasa, maggavagge dvādasa, pakiṇṇakavagge nava, nirayavagge nava, nāgavagge aṭṭha, taṇhāvagge dvādasa, bhikkhuvagge dvādasa, brāhmaṇavagge cattālīsāti pañcādhikāni tīṇi vatthusatāni.\nSatevīsacatussatā,\ncatusaccavibhāvinā;\nSatattayañca vatthūnaṁ,\npañcādhikaṁ samuṭṭhitāti.\nDhammapade vaggānamuddānaṁ\nYamakappamādo cittaṁ,\npupphaṁ bālena paṇḍito;\nArahanto sahassañca,\npāpaṁ daṇḍena te dasa.\nJarā attā ca loko ca,\nbuddho sukhaṁ piyena ca;\nKodho malañca dhammaṭṭho,\nmaggavaggena vīsati.\nPakiṇṇaṁ nirayo nāgo,\ntaṇhā bhikkhu ca brāhmaṇo;\nEte chabbīsati vaggā,\ndesitādiccabandhunā.\nGāthānamuddānaṁ\nYamake vīsati gāthā,\nappamādamhi dvādasa;\nEkādasa cittavagge,\npupphavaggamhi soḷasa.\nBāle ca soḷasa gāthā,\npaṇḍitamhi catuddasa;\nArahante dasa gāthā,\nsahasse honti soḷasa.\nTerasa pāpavaggamhi,\ndaṇḍamhi dasa satta ca;\nEkādasa jarā vagge,\nattavaggamhi tā dasa.\nDvādasa lokavaggamhi,\nbuddhavaggamhi ṭhārasa;\nSukhe ca piyavagge ca,\ngāthāyo honti dvādasa.\nCuddasa kodhavaggamhi,\nmalavaggekavīsati;\nSattarasa ca dhammaṭṭhe,\nmaggavagge sattarasa.\nPakiṇṇe soḷasa gāthā,\nniraye nāge ca cuddasa;\nChabbīsa taṇhāvaggamhi,\ntevīsa bhikkhuvaggikā.\nEkatālīsagāthāyo,\nbrāhmaṇe vaggamuttame;\nGāthāsatāni cattāri,\ntevīsa ca punāpare;\nDhammapade nipātamhi,\ndesitādiccabandhunāti.\nDhammapadapāḷi samattā.","v":[{"k":"muller","t":"Him I call indeed a Brahmana who knows his former abodes, who sees heaven and hell, has reached the end of births, is perfect in knowledge, a sage, and whose perfections are all perfect."},{"k":"wagiswara","t":"Who knows his former births, who sees both heaven and hell,\nWho now at last hath reached the end of births;\nPerfect in knowledge he who hath done all things well,\nThat sage I call a Brāhmaṇa."},{"k":"kaviratna","t":"He who knows his former abodes (his lives), who perceives (through spiritual insight) both heaven and hell, who has reached the end of all births, who has perfected himself in wisdom; such a sage who has accomplished all that ought to be accomplished (on the sublime path) — him I call a Brahman."},{"k":"buddharakkhita","t":"He who knows his former births, who sees heaven and hell, who has reached the end of births and attained to the perfection of insight, the sage who has reached the summit of spiritual excellence — him do I call a holy man."},{"k":"thanissaro","t":"He knows his former lives.\nHe sees heavens & states of woe,\nhas attained the ending of birth,\nis a sage who has mastered full-knowing,\nhis mastery\ntotally mastered:\nhe's what I call\na brahman."},{"k":"suddhaso","t":"One who knows their past lives,\nwho sees heaven and hell,\nwho has reached the elimination of birth,\na sage who has mastery of higher knowledge,\nwho has mastered every attainment -\nthat is who I call a brahmin."},{"k":"sujato","t":"One who knows their past lives,\nsees heaven and places of loss,\nand has attained the end of rebirth;\na sage of perfect insight\nat the summit of spiritual perfection:\nthat's who I declare a brahmin.\nThe Sayings of the Dhamma are complete."}]}]};
